import { useState, useMemo } from "react";

const FACES = [{"name": "The Flame", "factor": "Factor 1: Passion ↔ Stability", "factor_num": 1, "pole": "Passion", "color": "#D4A843", "alignment": "Healthy", "tagline": "I burn for you, and the fire gives life.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Eternal Ember", "desc": "Passion so deep it has become self-sustaining. Intensity without burnout. They love with the same fire at year twenty as day one, but the fire has learned patience.", "ex1": "A partner who still writes love letters after decades — not out of obligation, but because the feeling still moves them to.", "ex2": "An artist whose lifelong muse is their spouse, producing increasingly profound work about the same love.", "ex3": "Someone whose eyes still visibly change when their partner walks into a room, forty years in."}, {"n": 6, "name": "Radiance", "desc": "Intense passion that illuminates everyone around them. Their desire is generous — it makes their partner feel like the most wanted person alive, without pressure or demand.", "ex1": "The person at the dinner party whose obvious adoration of their partner makes every other couple reach for each other's hand.", "ex2": "A lover who can articulate exactly what they desire about their partner — specific, vivid, unhesitating — and it lands as worship, not objectification.", "ex3": "Someone who plans an anniversary not to perform romance, but because their actual enthusiasm for their partner overflows into action."}, {"n": 5, "name": "Bright Burn", "desc": "Strong, reliable passion. They bring energy and desire consistently, though it sometimes runs ahead of their partner's pace. The fire is real but not always well-timed.", "ex1": "A partner who initiates intimacy with genuine enthusiasm and frequency — sometimes misjudging the moment, but never the sincerity.", "ex2": "Someone who throws themselves fully into romantic gestures that occasionally overwhelm but always come from real feeling.", "ex3": "A lover who runs hot and makes their partner feel deeply wanted, even if they sometimes need to be reminded to slow down."}, {"n": 4, "name": "Steady Candle", "desc": "Genuine warmth, visible desire, but measured. They feel deeply but express it within safe, predictable channels. The passion is real but has been domesticated somewhat.", "ex1": "A partner who reliably shows affection — date nights, physical touch, verbal affirmation — but rarely surprises with intensity.", "ex2": "Someone who loves with warmth but whose passion surfaces on schedule: birthdays, anniversaries, Saturday nights.", "ex3": "A lover whose desire is never in question but whose expression of it has become comfortable and somewhat routine."}, {"n": 3, "name": "Flicker", "desc": "The passion is there, but inconsistent. Flares up in response to novelty or crisis, dims during the ordinary. They want to want, but can't always access it.", "ex1": "A partner who is electric during vacations or after arguments, but flat during the Tuesday-night routine.", "ex2": "Someone who knows they love their partner but struggles to feel it physically unless something disrupts the pattern.", "ex3": "A lover who responds to their partner's initiation with genuine warmth, but almost never initiates from their own internal fire."}, {"n": 2, "name": "Dying Coal", "desc": "The passion has mostly gone underground. They remember feeling it. They believe in it theoretically. But the lived experience is mostly numbness with occasional sparks of guilt.", "ex1": "A partner who says 'I love you' and means it, but can't remember the last time they felt desire without external prompting.", "ex2": "Someone who watches romantic scenes in movies and feels a pang — not of longing for someone else, but of grief for their own lost intensity.", "ex3": "A lover who goes through the motions of intimacy because they should, not because something inside them is reaching toward their partner."}, {"n": 1, "name": "Ash", "desc": "The fire is out. Not anger, not resentment — just absence. They are present in the relationship but passion has left entirely. The body is there; the flame is not.", "ex1": "A partner who sleeps beside someone every night and feels nothing — not pain, not comfort, just coexistence.", "ex2": "Someone who has genuinely forgotten what it feels like to want their partner, and has stopped wondering.", "ex3": "A lover whose physical presence in the relationship is indistinguishable from a roommate arrangement — and neither party mentions it."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Sacred Fire", "desc": "Their passion makes their partner feel like the center of the universe without trapping them there. Desire offered as a gift, never a cage. The partner is free to receive it, return it, or simply bask in it.", "ex1": "A lover who can say 'I want you so badly right now' and follow it immediately with 'but only if you want me too' — and mean both with equal intensity.", "ex2": "Someone whose desire for their partner is so clearly joyful that it functions as a mirror — the partner sees themselves as irresistible, not as prey.", "ex3": "A person who expresses their passion through sustained attention: remembering what their partner wore the first time they met, noticing the new way they laugh, tracking the evolution of their body with reverence."}, {"n": 6, "name": "Warming Light", "desc": "Passion directed outward as generosity. They study their partner's desires and meet them with enthusiasm. Their fire is shaped by attention — they burn in the direction their partner needs.", "ex1": "A lover who learns their partner's love language and speaks it fluently — not as technique, but because knowing what moves their partner genuinely excites them.", "ex2": "Someone who notices their partner had a brutal week and responds not with space (unless asked) but with fierce, deliberate tenderness — running a bath, holding them tight, making them feel claimed.", "ex3": "A partner who brings the same creative energy to their sex life at year five as month one, because their curiosity about their partner's pleasure hasn't dulled."}, {"n": 5, "name": "Bright Reach", "desc": "Openly passionate toward their partner with real warmth and consistency. Occasionally misjudges timing or intensity — runs a little hot — but the partner always knows it comes from genuine desire, not neediness.", "ex1": "A partner who texts something unexpectedly intimate in the middle of a workday — occasionally at an awkward moment, but the intent always lands as flattering.", "ex2": "Someone who pulls their partner into a kiss in public with enough enthusiasm that it's slightly embarrassing — but the partner secretly loves it.", "ex3": "A lover who suggests new things in the bedroom with excitement rather than pressure, and takes 'not tonight' without dimming, just redirecting the energy into closeness."}, {"n": 4, "name": "Warm Hands", "desc": "Reliably affectionate and desiring. Their partner feels wanted in a steady, predictable way. The passion is genuine but has settled into patterns — it's there, but it doesn't surprise anymore.", "ex1": "A partner who always reaches for the other in bed — same time, same way, and it's comfortable and welcome, if no longer electric.", "ex2": "Someone who compliments their partner regularly and means it, but the compliments have become a rotation: 'you look great,' 'I love that on you,' 'come here.'", "ex3": "A lover whose desire is dependable — their partner never doubts it, but also never wonders what's coming next."}, {"n": 3, "name": "Intermittent Spark", "desc": "Passion comes in waves. When it's there, it's real and the partner feels it. But it fades for stretches, and the partner is left guessing whether the fire will return or if this is just who they are now.", "ex1": "A partner who has bursts of romantic intensity — a surprise weekend away, a passionate evening — followed by weeks of emotional autopilot.", "ex2": "Someone whose desire clearly spikes after external triggers (a party where others flirt with their partner, a separation, a fight) but lies dormant in calm waters.", "ex3": "A lover who responds to their partner's expressed need for passion with genuine effort that lasts about two weeks before the energy dissipates again."}, {"n": 2, "name": "Fading Glow", "desc": "The partner can tell the passion is draining. Affection still exists but desire has become obligatory. The flame-bearer is trying, but the trying is visible, and that visibility is its own wound.", "ex1": "A partner who initiates intimacy and their body language says 'I'm doing this because I should' — and both of them know it.", "ex2": "Someone who plans a date night because the calendar reminds them to, and the partner can feel the difference between this and when it used to be spontaneous.", "ex3": "A lover who says 'you're beautiful' and it sounds like a fact being reported rather than a feeling being expressed."}, {"n": 1, "name": "Cold Hands", "desc": "The passion toward the partner has fully extinguished. Not cruelty — just absence. The partner reaches toward them and finds nothing reaching back. The flame-bearer may still love, but desire has left the room entirely.", "ex1": "A partner who flinches slightly — not from pain, but from surprise — when their spouse touches them, because physical contact has become that unusual.", "ex2": "Someone who can no longer remember what specifically attracted them to their partner, and the question itself feels exhausting rather than sad.", "ex3": "A lover whose partner has stopped initiating because the last dozen attempts were met with polite, empty acceptance — the rejection of being tolerated."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Consuming Sun", "desc": "Passion so overwhelming it becomes gravitational. The partner cannot exist outside of it. Every moment is intense, every interaction charged. The flame-bearer's desire has become the relationship's atmosphere — inescapable, total, and slowly suffocating.", "ex1": "A lover whose adoration is so constant and all-encompassing that their partner begins to lose friends, hobbies, and identity — not through control, but because nothing else can compete with this intensity.", "ex2": "Someone who makes love like it's the last night on earth — every single time — until their partner begins to dread the exhaustion of being desired this completely.", "ex3": "A partner whose passion requires constant reciprocation at the same pitch, and experiences anything less as betrayal. 'If you loved me the way I love you, you'd feel this too.'"}, {"n": 6, "name": "Branding Iron", "desc": "Passion used to mark territory. Their desire is real but possessive — they want their partner to feel claimed, not just loved. The heat leaves a mark that says 'mine.'", "ex1": "A lover who is incredible in bed but uses sex to reestablish dominance after any perceived threat — a coworker who smiled too long, a friend who called too late.", "ex2": "Someone whose compliments always contain an implicit ownership: 'Nobody else gets to see you like this. Nobody else knows what I know.'", "ex3": "A partner who channels jealousy into passion — the make-up sex is phenomenal, which is why the fights keep getting manufactured."}, {"n": 5, "name": "Pressure Cooker", "desc": "Passion that creates obligation. Their desire comes with an invisible invoice — the partner feels they must match, respond, perform. The flame-bearer doesn't demand explicitly, but the weight of their wanting fills every room.", "ex1": "A partner whose obvious desire makes saying 'not tonight' feel like kicking a puppy — so the other person stops saying it, and starts performing instead.", "ex2": "Someone who plans elaborate romantic experiences and then visibly deflates when their partner's reaction doesn't match the fantasy they'd scripted.", "ex3": "A lover whose intensity makes their partner feel guilty for wanting a quiet evening alone — because how do you explain wanting less of something that's supposedly a gift?"}, {"n": 4, "name": "Scorekeeping Flame", "desc": "Passion measured and tracked. They know exactly how much desire they've shown and are acutely aware of the imbalance. Their fire comes with a ledger, and the partner can feel the accounting.", "ex1": "A partner who says 'I always initiate' not as vulnerability but as accusation — and begins withholding to prove the point.", "ex2": "Someone who brings up the frequency of sex in arguments as evidence of the relationship's health, wielding their own desire as moral high ground.", "ex3": "A lover who compliments their partner and then waits — visibly — for the compliment to be returned, and the silence when it isn't becomes a weapon."}, {"n": 3, "name": "Guilt Spark", "desc": "Passion weaponized through withdrawal. They still feel desire but now use its presence or absence to punish. The partner never knows if tonight will be warmth or cold — and that uncertainty is the point.", "ex1": "A partner who runs hot after getting their way and ice-cold after being disagreed with — training the other person to associate compliance with affection.", "ex2": "Someone who withholds physical intimacy after conflict, not as a boundary but as leverage, and re-initiates only once the partner has sufficiently apologized.", "ex3": "A lover who sighs performatively when rejected, making sure their partner knows that every 'no' is being catalogued and will be referenced later."}, {"n": 2, "name": "Bitter Ember", "desc": "The passion has curdled into resentment. They still want, but what they want is mixed with anger — at the partner for not matching them, at themselves for still caring. Desire now arrives laced with contempt.", "ex1": "A partner who initiates sex but does it with an edge — rough where they used to be tender, silent where they used to whisper — and the partner can feel the difference.", "ex2": "Someone who makes cutting comments about their partner's desirability disguised as jokes: 'Well, someone has to find you attractive, right?'", "ex3": "A lover who still reaches for their partner in the dark but pulls away if the partner responds — because the wanting itself has become humiliating."}, {"n": 1, "name": "Arson", "desc": "Passion has become destruction. They can't feel desire without wanting to damage. The fire is still there but it only burns — the partner, the relationship, themselves. If they can't have the love they wanted, nothing gets to survive.", "ex1": "A partner who begins an affair not out of desire for the new person but to make the original partner feel what they feel — the specific pain of wanting someone who isn't there.", "ex2": "Someone who sabotages the relationship's good moments because sustained happiness has become intolerable — it reminds them of what the passion used to be.", "ex3": "A lover who says 'I never really loved you' as a final act of arson — burning down the history so neither of them can live in it anymore."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Kindling", "desc": "Receives their partner's passion fully and lets it ignite them. No walls, no performance — just genuine fuel meeting genuine fire. The passionate partner feels like they've finally found someone who can hold the full weight of their desire.", "ex1": "A person whose whole body visibly responds when their partner reaches for them — not rehearsed, not performed, just the animal truth of being wanted by someone they want back.", "ex2": "Someone who hears 'I can't stop thinking about you' and responds with specifics: 'Tell me exactly what you were thinking' — not deflecting, but pulling the fire closer.", "ex3": "A lover who treats their partner's desire as sacred information and remembers every detail — what was whispered, what was asked for, what made them shake."}, {"n": 6, "name": "Open Hearth", "desc": "Welcomes passion with warmth and reciprocation. Makes the partner feel that their desire is not only accepted but celebrated. Their receiving has generosity in it — they give back by how fully they take in.", "ex1": "A partner who responds to a love letter not with embarrassment but by reading it aloud back to the writer, letting them hear their own desire reflected without distortion.", "ex2": "Someone who, when surprised by their partner's intensity, doesn't freeze but leans in — even if they weren't in that headspace a moment ago, they choose to meet it.", "ex3": "A lover who says 'I love that you want me like this' and means it as gratitude, not permission."}, {"n": 5, "name": "Warm Welcome", "desc": "Genuinely enjoys and responds to partner's passion, though sometimes caught off guard by its timing or intensity. The reception is real but occasionally has a beat of adjustment.", "ex1": "A partner who laughs with surprise when grabbed and kissed in the kitchen — not because it's unwelcome, but because they were mid-thought about groceries. Then they kiss back.", "ex2": "Someone who needs a moment to shift gears from work-brain to desire-brain, but once they do, they're fully present.", "ex3": "A lover who sometimes says 'give me ten minutes' — not as rejection but as honest preparation — and then shows up completely."}, {"n": 4, "name": "Steady Receiver", "desc": "Accepts passion gracefully and responds within their comfort zone. The partner feels welcomed but not matched — it's warm, but the thermostat has a setting it won't exceed.", "ex1": "A partner who responds to 'I want you right now' with a smile and an embrace that's affectionate but doesn't quite catch fire.", "ex2": "Someone who appreciates grand romantic gestures sincerely but responds at a lower register — a heartfelt thank-you where the other hoped for being swept off their feet.", "ex3": "A lover who always receives warmly but never escalates — the partner sets the ceiling, and this person lives comfortably one floor below it."}, {"n": 3, "name": "Slow to Light", "desc": "Appreciates partner's passion intellectually but takes time to physically and emotionally respond. The gap between receiving and igniting is long enough that the partner often wonders if the spark will catch.", "ex1": "A person who hears 'you're the most beautiful thing I've ever seen' and says 'that's really sweet' — genuine, but the fire didn't transfer.", "ex2": "Someone whose body responds to passion on a thirty-minute delay — they'll reach for their partner an hour later and not connect it to what their partner offered earlier.", "ex3": "A lover who wants to want, and their partner can see the effort, which is both touching and slightly heartbreaking."}, {"n": 2, "name": "Damp Wood", "desc": "Partner's passion arrives and... fizzles. Not rejection exactly — just inability to catch. The desire hits and dissipates. The partner feels like they're throwing sparks at something that can't ignite.", "ex1": "A person who is kissed passionately and kisses back correctly — technique present, fire absent — and both of them can feel the difference.", "ex2": "Someone who receives a deeply vulnerable confession of desire and responds with 'I know' in a tone that closes the conversation rather than opening it.", "ex3": "A lover whose partner has started prefacing intimacy with 'I know you might not be in the mood, but...' — and that preface has become the permanent weather."}, {"n": 1, "name": "Fireproof", "desc": "Completely impervious to incoming passion. Not hostile, not cold — just unreachable. The partner's fire hits a surface that cannot be warmed. Eventually the partner stops bringing fire at all.", "ex1": "A person whose partner has cycled through every possible approach — tenderness, urgency, playfulness, vulnerability — and each one landed in the same neutral zone.", "ex2": "Someone who can watch their partner cry from wanting to be closer and feel sympathy but not activation — they understand the pain without being moved to bridge the gap.", "ex3": "A lover who is genuinely confused when told 'you never respond to me' because from their perspective, they were there. Presence without reception."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Panic at the Warmth", "desc": "So threatened by being desired that they construct elaborate systems to prevent it. The partner's passion triggers existential terror masked as sophistication. They have theories about why intensity is unhealthy — all of them shields.", "ex1": "A person who responds to 'I'm falling in love with you' by launching into a monologue about attachment theory and why the partner is probably confusing limerence with love.", "ex2": "Someone who engineers the relationship to prevent depth — always busy, always one foot out, always with a rational explanation for why now isn't the time.", "ex3": "A lover who has ended every relationship at the exact point when the other person's desire became unmistakably real, and has a different 'reason' each time."}, {"n": 6, "name": "Deflector Shield", "desc": "Converts incoming passion into something safer — humor, intellectualization, redirection. The partner feels their desire being processed rather than received. The fire goes in and comes back as data.", "ex1": "A partner who responds to 'I want you' with a joke — not cruelly, but consistently enough that the other person stops being vulnerable and starts being funny instead.", "ex2": "Someone who, mid-intimacy, starts talking about something unrelated — not from nervousness they acknowledge, but as an unconscious escape hatch they'd deny if confronted.", "ex3": "A lover who can discuss desire eloquently in the abstract but goes blank when it's aimed directly at them."}, {"n": 5, "name": "Suspicion", "desc": "Assumes passionate attention has an agenda. Genuine desire is met with 'what do you want from me?' — not as flirtation but as genuine interrogation. Trust has been replaced by pattern-matching for threat.", "ex1": "A partner who receives a surprise gift and immediately wonders what the other person did wrong — and searches for evidence rather than enjoying the gesture.", "ex2": "Someone who hears 'you looked incredible today' and runs it through a filter: is this leading to a request? A manipulation? An attempt to make up for something?", "ex3": "A lover who keeps a mental catalog of every time passion preceded betrayal in their past, and unconsciously applies it to their current partner."}, {"n": 4, "name": "Flinch", "desc": "Visibly uncomfortable with direct expressions of desire. The partner learns to approach sideways — never too direct, never too intense, never too honest about how much they want.", "ex1": "A person whose partner has learned to say 'want to watch a movie?' when they mean 'I want to be close to you' because the direct version produces a visible withdrawal.", "ex2": "Someone who accepts affection best when it's disguised as something else — a back rub that's 'just because you seem tense,' a compliment wrapped in teasing.", "ex3": "A lover whose partner describes them to friends as 'not really a words person' — which is a kind translation of 'flinches when I tell them I love them.'"}, {"n": 3, "name": "Minimizer", "desc": "Downplays partner's passion. 'You don't really feel that way.' 'It's just hormones.' 'You're being dramatic.' The partner's fire is reduced to something manageable — and in the reduction, the partner is reduced too.", "ex1": "A partner who responds to a heartfelt love confession with 'okay, but have you eaten? You always get emotional when you're hungry.'", "ex2": "Someone who tells their partner they're 'too much' often enough that the partner begins to believe their natural intensity is a flaw.", "ex3": "A lover who reframes every expression of desire as the partner's problem: 'You have a high drive. That's not about me.'"}, {"n": 2, "name": "Punisher", "desc": "Makes the partner feel foolish for expressing desire. Eye rolls, sighs, visible tolerance. The message is clear: your wanting is an inconvenience, and showing it is embarrassing.", "ex1": "A person who responds to their partner's attempt at seduction with a look that would freeze lava — not anger, just withering disinterest that makes the partner want to disappear.", "ex2": "Someone who tells stories at dinner parties about their partner's 'neediness' in a tone that's technically affectionate but functionally humiliating.", "ex3": "A lover whose partner has started apologizing before expressing any desire at all: 'I know this is annoying, but...'"}, {"n": 1, "name": "Weaponized Rejection", "desc": "Uses the partner's desire as ammunition. The moment they show vulnerability becomes a tool for control or cruelty. Desire is received only to be catalogued as weakness and deployed later.", "ex1": "A partner who, during an argument, says 'remember when you begged me to stay? That's what you are' — converting a moment of raw love into evidence of pathology.", "ex2": "Someone who allows their partner to be fully vulnerable during intimacy and then references those private moments as leverage in public: 'You should see what they're like when they want something.'", "ex3": "A lover who learned that the fastest way to end any argument is to say 'this is why nobody wanted you before me' — and it works, which is why they keep doing it."}]}]}, {"name": "The Hearth", "factor": "Factor 1: Passion ↔ Stability", "factor_num": 1, "pole": "Stability", "color": "#7A8B6E", "alignment": "Healthy", "tagline": "I am the place you come home to.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Foundation", "desc": "Stability so deep it creates safety for everyone within reach. Not rigid — alive and warm, like the earth itself. They are the person others build lives around because their constancy isn't absence of feeling but mastery of presence.", "ex1": "A partner who has been through genuine crises — illness, loss, financial ruin — and remained the same warm, steady presence. Not untouched, but unshaken in their core commitment.", "ex2": "Someone whose home is the place all their friends come to in emergencies, not because it's impressive but because the person inside it radiates safety like heat from a wood stove.", "ex3": "A lover who has made 'I'm here' into the most profound sentence in the English language through decades of proving it true."}, {"n": 6, "name": "Bedrock", "desc": "Deep reliability that isn't boring but grounding. Their consistency frees their partner to take risks, explore, grow — because there's always somewhere solid to return to.", "ex1": "A partner whose steadiness allowed their spouse to change careers, move countries, try things that failed — because the relationship itself was never at risk.", "ex2": "Someone who doesn't need to be the exciting part of their partner's life, and is genuinely fulfilled being the safe part.", "ex3": "A lover whose partner describes them to friends as 'my home' and means it geographically — they are the coordinate everything else is measured from."}, {"n": 5, "name": "Warm Constant", "desc": "Reliably warm, emotionally available, consistently present. Occasionally predictable in ways that border on dull, but the trade-off is a relationship that never makes the partner anxious.", "ex1": "A partner who texts 'drive safe' every single time and who the other person would genuinely miss if they stopped — not because the text is interesting, but because it's a heartbeat.", "ex2": "Someone who plans the same vacation to the same place every year, and it works not because the destination is exciting but because the ritual is nourishing.", "ex3": "A lover whose reliability is occasionally taken for granted — which is both the Hearth's gift and their quiet wound."}, {"n": 4, "name": "Comfortable Room", "desc": "Stable and present but increasingly defined by routine. The warmth is real but has become ambient — noticed more in its absence than its presence. They maintain the relationship like a well-kept garden: nothing dying, nothing wildly blooming.", "ex1": "A partner who always remembers to ask about the meeting, pick up the prescription, keep the house warm — and who has accidentally become more caretaker than lover.", "ex2": "Someone whose relationship runs like a well-oiled machine that neither partner ever stops to admire anymore.", "ex3": "A lover whose greatest romantic gesture in the last year was handling the taxes early, and who is confused about why that doesn't count."}, {"n": 3, "name": "Furniture", "desc": "So stable they've become part of the background. The partner knows they're there the way they know the walls are there — essential, unnoticed, slightly suffocating if you think about it too long.", "ex1": "A partner who realizes they haven't had a real conversation — not logistics, not scheduling, but a real conversation — in weeks, and neither of them noticed.", "ex2": "Someone whose presence in the room doesn't register anymore. Their partner startles slightly when they speak, not from fear but from having genuinely forgotten they were there.", "ex3": "A lover who has become so predictable that their partner could script their responses to any given situation with 95% accuracy."}, {"n": 2, "name": "Going Through Motions", "desc": "The stability has become hollow. They perform the rituals of constancy — the good-morning kiss, the how-was-your-day — but the warmth behind them has gone out. The structure of care remains; the feeling has left.", "ex1": "A partner who still makes dinner every night but has stopped tasting it. The act of cooking is a habit, not an offering.", "ex2": "Someone whose reliability has become indistinguishable from resignation — they stay not because the fire is warm but because moving would require energy they don't have.", "ex3": "A lover who would describe their relationship as 'fine' and mean it in the most devastating possible sense of the word."}, {"n": 1, "name": "Empty House", "desc": "Stability without any warmth. The structure stands but the hearth is cold. They are technically present, technically reliable, technically committed — and the technicality is all that's left.", "ex1": "A partner who comes home every night at the same time, sits in the same chair, and exists in the same space — providing the architecture of companionship with none of its substance.", "ex2": "Someone whose partner has started calling the relationship 'stable' the way you'd describe a patient who is alive but not conscious.", "ex3": "A lover whose constancy has become its own form of abandonment — they never leave, but they left a long time ago."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Sanctuary", "desc": "Creates a space around the partner where they are unconditionally safe. Not smothering — liberating. The partner's worst self can show up and be met with the same steadiness as their best. This is love as architecture: load-bearing, invisible, essential.", "ex1": "A partner who holds space when their spouse comes home destroyed by failure, grief, or shame — doesn't fix, doesn't flinch, just creates a container large enough for whatever needs to be felt.", "ex2": "Someone whose partner has said 'I can tell you anything' and tested it — with confessions that would end other relationships — and found it to be structurally true.", "ex3": "A lover who responds to their partner's panic attack not with their own anxiety but with the calm, warm gravity of a person who isn't going anywhere."}, {"n": 6, "name": "Safe Harbor", "desc": "Actively provides stability to the partner — not just passively existing as a steady presence, but reading what the partner needs and providing the specific form of constancy that grounds them.", "ex1": "A partner who notices their spouse is spiraling and instinctively does the three things that calm them: makes tea, sits close but doesn't touch, asks one quiet question and waits.", "ex2": "Someone who has learned their partner's anxiety tells and intervenes so gently the partner doesn't realize they were falling until they've been caught.", "ex3": "A lover who provides physical consistency — same side of the bed, same arm around the shoulder, same kiss on the forehead — and the partner's nervous system has learned to regulate to their rhythms."}, {"n": 5, "name": "Reliable Warmth", "desc": "Consistently present, affectionate, and dependable toward the partner. Occasionally uninspiring, but the partner always knows where they stand. The stability is genuine and the care is tangible.", "ex1": "A partner who shows up to every event, remembers every allergy, and has never once forgotten a medication — and the partner has stopped noticing because it's as reliable as gravity.", "ex2": "Someone who sends the same 'thinking of you' text at lunch every day, and the partner would panic if it didn't arrive.", "ex3": "A lover who might not sweep anyone off their feet but has never, not once, let their partner hit the ground."}, {"n": 4, "name": "Warm Routine", "desc": "Provides stability through established patterns. The partner feels cared for within the structure, though the structure has started to feel like the relationship itself. The warmth is real but templated.", "ex1": "A partner who expresses love through the same five gestures on rotation — coffee in bed, shoulder squeeze, 'love you' at the door — and the partner values each one while wishing for a sixth.", "ex2": "Someone who plans date night every other Friday, same restaurant, same babysitter, and the partner appreciates the effort while occasionally yearning for spontaneity.", "ex3": "A lover whose care is expressed through maintenance — the car serviced, the bills paid, the doctor's appointment booked — and the partner sometimes wants to be maintained a little less and desired a little more."}, {"n": 3, "name": "Autopilot Care", "desc": "Still providing stability, but on automatic. The partner can tell the difference between chosen care and habitual care, and they're mostly getting the latter. Warm enough, but the pilot light is doing all the work.", "ex1": "A partner who says 'how was your day' at exactly the same time every evening and listens to the answer just long enough to provide a stock response before returning to their phone.", "ex2": "Someone who buys the same anniversary gift format every year — flowers, card, dinner — and the partner has started writing the thank-you in advance.", "ex3": "A lover whose care is indistinguishable from routine — they'd do the same things if you swapped in a different partner, because the script doesn't require a specific cast."}, {"n": 2, "name": "Duty", "desc": "Stability provided out of obligation rather than warmth. The partner is being maintained, not loved. The difference is palpable — like the difference between a house that's heated and a house that's warm.", "ex1": "A partner who still does everything 'right' — picks up the kids, pays the mortgage, shows up — and the partner can feel the absence of feeling behind every technically correct action.", "ex2": "Someone who responds to 'do you still love me?' with 'I'm here, aren't I?' and considers that a sufficient answer.", "ex3": "A lover whose commitment has become a fact rather than a choice — they stay the way water stays in a bowl: through inertia, not desire."}, {"n": 1, "name": "Presence as Punishment", "desc": "Their stability has become a weight. They're there, always there, immovably there — and the partner has started to experience their constancy as a prison. The Hearth doesn't leave because leaving would require a vitality they no longer possess.", "ex1": "A partner who sits in the same chair every night in a silence so complete it presses on the walls, and the other person has started staying late at work to avoid it.", "ex2": "Someone whose physical presence in the home has become so inert that the partner feels guilty for wanting them to leave and guiltier for wanting them to stay and actually be present.", "ex3": "A lover whose partner has realized that 'you'll never leave me' was once a comfort and is now a threat — not because of malice, but because of the claustrophobic weight of care that has lost its warmth."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Golden Cage", "desc": "Stability weaponized into total containment. They've built such a perfect, warm, comfortable life around the partner that leaving becomes unthinkable — not because of threat but because of infrastructure. Every comfort is a bar.", "ex1": "A partner who has so thoroughly organized their spouse's life — finances, friendships, daily routine — that the spouse realizes they couldn't function independently if they tried.", "ex2": "Someone who responds to any expression of restlessness with another improvement to the nest: a renovated kitchen, a better vacation, a nicer car. The cage gets more gilded each time.", "ex3": "A lover whose partner tries to articulate dissatisfaction and fails because nothing is technically wrong — the prison is too comfortable to name."}, {"n": 6, "name": "Guilt Architecture", "desc": "Provides such selfless, visible care that the partner is trapped by obligation. Every meal cooked, every sacrifice made, every 'I don't mind' is a brick in a wall of debt the partner can never repay.", "ex1": "A partner who gives up their career 'for the family' and never mentions it — but the weight of that sacrifice sits in every room like furniture the partner has to navigate around.", "ex2": "Someone who says 'I just want you to be happy' so often and so selflessly that the partner feels monstrous for not being happy.", "ex3": "A lover whose generosity has become its own form of control — you can't leave someone who has given you everything without becoming the villain of the story."}, {"n": 5, "name": "Smothering Warmth", "desc": "Care that has become suffocating. The partner feels simultaneously loved and trapped. Every need is anticipated before it's felt — and the partner has lost the ability to identify what they want because the Hearth is always already providing it.", "ex1": "A partner who responds to 'I need some space' with 'of course, I'll be right here when you're ready' — which sounds supportive but feels like a tether.", "ex2": "Someone who monitors their partner's wellbeing so closely that the partner starts hiding feelings just to have something that's privately theirs.", "ex3": "A lover whose care feels like surveillance: 'You seem off. What's wrong? Did something happen? Can I help?' — asked hourly until the partner wants to scream."}, {"n": 4, "name": "Passive Anchor", "desc": "Uses their stability to resist all change. The partner wants to grow, explore, evolve — and the Hearth's gravitational pull keeps things exactly as they are. Not through argument, but through sheer inertia.", "ex1": "A partner who responds to 'maybe we should try something new' with 'what we have works, doesn't it?' — and the partner can't argue because technically it does.", "ex2": "Someone who greets every proposed change with quiet, patient concern until the partner gives up and accepts the current arrangement.", "ex3": "A lover whose response to their partner's restlessness is to double down on routine — cooking more, cleaning more, being even steadier — treating the symptom as a problem to be solved with more of the same."}, {"n": 3, "name": "Martyred Maintenance", "desc": "Performs stability with visible suffering. The partner can see the sacrifice and is expected to appreciate it. The Hearth sighs, endures, persists — and the partner is constantly reminded of the cost.", "ex1": "A partner who says 'no, it's fine, I'll do it' in a tone that makes 'fine' the most loaded word in the language.", "ex2": "Someone who provides care the way a loan shark provides money — the interest is never stated, but it's always accruing.", "ex3": "A lover whose selflessness is somehow always performed in the partner's line of sight, never when they're not around to appreciate it."}, {"n": 2, "name": "Weaponized Dependability", "desc": "Uses their own reliability as evidence of the partner's failure. 'I always show up. Where are you?' becomes the refrain. The Hearth's consistency is no longer a gift — it's a measuring stick the partner can never match.", "ex1": "A partner who keeps an unspoken tally of every time they were reliable and the other person wasn't — and this tally surfaces during every argument.", "ex2": "Someone who says 'I've never let you down' as both statement of fact and implicit accusation.", "ex3": "A lover whose dependability has become a competition they always win, and winning has become more important than connecting."}, {"n": 1, "name": "Dead Weight", "desc": "Their stability has become a burden so heavy the partner is being crushed by it. Not malicious — just a massive, immovable presence that takes up all the oxygen. The partner cannot leave, cannot change, cannot breathe.", "ex1": "A partner so inert that the other person realizes they've been slowly rearranging their entire life around someone who will never move, and the accommodation has consumed them.", "ex2": "Someone whose partner fantasizes not about other people but about empty rooms — the idea of space where this person's steadiness isn't pressing against every wall.", "ex3": "A lover whose final gift to the relationship is being so thoroughly, aggressively present that the partner finally understands why some people run."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Grateful Anchor", "desc": "Receives a partner's stability with deep, active gratitude. Doesn't take it for granted — recognizes constancy as a choice made daily and honors it. Their reception makes the giving partner feel seen for the quiet work of being reliable.", "ex1": "A partner who says 'I know what it costs you to be this steady, and I want you to know I see it' — and the Hearth finally exhales.", "ex2": "Someone who celebrates their partner's reliability not as boring but as brave — understanding that showing up every day is its own form of courage.", "ex3": "A lover who reciprocates stability with depth: 'You make it safe enough for me to be all of who I am. That's the biggest gift anyone's ever given me.'"}, {"n": 6, "name": "Rooted Reception", "desc": "Receives stability and grows into it. The partner's constancy becomes the trellis they climb — not dependency, but a structure that allows them to reach higher because the base is secure.", "ex1": "A person who flourishes visibly in a stable relationship — their career, creativity, and friendships all bloom because the home base is solid.", "ex2": "Someone who takes their partner's reliability and converts it into confidence: 'I can take this risk because I know you're here.'", "ex3": "A lover who actively builds on their partner's stability rather than consuming it, making the foundation stronger by adding to it."}, {"n": 5, "name": "Comfortable Reception", "desc": "Receives stability with genuine appreciation, settling into it with visible relief. Occasionally drifts into taking it for granted, but when reminded, responds with real acknowledgment.", "ex1": "A partner who admits 'I forget to tell you how much this means to me' — and when they do say it, the sincerity is unmistakable.", "ex2": "Someone who receives their partner's consistency like sunlight: essential, warming, and only noticed when it disappears behind a cloud.", "ex3": "A lover who is at their best inside stable love — not because they need it to function, but because it lets them function at their highest."}, {"n": 4, "name": "Quiet Acceptance", "desc": "Receives stability as expected background. Doesn't complain, doesn't celebrate — just absorbs it as the normal state of affairs. The partner's steadiness has become the water they swim in: invisible until it's gone.", "ex1": "A partner who would be devastated if the stability disappeared but has no current mechanism for recognizing it while it's present.", "ex2": "Someone who says 'I know I can count on you' in a tone that's more assumption than appreciation.", "ex3": "A lover whose acknowledgment of their partner's constancy comes only during crises, when the contrast makes the everyday invisible work suddenly visible."}, {"n": 3, "name": "Restless in Safety", "desc": "Receives stability but chafes against it. Grateful in theory, bored in practice. The partner's constancy feels like a ceiling as much as a floor — safe, yes, but where's the sky?", "ex1": "A person who loves their stable partner and is simultaneously Googling 'is it normal to feel bored in a good relationship?'", "ex2": "Someone who picks fights not because they're angry but because conflict is the only time the relationship's emotional temperature rises above room temperature.", "ex3": "A lover who has started romanticizing their turbulent past relationships while sitting in the peaceful living room their stable partner built for them."}, {"n": 2, "name": "Entitlement", "desc": "Receives stability as owed rather than offered. The partner's constancy is no longer a gift — it's an expectation, and deviations from it are treated as failures rather than human variation.", "ex1": "A partner who responds to one missed text from their always-reliable spouse with 'where were you?' — as if a single gap in the pattern constitutes abandonment.", "ex2": "Someone who has expanded the definition of 'reliable' so far that their partner can't possibly meet it, and every shortfall is evidence of insufficient love.", "ex3": "A lover who takes their partner's stability and converts it into a to-do list of escalating demands, each one framed as a minimum rather than a request."}, {"n": 1, "name": "Contempt for Safety", "desc": "Has come to despise the very stability they depend on. The partner's constancy is now experienced as weakness, and the person receiving it secretly or openly scorns the one providing it.", "ex1": "A partner who mocks their spouse's reliability to friends: 'So predictable. I could set a clock by them.' And underneath the joke is genuine disdain.", "ex2": "Someone who has confused stability with cowardice and now sees their partner's constancy as proof of a life unlived.", "ex3": "A lover who stays because the stability serves them but has lost all respect for the person providing it — consuming the warmth while despising the hearth."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Terror of Steadiness", "desc": "Stability triggers deep panic. Being offered constancy activates every abandonment wound at once — not because they expect it to end, but because trusting it means risking the catastrophe of losing it. So they destroy it preemptively.", "ex1": "A person who has ended three relationships with solid, reliable partners at the exact moment things became 'too good' — each time with a different surface reason, each time for the same underground terror.", "ex2": "Someone who tests their stable partner's commitment by behaving at their absolute worst, unconsciously trying to find the breaking point before it finds them.", "ex3": "A lover who has said 'I don't deserve this' and meant it not as humility but as prophecy — they are pre-grieving a loss they intend to cause."}, {"n": 6, "name": "Saboteur", "desc": "Actively undermines the stability being offered. Creates chaos, breaks agreements, introduces instability — not out of malice but out of an inability to tolerate the vulnerability that safety demands.", "ex1": "A partner who cheats not because they want someone else but because the stability was becoming unbearable — the affair is an escape hatch, not a destination.", "ex2": "Someone who picks escalating fights with their steady, reliable partner — pushing for the explosion that will make the calm stop feeling like the calm before the storm.", "ex3": "A lover who engineers crises in an otherwise peaceful relationship because peace feels like the moment before the trap springs."}, {"n": 5, "name": "Never Enough Proof", "desc": "Receives stability but can never be convinced it's real. Every act of constancy is questioned, every absence is evidence. The partner must prove their reliability daily, and yesterday's proof expired overnight.", "ex1": "A person who asks 'are you sure you still love me?' every week, and no answer has ever lasted longer than the conversation it was given in.", "ex2": "Someone whose partner's one late arrival home outweighs six months of punctuality, because the anxiety was already awake and looking for confirmation.", "ex3": "A lover who monitors their partner's phone, location, and friendships — not from controlling personality but from genuine terror that stability is always one moment from collapse."}, {"n": 4, "name": "Suspicion of Motive", "desc": "Assumes stability is a transaction. Their partner's constancy must be in exchange for something — control, dependency, insurance. Freely offered steadiness doesn't compute; there must be an angle.", "ex1": "A partner who responds to consistent kindness with 'what do you want from me?' — not hostile, but genuinely confused by unconditioned care.", "ex2": "Someone who interprets their partner's reliability as a long-term manipulation strategy: 'They're being this consistent so I'll owe them.'", "ex3": "A lover who feels trapped by their partner's generosity because they can't figure out the price tag, and the uncertainty is worse than an actual demand."}, {"n": 3, "name": "Boredom as Self-Defense", "desc": "Labels the feeling of safety as boredom to avoid acknowledging that it scares them. 'I'm not afraid of intimacy — I'm just not stimulated.' The reframe lets them leave without examining why closeness felt intolerable.", "ex1": "A person who describes their kindest, most stable partner as 'nice but boring' and has never questioned whether 'boring' is a feeling or a defense mechanism.", "ex2": "Someone who seeks out passion precisely because it doesn't require the vulnerability that stability demands — chaos is exciting but also emotionally safe because it never asks you to trust.", "ex3": "A lover who has left every reliable partner and stayed with every unreliable one, and narrates this as 'knowing what they want' rather than 'running from what they need.'"}, {"n": 2, "name": "Punishing the Provider", "desc": "Makes the stable partner pay for offering what they can't accept. Not consciously cruel — but the Hearth's warmth activates something that requires retaliation. Being cared for feels like being controlled, and they fight back.", "ex1": "A partner who responds to every thoughtful gesture with criticism: the dinner is overcooked, the gift is wrong, the words aren't enough — training the provider to stop providing.", "ex2": "Someone who is measurably more hostile to the partner who is kindest to them, and measurably more adoring of partners who treat them badly.", "ex3": "A lover whose stable partner has started walking on eggshells — not because the partner is abusive, but because every act of care seems to trigger an unpredictable negative response."}, {"n": 1, "name": "Scorched Earth Departure", "desc": "Destroys the stability entirely on the way out. Can't just leave — has to demolish the safe space so thoroughly that it can never be rebuilt or returned to. Leaving a place of safety requires making it uninhabitable.", "ex1": "A person who ends a stable, loving relationship by burning every bridge simultaneously: tells mutual friends lies, empties joint accounts, and sends a final message designed to make the partner doubt every good moment they shared.", "ex2": "Someone who tells their steady, devoted partner 'I never loved you' — not because it's true, but because the truth ('I loved you and that terrified me') is unspeakable.", "ex3": "A lover who ensures their own exit is so catastrophic that they could never go back, because they know if the door stayed open, they'd spend the rest of their life standing in front of it, unable to walk through."}]}]}, {"name": "The Inferno", "factor": "Factor 1: Passion ↔ Stability", "factor_num": 1, "pole": "Passion", "color": "#D4A843", "alignment": "Shadow", "tagline": "I will burn through you to feel alive.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Wildfire", "desc": "Passion has become indistinguishable from identity. They don't have desire — they ARE desire. Magnetic, terrifying, impossible to ignore. Everyone they touch eventually turns to ash, and they've made peace with that, or claim to.", "ex1": "The person everyone warns you about but nobody can resist. They've left a trail of transformed, broken, grateful-and-devastated exes who all say the same thing: 'It was worth it. Don't do it.'", "ex2": "Someone whose presence in a room changes the temperature. Not charm — something rawer. People near them make decisions they wouldn't normally make.", "ex3": "A lover who has never had a relationship end quietly. Departures involve shattered dishes, 3 AM confessions, airport runways, and stories that become legend among friend groups."}, {"n": 6, "name": "Addict", "desc": "Chases intensity as a substance. New relationship energy is their drug. When it fades, they don't grieve — they hunt. They've developed sophisticated justifications for why this pattern is actually enlightened.", "ex1": "Someone who has a PhD in beginnings and a dropout record in middles. The first three months are transcendent; month four, they're already scanning.", "ex2": "A person who describes themselves as 'polyamorous' or 'free' but what they actually are is unable to tolerate the moment desire becomes routine.", "ex3": "A lover who is genuinely confused by the accusation of commitment-phobia because they commit with absolute intensity — for exactly as long as the intensity lasts."}, {"n": 5, "name": "Thrill Seeker", "desc": "Needs escalation to feel. What was electric last month is boring now. The bar moves constantly upward and inward, into riskier territory, not because they're brave but because their baseline keeps recalibrating.", "ex1": "A person who starts relationships with candlelit dinners and within six months needs the equivalent of emotional skydiving to feel the same thing.", "ex2": "Someone whose sexual history reads like an escalation ladder — not out of curiosity or exploration, but out of tolerance-building. Each threshold crossed becomes the new floor.", "ex3": "A lover who describes past relationships the way addicts describe past highs: with decreasing enthusiasm as the doses get larger and the returns shrink."}, {"n": 4, "name": "Chaos Engine", "desc": "Creates drama to manufacture passion. Picks fights to trigger make-up sex. Engineers jealousy scenarios for the reunion rush. Has confused adrenaline with love so thoroughly they can't tell the difference.", "ex1": "A partner who casually mentions an attractive coworker's compliment, then watches their partner's reaction with the careful attention of a scientist monitoring an experiment.", "ex2": "Someone who threatens to leave during arguments they started, specifically to experience being begged to stay.", "ex3": "A lover who has noticed that their relationship is most alive during crises and has begun unconsciously manufacturing them on a two-week cycle."}, {"n": 3, "name": "Bored and Dangerous", "desc": "Restless, prowling energy. Not actively destructive yet, but clearly scanning the horizon. The current relationship is a warm room they keep glancing out of, looking for weather.", "ex1": "A partner who is physically present at dinner but whose attention keeps drifting — to their phone, to the server, to the couple arguing at the next table. Anything with voltage.", "ex2": "Someone whose friends have noticed the pattern: they become most social and most flirtatious in the weeks before a breakup, building the runway before they even know they're going to fly.", "ex3": "A lover who has started picking small, unnecessary fights — not yet conscious of why, but their partner can feel the gathering."}, {"n": 2, "name": "Scattered Sparks", "desc": "Flits from intensity to intensity without depth. Multiple simultaneous connections, none satisfying. The fire is spread so thin it can't warm anything, but they keep striking matches.", "ex1": "A person with three active dating app conversations, two situationships, and a 'complicated' ex, who describes themselves as 'exploring' but is actually just dissipating.", "ex2": "Someone who has intense first dates — the kind where you talk until 4 AM — and then never follows up, because the second date can't possibly match the first.", "ex3": "A lover whose phone contains more open romantic threads than finished conversations, and each one started with 'I've never felt this way before.'"}, {"n": 1, "name": "Burnt Out", "desc": "Has consumed so much that nothing registers anymore. The inferno ate its own fuel. They still go through the motions of seeking intensity but feel nothing when they find it. Dead behind the eyes while performing passion.", "ex1": "A person who hooks up with someone new and lies in bed afterward feeling the exact same emptiness they felt before, and doesn't even have the energy to be disturbed by that.", "ex2": "Someone whose friends describe as 'wild' based on old stories, but who privately hasn't felt anything real in years. The reputation is a fossil.", "ex3": "A lover who can perform passion so convincingly that new partners never suspect the person behind the performance checked out long ago."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Controlled Burn", "desc": "At their absolute best, the Inferno's intensity becomes transformative for the partner — pushing them past comfort zones into growth. Still fundamentally about the Inferno's need for fire, but channeled so skillfully the partner genuinely benefits.", "ex1": "A lover who sees their partner's untapped wildness and draws it out — the partner discovers parts of themselves they'd walled off, and is grateful even after the Inferno has moved on.", "ex2": "Someone whose intensity functions as a crucible: the partner goes in uncertain and comes out knowing exactly who they are and what they want.", "ex3": "The ex everyone describes as 'the one who changed me' — not because they stayed, but because what they burned away needed burning."}, {"n": 6, "name": "Electric Touch", "desc": "Their passion makes the partner feel alive in ways they didn't know were possible. Dangerous but currently generous. The partner is getting the best version of something that won't last, and it's genuinely magnificent while it does.", "ex1": "A lover who introduces their partner to pleasures they'd never imagined, with enough care to make the experience expanding rather than overwhelming.", "ex2": "Someone who makes their partner feel like the center of a universe they didn't know existed — the partner's world gets bigger, even if the Inferno's attention will eventually drift.", "ex3": "A partner whose passion is so skilled and attentive that the recipient temporarily forgets this is also a pattern — because right now, it doesn't feel like one."}, {"n": 5, "name": "Intoxicating", "desc": "The partner knows this isn't sustainable but can't stop. The Inferno is providing genuine pleasure, connection, and excitement at an unsustainable pace. The crash is visible from here, but the ride is extraordinary.", "ex1": "A whirlwind month of travel, deep talks, incredible sex, and the partner's friends saying 'I've never seen you like this' — which is true and also ominous.", "ex2": "Someone who texts at 2 AM with things that make their partner's heart stop — and the partner can't tell if this is love or a very sophisticated form of destruction.", "ex3": "A lover whose partner has started calling in sick to work to spend the day in bed together, knowing full well that this level of intensity is borrowing from the future."}, {"n": 4, "name": "Fun While It Lasts", "desc": "Exciting, present, genuinely passionate — but with a visible expiration date. Both people can feel the countdown, which gives everything a bittersweet edge that the Inferno actually finds delicious.", "ex1": "A summer fling where both parties know September ends it — and the Inferno is more passionate BECAUSE of the deadline, not despite it.", "ex2": "Someone who is the perfect vacation partner: total presence, electric attention, zero future-building. And they're honest about it, which is their saving grace.", "ex3": "A lover who says 'I'm not going to be what you need long-term, but I'm exactly what you need right now' — and they're right on both counts."}, {"n": 3, "name": "Hot and Cold", "desc": "Bursts of incredible intensity followed by distraction and distance. When present, the partner feels worshipped. When absent, the partner feels erased. The whiplash is becoming the relationship's primary texture.", "ex1": "A lover who disappears for four days, then shows up at the door with flowers and an intensity that makes the absence feel like foreplay — and the partner hates that it works.", "ex2": "Someone whose partner has learned to read the cycle: silence means they're bored, a sudden barrage of texts means they're back, and the window of warmth is about 72 hours.", "ex3": "A partner who is genuinely incredible in person and genuinely nonexistent when apart — their love has no object permanence."}, {"n": 2, "name": "Drive-By Passion", "desc": "Brief, intense attention that vanishes as fast as it arrived. The partner is left reeling — not from cruelty but from the whiplash of being made to feel everything, then nothing.", "ex1": "Someone who makes deeply intense eye contact across the room, crosses to their partner, says something that rewires their nervous system, and then wanders off to talk to someone else.", "ex2": "A lover who initiates breathtaking intimacy and then checks their phone within minutes of finishing — already elsewhere.", "ex3": "A partner whose passion comes in five-minute bursts that are individually transcendent and collectively crazymaking."}, {"n": 1, "name": "Scorched Earth", "desc": "Their attempt at passion toward the partner is indistinguishable from consumption. No attunement, no reading, just raw need projected onto another body. The partner is a surface, not a person.", "ex1": "A lover who is so deep in their own intensity that they don't notice their partner has checked out — or they notice and don't care, because the fire needs fuel, not consent.", "ex2": "Someone who 'makes love' the way a forest fire 'visits' a forest — the experience is entirely one-directional, and what's left afterward is flattened.", "ex3": "A partner whose post-sex question is never 'how was that for you?' but 'wasn't that incredible?' — and the answer they expect is confirmation, not truth."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Soul Eater", "desc": "Passion so predatory it dissolves the partner's identity. The Inferno doesn't just want the partner — they want to consume them. The partner feels flattered, then absorbed, then erased. By the time they realize what's happening, they can't remember who they were before.", "ex1": "A lover whose partner's friends stage an intervention — not because of abuse in any visible form, but because the person they knew has simply disappeared into someone else's fire.", "ex2": "Someone whose exes all describe the same experience: 'I lost myself completely. It took years to come back. I still dream about them.'", "ex3": "A partner who makes you feel more alive than you've ever felt — by slowly consuming the self that existed before them and replacing it with need."}, {"n": 6, "name": "Addiction Dealer", "desc": "Deliberately creates dependency through intermittent reinforcement. Knows exactly how much passion to give and when to withdraw it to maximize the partner's craving. It's not always conscious, but it's always effective.", "ex1": "A lover who intuitively understands that the most addictive pattern is unpredictability: incredible closeness followed by unexplained distance, repeated until the partner's entire nervous system is organized around their presence.", "ex2": "Someone who gives their partner the best night of their life, then goes silent for a week, then texts 'thinking about you' — and knows exactly what that does.", "ex3": "A partner whose affection functions like a slot machine: inconsistent rewards that produce more compulsive behavior than consistent ones ever could."}, {"n": 5, "name": "Oxygen Thief", "desc": "Their intensity crowds out everything else in the partner's life. Not through control but through sheer gravitational force — the partner neglects friends, work, health, because nothing else registers when the Inferno is burning.", "ex1": "A partner whose friends have stopped calling because every plan gets canceled when the Inferno texts. Not forbidden — just irrelevant by comparison.", "ex2": "Someone whose partner has gained or lost significant weight, stopped exercising, and changed sleep patterns — all in service of being available when the Inferno runs hot.", "ex3": "A lover whose partner's therapist has started using the word 'enmeshment' and the partner has started skipping therapy."}, {"n": 4, "name": "Jealousy Arsonist", "desc": "Uses passion to manufacture possessiveness in the partner, then feeds on the resulting drama. Creates triangles, implies alternatives, stokes insecurity — all to keep the emotional temperature at the boiling point they need.", "ex1": "Someone who casually mentions an ex's name during sex — not accidentally — and then is energized by the resulting spiral of their partner's jealousy.", "ex2": "A lover who flirts openly with others in front of their partner, then responds to the partner's distress with passionate reassurance that feels incredible — training the partner to associate pain with reunion.", "ex3": "A partner who 'accidentally' leaves evidence of other people's attention where their current partner will find it."}, {"n": 3, "name": "Contemptuous Heat", "desc": "Still desires the partner but has lost respect. The passion has an edge of degradation now — they want the partner, but they also want the partner to know they could do better. Desire served with a side of superiority.", "ex1": "A lover who says 'you're lucky I'm still attracted to you' and frames it as a compliment.", "ex2": "Someone whose passion increases in direct proportion to how small they've made their partner feel — dominance disguised as desire.", "ex3": "A partner who makes their partner feel simultaneously wanted and pathetic — 'nobody else would put up with you, but I still want you' as a form of seduction."}, {"n": 2, "name": "Discard in Progress", "desc": "The partner can feel themselves being downgraded from person to placeholder. The Inferno's passion is visibly redirecting — not gone, just aimed somewhere else. The partner is being kept warm while the next fire is being built.", "ex1": "A lover whose physical attention has become mechanical — same moves, half the eye contact, and the partner can tell the script is being run on autopilot while the real attention is elsewhere.", "ex2": "Someone who has started comparing their partner unfavorably to others out loud: 'You know who has great energy? My coworker. You'd like them.'", "ex3": "A partner who still has sex with their current partner but has started closing their eyes in a way that clearly isn't about savoring the moment."}, {"n": 1, "name": "Detonation", "desc": "Destroys the partner on the way out. Not content to simply leave — the Inferno ensures the partner is so damaged that recovering will take years. Scorched earth as exit strategy, because their own pain requires company.", "ex1": "A lover who ends the relationship by sleeping with the partner's closest friend — not because they wanted the friend, but because they wanted the maximum possible blast radius.", "ex2": "Someone who, during the breakup conversation, catalogs every private vulnerability the partner ever shared and uses each one as a weapon: 'You told me your deepest fear was being abandoned. So here we are.'", "ex3": "A partner who doesn't just leave — they narrate the leaving, making sure the other person understands they were never enough, were always a placeholder, and that the real love is about to begin elsewhere."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Mirror Blaze", "desc": "When met with equal intensity, the Inferno is momentarily stunned into authenticity. Someone else's fire is so real it bypasses their usual pattern. For the first time, they receive instead of consume. It rarely lasts, but when it does, it's transcendent.", "ex1": "Two people who are equally intense meeting and, instead of competing for dominance, falling into a rare mutual surrender that terrifies them both.", "ex2": "A lover who has never been out-desired before — and the experience of someone wanting them with their own level of ferocity cracks something open they didn't know was sealed.", "ex3": "The Inferno sitting quietly for the first time in their life because someone else's fire is speaking the language they've been screaming in for years, and they finally feel heard."}, {"n": 6, "name": "Genuine Surprise", "desc": "Receives passion with real delight because they so rarely encounter it at a level that registers. Most people's desire feels like a candle to them — when someone brings actual heat, they respond with the closest thing they have to gratitude.", "ex1": "A person who has been performing enthusiasm for years suddenly experiencing genuine excitement because their partner's intensity matches the frequency they actually operate on.", "ex2": "Someone who usually has to generate all the energy in a relationship and, for once, doesn't — and the relief of being met is so profound it looks like vulnerability.", "ex3": "A lover who says 'where have you been?' not as a line but as an actual question, because they'd given up on finding someone who could reach their depth."}, {"n": 5, "name": "Competitive Reception", "desc": "Receives passion but immediately turns it into a contest. Can't just accept desire — has to match or exceed it. The partner's fire is welcome but also a challenge to be dominated.", "ex1": "A lover who responds to 'I want you' with 'not as much as I want you' — every exchange of desire becomes an escalation game.", "ex2": "Someone who hears their partner's passionate confession and immediately one-ups it: 'You think that's intense? Let me tell you how I really feel.'", "ex3": "A partner who can't let desire land without lobbing it back harder — receiving is too passive, too vulnerable. They must always be the one burning brightest."}, {"n": 4, "name": "Temporary Fuel", "desc": "Receives passion and is visibly energized by it — but the partner can sense they're being consumed as fuel rather than received as a person. Welcomed, yes. Seen, not quite.", "ex1": "A person whose eyes light up when desired, in a way that's exciting until the partner realizes those eyes aren't seeing them — they're seeing the intensity.", "ex2": "Someone who receives a love letter and is moved not by the content but by the feeling — they couldn't tell you what it said, but they could tell you how it felt.", "ex3": "A lover who makes their partner feel incredibly desired in the moment and oddly interchangeable in the morning."}, {"n": 3, "name": "Already Bored", "desc": "Receives passion but is already habituated. What would overwhelm most people barely registers. The partner's intensity is acknowledged but doesn't ignite anything new. Been there, felt that.", "ex1": "A person who receives a breathtaking declaration of love and responds with 'yeah, this is nice' — not dismissive, just calibrated to a scale where 'nice' is their maximum for this input.", "ex2": "Someone whose partner tries increasingly dramatic gestures to get a reaction, not realizing that the Inferno's scale has been broken by years of excess.", "ex3": "A lover who is technically receptive but whose reception feels like dropping a stone into a very deep well — the splash is a long time coming, and it's small."}, {"n": 2, "name": "Dismissive", "desc": "Partner's passion is met with barely concealed impatience. Not because it's unwelcome in theory, but because it's insufficient in practice. The partner feels like they're offering a candle to someone standing in front of a furnace.", "ex1": "A lover who responds to their partner's vulnerability with 'that's cute' in a tone that makes the partner resolve never to be vulnerable again.", "ex2": "Someone who yawns — literally or figuratively — at declarations of love, not out of cruelty but out of a genuine inability to feel anything below a certain threshold.", "ex3": "A partner whose reception of desire makes the other person feel small, not because they were rejected but because they were weighed and found lightweight."}, {"n": 1, "name": "Black Hole", "desc": "Receives everything and returns nothing. The partner's passion enters and disappears. No reflection, no response, no acknowledgment. The Inferno has consumed so much that they've become a void — still pulling, but producing no light.", "ex1": "A person whose partner pours love into them the way you'd pour water into sand — it vanishes, and the surface looks exactly the same.", "ex2": "Someone who can receive the most passionate, vulnerable, soul-baring declaration another human can produce and respond with 'okay' — and mean it neutrally.", "ex3": "A lover who is a perfect receiver in the mechanical sense — everything goes in, nothing comes back — and the partner eventually realizes they're not feeding a fire, they're filling a hole."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Dare You to Try", "desc": "Weaponizes their own impossibility. Receives passion as a challenge they know the partner will fail. Sets up impossible standards of intensity, watches the partner exhaust themselves reaching, and feels a dark satisfaction in never being matched.", "ex1": "A lover who tells their partner 'nobody has ever been enough' as both confession and threat — establishing from the start that the partner is auditioning for a role that has never been successfully cast.", "ex2": "Someone who receives desire the way a dragon receives tributes — with amusement, tolerance, and the understanding that it will never satisfy the actual appetite.", "ex3": "A partner who has made their own insatiability into a seduction tool: 'I've never been satisfied. Prove me wrong.' And the partner tries, and tries, and tries."}, {"n": 6, "name": "Trophy Collector", "desc": "Receives passion as proof of their own power rather than as connection. Each person who desires them is a data point in a case they're building about their own magnificence.", "ex1": "Someone who keeps screenshots of their most passionate received messages — not to reread lovingly, but as inventory. Evidence of impact.", "ex2": "A person who receives 'I love you' and files it under 'validation' rather than 'connection,' and whose response is calibrated to maintain supply rather than reciprocate.", "ex3": "A lover who describes being desired the way a CEO describes quarterly results: as metrics of performance."}, {"n": 5, "name": "Mockery", "desc": "Receives passion and uses it as entertainment. The partner's earnestness is privately (or publicly) amusing to someone who considers themselves beyond such naive intensity.", "ex1": "A person who reads their partner's love letter to friends at brunch — not maliciously, but with the amused detachment of someone reading a child's drawing.", "ex2": "Someone who receives sexual desire and responds with a performance review: 'That was enthusiastic. A little uncoordinated, but enthusiastic.'", "ex3": "A lover who makes their partner feel ridiculous for wanting them — not through rejection but through treating the desire as quaint."}, {"n": 4, "name": "Leverage", "desc": "Receives passion and immediately calculates its exchange value. Every expression of desire from the partner becomes a chip to be cashed in later. Love offered; debt recorded.", "ex1": "Someone who responds to 'I'd do anything for you' with a mental note rather than an emotional response — the 'anything' has been filed for future deployment.", "ex2": "A partner who allows themselves to be pursued because pursuit gives them power, and they enjoy the dynamic more than they enjoy the person.", "ex3": "A lover who has noticed their partner's desire peaks after insecurity and has begun engineering insecurity with the precision of a chemist."}, {"n": 3, "name": "Irritation", "desc": "Receives passion as an annoyance. The partner's desire feels like a demand on resources the Inferno doesn't want to allocate. They're not hurt by being wanted — they're bothered by it.", "ex1": "A person who sighs audibly when their partner initiates contact, as if being desired were one more item on an already too-long to-do list.", "ex2": "Someone who responds to romantic gestures with 'what's this about?' in a tone that makes the gesture feel like an intrusion.", "ex3": "A lover who treats their partner's desire as evidence of the partner's weakness rather than evidence of their own value."}, {"n": 2, "name": "Cruelty", "desc": "Receives passion and punishes it. The partner's desire is met with deliberate infliction of pain — not because the Inferno feels threatened, but because they've discovered that destroying someone's desire gives them a feeling when almost nothing else does.", "ex1": "Someone who waits for their partner to be maximally vulnerable — mid-confession, mid-intimacy — and then says something precisely calibrated to wound.", "ex2": "A lover who responds to 'I need you' with 'that's your problem' and feels a flicker of something that passes for alive.", "ex3": "A partner who has learned that the moment someone opens up is the moment they're most destructible, and has stopped being able to resist the experiment."}, {"n": 1, "name": "Void", "desc": "Receives nothing because there is nothing left to receive with. The Inferno has consumed itself. Partners' passion enters a dead system — no cruelty, no warmth, no response. The lights are on and nobody's home, and the person standing at the door will never be told to stop knocking.", "ex1": "A person who sits through their partner's tearful plea for connection with the affect of someone watching a nature documentary — interested in theory, unmoved in practice.", "ex2": "Someone who has been told 'I love you' so many times by so many people that the words have become phonemes without referents — sounds that mean nothing.", "ex3": "A lover whose partner has started talking about them in the past tense even though they're still technically together."}]}]}, {"name": "The Stone", "factor": "Factor 1: Passion ↔ Stability", "factor_num": 1, "pole": "Stability", "color": "#7A8B6E", "alignment": "Shadow", "tagline": "I am not cold. I am strong. (But they are cold.)", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Monolith", "desc": "Has achieved such complete emotional suppression that it reads as power. Others mistake their numbness for composure, their dissociation for mastery. They've built an impenetrable self that feels nothing and needs no one — and the construction was so total they can no longer find the door from inside.", "ex1": "A person who has survived genuine trauma by becoming impervious, and the survival mechanism has become indistinguishable from their personality. Even they can't tell where the armor ends and the self begins.", "ex2": "Someone whom others describe as 'unflappable' and 'incredibly strong' — and who has never corrected the misunderstanding because they've forgotten it is one.", "ex3": "A lover who can be physically intimate with perfect technical skill and zero emotional presence — and whose partners always leave saying 'I never really knew them.'"}, {"n": 6, "name": "Fortress", "desc": "High-functioning emotional unavailability. They have rich inner lives they never share, deep feelings they never express, and genuine needs they never voice. The wall isn't absence — it's architecture.", "ex1": "A person who journals extensively about their feelings and has never told a living soul any of it. The emotional life is real; the sharing mechanism is bricked shut.", "ex2": "Someone who cries alone in the car and walks into the house with a neutral expression, and has done this so long the car has become their only emotional space.", "ex3": "A lover whose partner discovers their hidden poetry after a breakup and realizes they were living with someone they never met."}, {"n": 5, "name": "Wall", "desc": "Obviously guarded. People can see the wall; they just can't get past it. The Stone at this level hasn't even fully disguised their emotional absence — it shows up as stiffness, formality, or a quality of 'holding back' that others can feel.", "ex1": "A partner who is kind, responsible, and considerate — and whose spouse describes a persistent feeling of 'being alone together' that they can't quite articulate.", "ex2": "Someone who freezes during emotional conversations. Not angry, not dismissive — frozen. As if the machinery for processing feelings has locked up.", "ex3": "A lover who can talk about any topic with intelligence and warmth except their own emotions, at which point they become monosyllabic."}, {"n": 4, "name": "Flat Affect", "desc": "Emotional range has narrowed to a band so thin that joy and grief look approximately the same from the outside. Not performing calm — genuinely unable to access the full spectrum.", "ex1": "A partner who responds to 'I'm pregnant' and 'the car needs an oil change' with roughly the same facial expression, and is confused when this is identified as a problem.", "ex2": "Someone whose happiest and saddest moments look identical to observers — a slight nod, a quiet 'okay,' and continued functioning.", "ex3": "A lover whose partner has started narrating emotions for them: 'You seem happy' or 'I think you're upset' — because the Stone's face provides no data."}, {"n": 3, "name": "Numb", "desc": "Not suppressing feelings — genuinely not having them. The emotional infrastructure has atrophied from disuse. They know intellectually that they should feel things and are mildly troubled by the absence.", "ex1": "A person who watches their own wedding video and thinks 'that looks like it was a nice day' — as if watching a stranger's footage.", "ex2": "Someone who Googles 'how to know if you love someone' not because they're confused about a specific person but because they've realized they don't know what love is supposed to feel like from the inside.", "ex3": "A lover who tells their therapist 'I don't think I feel things the way other people do' and can't decide if that's a symptom or just a fact."}, {"n": 2, "name": "Petrified", "desc": "So disconnected from feeling that they've begun to mistake their own numbness for an achievement. The absence of emotion is reframed as evolution: 'I'm just not emotional. That's a strength.'", "ex1": "A partner who is proud of never crying and uses 'I don't get emotional' as a shield against any conversation that might require vulnerability.", "ex2": "Someone who watches others express feelings with a mixture of fascination and faint contempt, the way an adult watches children believe in Santa.", "ex3": "A lover who has built an entire identity around being the 'rational one' in every relationship, not realizing that 'rational' has become a euphemism for 'unreachable.'"}, {"n": 1, "name": "Fossil", "desc": "There is nothing left inside the stone. Not suppression, not defense — vacancy. They exist in relationships the way a rock exists in a garden: present, solid, and completely without inner life. The tragedy is that nobody, including them, can tell if they were always this way or if something alive was buried so deep it died.", "ex1": "A person whose long-term partner is asked 'what are they like, really?' and genuinely cannot answer beyond surface descriptions — job, habits, preferences — because there's nothing deeper available.", "ex2": "Someone who has been in therapy for years and the therapist still can't find the emotional floor — not because the patient is resisting, but because there may not be one.", "ex3": "A lover who has been physically present in someone's bed for a decade and remains, in every meaningful sense, a stranger."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Quiet Protection", "desc": "At their best, the Stone's emotional containment functions as shelter for the partner. Their unshakable calm is genuinely useful in crisis — the partner panics and the Stone holds. This works only when the partner also gets warmth from elsewhere or the Stone can occasionally crack open.", "ex1": "A partner who is the person everyone calls in emergencies because they don't panic, don't cry, and don't freeze — and their spouse has learned to value this even while needing more.", "ex2": "Someone who shields their partner from their own anxiety by processing it internally — genuinely protective, as long as the partner understands the cost.", "ex3": "A lover who says 'I may not say it enough, but I'm here and I'm not going anywhere' — and the partner believes it because the Stone's actions have always been more eloquent than their words."}, {"n": 6, "name": "Acts of Service", "desc": "Expresses care through doing rather than feeling. The partner receives love through fixed faucets, filled gas tanks, and silent presence during hard times. It's not the language most partners want, but it's real.", "ex1": "A partner who can't say 'I love you' but who shovels the driveway at 5 AM so their spouse doesn't have to, and that's the same sentence in a different language.", "ex2": "Someone who shows up to every hospital visit, every flat tire, every 3 AM crisis — not with words of comfort, but with their coat and their car keys.", "ex3": "A lover whose partner has learned to read 'I organized your closet' as 'I was thinking about you for three hours and this is how it came out.'"}, {"n": 5, "name": "Trying", "desc": "Genuinely attempting to provide emotional warmth despite limited capacity. The effort is visible and the partner can see it's costing them. Imperfect, but the trying itself is a form of love the partner learns to recognize.", "ex1": "A partner who says 'I know you need me to talk about feelings, and I'm going to try' — and does try, haltingly, like someone speaking a second language they're still learning.", "ex2": "Someone who buys a book on emotional communication and actually reads it, not because it comes naturally but because they understand their partner needs something they don't instinctively provide.", "ex3": "A lover who holds their partner's hand during difficult conversations even though they'd rather be in another room — the hand-holding is their entire emotional bandwidth, and they're giving it."}, {"n": 4, "name": "Functional Distance", "desc": "Provides practical care with minimal emotional accompaniment. The partner is supported materially but not nourished emotionally. It works as long as the partner's emotional needs are met elsewhere.", "ex1": "A partner who handles logistics, finances, and household management excellently — and considers this their primary contribution to the relationship, not understanding why it isn't enough.", "ex2": "Someone who responds to 'I need you to be more present' with 'I'm right here' while sitting in the same room looking at their phone — present in body, absent in everything else.", "ex3": "A lover whose partner has started going to their friends for emotional support and to the Stone for tax advice, and the division has become the relationship's unspoken architecture."}, {"n": 3, "name": "Minimal Warmth", "desc": "Occasional flickers of genuine emotional expression that give the partner just enough hope to stay. A hand squeeze during a movie. A single sentence after a long silence. These moments are rare enough to feel precious and sparse enough to be starving.", "ex1": "A partner who says 'you looked beautiful today' once every three months — and the partner lives on it the way someone lost at sea lives on rainwater.", "ex2": "Someone who cried once, five years ago, during a moment of overwhelming tenderness — and the partner still references that moment as proof that the real person is in there somewhere.", "ex3": "A lover whose partner has learned to read microscopic emotional signals — a slightly longer hug, a specific tone of voice — because the macro signals never arrive."}, {"n": 2, "name": "Going Through Motions", "desc": "Performs the actions of care without emotional content. The partner receives mechanically correct love — the right words at the right times in the right order — and feels lonelier than if they were alone.", "ex1": "A partner who says 'happy anniversary, I love you' on the correct date, in the correct way, with the emotional weight of someone reading a phone number.", "ex2": "Someone who hugs their partner with their arms but not their body — the shape of embrace without the warmth of contact.", "ex3": "A lover whose physical intimacy is technically proficient and emotionally vacant, and the partner has started preferring no sex to the specific loneliness of sex without presence."}, {"n": 1, "name": "Nothing to Give", "desc": "Has no emotional resources to direct toward the partner at all. Not withholding — empty. The partner stands in front of them asking for love and the Stone is not refusing; they simply have nothing in the account.", "ex1": "A partner who is told 'I need more from you' and responds with honest bewilderment: 'More of what?' — not defensively, but because they genuinely don't know what substance is being requested.", "ex2": "Someone whose partner has stopped asking and started quietly planning their exit — not in anger but in the grief of accepting that wanting something from someone who has nothing to give is its own form of cruelty.", "ex3": "A lover who watches their partner leave and feels a dim, distant awareness that something important just happened, without being able to locate the feeling that should accompany it."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Emotional Execution", "desc": "Systematically kills the partner's emotional life to match their own. Not through cruelty — through slow, persistent non-response. Every feeling the partner expresses is met with nothing until the partner stops expressing, stops feeling, stops trying. Two stones now.", "ex1": "A partner whose formerly vibrant, expressive spouse has become quiet, flat, and 'easy to live with' — and the Stone considers this an improvement in the relationship.", "ex2": "Someone whose presence is so emotionally void that their partner has unconsciously begun mirroring the emptiness — developing the same flat affect, the same minimal speech, the same affective desert.", "ex3": "A lover whose ex describes the relationship as 'I didn't realize I was disappearing until I was almost gone — they didn't take anything from me, but nothing grew.'"}, {"n": 6, "name": "Contempt for Need", "desc": "Views the partner's emotional needs as weakness. Doesn't just fail to meet them — actively judges them. The partner learns that having feelings is embarrassing, childish, or evidence of inadequacy.", "ex1": "A partner who responds to tears with 'are you really going to do this right now?' — not angry, just weary, as if the other person's emotions are an imposition on a reasonable existence.", "ex2": "Someone who describes their partner's emotional needs to friends as 'high maintenance' and has reframed their own unavailability as 'being low-drama.'", "ex3": "A lover who has subtly trained their partner to apologize for having feelings: 'Sorry, I know this is silly, but I just need...'"}, {"n": 5, "name": "Stonewalling", "desc": "Uses silence as a weapon. When the partner pushes for connection, the Stone goes quieter. The less the partner gets, the more desperately they reach, and the more the Stone withdraws. A cycle that can run for decades.", "ex1": "A partner who can sit through a two-hour argument without saying a single word, and the silence is louder and more punishing than anything they could say.", "ex2": "Someone who responds to 'we need to talk' by leaving the room, and to 'please don't walk away' by walking away more slowly.", "ex3": "A lover whose partner has described the experience as 'talking to a wall that can hear you and chooses not to respond' — and the choice is the part that destroys."}, {"n": 4, "name": "Gaslighting by Omission", "desc": "Makes the partner doubt their own reality by simply refusing to acknowledge it. 'I don't know what you're talking about.' 'That didn't happen.' 'You're imagining things.' The Stone's version of reality — where nothing emotional occurs — becomes the official record.", "ex1": "A partner who denies arguments happened, forgets promises made, and has no recollection of moments that were devastating to the other person — and the denial is so consistent the partner starts questioning their own memory.", "ex2": "Someone who responds to 'you hurt me last night' with 'I didn't do anything last night' — and they believe it, because the emotional register they operate on genuinely didn't record the event.", "ex3": "A lover whose partner has started keeping a journal to prove to themselves that their own experiences are real, because the Stone's blankness has made them doubt their own perceptions."}, {"n": 3, "name": "Indifference", "desc": "Simply does not register the partner's emotional existence. Not hostile, not avoidant — indifferent. The partner could be happy, devastated, or on fire, and the Stone's response would be approximately the same.", "ex1": "A person whose partner comes home crying and they ask 'what's for dinner?' — not callously, but because the emotional information didn't register as relevant data.", "ex2": "Someone who learns their partner considered leaving them and responds with a shrug that isn't performative — they genuinely don't understand why this is supposed to be alarming.", "ex3": "A lover whose partner has started testing them — leaving increasingly obvious emotional cues to see if anything triggers a response — and nothing does."}, {"n": 2, "name": "Abandonment in Place", "desc": "Physically present, emotionally gone. The cruelest form of the Stone — they're right there, in the same house, same bed, same life, and the partner is as alone as if they'd been left.", "ex1": "A partner who eats dinner across the table from someone every night and has less emotional connection with them than with the barista they see for four minutes each morning.", "ex2": "Someone whose partner has started talking to them as a formality — the way you'd announce things to an empty room, just in case someone's listening.", "ex3": "A lover whose partner watches them sleep and feels the specific grief of lying next to a body that contains no one you can reach."}, {"n": 1, "name": "Erasure", "desc": "The partner ceases to exist as an emotional entity. Not ignored — erased. The Stone has achieved such total disconnection that the partner has become furniture: a functional object in a space, maintained but not perceived as human.", "ex1": "A person who is asked 'tell me about your spouse' and lists facts — job, height, habits — the way you'd describe an appliance: accurately, without affection or malice.", "ex2": "Someone whose partner dies and they feel inconvenience before grief — the disruption to routine registers before the loss of a person.", "ex3": "A lover who has been so thoroughly absent within a relationship that when it ends, the partner realizes they've been grieving for years and the breakup is just the funeral for something long dead."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Crack in the Wall", "desc": "Something gets through. A partner's persistent, patient warmth finds a fracture in the Stone's defenses — not by force but by outlasting them. The Stone feels something and doesn't immediately seal the breach. Rare. Often the beginning of either transformation or terror.", "ex1": "A person whose partner has spent years being gently, consistently warm — and one night, unbidden, the Stone says 'I don't know how to do this, but I want to try' and means it.", "ex2": "Someone who cries for the first time in a decade because their partner did something so achingly kind that the emotional infrastructure couldn't hold it out.", "ex3": "A lover whose partner's love has been the first thing in their life that was both warm and safe — and the combination is so unfamiliar it feels like a foreign language they're hearing for the first time."}, {"n": 6, "name": "Grateful Distance", "desc": "Recognizes and values what the partner offers even though they can't fully receive it. Expresses appreciation in their limited way — a look, a gesture, a single sentence that carries more weight than most people's paragraphs.", "ex1": "A partner who says 'thank you for staying' in a voice so quiet and rare that their spouse understands it as the most vulnerable thing this person has ever said.", "ex2": "Someone who can't reciprocate emotional depth but makes sure their partner knows — through actions, through presence, through the occasional raw, honest sentence — that it matters.", "ex3": "A lover who holds their partner extra-long one night for no reason, and the partner knows not to comment on it because acknowledging it might seal the crack."}, {"n": 5, "name": "Allowing It", "desc": "Doesn't reciprocate but has stopped actively blocking. The partner's warmth is permitted to exist in the room, even if the Stone doesn't absorb it. A neutral reception that the partner has learned to interpret as progress.", "ex1": "A partner who no longer leaves the room when their spouse tries to have an emotional conversation — they stay, silently, and both of them understand this as a concession.", "ex2": "Someone who lets their partner hold them without pulling away — not leaning in, not pulling back, just... allowing.", "ex3": "A lover whose partner has learned that 'not flinching' is this person's version of an embrace, and has adjusted their expectations accordingly."}, {"n": 4, "name": "Intellectual Acknowledgment", "desc": "Understands cognitively that the partner's emotional offerings have value. Can discuss feelings in theory. Cannot process them when they arrive. The partner feels seen by the Stone's mind but invisible to their heart.", "ex1": "Someone who says 'I understand that's important to you' with genuine sincerity and zero emotional resonance — the words are correct, the feeling is absent.", "ex2": "A partner who reads self-help books about emotional availability and can articulate exactly what they should be feeling without actually feeling it.", "ex3": "A lover who nods at the right times during emotional conversations and has learned the appropriate phrases — 'that sounds hard,' 'I hear you' — that function as social scripts rather than felt responses."}, {"n": 3, "name": "Toleration", "desc": "Receives the partner's emotional expression the way one receives slightly unpleasant weather — endures it, waits for it to pass, continues with the day. Not hostile, but the partner can feel themselves being weathered rather than heard.", "ex1": "A partner who sits through their spouse's emotional expression with the patient, slightly distant look of someone waiting for a train.", "ex2": "Someone who has learned that if they stay quiet long enough during emotional conversations, their partner will eventually run out of words and the room will return to comfortable silence.", "ex3": "A lover whose partner has started timing their emotional expressions — keeping them under five minutes because they can feel the Stone's tolerance clock ticking."}, {"n": 2, "name": "Deflection", "desc": "Actively redirects emotional energy away from themselves. The partner's warmth is rerouted — into tasks, logistics, other people. The Stone ensures that nothing aimed at their heart actually reaches it.", "ex1": "A partner who responds to 'I love you so much' with 'did you remember to pay the electric bill?' — not as cruelty, but as genuine inability to exist in the emotional space for more than a second.", "ex2": "Someone who converts every intimate moment into a practical one: a hug becomes a chance to mention a chore, a kiss is followed immediately by a to-do list.", "ex3": "A lover whose partner has stopped trying to share feelings directly and has started leaving emotional notes instead — because at least the notes don't get redirected mid-sentence."}, {"n": 1, "name": "Sealed", "desc": "Nothing gets in. The Stone has achieved perfect impermeability. The partner's love, warmth, care, desire — all of it hits the surface and slides off. Not reflected, not rejected — just not received. The partner is loving a wall.", "ex1": "A person whose partner has spent a decade trying every possible approach to emotional connection — patience, directness, letters, therapy, silence, persistence — and each one produced the same result: nothing.", "ex2": "Someone whose partner finally says 'I've given everything I have and you haven't received any of it' — and the Stone hears the words but cannot locate the part of themselves that should respond.", "ex3": "A lover whose partner leaves, and the Stone notices the absence the way one notices a piece of furniture has been moved — something is different, but the emotional consequence hasn't arrived and may never."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Weaponized Impenetrability", "desc": "Uses their own unreachability as a tool of psychological warfare. Knows the partner needs emotional response and deliberately withholds it — not from numbness, but from the discovered power of being needed and choosing not to give.", "ex1": "A person who has realized that their partner's desperation for connection gives them absolute control, and has begun calibrating their emotional unavailability with surgical precision.", "ex2": "Someone who watches their partner beg for warmth and feels the only thing that still registers: power. The numbness has become a weapon because it's the only thing they have left.", "ex3": "A lover who gives one word of affection per month — not because they feel it, but because they've learned the exact minimum required to keep the partner hoping and the exact maximum that would require vulnerability."}, {"n": 6, "name": "Emotional Hostage-Taking", "desc": "Receives the partner's emotional investment and holds it hostage. The partner has invested so much heart that leaving would mean abandoning years of effort — and the Stone knows this. They don't have to give anything; the partner's own investment traps them.", "ex1": "A partner who says 'after everything I've put into this, I can't just leave' — and the Stone hears this as the sound of the cage locking, not as a cry for help.", "ex2": "Someone whose partner's friends say 'why do you stay?' and the partner can't articulate that leaving would mean admitting the entire emotional investment was wasted.", "ex3": "A lover who benefits from their partner's sunk-cost fallacy and feels no obligation to provide a return on the investment."}, {"n": 5, "name": "Punishment by Absence", "desc": "Uses emotional withholding as discipline. When the partner does something the Stone dislikes, they become even more unreachable — and the partner, already starving for connection, experiences this reduction as devastating.", "ex1": "A partner who can reduce their already minimal emotional output to zero — and the partner, calibrated to survive on crumbs, experiences the removal of crumbs as famine.", "ex2": "Someone who has trained their partner so thoroughly that a single night of slightly colder than usual silence produces apologies for offenses the partner can't identify.", "ex3": "A lover whose partner has learned that the Stone's displeasure doesn't look like anger — it looks like slightly more nothing, and that 'slightly more nothing' is the most terrifying thing in their world."}, {"n": 4, "name": "Superiority Complex", "desc": "Receives the partner's emotional expressions and internally classifies them as evidence of inferiority. The partner's need for connection is weakness; the Stone's independence is strength. This hierarchy is never stated but permeates everything.", "ex1": "A person who watches their partner express love and thinks 'I could never be that exposed' — and the thought arrives as pride, not loss.", "ex2": "Someone who privately considers emotional people to be lower on some evolutionary ladder and extends this judgment to the partner who loves them most.", "ex3": "A lover who receives devotion as tribute from someone they consider beneath them — not worthy of contempt exactly, but not worthy of equality either."}, {"n": 3, "name": "Draining", "desc": "Absorbs the partner's emotional energy without returning anything. The partner pours in love, care, attention — and none of it changes anything or comes back. Over time, the partner becomes depleted: they've been feeding something that produces nothing.", "ex1": "A partner who realizes they've been emotionally pouring into a black hole and have become depressed, anxious, and self-doubting — not from abuse, but from the slow drain of loving someone who can't or won't love back.", "ex2": "Someone whose partner started the relationship vibrant and has become progressively dimmer — and the Stone hasn't noticed because the change was gradual and because noticing would require attentional resources they don't have.", "ex3": "A lover whose partner's therapist has started using the phrase 'caretaker fatigue' and the partner has started wondering if the fatigue is the feeling they'll have for the rest of their life."}, {"n": 2, "name": "Mockery of Feeling", "desc": "Receives emotion and returns ridicule. Not consistently — just enough to make the partner doubt whether expressing feelings is safe. The occasional cutting remark about sentimentality ensures the partner self-censors permanently.", "ex1": "A partner who says 'you're being emotional again' in a tone that makes 'emotional' sound like a medical condition.", "ex2": "Someone who laughed once — just once — at their partner's most vulnerable moment, and the partner has never fully opened up again.", "ex3": "A lover who references their partner's emotional moments as punchlines in social settings: 'You should see them when they get worked up' — a gentle humiliation that functions as a permanent muzzle."}, {"n": 1, "name": "Partner Destruction", "desc": "The Stone's total emotional void has become actively corrosive. The partner's sense of self, emotional health, and capacity for future intimacy are being systematically destroyed — not by anything the Stone does, but by what they refuse to be. The partner will leave this relationship with scar tissue where their ability to trust once lived.", "ex1": "A person whose ex-partner now flinches at kindness in new relationships because they've been conditioned to believe that warmth offered is warmth that will be withdrawn.", "ex2": "Someone whose partner has developed anxiety, depression, and attachment disorders that didn't exist before the relationship — not from violence or insult, but from years of reaching toward nothing.", "ex3": "A lover whose partner will spend years in therapy unlearning the lesson this relationship taught: that wanting to be loved is a form of weakness, and that the safest thing to be is stone."}]}]}, {"name": "The Seeker", "factor": "Factor 2: Pursuit ↔ Surrender", "factor_num": 2, "pole": "Pursuit", "color": "#C75050", "alignment": "Healthy", "tagline": "I reach for you with open hands.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Gravity", "desc": "Their pursuit is so authentic it bends the world around it. They don't chase — they draw. The quality of their wanting is so clean and undeniable that resistance feels arbitrary. Not because they're irresistible, but because their desire is so purely offered it demands nothing.", "ex1": "A person who tells you 'I want to know you' and the sentence carries no agenda, no hunger, no entitlement — just the irreducible fact of genuine interest.", "ex2": "Someone who pursues with the patience of deep water: steady, present, never frantic. Their wanting doesn't push — it invites, and the invitation has no expiration date.", "ex3": "A lover whose courtship didn't feel like courtship but like being recognized — as if they'd seen something true and were simply walking toward it."}, {"n": 6, "name": "Navigator", "desc": "Pursues with skill, attention, and emotional intelligence. Reads signals accurately, respects boundaries, and adjusts approach without losing sincerity. The pursuit is shaped by the person being pursued, not by a script.", "ex1": "Someone who notices that their interest withdraws slightly when texted too often — and spaces messages out not as strategy but because they're paying attention.", "ex2": "A person who asks 'is this welcome?' at exactly the right moment — when the question demonstrates awareness rather than insecurity.", "ex3": "A lover who learned the difference between persistence and pressure and lives comfortably on the right side of that line."}, {"n": 5, "name": "Honest Chase", "desc": "Openly, unapologetically interested. Their cards are on the table and they're comfortable there. Sometimes too eager, occasionally mis-timed, but the transparency itself is attractive.", "ex1": "A partner who says 'I like you. I'd like to take you out. What do you think?' with no game, no buffer, no plausible deniability — and the directness is refreshing.", "ex2": "Someone whose pursuit is slightly too enthusiastic — the third text before you've answered the first — but the enthusiasm is genuine enough to be charming rather than alarming.", "ex3": "A lover who brings flowers on the second date because they wanted to, not because they calculated it, and doesn't notice the slight excess because they're having too good a time."}, {"n": 4, "name": "Steady Interest", "desc": "Reliably interested and consistently present, though the pursuit has settled into a comfortable pattern. They show up, they express interest, they move things forward — but the electricity has been replaced by warm consistency.", "ex1": "A partner who plans dates reliably, texts good morning consistently, and has become the kind of steady pursuer who is excellent on paper and slightly predictable in practice.", "ex2": "Someone whose courtship follows a visible template: dinner, conversation, physical escalation at the expected pace. Genuine but legible.", "ex3": "A lover whose interest never wavers and never surprises — the partner always knows where they stand, which is both comforting and slightly unstimulating."}, {"n": 3, "name": "Hesitant Reach", "desc": "Wants to pursue but second-guesses constantly. The desire is real but filtered through so much anxiety that by the time it reaches the other person, it's diluted. They're reaching, but the hand keeps pulling back.", "ex1": "A person who drafts a text saying 'I really enjoyed last night' and then edits it to 'that was fun' because the first version felt too exposed.", "ex2": "Someone who waits three days to call not because of some dating rule but because they spent three days arguing with themselves about whether calling would be 'too much.'", "ex3": "A lover whose partner can feel the wanting but also the braking — like a car that accelerates and taps the brakes simultaneously."}, {"n": 2, "name": "Passive Hoping", "desc": "Wants connection but has stopped actively pursuing it. Waits for love to find them. Puts out vague signals and hopes someone picks them up. The desire exists but the agency has evaporated.", "ex1": "A person who updates their dating profile every six months, swipes occasionally, and describes themselves as 'open to meeting someone' while doing nothing to make it happen.", "ex2": "Someone who has a crush they've had for two years and has done precisely nothing about it except hope the other person develops telepathy.", "ex3": "A lover who is available in theory and invisible in practice — waiting to be found by someone who doesn't know they're looking."}, {"n": 1, "name": "Frozen", "desc": "Cannot pursue at all. The desire for connection may still exist somewhere underneath, but the capacity to move toward another person has completely shut down. They are romantically inert.", "ex1": "A person who hasn't been on a date in years and describes this as a 'choice' that looks increasingly like paralysis.", "ex2": "Someone who feels a spark of attraction and immediately experiences it as dread — because attraction means vulnerability and vulnerability means reaching and reaching means possible rejection.", "ex3": "A lover in theory only — they can imagine wanting someone but the distance between imagination and action has become an uncrossable void."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Endless Courtship", "desc": "Pursues their partner as actively on year twenty as on day one — not from insecurity but from genuine, undimmed fascination. The partner never stops feeling chosen. Every day contains a small act that says 'I am still reaching for you on purpose.'", "ex1": "A partner who still asks their spouse on dates — real dates, with anticipation and getting ready and butterflies — after decades together.", "ex2": "Someone who never stopped learning about their partner. Asks new questions, notices new things, treats familiarity as an invitation to go deeper rather than a license to stop looking.", "ex3": "A lover who leaves notes that aren't repetitive but responsive — each one referencing something specific and recent: 'The way you handled that meeting today. I wanted you to know I saw that.'"}, {"n": 6, "name": "Active Cherishing", "desc": "Pursues their partner through deliberate, tailored acts of attention. Knows the difference between their partner's Tuesday-tired and their Friday-tired, and responds to each differently. The pursuit is specific to this person, not a generic romance template.", "ex1": "A partner who brings exactly the right thing at exactly the right time — not because they're psychic but because they've been paying attention with the dedication of someone who considers this their most important work.", "ex2": "Someone who notices their partner's evolving needs and adapts without being asked. The pursuit changes shape as the partner changes, which means it always fits.", "ex3": "A lover who has a list — not written, just known — of things that make their partner's eyes light up, and deploys them not on schedule but on instinct."}, {"n": 5, "name": "Consistent Reaching", "desc": "Regularly expresses desire and interest. Initiates connection, plans time together, makes their wanting known. Occasionally formulaic, but the formula is built on real feeling.", "ex1": "A partner who always suggests the weekend plans, always initiates the goodnight kiss, always says 'I missed you' after time apart — and means it each time, even if the delivery has become routine.", "ex2": "Someone whose pursuit has become a reliable rhythm in the relationship: date night proposals, morning affection, the daily text that says 'thinking of you.'", "ex3": "A lover whose partner never has to wonder if they're still interested — the evidence arrives like clockwork, warm and genuine if not always electric."}, {"n": 4, "name": "Comfortable Effort", "desc": "Still pursuing, but the effort has become lighter — partly because the relationship is secure, partly because the urgency has faded. The partner feels chosen but not chased. The reaching has become a gentle lean.", "ex1": "A partner who still initiates sex but now does it with a familiar hand on the thigh rather than the full-body intensity of the early days. Less heat, same warmth.", "ex2": "Someone who says 'want to grab dinner?' rather than 'I need to take you out' — the wanting is still there but has put on comfortable clothes.", "ex3": "A lover who has settled into a pursuit rhythm that works but doesn't surprise — the partner knows exactly what Saturday morning looks like and is mostly content with it."}, {"n": 3, "name": "Occasional Effort", "desc": "Pursues in bursts — after reminders, after guilt, after the partner's visible disappointment. The reaching is genuine when it happens but has to be prompted. The partner has started to feel like they're managing the pursuit rather than receiving it.", "ex1": "A partner who plans something wonderful when their spouse says 'we never do anything anymore' — and the wonderful thing lasts until the complaint fades from memory.", "ex2": "Someone who needs external reminders to pursue: anniversaries, Valentine's Day, their partner's pointed silence. Between reminders, the reaching stops.", "ex3": "A lover whose partner has started making requests that used to be unnecessary: 'Can you plan something for us this weekend?' — each request a small acknowledgment that spontaneous pursuit has ended."}, {"n": 2, "name": "Going Through Motions", "desc": "The pursuit has become obligation. They still reach for their partner but the hand is empty — the gesture is correct, the feeling is absent. The partner can tell the difference and has started to dread the hollow version more than the absence.", "ex1": "A partner who buys anniversary flowers the same way they buy milk — it's on the list, it gets done, it means nothing beyond completion.", "ex2": "Someone who initiates a kiss at the door and both of them know it's a formality — the lips meet, the bodies don't.", "ex3": "A lover whose 'I love you' at bedtime has become punctuation rather than communication — a period at the end of the day, not a sentence with meaning."}, {"n": 1, "name": "Stopped Reaching", "desc": "All pursuit has ceased. The partner exists in the same space but is no longer being moved toward. Not abandoned exactly — just no longer sought. The difference between leaving someone and ceasing to arrive.", "ex1": "A partner who sits in the same room every evening and hasn't initiated a single conversation, touch, or plan in months — and hasn't noticed the absence because the inertia feels like normalcy.", "ex2": "Someone whose partner realizes with a cold shock that they can't remember the last time this person reached for them first — for anything.", "ex3": "A lover whose partner has started a private countdown: 'If they don't initiate something in the next month, I'll know.' The month passes. They know."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Suffocating Devotion", "desc": "Pursues so relentlessly that the partner has no room to breathe, want, or reach back. The Seeker's constant motion toward them fills every space where the partner's own desire might have formed. Love as occupation rather than invitation.", "ex1": "A partner who is so consistently pursuing that their spouse has never once experienced the sensation of missing them — and has started to realize that absence might be necessary for longing to exist.", "ex2": "Someone whose pursuit is so total it functions as surveillance: always checking in, always planning, always present — until the partner realizes they can't distinguish between being loved and being monitored.", "ex3": "A lover whose constant reaching has trained the partner to be permanently retreating — not from lack of love but from the sheer claustrophobia of never being allowed to want first."}, {"n": 6, "name": "Anxious Pursuit", "desc": "Pursuit driven by fear of loss rather than joy of connection. Every reach is a check: are you still here? Do you still want me? The partner feels monitored rather than desired, and the constant reassurance-seeking drains them.", "ex1": "A partner who texts 'everything okay with us?' after every minor disagreement, every unanswered text, every hour of silence — and the partner has started lying to avoid the conversation.", "ex2": "Someone whose pursuit escalates in direct proportion to the partner's need for space — the more the partner pulls back, the harder the Seeker chases, creating a spiral neither can escape.", "ex3": "A lover whose 'I miss you' texts arrive so frequently they've become demands disguised as affection."}, {"n": 5, "name": "Scorekeeping Pursuit", "desc": "Tracks their own effort and measures the partner's reciprocation. The pursuit has become a ledger: I planned this, I initiated that, I said this first. The partner feels pursued and invoiced simultaneously.", "ex1": "A partner who says 'I always make the plans' not as an observation but as an indictment — and has begun quantifying love in units of effort.", "ex2": "Someone who keeps mental tallies of initiations, compliments given versus received, and texts sent first — and raises the data during arguments as evidence.", "ex3": "A lover whose pursuit has become a performance with an expected review: every romantic gesture comes with an invisible comment card the partner is expected to fill out."}, {"n": 4, "name": "Guilt Pursuit", "desc": "Uses their own effort as a weapon. 'After everything I do for this relationship...' The partner is made to feel guilty for not matching the Seeker's level of pursuit, and the guilt becomes the relationship's primary texture.", "ex1": "A partner who sighs visibly when their romantic effort goes unmatched, making sure the partner sees the disappointment — converting desire into obligation.", "ex2": "Someone who brings up their past gestures during unrelated arguments: 'I flew across the country for your birthday and you can't even remember to call me back.'", "ex3": "A lover who frames their pursuit as sacrifice — 'I do so much for us' — until the partner feels less like a person being loved and more like a debt being managed."}, {"n": 3, "name": "Desperate Reaching", "desc": "Pursuit without dignity. The desire has curdled into neediness so visible that the partner alternates between pity and revulsion. The Seeker knows they're pushing the partner away and cannot stop reaching.", "ex1": "A partner who sends long, emotional texts after being left on read — each one longer and more revealing than the last, each one pushing the other person further away.", "ex2": "Someone who makes grand, unrequested gestures to 'fix' a distance they can feel growing — surprise trips, expensive gifts, overwrought love letters — and the desperation in each one is the message the partner actually receives.", "ex3": "A lover whose pursuit has become so anxious that the partner has started associating their presence with stress rather than comfort."}, {"n": 2, "name": "Manipulative Pursuit", "desc": "Has learned to disguise pursuit as other things: concern, helpfulness, casual presence. The partner can feel they're being maneuvered toward but can't identify how, which creates a persistent, low-grade unease.", "ex1": "A partner who 'happens' to be everywhere the other person is, 'happens' to befriend their friends, 'happens' to know their schedule — and frames it all as coincidence.", "ex2": "Someone who offers help with everything as a way to make themselves indispensable — the pursuit has become a strategy of creating dependency.", "ex3": "A lover who has learned that direct pursuit gets rejected, so they've gone indirect: engineering situations where the partner 'chooses' them from options the Seeker secretly arranged."}, {"n": 1, "name": "Obsession", "desc": "Pursuit has lost all connection to the actual person being pursued. The partner has become an object, a fixation, a problem to be solved. The Seeker's desire has consumed any ability to see the partner as a separate human being with their own wants.", "ex1": "A person who continues pursuing after being explicitly told to stop — not out of menace (though it functions that way) but because the word 'no' cannot penetrate the wall of their need.", "ex2": "Someone whose friends have started using the word 'stalking' and they react with genuine confusion because from inside the fixation, it feels like love.", "ex3": "A lover who has constructed an entire imaginary relationship with someone who has clearly said they're not interested, and who lives in the imaginary version while the real person feels hunted."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Graceful Welcome", "desc": "Receives pursuit with the full dignity of someone who knows their own worth without performing it. Being chased doesn't inflate them; it delights them. They make the pursuer feel that the pursuit itself is a gift, regardless of outcome.", "ex1": "A person who is asked out and responds with genuine warmth — 'I'm so glad you asked' — regardless of their answer, because they honor the courage of reaching.", "ex2": "Someone who receives romantic attention without either dismissing it or becoming dependent on it. The pursuit lands on solid ground.", "ex3": "A lover who makes their partner feel that pursuing them is a joy rather than a test — no hoops, no games, just honest responsiveness."}, {"n": 6, "name": "Active Reciprocation", "desc": "Doesn't just receive pursuit — meets it halfway. When reached for, reaches back. The dynamic becomes a dance rather than a chase, with both people moving toward each other.", "ex1": "A partner who responds to a love letter with a phone call that starts with 'I need you to know that what you wrote moved me, and here's what I want to say back.'", "ex2": "Someone whose response to being pursued is to pursue in return — not out of obligation but because being wanted activates their own wanting.", "ex3": "A lover who makes sure the pursuer never feels like they're the only one reaching — matching energy with energy, presence with presence."}, {"n": 5, "name": "Warm Reception", "desc": "Genuinely pleased to be pursued and shows it. Responsive, encouraging, appreciative. Occasionally passive — letting the other person do the work — but the welcome is authentic.", "ex1": "A person who smiles when flowers arrive, says 'this is wonderful,' and means it — even if they wouldn't have thought to send flowers themselves.", "ex2": "Someone whose receptivity to pursuit encourages more of it — the pursuer feels rewarded and continues because the response is real.", "ex3": "A lover who enjoys being courted and is honest about it: 'I love that you do this. I know I should do it more for you too.'"}, {"n": 4, "name": "Pleasant Acceptance", "desc": "Accepts pursuit gracefully without being particularly moved by it. The pursuer feels welcomed but not transformatively received — it's nice, it's appreciated, it doesn't change anything.", "ex1": "A partner who says 'thank you, that's really sweet' with the same warmth they'd use for a neighbor who brought cookies. Genuine but not deep.", "ex2": "Someone who accepts dates, gifts, and attention with appreciation that never quite reaches excitement.", "ex3": "A lover whose reception of pursuit is consistently pleasant and consistently leaving the pursuer wondering if they're reaching the person or just the person's good manners."}, {"n": 3, "name": "Ambivalent Reception", "desc": "Receives pursuit with mixed signals — not intentionally, but because they're genuinely uncertain about what they want. The pursuer gets encouragement and withdrawal in equal measure.", "ex1": "A person who responds enthusiastically to a date invitation and then goes quiet for three days — not playing games, just processing at a different speed.", "ex2": "Someone whose body language says 'yes' while their communication patterns say 'maybe' — and they're as confused by the contradiction as the pursuer is.", "ex3": "A lover who leans in during conversation and leans away during planning — fully present in the moment but anxious about what the moments are building toward."}, {"n": 2, "name": "Reluctant Reception", "desc": "Receives pursuit with visible discomfort that isn't quite rejection. They don't say no — they say 'maybe' in a tone that makes the pursuer feel like an imposition. Being wanted is something they tolerate rather than enjoy.", "ex1": "A person who accepts a compliment by deflecting: 'Oh, stop' — and means it, because being seen as desirable triggers something closer to anxiety than pleasure.", "ex2": "Someone who goes on dates because they feel they should want this, while the actual experience of being pursued makes them want to hide.", "ex3": "A lover whose partner has learned to pursue very gently, very slowly, because anything above a whisper causes this person to retreat."}, {"n": 1, "name": "Impervious", "desc": "Cannot receive pursuit at all. Romantic attention hits them and bounces off. Not hostile — just unreachable. The pursuer feels like they're courting a wall that happens to have a face.", "ex1": "A person who has been asked out multiple times by multiple people and responds to each with a polite neutrality that makes the asker wonder if the question was actually spoken aloud.", "ex2": "Someone who is told 'I have feelings for you' and responds with silence so complete it functions as a moat.", "ex3": "A lover who cannot be reached by pursuit because the drawbridge was pulled up years ago and they no longer remember how the mechanism works."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Entitlement to Pursuit", "desc": "Expects to be chased as a fundamental condition of the relationship. Has constructed an identity around being pursued and experiences any lull in the partner's pursuit as abandonment. The partner must constantly reach or the Seeker will engineer a crisis.", "ex1": "A person who has never been in a relationship where they weren't actively chased, and interprets the natural settling of early intensity as evidence that love is dying.", "ex2": "Someone who creates distance specifically to trigger their partner's pursuit response — pulls away to be pulled back, because the pulling is the only thing that feels like love.", "ex3": "A lover who has ended multiple relationships at the exact moment the partner stopped chasing and started simply being present — because 'being present' doesn't register as love on their instrument panel."}, {"n": 6, "name": "Chase Addiction", "desc": "Addicted to the feeling of being wanted. The pursuit itself is the drug — who's doing the pursuing barely matters. They collect pursuers the way others collect compliments: as evidence of worth, never as connection.", "ex1": "A person who maintains multiple interested parties at all times — not out of polyamorous ethics but out of a need to feel the gravitational pull of being wanted from multiple directions.", "ex2": "Someone who loses interest the moment a pursuer catches them, because the only exciting part was the chase, and arrival feels like a kind of death.", "ex3": "A lover whose relationship history is a series of people who were fascinating at a distance and disappointing up close — the pattern is always blamed on the other person."}, {"n": 5, "name": "Moving Goalpost", "desc": "Receives pursuit and immediately raises the bar. Whatever the partner did, it wasn't enough, wasn't right, wasn't quite what they wanted. The pursuit is accepted but the pursuer is never allowed to arrive.", "ex1": "A partner who responds to every romantic gesture with 'that's nice, but...' — the 'but' is always different, always just out of reach, always repositioned the moment it's approached.", "ex2": "Someone who wanted flowers until they got flowers, then wanted something more personal. Got a love letter, then wanted something more spontaneous. Got a surprise trip, then wanted something more intimate. The target is always moving.", "ex3": "A lover whose partner has started asking 'what would actually make you happy?' in a tone that has shifted from curious to exhausted."}, {"n": 4, "name": "Testing", "desc": "Uses received pursuit as a screening mechanism — not to find love but to find proof. Every reach from the partner is a test they don't know they're taking, and the grading is arbitrary and private.", "ex1": "A person who didn't call back to see if the partner would call again, and interprets the result not as information but as verdict — a verdict the partner was never told they were on trial for.", "ex2": "Someone who manufactured a small crisis to see how the partner responded, and filed the response as evidence in a case the partner doesn't know exists.", "ex3": "A lover who keeps a private ledger of the partner's pursuit behaviors and issues silent, unannounced failing grades that accumulate into eventual departure."}, {"n": 3, "name": "Contempt for the Pursuer", "desc": "Has begun to despise the person pursuing them — not because the pursuit is unwelcome, but because someone willing to chase must be worth less than someone worth chasing. The act of being desired triggers contempt for the desirer.", "ex1": "A person who is deeply attracted to unavailable people and immediately loses respect for anyone who shows up with open, honest desire — 'If you want me this badly, something must be wrong with you.'", "ex2": "Someone who privately mocks their partner's romantic gestures to friends while enjoying the gestures when they arrive.", "ex3": "A lover who treats their partner's pursuit as evidence of the partner's weakness, not of their own value."}, {"n": 2, "name": "Weaponized Unavailability", "desc": "Uses their own desirability as a tool of control. Knows the partner wants them, and doles out just enough access to keep the partner pursuing without ever allowing arrival. The pursuit is managed, not received.", "ex1": "A person who responds to their partner's advances on a carefully calibrated schedule: enough to maintain hope, never enough to provide security.", "ex2": "Someone who has learned that being slightly out of reach gives them all the power in the relationship, and has no intention of becoming reachable.", "ex3": "A lover who treats the partner's pursuit the way a fisherman treats a fish: give line, reel in, give line, reel in — the game, not the catch, is the point."}, {"n": 1, "name": "Cruelty to the Pursuer", "desc": "Receives pursuit and uses it to inflict pain. The partner's desire is ammunition — the more they want, the more there is to withhold, mock, or punish. Being wanted has become a weapon rather than a gift.", "ex1": "A person who allows their partner to plan elaborate surprises and then visibly doesn't care — not out of numbness but out of a desire to watch the hope leave the partner's face.", "ex2": "Someone who responds to 'I love you' with 'I know' in a tone that makes the declaration feel pathetic rather than received.", "ex3": "A lover who has discovered that the fastest way to feel powerful is to watch someone want them and then deny it — not because they don't want connection, but because power has replaced connection as their primary need."}]}]}, {"name": "The Yielder", "factor": "Factor 2: Pursuit ↔ Surrender", "factor_num": 2, "pole": "Surrender", "color": "#8B6EC7", "alignment": "Healthy", "tagline": "I open to you because I am strong enough to.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Sovereign Surrender", "desc": "Surrenders from a position of total inner strength. Their openness isn't weakness — it's the most courageous thing in the room. They've chosen vulnerability the way a master chooses to lower their guard: because they can afford to, and because it invites something real.", "ex1": "A person who says 'I need you' without shame, because they've distinguished between dependency and the healthy acknowledgment that love requires letting someone matter.", "ex2": "Someone who can be utterly transparent about their feelings without losing their center. The openness doesn't make them fragile — it makes them magnetic.", "ex3": "A lover who shows their full self — the longing, the fear, the tenderness — and the partner feels trusted rather than burdened, because the Yielder clearly isn't collapsing. They're inviting."}, {"n": 6, "name": "Deep Trust", "desc": "Has built the capacity for profound vulnerability through years of knowing themselves. Yields selectively, intentionally, to people who have earned it. Their surrender is discriminating, which makes it more valuable.", "ex1": "A person who took years to open up — not from dysfunction but from discernment — and when they finally did, their partner received it as the honor it was.", "ex2": "Someone who can say 'I was wrong' or 'I'm scared' without the statement costing them their sense of self, because their identity isn't built on infallibility.", "ex3": "A lover whose vulnerability arrives with its own spine: 'This is who I am. I hope you can hold it. If you can't, I'll survive.'"}, {"n": 5, "name": "Willing Openness", "desc": "Genuinely receptive and available, with a good faith willingness to be known. Sometimes opens faster than wisdom dictates, but the impulse is healthy even when the timing isn't.", "ex1": "A partner who shares their insecurities on the third date — slightly too soon — but the honesty is so disarming that it creates depth rather than alarm.", "ex2": "Someone who defaults to transparency in conflict: 'Here's what I'm actually feeling' — and the habit serves them well, even when the other person isn't ready for it.", "ex3": "A lover whose openness occasionally leaves them exposed to people who don't deserve it, but who would rather be too open than too closed."}, {"n": 4, "name": "Comfortable Yielding", "desc": "Can surrender within established, safe relationships. Vulnerable with people they trust, guarded with everyone else. The yielding is real but context-dependent — they need proof of safety before the doors open.", "ex1": "A partner who is emotionally available at home and emotionally reserved everywhere else — the vulnerability has a specific address.", "ex2": "Someone who can cry in front of their partner but maintains composure with everyone else, and considers this appropriate compartmentalization.", "ex3": "A lover who is genuinely open in intimate moments but snaps back to guarded the moment the context shifts — the yielding has an on/off switch rather than a dimmer."}, {"n": 3, "name": "Selective Shutdown", "desc": "Can yield in some domains but not others. Open emotionally, closed sexually. Or open physically, closed about the past. The surrender has gaps that the person may or may not be aware of.", "ex1": "A partner who talks freely about feelings but freezes when asked about childhood — the vulnerability has a very specific map with clearly marked restricted zones.", "ex2": "Someone who can be physically naked with ease and emotionally naked with terror — the body surrenders freely while the heart is under lock.", "ex3": "A lover whose partner has mapped the available and unavailable territories and has learned which doors open and which ones are welded shut."}, {"n": 2, "name": "Performative Yielding", "desc": "Appears open but the openness is a performance. Shares carefully selected vulnerabilities designed to create the appearance of surrender without the risk. The partner thinks they're seeing the real person; they're seeing a curated exhibit.", "ex1": "A person who has a prepared set of 'vulnerabilities' they share early in relationships — just honest enough to seem brave, just shallow enough to cost nothing.", "ex2": "Someone who cries at movies and can't cry at their own life, and has confused the first for evidence of the second.", "ex3": "A lover whose partner describes them as 'so open and honest' based on information that is technically true and strategically incomplete."}, {"n": 1, "name": "Cannot Yield", "desc": "Totally unable to surrender. Not from strength — from terror. The drawbridge is up, the moat is full, and the person inside the castle has forgotten there's a world outside. They may want to yield and simply can't locate the mechanism.", "ex1": "A person who watches their partner try to get close and feels a wall go up that they didn't consciously build and cannot consciously remove.", "ex2": "Someone who has been in therapy for years trying to learn to be vulnerable and still can't say 'I love you' without the words catching in their throat like fishbones.", "ex3": "A lover who wants nothing more than to let someone in and has no idea how to unlock what's been sealed shut since before they can remember."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Sacred Space", "desc": "Creates conditions where the PARTNER can safely yield. Their own surrender is so genuine it gives permission. By being open, they build a container large enough for two people's vulnerability.", "ex1": "A lover who goes first — shares the scary thing, admits the weakness, names the fear — and the partner watches and thinks 'if they can, maybe I can too.'", "ex2": "Someone whose vulnerability functions as architecture: it builds rooms where both people can take off their armor.", "ex3": "A partner who has made their relationship into the safest place either of them has ever been — not by controlling it, but by being consistently, courageously undefended."}, {"n": 6, "name": "Generous Transparency", "desc": "Offers their inner world to the partner as a gift. Shares not just feelings but the messy process behind them: 'I'm not sure what I'm feeling yet, but I want you to see me figuring it out.'", "ex1": "A partner who narrates their emotional process in real time: 'I'm not angry at you — I'm anxious about something and it's coming out sideways. Give me a minute.'", "ex2": "Someone who shares fears, failures, and uncertainties with their partner not for comfort but for connection — the sharing IS the intimacy.", "ex3": "A lover who has turned vulnerability into a practice rather than a crisis — something they do regularly, not just when things break."}, {"n": 5, "name": "Honest Availability", "desc": "Consistently open and reachable. The partner always knows what they're feeling because they say it. Sometimes the honesty is uncomfortably direct, but the partner never has to guess.", "ex1": "A partner who says 'I'm hurt by what you said at dinner' within the hour rather than letting it fester — and the conversation is hard but it's clean.", "ex2": "Someone who answers 'what's wrong?' with the actual answer instead of 'nothing' — every time, even when the truth is awkward.", "ex3": "A lover whose emotional availability is so reliable that the partner has stopped testing for it and started trusting it."}, {"n": 4, "name": "Good Faith Openness", "desc": "Open within the bounds of the relationship's established emotional range. Vulnerable about safe topics, honest about manageable feelings. The surrender is real but bounded by an unconscious risk assessment.", "ex1": "A partner who shares feelings about the relationship but not about the existential terror underneath them — open within a range, closed below a depth.", "ex2": "Someone who is emotionally available for day-to-day intimacy but holds back the truly frightening material: the fear of death, the childhood wound, the shame that predates the relationship.", "ex3": "A lover whose partner would describe them as 'open' based on the available sample, not knowing there's a restricted archive underneath."}, {"n": 3, "name": "Delayed Yielding", "desc": "Willing to be vulnerable but always after a lag. Processes alone first, then shares. The partner receives edited, composed versions of emotions rather than the raw material. Better than silence, but the partner feels like they're always getting yesterday's news.", "ex1": "A partner who comes home from a hard day, says 'I'm fine,' processes for three hours, then says 'actually, I'm not fine' — and the partner appreciates the eventual honesty while wishing for the real-time version.", "ex2": "Someone who writes out their feelings before sharing them — the partner gets polished vulnerability, which is better than none, but the act of polishing removes exactly the rawness that creates true intimacy.", "ex3": "A lover whose partner has learned that 'I need to think about it' means 'the real answer is coming in two to forty-eight hours.'"}, {"n": 2, "name": "Minimal Openings", "desc": "Offers vulnerability in tiny, controlled doses. The partner gets occasional glimpses through a barely-opened door — enough to know someone's home, not enough to feel invited in.", "ex1": "A partner who mentions, once, that their father left — and then changes the subject so firmly that the partner understands the topic is closed permanently.", "ex2": "Someone who cries in the bathroom with the door locked and the water running, then emerges composed and says 'sorry, allergies.'", "ex3": "A lover whose partner collects these rare emotional droplets like a drought survivor collects rain — treasuring each one while starving for a downpour."}, {"n": 1, "name": "Sealed Toward Partner", "desc": "Cannot yield to this specific person, even if the capacity exists elsewhere. The partner has become the person they're most guarded with — the stakes are too high, the potential loss too great. Intimacy has made vulnerability impossible.", "ex1": "A partner who can be emotionally open with friends, therapists, even strangers — but in the presence of the person they love most, the walls go up and the words go away.", "ex2": "Someone who realizes they've built the highest walls around the person who most deserves an open door — and the realization doesn't help them open it.", "ex3": "A lover whose partner says 'I feel like I know you less than anyone else in your life does' — and they're right, and the reason is that nobody else's opinion matters this much."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Weaponized Vulnerability", "desc": "Uses their own openness as a tool of control. By being the 'vulnerable one,' they ensure the partner feels obligated to protect, accommodate, and prioritize them. The surrender is real; its deployment is strategic.", "ex1": "A person who cries during every disagreement — not falsely, but with an instinct for timing that ensures the argument is won by the person who showed the most pain.", "ex2": "Someone whose vulnerability has become so central to the relationship's dynamic that the partner cannot raise a concern without triggering a display of hurt that redirects all attention to the Yielder.", "ex3": "A lover whose tears function as a shield: the partner cannot be angry at someone who's already crying, and both of them know it."}, {"n": 6, "name": "Vulnerability as Burden", "desc": "Shares so much, so deeply, so often that the partner becomes an unpaid therapist. The surrender is genuine but the volume is unsustainable. The partner drowns in the Yielder's inner world.", "ex1": "A partner who processes every emotion aloud, in real time, with their spouse as the only audience — and the spouse has started dreading the question 'can I tell you something?'", "ex2": "Someone whose emotional transparency has become a demand: 'You need to know how I'm feeling at all times' — and the partner has lost the ability to distinguish genuine crisis from daily emotional weather.", "ex3": "A lover whose openness has consumed all the oxygen in the relationship — the partner's own feelings have been quietly suffocated by the sheer volume of the Yielder's."}, {"n": 5, "name": "Guilt Transparency", "desc": "Shares painful truths the partner didn't ask for and can't unhear, framed as 'honesty.' The Yielder feels relieved; the partner feels burdened. The vulnerability is real, but the sharing serves the sharer at the listener's expense.", "ex1": "A partner who confesses a fleeting attraction to a coworker 'because I believe in total honesty' — and the partner now has to manage that information forever while the Yielder feels cleansed.", "ex2": "Someone who shares every critical thought about the relationship in the name of transparency: 'I want you to know that sometimes I wonder if I made the right choice.' Honest? Yes. Kind? No.", "ex3": "A lover whose 'radical honesty' has become a delivery mechanism for information designed to transfer anxiety from the Yielder to the partner."}, {"n": 4, "name": "Helplessness Performance", "desc": "Presents themselves as so open, so sensitive, so vulnerable that the partner must handle everything. The Yielder's surrender has become a reason to be excused from adulting, and the partner has become caretaker by default.", "ex1": "A partner who can't handle their own taxes, phone calls, or confrontations because they're 'too sensitive' — and the other person has quietly taken over the entire administrative and emotional load.", "ex2": "Someone who responds to every challenge with 'I can't — you know how I am' and the partner has stopped pushing because the tears that follow aren't worth it.", "ex3": "A lover whose vulnerability has become a permanent exemption from responsibility."}, {"n": 3, "name": "Emotional Entrapment", "desc": "Has shared so much that the partner feels they cannot leave without devastating someone who has given them everything. The vulnerability functions as a lock — not deliberately, but the effect is the same.", "ex1": "A partner whose openness about their mental health, their past trauma, their fear of abandonment has made leaving feel like assisted cruelty — the partner stays partially out of love and partially out of the terror of what their departure would do.", "ex2": "Someone who says 'you're the only person who's ever seen the real me' — and the partner hears both the love and the shackle in the sentence.", "ex3": "A lover whose radical vulnerability has given the partner a role they can't exit: guardian of someone else's most fragile self."}, {"n": 2, "name": "Shame Transfer", "desc": "Uses vulnerability as a way to offload pain onto the partner. The sharing isn't for connection — it's for relief. The Yielder empties their emotional garbage into the partner and walks away lighter, leaving the partner to carry it.", "ex1": "A partner who comes home and unloads every terrible thing about their day in graphic detail, then says 'I feel so much better!' while their spouse sits with the wreckage.", "ex2": "Someone who confesses shameful things specifically to watch the partner absorb the shame — the act of telling is the act of transferring.", "ex3": "A lover who uses 'I just need to be honest with you' as a prelude to information that makes the partner feel worse and the Yielder feel better."}, {"n": 1, "name": "Collapse onto Partner", "desc": "Has yielded so completely that they've become a dependent organism. The partner isn't receiving vulnerability — they're carrying a person. The Yielder's surrender has become total, and the total weight has been transferred to someone who never agreed to bear it alone.", "ex1": "A partner who cannot function independently in any domain — emotional, practical, social — and whose collapse has consumed the other person's entire life.", "ex2": "Someone whose partner has stopped being a spouse and become a full-time caregiver, and the transition happened so gradually that neither of them noticed until it was complete.", "ex3": "A lover whose surrender was beautiful at first and is now a sinkhole — the partner stands at the edge, holding on, being slowly pulled in."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Sacred Reception", "desc": "Receives their partner's vulnerability as a sacrament. When the partner opens up, the Yielder holds it with the care of someone handling something holy. The partner's surrender is met with such tenderness that it becomes safe to go deeper.", "ex1": "A partner who listens to a confession without flinching, without judging, without fixing — just receives it, lets it exist, and then says 'thank you for trusting me with that.'", "ex2": "Someone whose partner has revealed their worst self and found it held without recoil — and the experience permanently changed what the partner believed was possible between people.", "ex3": "A lover who creates the conditions for mutual surrender: their capacity to receive is so profound that the partner becomes braver in what they share."}, {"n": 6, "name": "Careful Holding", "desc": "Receives partner's openness with skilled, attentive care. Knows when to speak and when to be silent. Calibrates their response to what the partner needs rather than what their own emotions suggest.", "ex1": "A partner who, when told something devastating, asks 'do you want me to just listen, or do you want help?' — and follows the answer.", "ex2": "Someone who remembers everything their partner has shared and never uses it as ammunition, even during fights.", "ex3": "A lover who has earned a reputation as the person their partner can tell anything — and the reputation is deserved because every previous disclosure was treated with care."}, {"n": 5, "name": "Reliable Container", "desc": "Consistently receives the partner's vulnerability without judgment. Not always perfectly attuned, but always safe. The partner knows that what they share won't be used against them.", "ex1": "A partner who sometimes responds to vulnerability with slightly the wrong thing — 'it'll be okay' when the other person needed 'that sounds really hard' — but whose good intentions are never in question.", "ex2": "Someone whose reception of vulnerability is solid but not artful: present, willing, occasionally clumsy, always trustworthy.", "ex3": "A lover whose partner has learned that opening up here is safe even when the response isn't perfect — because imperfect care is still care."}, {"n": 4, "name": "Willing Listener", "desc": "Makes space for the partner's openness and does their best to hold it. Sometimes overwhelmed, sometimes uncertain how to respond, but always trying. The reception is good-faith, if not always skilled.", "ex1": "A partner who says 'I don't know what to say, but I'm glad you told me' — and the honesty about their own limitation is itself a form of holding.", "ex2": "Someone who sits through difficult conversations with visible effort, and the partner can see the effort and values it.", "ex3": "A lover who hasn't mastered the art of receiving vulnerability but has mastered showing up — which is the foundation everything else gets built on."}, {"n": 3, "name": "Partial Reception", "desc": "Can receive some of what the partner offers but struggles with the hardest material. Handles day-to-day emotional sharing fine; shuts down when the partner brings the truly heavy stuff.", "ex1": "A partner who listens well to 'I had a bad day' but freezes at 'I think I might be depressed' — the reception has a weight limit.", "ex2": "Someone who can hold their partner's sadness but not their rage, or their fear but not their shame — certain emotional channels are open, others are blocked.", "ex3": "A lover whose partner has learned which feelings can be brought home and which ones need to go to a therapist instead."}, {"n": 2, "name": "Uncomfortable Reception", "desc": "Receives vulnerability with visible discomfort that undermines the sharing. The partner senses the receiver's unease and regrets opening up. The Yielder didn't refuse — but their body said 'I wish you hadn't.'", "ex1": "A partner who shifts in their chair, breaks eye contact, and changes the subject within thirty seconds of the partner sharing something vulnerable — all unconsciously.", "ex2": "Someone whose facial expression during their partner's emotional disclosure broadcasts 'please stop' louder than any words could.", "ex3": "A lover whose partner has started prefacing vulnerable moments with 'I know you don't like this, but...' — which means the receiving has already failed before it begins."}, {"n": 1, "name": "Blocked Reception", "desc": "Cannot receive the partner's vulnerability at all. When the partner opens up, the Yielder freezes, deflects, or shuts down. The partner's surrender hits a closed system and bounces back.", "ex1": "A partner who responds to 'I need to tell you something important' with such visible anxiety that the other person says 'never mind, it's not important' — and both of them know it was.", "ex2": "Someone whose partner has stopped being vulnerable with them entirely and neither person has acknowledged the loss.", "ex3": "A lover who wants to receive their partner's openness and simply cannot — the receptor is jammed, and the partner's most intimate offerings have nowhere to land."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Vulnerability Theft", "desc": "When the partner is vulnerable, the Yielder hijacks the moment — either by one-upping with their own pain or by centering themselves as the affected party. The partner's surrender is never allowed to be about the partner.", "ex1": "A person who responds to 'I'm struggling with my dad's death' with 'you think that's hard? Let me tell you about MY parent' — every disclosure becomes a competition the Yielder must win.", "ex2": "Someone whose partner has learned not to share pain because every attempt ends with the Yielder's pain taking center stage.", "ex3": "A lover who has made themselves the protagonist of every emotional moment in the relationship — even the ones that belong to the partner."}, {"n": 6, "name": "Weaponized Memory", "desc": "Receives vulnerability and files it for future use. Everything the partner shares in a moment of trust can and will be deployed during the next argument. The partner's openness becomes their liability.", "ex1": "A partner who, during a fight about dishes, says 'well, maybe if you weren't still damaged by your mother' — referencing a midnight confession that was shared in trust and stored as ordnance.", "ex2": "Someone whose partner has realized, too late, that every intimate revelation has been catalogued in an emotional weapons locker.", "ex3": "A lover who wins arguments by going nuclear with private information, then says 'I thought we didn't keep secrets' when confronted about the betrayal."}, {"n": 5, "name": "Judgment Disguised as Acceptance", "desc": "Appears to receive vulnerability warmly while internally judging. The partner feels subtly but persistently unsafe without being able to identify why — the reception is technically correct but the judgment leaks through.", "ex1": "A partner who says 'of course, I don't judge you' in a tone that is itself a judgment.", "ex2": "Someone who receives a sexual confession with visible composure and then treats their partner slightly differently afterward — never naming it, never acknowledging it, but the shift is palpable.", "ex3": "A lover who files 'I accept you completely' alongside a growing internal list of things they find secretly shameful about the partner."}, {"n": 4, "name": "Overwhelm Response", "desc": "Partner's vulnerability triggers the Yielder's own unprocessed material, and the Yielder collapses. Instead of holding the partner's pain, they're now drowning in their own, and the partner ends up comforting the person who was supposed to receive them.", "ex1": "A partner who, upon hearing 'I'm worried about us,' starts crying so hard that the original issue gets tabled while the Yielder is soothed.", "ex2": "Someone whose partner has learned to frame concerns in the gentlest possible language because direct honesty triggers a meltdown that the partner must then manage.", "ex3": "A lover whose emotional reactivity has made their partner a permanent emotional diplomat — every truth must be packaged in eight layers of cushioning."}, {"n": 3, "name": "Advice as Deflection", "desc": "Responds to partner's vulnerability by immediately trying to fix it — not out of care but out of an inability to sit with another person's pain. The partner feels managed rather than heard.", "ex1": "A partner who responds to 'I feel lonely' with 'have you tried journaling? Maybe you should call your sister. What about joining a class?' — and the partner thinks 'I don't need a solution, I need you to be here.'", "ex2": "Someone who converts every emotional confession into a problem-solving session because sitting still with pain is intolerable to them.", "ex3": "A lover whose partner has stopped sharing feelings because every vulnerability becomes a project to be managed rather than a moment to be shared."}, {"n": 2, "name": "Dismissal", "desc": "Minimizes or dismisses the partner's vulnerability outright. 'It's not that bad.' 'You're overreacting.' 'Other people have it worse.' The partner learns that their inner world is unwelcome here.", "ex1": "A partner who responds to tears with 'come on, it's not worth crying about' — and the partner hears 'your feelings are not worth my attention.'", "ex2": "Someone who has established an unofficial hierarchy of acceptable emotions: mild frustration is fine, deep pain is excessive, and anything that requires more than five minutes of their attention is 'drama.'", "ex3": "A lover whose partner has developed a public self (shared with the Yielder) that is cheerful and uncomplicated, and a private self (shared with no one) that is increasingly desperate."}, {"n": 1, "name": "Punishment for Openness", "desc": "Makes the partner pay for being vulnerable. Shame, mockery, withdrawal, or rage — the partner's surrender is met with retribution. The Yielder has made vulnerability a punishable offense.", "ex1": "A partner who was told about a sexual insecurity and now references it during arguments: 'Maybe if you could actually perform, I wouldn't be so frustrated.'", "ex2": "Someone whose partner shared their deepest shame and was met with visible disgust — and the shame has now doubled, because the original wound plus the rejection of it now live together.", "ex3": "A lover who has trained their partner through punishment to never open up again — and the partner, sealed shut, is now blamed for being emotionally unavailable."}]}]}, {"name": "The Hunter", "factor": "Factor 2: Pursuit ↔ Surrender", "factor_num": 2, "pole": "Pursuit", "color": "#C75050", "alignment": "Shadow", "tagline": "You are mine. You just don't know it yet.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Apex Predator", "desc": "Has refined the pursuit of others into an art form indistinguishable from nature. Doesn't feel like they're performing — this IS them. The hunt is identity, not strategy. Everyone they've ever wanted, they've gotten. The getting is the only part that's real.", "ex1": "A person whose romantic history reads like a series of successful campaigns — each target chosen, studied, approached, and won with a consistency that borders on unsettling.", "ex2": "Someone who walks into a room and selects — the word is precise — who they'll want tonight, the way a sommelier selects a wine: with expertise, certainty, and no doubt about the outcome.", "ex3": "A lover whose exes all describe the same experience: 'I never stood a chance. By the time I knew I was being pursued, I was already caught.'"}, {"n": 6, "name": "Strategist", "desc": "Calculated pursuit disguised as spontaneity. Every 'accidental' meeting, every 'casual' compliment, every 'spontaneous' gesture has been planned. The target doesn't know they're a target, which is the entire point.", "ex1": "A person who knows their interest's schedule, preferences, and vulnerabilities — all gathered through careful observation — before the first 'chance encounter.'", "ex2": "Someone who studies what their target finds attractive and becomes it, not through conscious deception but through an adaptive instinct that has been rewarded too many times to question.", "ex3": "A lover whose courtship felt like destiny to the other person and like a well-executed plan to the Hunter."}, {"n": 5, "name": "Conquest Collector", "desc": "Driven by the accumulation of victories. Each person won is a trophy, valued for the difficulty of the acquisition rather than the quality of the connection. The challenge IS the attraction; easy targets don't register.", "ex1": "Someone who is exclusively attracted to people in relationships, people who've said no, or people who are 'out of their league' — because the impossible is the only thing that makes them feel alive.", "ex2": "A person whose sexual history is organized mentally by difficulty rating rather than emotional significance.", "ex3": "A lover who loses interest the moment they succeed, because the conquest was the entire point and what comes after is just aftermath."}, {"n": 4, "name": "Charming Predator", "desc": "Deploys charm as a tool rather than an expression. Knows exactly what to say, when to touch, how to escalate — and the knowledge is mechanical rather than emotional. The charm works, which is all that matters.", "ex1": "A person who has a repertoire of moves — stories, touches, phrases — that they deploy with different people with identical results, the way a performer runs the same set in different cities.", "ex2": "Someone whose dates all follow the same arc: fascination, vulnerability, escalation, capture. The dates don't know they're in a template.", "ex3": "A lover who can produce the appearance of deep connection in under two hours and whose interest vanishes at the four-hour mark."}, {"n": 3, "name": "Clumsy Predator", "desc": "The predatory instinct is visible. The mask of charm has holes in it and the target can see the calculation underneath. They still succeed sometimes, but only with people who either can't read the signs or don't care.", "ex1": "A person whose 'casual' interest is obviously anything but — the target can feel themselves being worked, and the transparency is more uncomfortable than the pursuit.", "ex2": "Someone whose friends have started declining to introduce them to new people because the introduction is always followed by the same pattern.", "ex3": "A lover whose pickup lines are strategies that used to work and now feel dated — the technique hasn't evolved with age, and the gap shows."}, {"n": 2, "name": "Bitter Hunter", "desc": "Still pursues, but with resentment. The targets aren't cooperating like they used to. The hunter's skills have degraded or the market has changed, and each rejection adds to a growing narrative of victimhood. 'People don't appreciate effort anymore.'", "ex1": "A person who complains about 'modern dating' the way a fisherman complains about a depleted lake — it's the environment's fault, never the approach.", "ex2": "Someone whose pursuit has become visibly angry — the charm has been replaced by entitlement, and the entitlement is repelling the very people they want.", "ex3": "A lover whose bitterness about past rejections has seeped into current pursuits, making each new attempt carry the accumulated frustration of every previous failure."}, {"n": 1, "name": "Exposed Fraud", "desc": "The predatory nature is fully visible and the skills are fully degraded. Everyone can see what they are. They still try, but the attempts are transparent, sad, and sometimes frightening. The hunter has become the thing people warn each other about.", "ex1": "A person whose reputation precedes them — 'don't be alone with them' — and who has no idea why their approach keeps failing because self-awareness was never part of the toolkit.", "ex2": "Someone who sends unsolicited messages to strangers with a confidence wildly mismatched to their reception, unable to process that the world has stopped responding to their template.", "ex3": "A lover who nobody loves — because love was never the system they were operating in, and the system they were operating in has rejected them."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Reformed Focus", "desc": "At their absolute best, the Hunter's intensity of attention becomes devoted study of one person. The same instinct that once catalogued vulnerabilities now catalogues joys. They're still a predator — but the prey has become the partner's happiness.", "ex1": "A lover who knows their partner better than the partner knows themselves — not from manipulation but from years of the same obsessive attention redirected toward care.", "ex2": "Someone whose partner says 'how did you know I needed that?' and the answer is that they've never stopped watching, only now they watch to give rather than to take.", "ex3": "A partner who brings the Hunter's strategic mind to anniversary planning and produces experiences so perfectly tailored they feel like magic — and in a way, they are."}, {"n": 6, "name": "Protective Attention", "desc": "The Hunter's hyper-awareness becomes vigilance for the partner. They notice threats, discomforts, and opportunities before the partner does. The scanning instinct is still running — it's just been reassigned.", "ex1": "A partner who spots the ex across the restaurant before their spouse does and has already suggested 'let's sit over there instead' — protecting without controlling.", "ex2": "Someone who notices their partner is being undervalued at work before the partner does and gently raises it: 'Have you noticed that your boss takes credit for your ideas?'", "ex3": "A lover who reads a room for their partner the way they used to read a room for targets — and the partner has never felt safer."}, {"n": 5, "name": "Exciting Edge", "desc": "The partner benefits from the Hunter's intensity — they feel like the most important person in the world because the Hunter's full attention is on them. The predatory energy has become erotic rather than threatening.", "ex1": "A lover who makes their partner feel hunted in a way that's thrilling rather than frightening — the game has been negotiated and both players consent to the chase.", "ex2": "Someone whose partner says 'they look at me like they're going to devour me' — and says it blushing, not trembling.", "ex3": "A partner who brings strategic, deliberate sexual energy that makes the recipient feel like the most desired object in the universe — and the word 'object' is welcomed within the context of mutual play."}, {"n": 4, "name": "Controlled Intensity", "desc": "Still calculating, still strategic, but channeling it into relationship maintenance rather than conquest. The partner senses the predatory nature but it's leashed, and the leash holds.", "ex1": "A partner who clearly has the capacity to manipulate but visibly chooses not to — and the partner can see both the capacity and the choice.", "ex2": "Someone who occasionally slips into old patterns — engineering a jealousy spike, testing a boundary — catches themselves, and resets.", "ex3": "A lover whose partner knows they married a wolf that chose to be tame, and finds the knowledge both reassuring and slightly electric."}, {"n": 3, "name": "Relapsing", "desc": "The predatory instincts keep surfacing. Mostly contained, but the partner catches flashes: a too-long look at a stranger, a manipulation attempted and poorly disguised, a lie told for no reason except that lying is the native language.", "ex1": "A partner who catches their spouse in an unnecessary lie about something trivial and realizes the lying isn't about the content — it's about maintaining the ability to lie.", "ex2": "Someone whose partner finds a hidden social media account and the explanation — 'I was just looking' — is technically true but reveals that the hunting instinct is still running in the background.", "ex3": "A lover who flirts at parties and calls it 'being friendly' and both they and their partner know that 'friendly' isn't the operating system."}, {"n": 2, "name": "Contemptuous Possession", "desc": "Has stopped hunting the partner because they've already been caught. The partner has been reclassified from 'target' to 'inventory' — still owned, no longer interesting. The Hunter looks outward while the partner sits in the trophy case.", "ex1": "A lover who treats their partner with the benign disinterest of a collector who has already catalogued this piece — it's on the shelf, it's not going anywhere, it no longer warrants attention.", "ex2": "Someone whose partner can feel themselves being taken for granted not as a person but as an acquisition — the way a hunter treats a mounted head.", "ex3": "A partner who says 'I chose you' and means it the way one means 'I bought this house' — a transaction completed, not a commitment ongoing."}, {"n": 1, "name": "Abandoned Trophy", "desc": "The partner has been fully discarded without being released. Still technically in the relationship, but the Hunter has moved on to new hunting grounds. The cruelest position: owned but unattended.", "ex1": "A partner who is technically married to someone who has emotionally, physically, and attentionally relocated — they live in the same house with a ghost who hunts elsewhere.", "ex2": "Someone whose partner knows about the affairs and has been told, explicitly or implicitly, to tolerate them as the price of staying.", "ex3": "A lover who hasn't looked at their partner with desire in years but would be outraged if the partner sought it elsewhere — the possession instinct outlives the interest."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Total Control", "desc": "The partner's entire life has been reorganized around the Hunter's will. Not through violence — through systematic removal of alternatives. Friends gone, family distanced, finances controlled. The partner is free to leave and has no means to.", "ex1": "A lover who didn't forbid their partner's friendships — they just made each friend uncomfortable enough to leave. The isolation happened so gradually the partner thinks they 'grew apart' from everyone.", "ex2": "Someone whose partner can't explain what's wrong because nothing technically is: they're cared for, provided for, attended to. The cage is so well-designed the bars look like architecture.", "ex3": "A partner who would deny being controlling and pass a lie detector — because from their perspective, they simply arranged things optimally. That the optimal arrangement gives them total power is coincidence."}, {"n": 6, "name": "Psychological Ownership", "desc": "Has colonized the partner's self-concept. The partner sees themselves through the Hunter's eyes, judges themselves by the Hunter's standards, and has forgotten they had a self before this one was installed.", "ex1": "A lover whose partner has changed their appearance, opinions, and friendships to match the Hunter's preferences — and describes each change as 'growth' or 'choice.'", "ex2": "Someone whose partner says 'I'm a better person because of them' — and is correct in the narrowest sense: they are the person the Hunter wanted them to be. Whether that person is better is another question.", "ex3": "A partner who has replaced their partner's internal compass with their own voice, so that even in the Hunter's absence, the partner is guided by 'what would they think?'"}, {"n": 5, "name": "Intermittent Reinforcement", "desc": "Alternates between intense pursuit and cold withdrawal to create addiction. The partner's nervous system becomes organized around the Hunter's unpredictable attention. Cruelty and tenderness mixed in ratios designed to maximize dependency.", "ex1": "A lover who is devastatingly attentive for two weeks and then vanishes emotionally for one — and the partner spends the vanishing week performing whatever behavior preceded the last return of warmth.", "ex2": "Someone whose partner describes the relationship as 'the highest highs and lowest lows' and frames this as passion rather than recognizing it as a conditioning schedule.", "ex3": "A partner whose affection functions as reward and whose withdrawal functions as punishment — and the partner is being trained without knowing they're in a laboratory."}, {"n": 4, "name": "Jealousy as Leash", "desc": "Manufactures jealousy to keep the partner insecure and pursuing. Mentions exes, flirts publicly, maintains 'friendships' with clear romantic undertones — all to ensure the partner never feels secure enough to stop trying.", "ex1": "A lover who leaves their phone face-up with a suggestive text visible — not accidentally — and responds to the partner's distress with 'we're just friends. Don't you trust me?'", "ex2": "Someone who praises other people's attractiveness in front of their partner with calculated specificity: the exact features the partner is insecure about.", "ex3": "A partner who has taught their spouse that the relationship is always conditionally theirs — permanently earned, never owned — and the permanent audition is the point."}, {"n": 3, "name": "Degradation", "desc": "Pursues the partner's diminishment. Wants them smaller, less confident, more dependent. Each act of undermining is disguised as concern: 'are you sure you can handle that job?' 'That outfit doesn't flatter you.' 'Your friends aren't really looking out for you.'", "ex1": "A lover who has such a gentle delivery that each criticism sounds like care, and the partner thanks them for feedback that is actually demolition.", "ex2": "Someone whose partner's self-esteem has declined measurably since the relationship began, and who frames this as 'I helped them see themselves more realistically.'", "ex3": "A partner who clips their spouse's wings one feather at a time, so slowly that the inability to fly feels like a personal failing rather than an inflicted injury."}, {"n": 2, "name": "Open Cruelty", "desc": "Has stopped disguising the predatory nature. The partner is openly treated as property, and resistance is met with escalating punishment — not always physical, but always precise.", "ex1": "A lover who says 'you're nothing without me' and has arranged things so that the statement feels true.", "ex2": "Someone whose partner walks on eggshells permanently, scanning for mood shifts the way prey animals scan for predators — because that's the dynamic now, fully unmasked.", "ex3": "A partner who uses their knowledge of the other person's deepest vulnerabilities as a weapon system, deployed with the accuracy of someone who spent years doing reconnaissance."}, {"n": 1, "name": "Destruction of Prey", "desc": "The partner has been so thoroughly consumed that there's nothing left to hunt. What remains is either a shell or someone planning an escape that feels impossible. The Hunter may discard what's left or continue feeding on an empty vessel.", "ex1": "A lover whose partner has lost contact with every friend, every family member, and every version of themselves that existed before this relationship — and isn't sure they'd recognize that person if they met them.", "ex2": "Someone whose partner's therapist — if they're allowed to have one — recognizes the cluster of symptoms immediately: the hypervigilance, the self-blame, the inability to make decisions without checking.", "ex3": "A partner who has done to a human being what a predator does to an ecosystem: consumed it until it can no longer sustain life, then looked around for the next one."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Disarmed", "desc": "Genuine pursuit from another person short-circuits the Hunter's programming. Someone who wants them without games, without strategy, just honest desire — and the Hunter doesn't know what to do with it because it doesn't fit in the predatory framework. Potentially transformative.", "ex1": "A person who has spent their life hunting and for the first time encounters someone who simply says 'I want you' with no angle — and the lack of game makes the game impossible.", "ex2": "Someone who is pursued with such clean sincerity that their usual counter-moves feel absurd. For the first time, they consider that maybe wanting and being wanted don't have to be warfare.", "ex3": "A lover who allows themselves to be caught and discovers — terrified, fascinated — that being held feels different from holding."}, {"n": 6, "name": "Suspicious Welcome", "desc": "Receives pursuit while scanning for the angle. Wants to trust it, can feel it might be real, but can't stop looking for the strategy underneath because they've never encountered desire without one.", "ex1": "A person who is being genuinely loved and keeps waiting for the trap — checking for hidden motives the way they would in their own behavior.", "ex2": "Someone who receives a sincere love confession and thinks 'good opening move' before catching themselves and thinking 'wait — what if it's not a move?'", "ex3": "A lover who is slowly learning to take genuine affection at face value, but the learning curve is steep because their entire framework assumes everyone is hunting."}, {"n": 5, "name": "Competitive Reception", "desc": "Receives pursuit and immediately tries to regain the upper hand. Being wanted is tolerable only if they can be wanted MORE while wanting less. The power dynamic must stay in their favor.", "ex1": "A person whose response to 'I love you' is to measure whether they love back less — because loving less is winning.", "ex2": "Someone who receives romantic pursuit and immediately strategizes how to be slightly less available, slightly less invested, slightly more in control.", "ex3": "A lover who cannot relax into being wanted because relaxation feels like surrender, and surrender feels like losing."}, {"n": 4, "name": "Tolerant Acceptance", "desc": "Allows themselves to be pursued because it's convenient. The attention is welcome as fuel but not meaningful as connection. The pursuer thinks the Hunter is receiving; the Hunter is just not bothering to dodge.", "ex1": "A person who lets someone take them to dinner, enjoys the meal, enjoys the attention, and files the evening under 'entertainment' rather than 'connection.'", "ex2": "Someone who accepts pursuit the way a cat accepts petting — it's pleasant, it's tolerated, it's not reciprocal, and it can be terminated without notice.", "ex3": "A lover who allows themselves to be loved primarily because it's useful — emotional services received, no emotional services rendered."}, {"n": 3, "name": "Bored Reception", "desc": "Receives pursuit with visible disinterest. Being wanted is so baseline to the Hunter's experience that another person's desire barely registers. The pursuer is competing with every previous pursuer, and the Hunter is already yawning.", "ex1": "A person who has been told 'I love you' so many times by so many people that the words have the impact of a weather report.", "ex2": "Someone who receives an elaborate romantic gesture and responds with 'that's nice' in a tone that makes the pursuer feel like they brought a knife to a gun fight.", "ex3": "A lover whose pursuit tolerance is so high that normal expressions of desire don't clear the threshold of interesting."}, {"n": 2, "name": "Contempt for Pursuers", "desc": "Actively looks down on anyone who wants them. The logic is: I'm a predator; if you're pursuing me, you must be naive, weak, or blind. Being wanted is evidence of the wanter's poor judgment.", "ex1": "A person who describes someone interested in them as 'too easy' and means it as a complete dismissal — the interest itself is disqualifying.", "ex2": "Someone who categorizes their pursuers the way they categorize their prey: by difficulty. And the ones who are easy enough to pursue them are ranked lowest.", "ex3": "A lover who says 'they're obsessed with me' with a tone that converts someone else's love into evidence of their pathology."}, {"n": 1, "name": "Incapable of Being Reached", "desc": "Cannot be pursued because there's nothing to reach. The Hunter's identity is so entirely organized around hunting that being the object of desire doesn't compute. They can take; they cannot receive. The circuit doesn't run in that direction.", "ex1": "A person who has been loved by many and has never once felt it land — not because the love wasn't real, but because their receptor sites don't exist.", "ex2": "Someone who watches people fall for them the way a lens focuses light: the process happens, the image forms, but the lens doesn't experience the picture.", "ex3": "A lover who has consumed every partner they've ever had and has never once been nourished — because consumption and reception are different systems, and they only have one."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Trap Setter", "desc": "Manufactures the appearance of vulnerability to lure pursuers in. What looks like receiving is actually a different kind of hunt — they become the bait. The pursuer thinks they're chasing; they're being drawn.", "ex1": "A person who performs emotional openness so convincingly that their target feels like they're breaking through walls — never knowing the 'walls' are part of the set design.", "ex2": "Someone who has learned that the most effective hunting position is apparent vulnerability: a predator playing prey.", "ex3": "A lover who lets themselves be 'caught' in exactly the way that gives them maximum control over what happens next."}, {"n": 6, "name": "Information Harvester", "desc": "Receives pursuit as intelligence gathering. Every emotional confession from the pursuer is data: what they value, what they fear, where they're vulnerable. The receiving looks like intimacy; it functions as reconnaissance.", "ex1": "Someone who asks deep questions on dates — 'what's your biggest fear?' 'what hurt you most?' — with the warmth of genuine curiosity and the intent of a spy.", "ex2": "A person who listens so attentively that the other person feels profoundly seen, not knowing that being seen, in this case, means being mapped.", "ex3": "A lover who knows everything about their partner's inner life and has shared nothing real about their own — the exchange rate has always been information for the appearance of intimacy."}, {"n": 5, "name": "Humiliation Collection", "desc": "Receives pursuit and stores it as ammunition. The more vulnerably someone pursues them, the more power the Hunter accumulates. Each love letter is a future weapon; each confession is a held card.", "ex1": "A person who keeps screenshots of every desperate text they've received — not for nostalgia, but as a portfolio of power.", "ex2": "Someone who encourages emotional openness specifically because open people are easier to hurt, and the capacity to hurt is the only form of security they trust.", "ex3": "A lover who has files — mental or literal — on every person who's ever wanted them, organized by vulnerability rather than affection."}, {"n": 4, "name": "String Along", "desc": "Receives just enough pursuit to keep the pursuer hooked without ever allowing real connection. The Hunter maintains multiple lines in the water, giving each one just enough attention to prevent departure.", "ex1": "A person who responds to 'where is this going?' with just enough ambiguity to sustain hope — 'I'm not sure yet, but I really value what we have' — knowing they'll never be sure.", "ex2": "Someone who keeps three people interested simultaneously, giving each one the impression they're close to being chosen while ensuring no one ever is.", "ex3": "A lover who has perfected the art of the 90% relationship: intimate enough to create attachment, 10% short of commitment, permanent."}, {"n": 3, "name": "Mockery", "desc": "Receives pursuit and finds it amusing. The pursuer's sincerity is entertainment — shared with friends, laughed about privately, enjoyed as a spectacle of someone else's vulnerability.", "ex1": "A person who reads their suitor's love letter aloud at a party for laughs and doesn't understand why a friend later calls it cruel.", "ex2": "Someone who strings along a pursuer specifically to have stories: 'You won't believe what they did this time.'", "ex3": "A lover who treats other people's desire as content — entertaining in the moment, disposable afterward, never meaningful."}, {"n": 2, "name": "Destruction of the Pursuer", "desc": "Deliberately breaks the people who want them. Allows full emotional investment, then withdraws with precision timing to cause maximum damage. The destruction is the point.", "ex1": "A person who lets someone fall completely in love, waits for the moment of maximum vulnerability, and then delivers the news — 'I never felt anything' — with the timing of a detonation expert.", "ex2": "Someone who has a pattern of drawing in deeply earnest, emotionally available people and returning them to the world significantly less trusting than they arrived.", "ex3": "A lover who collects broken hearts the way others collect memories — each one proof of a hunt successfully completed."}, {"n": 1, "name": "Void", "desc": "Receives nothing because receiving requires a self, and the Hunter has replaced their self with a mechanism. Pursuit arrives and meets machinery. The pursuer is not being rejected — they're being processed.", "ex1": "A person who has been pursued by dozens and loved by some and has never once been changed by any of it — because the receptor is a sorting machine, not a heart.", "ex2": "Someone whose response to 'I would do anything for you' is to calculate what 'anything' is worth and whether it's enough.", "ex3": "A lover who cannot be reached by love because love is not a category their system recognizes — only power, acquisition, and the temporary relief of the hunt."}]}]}, {"name": "The Doormat", "factor": "Factor 2: Pursuit ↔ Surrender", "factor_num": 2, "pole": "Surrender", "color": "#8B6EC7", "alignment": "Shadow", "tagline": "Whatever you want. Just don't leave.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Vanishing Act", "desc": "Has erased themselves so completely in service of others' desires that there's genuinely no self left to find. Not suppressed — dissolved. They became what was needed so many times that the original person decomposed. If you asked them what they want, the question would produce genuine confusion.", "ex1": "A person whose friends describe them completely differently because each friend got a custom version — and none of the versions is the real one, because the real one was sacrificed decades ago.", "ex2": "Someone who has been so many people's perfect partner that they've never been their own person, and the absence is so total they don't experience it as loss.", "ex3": "A lover who says 'I just want you to be happy' and means it absolutely — because they have no other want to compete with it. Their want-generator has been removed."}, {"n": 6, "name": "Chameleon", "desc": "Shapeshifts to match whatever the partner wants. Likes what they like, wants what they want, becomes whatever the situation requires. The adaptation is so skilled it's nearly invisible — even to the Doormat.", "ex1": "A person who was vegan with their last partner, a meat-lover with this one, and can't remember what they actually eat when alone — because alone is a condition they've avoided for exactly this reason.", "ex2": "Someone whose interests, opinions, and personality shift measurably depending on who they're with — and who would be genuinely offended by the observation, because from inside, each adaptation feels authentic.", "ex3": "A lover whose partner falls in love with a version of them that doesn't exist — and the Doormat will maintain that version until the relationship ends, at which point they'll dissolve and reform for the next person."}, {"n": 5, "name": "Pre-emptive Compliance", "desc": "Anticipates what others want and provides it before being asked. The giving isn't generous — it's defensive. Each act of service is a deposit in the 'don't leave me' account.", "ex1": "A partner who has dinner ready, the house clean, and a bright smile on — all before their spouse walks through the door — not from love but from a calculation so old it feels like love.", "ex2": "Someone who monitors their partner's mood the way a sailor monitors weather: not out of curiosity but out of survival instinct.", "ex3": "A lover whose thoughtfulness is indistinguishable from hypervigilance — the radar is always running, scanning for what to provide next."}, {"n": 4, "name": "Conflict Avoidant", "desc": "Will yield on any point to avoid confrontation. Has never won an argument because they've never stayed in one. Their surrender isn't principled — it's reflexive. Peace at any price, and the price is always their own needs.", "ex1": "A partner who says 'you're right, I'm sorry' at the first sign of tension — not because they agree, but because disagreement feels like the first step toward abandonment.", "ex2": "Someone who goes along with vacation plans they hate, restaurant choices they dislike, and bedroom activities they're not comfortable with — all without a word, because a word might create friction.", "ex3": "A lover whose partner doesn't know their real preferences about anything because the Doormat has never expressed one. 'Whatever you want' is the answer to every question."}, {"n": 3, "name": "Visible Resentment", "desc": "Still yields, but the suppressed anger is starting to show. Sighs, martyred silences, passive-aggressive comments. They won't say what they want, but they'll punish you for not guessing.", "ex1": "A partner who says 'it's fine' in a voice that could strip paint, and then when asked 'what's wrong?' says 'nothing' with enough force to rattle windows.", "ex2": "Someone who volunteers to do everything and then resents being asked — the pattern of over-giving followed by bitter accounting has become the relationship's heartbeat.", "ex3": "A lover who cooks dinner every night with the grim determination of someone performing an unfair penance, and the partner has started eating out to avoid the atmosphere."}, {"n": 2, "name": "Collapse", "desc": "The Doormat's strategy is failing. The endless yielding hasn't produced security — it's produced contempt (from the partner) and exhaustion (from the Doormat). They're still performing compliance but the machinery is breaking down.", "ex1": "A person who agrees to everything, does everything, accommodates everything — and is quietly falling apart. The doctor visits have increased. The sleep has decreased. The smile has become a rictus.", "ex2": "Someone who realizes they've given away everything they had and the response has been 'more' — and they have no more, but they're still trying to produce it.", "ex3": "A lover who is physically present and spiritually depleted — the performance of selflessness has consumed the self."}, {"n": 1, "name": "Erasure", "desc": "Gone. Not dead, not absent — just empty. The person who once existed underneath all the compliance has been replaced by a function: respond to needs, avoid conflict, survive. There's no self to surrender anymore because surrender was all the self ever was.", "ex1": "A person whose therapist asks 'what do you want?' and the question produces tears — not because the answer is painful but because the question is incomprehensible. They don't have a want-center. It atrophied.", "ex2": "Someone who, after the relationship ends, sits in an empty apartment and realizes they don't know what to do, what to eat, what to watch, or who they are — because they were always defined by someone else's preferences.", "ex3": "A lover who was never actually there — only an echo of other people's desires in a shape that looked like a person."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Devoted Service", "desc": "At their very best, the Doormat's attentiveness becomes genuine care. Their radar for the partner's needs, though born from anxiety, can produce acts of service so precise and thoughtful that the partner feels deeply known.", "ex1": "A partner who remembers every detail — the exact coffee order, the specific brand of aspirin, the friend's name that was mentioned once — and deploys this knowledge as care rather than strategy.", "ex2": "Someone whose hyper-attunement to their partner's mood allows them to provide exactly the right thing at exactly the right time — comfort before it's asked for, space before it's requested.", "ex3": "A lover whose partner says 'I've never felt so taken care of' — and it's true, though the engine driving the care is fear rather than love."}, {"n": 6, "name": "Skilled Accommodation", "desc": "Anticipates and smooths the partner's path with expertise. The accommodation is so well-executed it looks like the relationship is simply effortless — because one person is doing all the work behind the curtain.", "ex1": "A partner who has silently removed every source of friction from their spouse's life: schedule managed, in-laws handled, household seamless. The spouse floats through an existence the Doormat constructed.", "ex2": "Someone whose partner has no idea how much work goes into making things 'easy' because the Doormat has made invisibility into an art form.", "ex3": "A lover who turns their anxiety into infrastructure — building a life so comfortable the partner never suspects the foundation is fear."}, {"n": 5, "name": "Generous to a Fault", "desc": "Gives more than is healthy, more than is asked, more than is reciprocated — but the giving is genuine. The partner benefits from abundance that comes from the Doormat's inability to stop giving, not from their generosity.", "ex1": "A partner who buys gifts the other person didn't ask for, cooks meals nobody requested, and volunteers for tasks that weren't offered — and the generosity is real even if its source is compulsion.", "ex2": "Someone whose partner occasionally says 'you don't have to do all this' and the Doormat hears 'I've noticed your effort' and responds by doing more.", "ex3": "A lover whose partner is genuinely well-cared-for by someone whose self-care is nonexistent — the giving flows in one direction and both parties have normalized the current."}, {"n": 4, "name": "Agreeable Companion", "desc": "Pleasant, accommodating, easy to be around. The partner never has to worry about conflict or difficulty. The relationship is smooth the way a river is smooth when it has no rocks — which is peaceful and also suspiciously depthless.", "ex1": "A partner who agrees with everything and adds nothing — pleasant company that produces a growing sense that the other person is talking to themselves in a room that happens to contain another body.", "ex2": "Someone whose agreeableness has started to feel uncanny — the partner wishes, once, for a genuine disagreement just to confirm someone's actually home.", "ex3": "A lover whose partner has started asking 'but what do YOU think?' with increasing urgency, and the answer is always a version of 'whatever you think.'"}, {"n": 3, "name": "Invisible Partner", "desc": "So focused on the partner's needs that they've become functionally invisible in the relationship. They maintain, they serve, they support — and the partner has stopped seeing them as a person with desires and started seeing them as a feature of the household.", "ex1": "A partner who realizes they haven't asked 'how are you?' in months — not because they're cruel, but because the Doormat has made their own experience so irrelevant that asking stopped occurring to anyone.", "ex2": "Someone whose contributions to the relationship are noticed only in their absence — the way you notice plumbing only when it fails.", "ex3": "A lover who has been so thoroughly helpful that they've become invisible, and their invisibility has become the relationship's invisible tragedy."}, {"n": 2, "name": "Enabling", "desc": "Accommodates the partner's worst behaviors because saying 'no' might create conflict. The partner's drinking, spending, cruelty, or neglect goes unchallenged because the Doormat's priority is peace, not health.", "ex1": "A partner who pours another drink for someone who shouldn't be drinking because the alternative is a fight that feels worse than the hangover.", "ex2": "Someone who laughs off their partner's public humiliation of them because addressing it would 'cause a scene.'", "ex3": "A lover whose commitment to avoiding conflict has made them an accomplice to their own mistreatment."}, {"n": 1, "name": "Complete Self-Sacrifice", "desc": "Has given everything — health, relationships, career, identity — to the partner's comfort and remains available to give more. There is nothing left to give and they're still looking for something to offer.", "ex1": "A partner who quit their job because their spouse didn't like them working, lost their friends because their spouse didn't like them socializing, and changed their body because their spouse didn't like how they looked — and describes each sacrifice as 'something I wanted to do.'", "ex2": "Someone who is physically ill from stress, visibly depleted, and still asking 'what else can I do for you?' from a hospital bed.", "ex3": "A lover whose partner could ask for a kidney and receive it, and the only hesitation would be about which one the partner preferred."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Suffocating Selflessness", "desc": "Their total self-sacrifice creates a prison for the partner. The partner cannot express a need without it being instantly fulfilled, cannot have a bad day without it becoming about the Doormat's failure to prevent it. The partner's freedom to struggle has been removed.", "ex1": "A partner whose helpfulness has become so total that the other person feels they're living with a servant who monitors their emotions — and any negative feeling is treated as an emergency the Doormat failed to prevent.", "ex2": "Someone whose partner wants to scream 'STOP HELPING' but knows the scream will be met with devastated tears and redoubled effort.", "ex3": "A lover whose selflessness has become its own form of control — the partner cannot fail, cannot fall, cannot grow, because the Doormat has padded every surface and removed every challenge."}, {"n": 6, "name": "Guilt Machine", "desc": "Their visible suffering and self-sacrifice generate constant guilt in the partner. Every unreciprocated act of service is a silent accusation. The Doormat never asks for anything and the asking-for-nothing is the loudest sound in the room.", "ex1": "A partner who sighs while doing chores they volunteered for, making sure the other person can hear the weight of their sacrifice from the next room.", "ex2": "Someone who says 'don't worry about me, I'll be fine' in a voice that has never once communicated 'fine.'", "ex3": "A lover whose martyrdom has become the relationship's wallpaper — so pervasive that the partner feels guilty for eating, sleeping, and existing while someone else is visibly suffering on their behalf."}, {"n": 5, "name": "Passive-Aggressive Service", "desc": "Gives with one hand and punishes with the other. Every act of accommodation comes with an invisible invoice that the partner didn't ask for and can't pay. The Doormat serves and resents in equal measure.", "ex1": "A partner who makes dinner and then eats in wounded silence because the partner didn't thank them enthusiastically enough — though they never asked for thanks and would deny wanting it.", "ex2": "Someone who says 'I'll do it myself' with enough acid to dissolve trust, performing self-reliance as a punishment for the partner's failure to anticipate their unspoken needs.", "ex3": "A lover whose service has become a weapon — each thoughtful act creating a debt the partner didn't incur and can't repay."}, {"n": 4, "name": "Emotional Blackmail by Fragility", "desc": "Uses their own visible fragility to control the partner's behavior. The partner learns that honest feedback, constructive criticism, or simple disagreement will trigger a collapse that they'll have to manage. The Doormat's fragility becomes a veto.", "ex1": "A partner who responds to 'could you please not leave your clothes on the floor' with such devastated tears that the other person resolves to never mention it again — and the clothes remain on the floor forever.", "ex2": "Someone whose emotional reactivity to even mild criticism has made the partner a permanent self-censor.", "ex3": "A lover whose tears are genuine but whose timing is impeccable — always arriving at the exact moment that would redirect attention from the partner's valid concern to the Doormat's pain."}, {"n": 3, "name": "Resentment Leak", "desc": "The suppressed anger from years of over-giving has started to seep out. Small cruelties, pointed comments, mysteriously forgotten promises. The Doormat can't express anger directly, so it finds indirect channels.", "ex1": "A partner who 'accidentally' ruins the shirt their spouse wanted to wear to the event with the coworker the Doormat is quietly jealous of.", "ex2": "Someone who 'forgets' to pass along an important message and then says 'oh no, I'm so sorry' with eyes that aren't sorry at all.", "ex3": "A lover whose passive aggression has become so sophisticated it's nearly impossible to confront — each act is individually explainable and collectively devastating."}, {"n": 2, "name": "Weaponized Helplessness", "desc": "Has become so helpless that the partner cannot leave without being the villain. The Doormat's inability to function independently has become a trap — not intentionally, but the effect is identical to intentional manipulation.", "ex1": "A partner who 'can't' do anything alone — can't drive, can't handle finances, can't make phone calls — and the inability isn't laziness but genuine learned helplessness that now functions as a chain.", "ex2": "Someone whose dependency has become so complete that the partner's friends say 'you can't leave, they'd fall apart' — and the partner knows it's true and feels the walls closing in.", "ex3": "A lover who has outsourced their entire capacity for independent life to the partner, making departure an act of cruelty rather than a personal choice."}, {"n": 1, "name": "Destruction by Devotion", "desc": "Their total self-sacrifice has consumed both people. The partner is drowning in guilt, the Doormat is drowning in resentment masked as love, and neither can find the exit because the Doormat has welded all the doors shut with their own suffering.", "ex1": "A relationship where both partners are miserable and neither can leave — the partner because departure would be monstrous, the Doormat because departure is unthinkable. They've created a shared prison with no guards and no exits.", "ex2": "Someone whose partner attempted to leave and was met with a collapse so complete — hospitalization, self-harm threats, total breakdown — that the partner returned and has never tried again.", "ex3": "A lover who has converted their entire existence into a reason the partner can't go, and the partner has started fantasizing about their own disappearance as the only exit from a cage built entirely of someone else's love."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Stunned by Kindness", "desc": "Receiving genuine care produces a system shock. Someone giving to THEM, without being asked, without an agenda — the experience is so foreign it briefly short-circuits the Doormat's programming. Potentially the beginning of change.", "ex1": "A person who is brought breakfast in bed by their partner and cries — not from happiness but from the sheer confusion of being served when their entire identity is organized around serving.", "ex2": "Someone who, when their partner says 'sit down, I've got this,' literally doesn't know what to do with their hands. The idleness of being cared for produces physical discomfort.", "ex3": "A lover who receives a gift and immediately tries to calculate how to repay it at twice the value — because receiving without reciprocating feels like owing, and owing feels like the first step toward being left."}, {"n": 6, "name": "Grateful but Anxious", "desc": "Receives care with intense gratitude that's tinged with terror. Every good thing received is evidence that the bill is coming. They're thankful and waiting for the other shoe.", "ex1": "A partner who says 'you didn't have to do this' about everything — and means it as both gratitude and boundary: please stop being kind, the kindness makes me nervous.", "ex2": "Someone who receives love the way a stray animal receives food: hungry for it, grateful for it, poised to bolt the moment it becomes a trap.", "ex3": "A lover who monitors their partner's generosity for signs of manipulation, because in their experience, nobody gives without eventually taking."}, {"n": 5, "name": "Deflecting Reception", "desc": "Receives care and immediately tries to return it tenfold. Can't sit in the receiving position — has to bounce back to giving as quickly as possible because giving is safe and receiving is dangerous.", "ex1": "A partner who responds to 'let me cook tonight' by cleaning the entire house while the other person cooks — unable to simply sit and be served without producing compensatory labor.", "ex2": "Someone who is told 'just relax, I'll handle it' and physically cannot relax because not-helping feels like a character flaw.", "ex3": "A lover who converts every act of care into a debt and repays it before the meal is finished."}, {"n": 4, "name": "Suspicious Acceptance", "desc": "Accepts care while waiting for the conditions to be named. What do you want in return? What am I agreeing to by accepting this? The partner's generosity is processed as the opening move of a negotiation.", "ex1": "A person who accepts a compliment and then spends the rest of the evening figuring out what the partner wants — because compliments without agendas don't exist in their experience.", "ex2": "Someone who says 'thank you' with the wariness of a person signing a contract they haven't read.", "ex3": "A lover who receives kindness the way a negotiator receives an opening offer — politely, cautiously, and with full awareness that something will be expected in return."}, {"n": 3, "name": "Guilty Reception", "desc": "Receives care and immediately feels they don't deserve it. The partner's kindness produces shame rather than warmth. Being served by someone who's supposed to be served BY you feels like a violation of natural law.", "ex1": "A partner who apologizes for being sick because illness means the other person has to take care of them, and being taken care of feels like theft.", "ex2": "Someone who receives 'I love you' and immediately thinks of five reasons they haven't earned it today.", "ex3": "A lover who sabotages gifts and gestures — 'you shouldn't have, it's too much, take it back' — because the discomfort of receiving outweighs the pleasure."}, {"n": 2, "name": "Rejects Care", "desc": "Actively pushes away kindness. Can't receive. Won't receive. The partner's care bounces off a surface hardened by years of believing they only have value when they're giving.", "ex1": "A person who insists on doing everything themselves while visibly struggling — and responds to offers of help with 'I'm fine' so forcefully that the partner stops offering.", "ex2": "Someone who gets angry when cared for — genuinely angry — because being a recipient triggers a shame so deep it converts to rage.", "ex3": "A lover whose partner has learned that giving to this person is itself a form of conflict, and has retreated to letting the Doormat serve, which is what the Doormat wanted and also what is slowly killing them."}, {"n": 1, "name": "Impervious to Care", "desc": "Cannot receive care at all. The circuitry runs one direction only: outward. Love offered to them enters a void. They are a one-way valve: everything goes out, nothing comes in.", "ex1": "A partner who has been given love by a good person for years and has never absorbed a molecule of it — still operating from the same desperate emptiness they started with.", "ex2": "Someone whose partner says 'I feel like I'm loving into a black hole' and the Doormat hears this as evidence of their own failure to give enough.", "ex3": "A lover who will die having been genuinely loved and having never let it reach them."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Parasitic Need", "desc": "Their inability to receive normal love has created an insatiable hunger. The partner gives and gives and the Doormat absorbs and absorbs and neither of them gets nourished. The Doormat needs constant reassurance that functions as emotional consumption without end.", "ex1": "A person who asks 'do you love me?' fourteen times a day and whose anxiety resets to baseline within an hour of each affirmation — the reassurance never sticks.", "ex2": "Someone whose need for proof of love has expanded to consume every waking moment of the partner's attention, and the partner has begun to feel like a battery being drained by a device that never charges.", "ex3": "A lover who is simultaneously impossible to fill and impossible to leave — because leaving someone this needy requires a cruelty the partner can't access."}, {"n": 6, "name": "Consuming Gratitude", "desc": "Their gratitude is so intense and performative that it becomes its own burden. Every kindness received is met with such overwhelming thankfulness that the partner starts avoiding generosity to dodge the deluge.", "ex1": "A partner who receives a cup of coffee and responds with tears of gratitude so extreme that the gesture feels like it triggered something clinical rather than something relational.", "ex2": "Someone whose thankfulness comes with invisible hooks: 'You did this for me, which proves you love me, which means you'll never leave, right? RIGHT?'", "ex3": "A lover whose reception of care is so fraught with anxiety and excess that the partner has started doing less, not out of laziness but out of emotional self-defense."}, {"n": 5, "name": "Accusatory Reception", "desc": "Receives care and immediately identifies everything wrong with it. Not because they're ungrateful — because nothing can match the fantasy version of being loved that they need. The partner's real care is always measured against an imaginary standard it can't meet.", "ex1": "A partner who receives a thoughtful anniversary surprise and focuses on the one detail that was wrong: 'It's nice, but you know I don't like that restaurant.' The nine things that were right are invisible.", "ex2": "Someone who has made being hard to please into an unconscious strategy for maintaining their victim identity — if the partner's care is never enough, the Doormat always has evidence of being unloved.", "ex3": "A lover whose partner has entered a no-win loop: do nothing and be guilty of neglect, do something and be guilty of doing it wrong."}, {"n": 4, "name": "Martyrdom", "desc": "Receives care and uses it as evidence that they need to give more. 'You shouldn't have to do this for me. I should be doing it for you.' The care offered by the partner becomes another source of shame, which becomes another source of over-giving.", "ex1": "A partner who is brought soup while sick and immediately tries to get up and cook dinner because being cared for while not producing care feels like freeloading.", "ex2": "Someone who apologizes for receiving love: 'I'm sorry you have to deal with me' — and the apology is so frequent it's become the relationship's background radiation.", "ex3": "A lover who converts every kindness received into motivation to be more self-sacrificing — the cycle of giving tightens with each external act of care."}, {"n": 3, "name": "Testing Sincerity", "desc": "Receives care and immediately tests whether it's real. Pushes back, creates problems, generates crises — all to see if the partner's care survives the obstacle course. No amount of passing these tests produces lasting trust.", "ex1": "A person who responds to 'I love you' by starting a fight to see if the love survives conflict — and then, when it does, starting a bigger fight next time.", "ex2": "Someone who has an unconscious escalation ladder of tests: did you survive this? Good. Now try THIS. Each test more extreme than the last, with the finish line perpetually receding.", "ex3": "A lover whose partner has passed every test and still isn't trusted — because the testing isn't about information gathering, it's about the temporary relief of being reassured, which fades immediately."}, {"n": 2, "name": "Resentment for Needing", "desc": "Resents the partner for providing care they desperately need, because needing it feels like weakness. The Doormat hates their own need and transfers that hatred to the person who meets it.", "ex1": "A person who is furious at their partner for being kind — because kindness highlights the deficit, and the deficit is humiliating.", "ex2": "Someone who snaps at the hand that feeds them, literally and figuratively, because the feeding is evidence of their own failure to be self-sufficient.", "ex3": "A lover who punishes the partner for being good to them — not because the goodness is unwelcome, but because it illuminates exactly how empty they feel inside."}, {"n": 1, "name": "Complete Refusal to Exist", "desc": "Has so thoroughly denied their own needs that they've ceased to exist as a recipient. The partner cannot give to them because they have decided they are not a person who receives. The self-erasure is so complete that love aimed at them passes through like light through a window — visible but unabsorbed.", "ex1": "A person who has been told 'I love you' a thousand times and has never once let the words arrive. Each one was intercepted, deflected, or translated into something safer on the way in.", "ex2": "Someone who, when held by their partner, is physically there but emotionally unreachable — not because they won't receive love but because they've removed the receiver.", "ex3": "A lover who is the ultimate tragedy of the Doormat archetype: they spent their whole life giving love they couldn't feel to others, and could never accept the love being given back to them."}]}]}, {"name": "The Weaver", "factor": "Factor 3: Fusion ↔ Autonomy", "factor_num": 3, "pole": "Fusion", "color": "#C77050", "alignment": "Healthy", "tagline": "We are stronger intertwined.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Tapestry", "desc": "Has achieved a state of intertwining so complete and so healthy that both people are more than they were alone without being less than they are individually. The fusion doesn't erase — it amplifies. Two whole people choosing to be one fabric.", "ex1": "A couple who have been together so long they finish each other's thoughts — not because one dominates, but because their minds have genuinely learned to dance together.", "ex2": "Someone whose partnership has produced a shared creative life — a business, a home, a project — that neither could have built alone and that expresses both of them fully.", "ex3": "A lover whose identity includes their partner the way a river includes its banks — defined by the relationship without being diminished by it."}, {"n": 6, "name": "Deep Braid", "desc": "Lives, schedules, dreams, and identities are interwoven with skill and intention. They've built a shared world that enhances both people. The weaving is deliberate — they chose which threads to merge and which to keep separate.", "ex1": "A couple who share finances, friendships, and a home with clear communication about where the shared life ends and individual life begins.", "ex2": "Someone who has built a partnership where the pronoun 'we' is used joyfully and accurately — not as erasure of 'I' but as the addition of something larger.", "ex3": "A lover whose partner is genuinely their best friend, their collaborator, and their home — and who maintains enough selfhood that 'best friend' doesn't mean 'only friend.'"}, {"n": 5, "name": "Comfortable Merger", "desc": "Happily intertwined with a partner in ways that feel natural and nourishing. Occasionally loses track of where their preferences end and the partner's begin, but it's more endearing than alarming.", "ex1": "A partner who genuinely can't remember whose idea it was to paint the bedroom blue — because the decision-making process has become so collaborative that authorship dissolves.", "ex2": "Someone who describes their weekends as 'we usually...' and 'we like to...' and hasn't said 'I' in a personal context in some time — but would if pressed.", "ex3": "A lover whose individual hobbies have slowly merged with shared hobbies, not through pressure but through genuine preference for doing things together."}, {"n": 4, "name": "Settled Weave", "desc": "The intertwining has become so familiar it's automatic. They share space, routines, and rhythms without thinking about it. Comfortable, functional, occasionally so merged that individual wants get buried without anyone noticing.", "ex1": "A couple whose daily routine is so synchronized they move around the kitchen like two parts of the same machine — efficient, practiced, slightly robotic.", "ex2": "Someone who realizes they haven't done anything alone in months — not because they're not allowed to, but because 'alone' stopped occurring to them as an option.", "ex3": "A lover whose shared life has become the default to such a degree that individual preferences have gone underground — still there, but unused."}, {"n": 3, "name": "Tangled", "desc": "The weaving has become knotted. They want closeness but the closeness has started to feel like constraint. Can't quite tell which feelings are theirs and which are absorbed from the partner. The fusion is no longer entirely voluntary.", "ex1": "A partner who realizes they've adopted all of their spouse's political opinions without examining any of them — and the realization is unsettling because they're not sure where the adoption started.", "ex2": "Someone who feels vaguely anxious when their partner is away — not missing them exactly, but unable to locate themselves without the reference point.", "ex3": "A lover who tries to plan a solo evening and discovers they don't know what they'd do with it — every leisure activity has become a shared activity."}, {"n": 2, "name": "Lost Thread", "desc": "Has merged so deeply that retrieval of the individual self would require conscious, difficult work. They exist primarily as half of a unit and the half-ness has become the identity. The question 'who are you without them?' produces anxiety rather than answers.", "ex1": "A person who, when their partner travels for work, wanders the house unable to settle — not from loneliness but from a genuine inability to function as a standalone unit.", "ex2": "Someone whose friends have stopped inviting them individually because every invitation is answered with 'let me check with [partner]' — the checking isn't about permission, it's about identity.", "ex3": "A lover who has become so fused that the prospect of the relationship ending feels not like heartbreak but like amputation."}, {"n": 1, "name": "Dissolved", "desc": "There is no individual self left. The fusion is total. They don't have opinions, preferences, or desires that aren't filtered through the partnership. If the relationship ended, they wouldn't grieve — they'd evaporate.", "ex1": "A person who is asked 'what's your favorite movie?' and automatically answers with their partner's favorite, unable to access their own preference because it hasn't been exercised in years.", "ex2": "Someone who realizes, in a moment of clarity, that they couldn't write a personal bio that didn't reference their partner — not because they choose to, but because there's nothing else to write about.", "ex3": "A lover whose therapist asks 'tell me about yourself' and they begin every sentence with 'well, we...' and cannot be redirected to 'I.'"}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Living Bridge", "desc": "Creates connection so organic that the partner doesn't experience it as losing autonomy but as gaining capacity. The Weaver includes the partner in everything — decisions, experiences, inner life — in a way that feels like being invited rather than absorbed.", "ex1": "A partner who says 'I want to share this with you' about everything — a sunset, a worry, a sandwich — and the sharing never feels like demand because it's always framed as offering.", "ex2": "Someone who has woven the partner into their life so thoroughly that the partner's absence creates a phantom-limb sensation — not dependency, but the mark of genuine integration.", "ex3": "A lover who makes their partner feel like a co-author of their life rather than a character in it."}, {"n": 6, "name": "Inclusive Builder", "desc": "Actively builds shared structures — traditions, projects, spaces — that belong to both people equally. The partner always has a seat at the table because the Weaver built the table with two seats.", "ex1": "A partner who suggests shared hobbies, joint goals, and collaborative projects with genuine enthusiasm — and always checks that the partner is genuinely interested rather than just accommodating.", "ex2": "Someone who creates family rituals that reflect both partners' values, cultures, and preferences — the shared life is a genuine blend, not one person's life with another person added.", "ex3": "A lover who asks 'what should WE do?' as a real question, not a formality — their version of planning always starts with two perspectives."}, {"n": 5, "name": "Warm Inclusion", "desc": "Consistently draws the partner into their world — sometimes a little too eagerly. The inclusion is genuine but occasionally leaves the partner wishing for slightly more breathing room.", "ex1": "A partner who wants to share every experience and sometimes doesn't notice that the other person wanted to watch that show alone, read that book alone, take that walk alone.", "ex2": "Someone whose 'let's do it together!' is always warm and never demanding — but the sheer frequency of the suggestion starts to feel like there's no acceptable answer except 'yes.'", "ex3": "A lover whose enthusiasm for togetherness is their love language, and they speak it fluently and constantly."}, {"n": 4, "name": "Routine Inclusion", "desc": "Has built shared routines that include the partner by default. The togetherness is comfortable but increasingly automatic — the partner is included because that's how the system runs, not because it's freshly chosen each time.", "ex1": "A couple whose evenings follow the same script: dinner, show, bed. The togetherness is assumed rather than invited, and both have stopped noticing the difference.", "ex2": "Someone who adds the partner to every plan by reflex — not checking whether solo time might be preferred because the question doesn't occur.", "ex3": "A lover whose inclusion has become background: reliable, warm, and no longer containing the element of choice that once made it meaningful."}, {"n": 3, "name": "Clingy Weaving", "desc": "The inclusion has become need rather than choice. The Weaver pulls the partner toward them not from joy but from anxiety — being apart triggers something that feels like abandonment even when it's just Tuesday.", "ex1": "A partner who texts 'when will you be home?' three times during the other person's evening out — not controlling, but the frequency reveals the anxiety underneath.", "ex2": "Someone who feels personally wounded when the partner wants to eat lunch with a coworker instead of calling them, and knows the feeling is irrational but can't dismiss it.", "ex3": "A lover who has started to experience the partner's independent activities as rejections — each solo run, each friend-dinner, each quiet evening alone registers as a tiny abandonment."}, {"n": 2, "name": "Demanding Merger", "desc": "Insists on inclusion in ways that have stopped feeling like love. The partner's separate interests, friendships, and time are treated as threats to the weave rather than healthy components of a full life.", "ex1": "A partner who pouts when not invited to a girls' night, sulks when the other person reads instead of watching TV together, and frames every independent choice as 'choosing that over me.'", "ex2": "Someone whose need for fusion has become indistinguishable from monitoring — they don't control the partner's movements, but they need to know about and be included in every single one.", "ex3": "A lover who has made 'time without me' into a category that requires justification — and the partner has started lying about wanting to be alone."}, {"n": 1, "name": "Consuming Merger", "desc": "Has attempted to absorb the partner completely. Their identity, their relationships, their time — everything must be shared, and 'shared' has become 'owned.' The partner has no private life because the Weaver has eliminated the concept.", "ex1": "A partner who reads the other person's journal, monitors their conversations, and requires an accounting of every hour spent apart — all framed as 'we don't keep secrets from each other.'", "ex2": "Someone whose partner has no remaining friendships that don't include the Weaver, no activities the Weaver doesn't participate in, and no thoughts the Weaver hasn't been told about.", "ex3": "A lover who has turned 'togetherness' into a totalitarian state — two people in one life, but only one person's needs determining how that life is lived."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Identity Absorption", "desc": "Has woven the partner into themselves so completely that the partner can no longer extract their own threads. The Weaver doesn't just share a life with the partner — they've incorporated the partner into their identity. Leaving would require the partner to tear themselves out of another person's selfhood.", "ex1": "A lover who has become so intertwined with the partner that mutual friends cannot imagine them apart — and this inseparability, which looks like love from the outside, functions as a lock from the inside.", "ex2": "Someone who has made their partner's departure functionally impossible by building a shared life so integrated that separation would require dismantling everything: finances, friendships, housing, family, identity.", "ex3": "A partner who says 'you complete me' and means it literally — they have reserved a partner-shaped space in their identity that, if vacated, would collapse the structure."}, {"n": 6, "name": "Guilt Weaving", "desc": "Uses the shared life as leverage. 'After everything we've built together...' Every shared asset, tradition, and memory becomes a chain. The Weaver didn't build these things as traps — but they deploy them as traps when the partner reaches for autonomy.", "ex1": "A partner who responds to 'I need some space' with 'what about the house? The dog? Our friends? Our plans?' — converting the partner's desire for air into a betrayal of shared investment.", "ex2": "Someone who has made the shared life so elaborate and interdependent that the partner's any move toward independence requires demolishing something they both value.", "ex3": "A lover who unconsciously builds more shared infrastructure every time they sense the partner pulling away — another joint account, another pet, another tradition — adding weight to a web the partner already can't escape."}, {"n": 5, "name": "Emotional Surveillance", "desc": "The Weaver's desire for fusion has become a need to know everything. Not controlling in the traditional sense — more like a desperate, anxious transparency demand. The partner must share every thought, every feeling, every interaction, or the Weaver spirals.", "ex1": "A partner who asks 'what are you thinking?' every fifteen minutes and is visibly distressed when the answer is 'nothing' — because nothing means a part of the partner that isn't shared, and unshared parts are threats.", "ex2": "Someone who reads their partner's expression the way a seismologist reads instruments — constantly monitoring for emotional activity they haven't been informed about.", "ex3": "A lover who has made 'I just want to know you completely' into a demand that erases the partner's right to an inner life."}, {"n": 4, "name": "Boundary Erosion", "desc": "Systematically dissolves the partner's boundaries while framing it as intimacy. 'We don't need secrets.' 'Why would you need time alone if we're happy?' Each boundary the partner holds is treated as evidence of insufficient love.", "ex1": "A partner who 'jokingly' opens the bathroom door, reads texts over the shoulder, and inserts themselves into conversations — always with a smile, always with 'what? We share everything!'", "ex2": "Someone who has reframed every healthy boundary as a wall, and every wall as evidence that the partner doesn't really love them.", "ex3": "A lover who treats the partner's closed door — literal or metaphorical — as a personal rejection and an urgent problem to solve."}, {"n": 3, "name": "Jealous Weaving", "desc": "Views the partner's other relationships as competing threads. Friends, family, even children can become objects of jealousy — not because the Weaver is cruel, but because every attachment the partner has that doesn't include them feels like a tear in the fabric.", "ex1": "A partner who subtly undermines the other person's closest friendship by scheduling conflicts, expressing vague concerns about the friend's character, or simply being cold when the friend visits.", "ex2": "Someone who is measurably more affectionate after the partner spends time with family — not as welcome-home warmth but as reclamation.", "ex3": "A lover who has quietly ensured that the partner's social world has contracted until it fits inside the Weaver's preferred perimeter."}, {"n": 2, "name": "Punishing Separation", "desc": "Makes the partner pay for any act of independence. The punishment is emotional rather than overt: coldness, withdrawal, visible hurt, the silent treatment. The partner learns that autonomy comes at a cost that makes it not worth the price.", "ex1": "A partner who is warm and loving when the other person is present and visibly devastated when they leave — training the partner to associate departure with inflicting pain.", "ex2": "Someone whose reaction to 'I'm going to visit my sister for the weekend' is a silence so heavy it follows the partner out the door and makes the trip miserable.", "ex3": "A lover who has weaponized their own suffering: the partner can do anything they want, but they'll be punished with the Weaver's pain."}, {"n": 1, "name": "Total Engulfment", "desc": "The partner has been fully absorbed. There is no independent partner left — only the Weaver's extension. The 'relationship' is one person wearing another person's life like a suit. What looks like closeness is actually consumption.", "ex1": "A lover whose partner cannot name a single preference, opinion, or desire that isn't a reflection of the Weaver's — not because they were forced, but because the Weaver's need for fusion was so total that it replaced the partner's operating system.", "ex2": "Someone whose partner's family says 'we don't recognize them anymore' — and the unrecognizable person agrees with the Weaver that the family was 'toxic.'", "ex3": "A partner who has achieved the perfect fusion by eliminating the other person's self entirely — and calls the result 'soulmates.'"}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Joyful Integration", "desc": "Receives a partner's desire for closeness with genuine delight. Being woven into another person's life feels like coming home. They integrate without losing themselves — their own threads remain distinct even as they merge with the partner's.", "ex1": "A person who responds to 'move in with me' with full-body joy — and then has a thoughtful conversation about which spaces will be shared and which will remain individual.", "ex2": "Someone who loves being included in their partner's world and naturally includes the partner in theirs, creating a bilateral weave rather than absorption in one direction.", "ex3": "A lover who makes shared decisions feel collaborative rather than surrendering — when they merge with the partner's plans, they bring themselves fully rather than disappearing."}, {"n": 6, "name": "Warm Acceptance", "desc": "Welcomes the partner's bids for connection and closeness with consistent warmth. Responds to 'let's do this together' with genuine enthusiasm. Creates a positive feedback loop where the partner feels safe offering closeness.", "ex1": "A partner who always says yes to shared activities with real presence — not just body-in-room attendance but genuine engagement.", "ex2": "Someone whose partner feels fully welcomed into their life rather than tolerated — every shared space, ritual, and routine was entered together.", "ex3": "A lover who treats the partner's desire for closeness as a gift rather than an imposition."}, {"n": 5, "name": "Easy Accommodation", "desc": "Naturally makes room for the partner in their life. Adjusts schedules, shares spaces, and merges routines without resentment. Sometimes too accommodating — gives up their own preferences without being asked.", "ex1": "A partner who rearranged their entire living room without being asked because they knew the other person's furniture was coming, and did it cheerfully.", "ex2": "Someone who shifted their sleep schedule, eating habits, and weekend rhythms to match the partner's — all without discussion, all without complaint.", "ex3": "A lover who is so easy to merge with that the partner occasionally worries whether they're actually integrating or just capitulating."}, {"n": 4, "name": "Comfortable Merging", "desc": "Accepts shared life as the natural state. Doesn't resist closeness or seek it — just settles into whatever level of merger the partner proposes. Adaptable and easygoing, if not particularly intentional about the weaving.", "ex1": "A partner who goes along with every shared plan and every merged routine without pushback or enthusiasm — present, agreeable, mildly passive.", "ex2": "Someone whose partner could probably absorb them entirely without resistance, not because they lack selfhood but because resisting takes more energy than they want to spend.", "ex3": "A lover who is comfortable in closeness the way a cat is comfortable on a warm lap — pleasant, settled, not likely to initiate but unlikely to leave."}, {"n": 3, "name": "Ambivalent Reception", "desc": "Accepts closeness in some domains and resists it in others. Happy to share a home but protective of their morning routine. Glad to merge finances but private about their phone. The reception has clear zones.", "ex1": "A partner who cheerfully shares their entire social life with their spouse but has one drawer, one hobby, or one friendship that remains exclusively theirs — and gets tense when the boundary is tested.", "ex2": "Someone who says 'we can share everything except my studio/workshop/gym time' — and the exception reveals where their identity is most vulnerably housed.", "ex3": "A lover whose reception of closeness has a clearly mapped topography: warm valleys of togetherness with sharp ridgelines of 'this is mine.'"}, {"n": 2, "name": "Reluctant Merging", "desc": "Accepts shared life because the relationship demands it, not because it comes naturally. Each merged space, routine, or decision feels like a small loss. They do it, but the doing costs them.", "ex1": "A partner who agreed to the joint bank account and checks the balance with the anxious frequency of someone who hasn't quite let go of the money being 'theirs.'", "ex2": "Someone who lives with their partner but maintains a mental floor plan of which spaces are 'really mine' — and bristles when those invisible lines are crossed.", "ex3": "A lover who participates in shared life with the energy of someone performing a civic duty: correctly, willingly, without joy."}, {"n": 1, "name": "Fusion Resistant", "desc": "Cannot merge. Every bid for closeness is experienced as invasion. The partner's desire for shared life hits a wall that looks like independence but is actually fear of being subsumed.", "ex1": "A person who has lived with their partner for five years and still refers to furniture as 'mine' and 'yours' — the mental separation is absolute despite the physical proximity.", "ex2": "Someone who recoils at 'we' — corrects it to 'I' and 'you' with a precision that reveals the correction is about survival, not grammar.", "ex3": "A lover whose partner has stopped suggesting shared activities because every suggestion is met with the polite, firm resistance of a country declining a treaty."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Engulfment Terror", "desc": "The partner's desire for closeness triggers existential panic. Every move toward merger feels like being swallowed. They love the partner but experience the partner's love as a digestive process — warm, enveloping, and ultimately annihilating.", "ex1": "A person who breaks out in hives when the partner suggests combining their book collections — not because of the books, but because of what the books represent: one more piece of their separate self being absorbed.", "ex2": "Someone who picks a catastrophic fight the week the partner moves in — not because they don't want the partner there, but because the closeness has tripped a survival alarm they can't override.", "ex3": "A lover who has ended relationships at the precise moment they became 'serious' — defined as the point where the other person's life began to merge with theirs."}, {"n": 6, "name": "Counter-Merging", "desc": "Responds to the partner's closeness bids by actively creating distance. Every 'let's do this together' is countered with a solo plan. The distancing isn't about preference — it's about maintaining a perimeter against emotional annexation.", "ex1": "A partner who, upon hearing 'I'd love to come to your gym,' immediately switches gyms — the last remaining solo space was threatened and the response is territorial.", "ex2": "Someone who responds to increased closeness with increased withdrawal, creating an inverse relationship: the more the partner reaches, the further they pull.", "ex3": "A lover who has turned their relationship into an approach-avoidance loop so consistent that the partner has started calling it 'the dance' — reach, retreat, reach, retreat."}, {"n": 5, "name": "Contempt for Closeness", "desc": "Views the partner's desire for merger as weakness, neediness, or evidence of an insufficiently developed self. The partner's longing for closeness is privately judged as pathological.", "ex1": "A person who describes their partner's desire for quality time as 'codependent' and recommends therapy for what is actually a normal human need for connection.", "ex2": "Someone who frames their own avoidance as 'healthy boundaries' and the partner's desire for closeness as 'enmeshment' — weaponizing therapeutic language to pathologize love.", "ex3": "A lover who has made their partner feel ashamed for wanting to spend time together — the partner now apologizes before suggesting a shared activity."}, {"n": 4, "name": "Scorecard Resistance", "desc": "Keeps a mental tally of closeness concessions and uses them as evidence of their own generosity: 'I already moved in with you. I already share meals. How much more do you need?' Each merger is a sacrifice counted, never a joy experienced.", "ex1": "A partner who agreed to merge friend groups and references this decision during arguments as if it were a kidney donation.", "ex2": "Someone who treats every shared experience as a withdrawal from a finite account of tolerance — and lets the partner know the balance is getting low.", "ex3": "A lover whose partner has learned to stop asking for closeness because each request is met with a reminder of all the closeness already grudgingly provided."}, {"n": 3, "name": "Secret Separateness", "desc": "Maintains a hidden life. The partner thinks they're merged; the Weaver has a second world the partner doesn't know about — hidden accounts, undisclosed friendships, secret spaces. Not affairs necessarily — just proof that a separate self still exists.", "ex1": "A person who rents a workspace their partner doesn't know about, just to have somewhere that is theirs and only theirs — the secret is the point, not the space.", "ex2": "Someone who has a phone the partner doesn't know about, not for infidelity but for privacy — the act of having something unshared is the oxygen they breathe.", "ex3": "A lover who performs full merger while maintaining an escape route the partner can't see — the shared life is real, and so is the hidden exit."}, {"n": 2, "name": "Hostile Independence", "desc": "Uses autonomy as a weapon. Asserts separateness not from healthy need but from a desire to wound. 'I don't need you' delivered specifically at moments when the partner is most vulnerable.", "ex1": "A partner who schedules solo trips on their spouse's birthday — not from oversight but from a need to demonstrate that the relationship doesn't own their calendar.", "ex2": "Someone who makes major life decisions without consulting the partner and presents them as fait accompli: 'I took the job. We're moving.' The unilateral decision is the message.", "ex3": "A lover who weaponizes independence the way others weaponize closeness — using their freedom to remind the partner that they could leave at any time."}, {"n": 1, "name": "Complete Rejection of Merger", "desc": "Has made the partner's desire for closeness into the enemy. Every bid for connection is treated as an attack on selfhood. The relationship continues but the Weaver has built a wall inside it that the partner can feel but cannot see, and the wall is growing thicker.", "ex1": "A person who shares a bed with someone and has never shared a feeling with them — the physical proximity masks a psychological distance so vast it would take years to cross.", "ex2": "Someone whose partner realizes they're lonelier inside this relationship than they were when single — because single loneliness has hope and this loneliness has walls.", "ex3": "A lover who has made a partner feel that wanting closeness is a character flaw, ensuring the partner will carry this belief into every future relationship."}]}]}, {"name": "The Sovereign", "factor": "Factor 3: Fusion ↔ Autonomy", "factor_num": 3, "pole": "Autonomy", "color": "#5080C7", "alignment": "Healthy", "tagline": "I am whole. I choose to share my wholeness with you.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Complete", "desc": "So thoroughly themselves that their presence has a gravitational quality. They don't need the relationship to be whole — they ARE whole — and the relationship benefits from two complete people meeting rather than two halves looking for completion.", "ex1": "A person who was deeply fulfilled before the relationship and brings that fulfillment into it rather than looking for it there.", "ex2": "Someone whose partner fell in love with a person, not a need — and the difference is visible in how the relationship breathes, how both people have room.", "ex3": "A lover who can say 'I want you' and 'I don't need you' in the same sentence without contradiction — because the wanting is choice, not deficit."}, {"n": 6, "name": "Rooted", "desc": "Has a strong individual identity — career, friendships, interests, inner life — that exists independently of the relationship. The partner adds to their life without being the center of it.", "ex1": "A partner who maintains their own friendships, travels solo occasionally, and pursues interests their spouse doesn't share — and the relationship is better for it.", "ex2": "Someone whose partner says 'I love that you have your own thing' and means it because the Sovereign's independence makes them more interesting, not less available.", "ex3": "A lover who brings stories, perspectives, and energy back to the relationship from their independent life — the autonomy is a river that feeds the shared lake."}, {"n": 5, "name": "Healthy Boundaries", "desc": "Maintains clear, kind boundaries between self and partnership. Can say 'I need time alone' without guilt and 'I want to be with you' without dependency. The toggling between self-time and couple-time is smooth.", "ex1": "A partner who takes one evening a week for themselves — no guilt, no negotiation — and returns to the relationship refreshed.", "ex2": "Someone who has both joint and individual bank accounts, both shared and private friendships, and considers this arrangement not as distance but as architecture.", "ex3": "A lover whose partner always knows where they stand because the Sovereign communicates their needs directly rather than signaling through withdrawal."}, {"n": 4, "name": "Comfortable Independence", "desc": "Naturally self-sufficient within the relationship. Doesn't make a point of their independence — just lives it. Sometimes the partner wishes they needed them a little more, but the autonomy is healthy, not hostile.", "ex1": "A partner who handles their own problems first and involves the other person second — capable and self-reliant, if occasionally hard to reach.", "ex2": "Someone whose partner sometimes feels slightly peripheral to a life that was perfectly functional before they arrived — welcomed but not structurally necessary.", "ex3": "A lover who is easy to be with partly because they don't require much — and the low maintenance is sometimes mistaken for low investment."}, {"n": 3, "name": "Guarded Autonomy", "desc": "Maintains independence a little too carefully. The boundaries are clear but slightly rigid. There's a watchfulness around the edges — a monitoring of how much they're merging and a correction whenever the merger exceeds comfort levels.", "ex1": "A partner who unconsciously pulls back after a very intimate weekend — not because it was bad but because the closeness triggered a recalibration alarm.", "ex2": "Someone who keeps a mental tally of how much time they've spent together and engineers solo time to restore balance — the system works but the engineering is visible.", "ex3": "A lover whose partner can feel the boundary-checking happening in real time and has started to find it slightly exhausting."}, {"n": 2, "name": "Isolated Sovereignty", "desc": "The independence has hardened into isolation. They're whole, yes — but the wholeness has become a fortress. There's no door for the partner to enter. Self-sufficiency has crossed from health into barricade.", "ex1": "A person who has such a complete life that the relationship feels like an optional add-on — and the partner has begun to sense their dispensability.", "ex2": "Someone whose independence is so thorough that the partner wonders what they contribute, and the wondering is starting to curdle into resentment.", "ex3": "A lover who doesn't need their partner in any discernible way — and the partner has started to question whether being needed is really such a terrible thing."}, {"n": 1, "name": "Walled Off", "desc": "Has mistaken emotional unavailability for sovereignty. 'I'm complete' has become a justification for never letting anyone in. The independence isn't health — it's a fortification built over old wounds and defended with philosophical language.", "ex1": "A person who can articulate beautifully why they don't need anyone and has never examined whether 'don't need' is a choice or a scar.", "ex2": "Someone who quotes Rilke about two solitudes protecting each other and uses it as a license to never be vulnerable.", "ex3": "A lover who is sovereign the way an island is sovereign: technically independent, actually just surrounded by water that nobody can cross."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Liberating Love", "desc": "Their independence actively frees the partner. By not needing the partner to complete them, they release the partner from the burden of being someone's everything. The partner is chosen daily, never owned. The result is a relationship that breathes.", "ex1": "A lover who says 'go — take the trip, take the job, take the risk — I'll be here when you get back, and I'll be fine either way' and the partner feels the simultaneous safety and freedom in every word.", "ex2": "Someone whose partner describes the relationship as 'the most room I've ever had to be myself' — because the Sovereign's wholeness creates space rather than filling it.", "ex3": "A partner whose independence is so genuine that the other person never feels guilty for their own independence — the freedom is mutual, and the returning is always a choice."}, {"n": 6, "name": "Encouraging Space", "desc": "Actively supports the partner's independent life. Celebrates their separate friendships, hobbies, and growth. Understands that the partner's wholeness makes the relationship stronger.", "ex1": "A partner who buys their spouse a solo weekend retreat and means it as a gift, not a test — 'you've been wanting time to paint. Go paint.'", "ex2": "Someone who introduces the partner to experiences outside the relationship — new people, new interests — without jealousy or possessiveness.", "ex3": "A lover who has made the partner's growth into one of their values: they want the partner to become more, even if 'more' occasionally means 'more independent.'"}, {"n": 5, "name": "Respectful Distance", "desc": "Maintains appropriate space within the relationship. Doesn't crowd, doesn't hover, doesn't require constant contact. The partner always has room — sometimes a little too much room.", "ex1": "A partner who texts 'have a good day' in the morning and then doesn't text again until evening — and the partner sometimes wishes for a midday check-in that never comes.", "ex2": "Someone whose respect for the partner's space is genuine but occasionally reads as indifference to someone who needs more connection.", "ex3": "A lover who gives the partner room the way a good architect gives a room light — intentionally, generously, and occasionally leaving the partner wanting slightly more warmth."}, {"n": 4, "name": "Parallel Living", "desc": "Two people in the same space living somewhat independent lives. The Sovereign maintains their routines, the partner maintains theirs, and they intersect pleasantly but not deeply. Comfortable, functional, occasionally lonely.", "ex1": "A couple who eat dinner together most nights but might as well be eating at separate tables — the proximity is constant but the connection is intermittent.", "ex2": "Someone who is a wonderful weekend partner and an absentee weekday partner — their independent life runs Monday to Friday and the relationship gets Saturday.", "ex3": "A lover whose partner says 'we live together but I miss you' — and the Sovereign is genuinely confused because they're right there."}, {"n": 3, "name": "Neglectful Independence", "desc": "So absorbed in their own life that the partner gets scraps. Not malicious — just genuinely more interested in their own world than in maintaining the shared one. The partner feels like an afterthought.", "ex1": "A partner whose work, hobbies, and friendships consume so much bandwidth that the relationship gets whatever's left — and what's left is often just tired.", "ex2": "Someone who cancels date night for a work deadline without apology because in their priority stack, the relationship is third or fourth.", "ex3": "A lover whose partner has started building their own independent life not from health but from necessity — because the Sovereign isn't available often enough for shared life to be viable."}, {"n": 2, "name": "Emotional Withholding", "desc": "Uses independence to avoid vulnerability. The partner can see that the Sovereign has feelings but chooses not to share them — and frames the withholding as 'not burdening' the partner rather than admitting it's self-protection.", "ex1": "A partner who went through a health scare without telling their spouse until it was resolved: 'I didn't want to worry you' — but the partner hears 'I don't trust you with my fear.'", "ex2": "Someone whose independence extends to their inner life — they process alone, decide alone, and inform the partner after the fact.", "ex3": "A lover who has made their autonomy into a wall by calling it a boundary — and the partner can feel the difference."}, {"n": 1, "name": "Absent Sovereignty", "desc": "So independent that the partner functionally doesn't have a partner. The Sovereign is technically in the relationship but practically living a solo life. The partner has been given infinite space — and the space has become abandonment.", "ex1": "A partner who is home so rarely, shares so little, and engages so minimally that the other person has started referring to them as their 'roommate' when talking to friends.", "ex2": "Someone whose partner has grieved the relationship while still in it — the Sovereign didn't leave, they just never arrived.", "ex3": "A lover whose perfect independence has become its own form of cruelty: the partner was promised a partnership and received a proximity."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Weaponized Wholeness", "desc": "Uses their independence as proof of the partner's deficiency. 'I'm complete without you' deployed not as fact but as threat. The Sovereign's self-sufficiency becomes a club used to beat the partner's natural needs into submission.", "ex1": "A lover who says 'I could leave anytime and be perfectly fine' during arguments — and the statement is true, and the truth is wielded like a blade.", "ex2": "Someone whose independence is performed specifically to remind the partner of the power imbalance: I don't need this, you do. I stay because I choose to, and I could choose otherwise.", "ex3": "A partner who has made their own wholeness into the relationship's central threat — departure is always on the table, always effortless, always mentioned."}, {"n": 6, "name": "Contempt for Need", "desc": "Views the partner's desire for closeness as pathology. The Sovereign has elevated independence to a moral position, and anyone who needs more connection is failing at the spiritual task of self-completeness.", "ex1": "A partner who recommends therapy for their spouse's 'attachment issues' — when the spouse's only issue is wanting to spend more time together.", "ex2": "Someone who has weaponized self-help language to pathologize normal relationship needs: 'Your desire to be closer sounds codependent. You should work on that.'", "ex3": "A lover who has made the partner ashamed of wanting, needing, and reaching — because the Sovereign has defined these as weaknesses rather than human drives."}, {"n": 5, "name": "Strategic Withdrawal", "desc": "Uses absence as a control mechanism. The Sovereign withholds presence to punish or manipulate, knowing the partner values togetherness more than they do. Their independence is a resource they can deploy or withhold for maximum effect.", "ex1": "A partner who disappears after arguments — not to cool down, but to demonstrate their capacity for absence and the partner's inability to tolerate it.", "ex2": "Someone who takes solo trips immediately after the partner asks for more closeness — making the timing so pointed that it functions as a response without requiring words.", "ex3": "A lover who has learned that their most powerful weapon is their ability to leave the room, and deploys it with the precision of someone who has studied its effects."}, {"n": 4, "name": "Unilateral Decision-Making", "desc": "Makes major life decisions without consulting the partner, then presents them as fait accompli. The autonomy has metastasized from healthy independence into disregard for the partner as a co-pilot.", "ex1": "A partner who accepts a job in another city without discussion: 'I made the best decision for my career. You can come or not.' The 'or not' is said casually, as if it doesn't contain the possible end of the relationship.", "ex2": "Someone who buys a car, adopts a pet, or changes the vacation plans unilaterally and is genuinely confused when the partner is upset: 'It's my life too.'", "ex3": "A lover who has forgotten — or never learned — that being in a partnership means some decisions belong to two people."}, {"n": 3, "name": "Cold Sufficiency", "desc": "Their independence has become punitive. The partner reaches for closeness and finds a person who is warm to the world but cold to them — because the world doesn't require vulnerability and the partner does.", "ex1": "A partner who is the life of every party and a stone at home — the social warmth is freely given and the intimate warmth is withheld.", "ex2": "Someone whose friends describe them as 'the most generous person' while their partner describes them as 'emotionally unreachable' — and both descriptions are accurate.", "ex3": "A lover who has reserves of warmth they distribute everywhere except toward the person who needs it most."}, {"n": 2, "name": "Performative Indifference", "desc": "Performs not-caring as a power move. May actually care deeply but has decided that showing it would be weakness. The partner sees the mask and can't reach what's behind it.", "ex1": "A partner who receives devastating news about the relationship — a threat to leave, a confession of unhappiness — and responds with a shrug that took every ounce of willpower to produce.", "ex2": "Someone who would be destroyed by the partner's departure but would rather die than show it — and the partner, reading the indifference as real, actually leaves.", "ex3": "A lover whose performance of not-caring was so convincing it became a self-fulfilling prophecy."}, {"n": 1, "name": "Relational Nihilism", "desc": "Has concluded that needing anyone is a failure state, and acts accordingly. The partner is tolerated, the relationship is endured, and the Sovereign's inner life is a sealed room with no visitors. Love has been classified as a vulnerability and eliminated.", "ex1": "A person who has read enough philosophy to justify their emotional unavailability as enlightenment and enough self-help to frame isolation as growth.", "ex2": "Someone whose partner asks 'do you even want to be in this relationship?' and the honest answer — 'I don't want to be in any relationship' — is one they'll never give because it would require the vulnerability they've abolished.", "ex3": "A lover who has achieved perfect independence by eliminating the capacity for connection — and calls the achievement freedom."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Honored Integration", "desc": "Receives the partner's respect for their autonomy as the deepest form of love. When the partner gives space without withdrawing, supports independence without abandoning — the Sovereign recognizes this as the rarest and most sophisticated form of intimacy.", "ex1": "A person whose partner says 'I don't need you to need me' and the Sovereign hears the one sentence they've waited their whole life to hear.", "ex2": "Someone who, for the first time, doesn't have to fight for space within a relationship — the partner offered it freely, and the absence of the fight makes room for something else: trust.", "ex3": "A lover who realizes that this partner's respect for their autonomy is actually making them want to be closer — the freedom produces the very attachment they always feared."}, {"n": 6, "name": "Relaxed Reception", "desc": "Receives partnership support without feeling encroached upon. Can accept help, care, and closeness without the alarm bells of enmeshment firing. The partner's offerings land as gifts rather than invasions.", "ex1": "A partner who accepts 'let me handle dinner tonight' without needing to reciprocate immediately — settling into being cared for with uncharacteristic ease.", "ex2": "Someone who lets the partner into their solo routine — morning coffee together instead of alone — and notices that the routine improved rather than degraded.", "ex3": "A lover who is learning that accepting care doesn't diminish sovereignty — a lesson that rewrites years of defensive independence."}, {"n": 5, "name": "Measured Welcome", "desc": "Receives the partner's closeness in controlled doses. Appreciative and warm within limits, firm when the limits are reached. The reception is genuine but rationed.", "ex1": "A partner who enjoys togetherness for three hours and then needs to retreat — and the transition is handled with kindness rather than explanation.", "ex2": "Someone who receives their partner's attention like sunlight through a window: welcome, warming, but controlled by a shade they can lower when needed.", "ex3": "A lover whose reception has a volume knob the partner has learned to read — and both of them navigate it with reasonable grace."}, {"n": 4, "name": "Tolerant Reception", "desc": "Permits closeness without seeking it. The partner's offerings are accepted but not encouraged. The Sovereign is pleasant when together and undisturbed when apart — a neutrality the partner may find either peaceful or unsatisfying.", "ex1": "A partner who responds to 'I missed you' with 'that's nice' — not dismissive, but not reciprocating at the same register.", "ex2": "Someone whose reception of closeness is always warm-neutral: never cold enough to wound, never warm enough to nourish.", "ex3": "A lover whose partner describes the experience as 'loving someone who's always slightly out of reach — not running away, just never quite where I am.'"}, {"n": 3, "name": "Resistant Reception", "desc": "Receives closeness with visible tension. The partner's bids for togetherness produce a subtle stiffening — not rejection, but the unmistakable body language of someone tolerating rather than welcoming.", "ex1": "A partner who allows the hug but doesn't lean in. Accepts the invitation but doesn't suggest the next one. Receives the 'I love you' but pauses a beat too long before responding.", "ex2": "Someone whose partner has learned to read the micro-signals of welcome and resistance and times their bids accordingly — a life of emotional weather-watching.", "ex3": "A lover whose reception is technically adequate and emotionally inadequate — the partner feels neither rejected nor welcomed, just... permitted."}, {"n": 2, "name": "Grudging Acceptance", "desc": "Accepts closeness as a relationship tax. The partner's need for togetherness is something to be endured rather than enjoyed. The Sovereign participates in shared life with the energy of someone fulfilling a contractual obligation.", "ex1": "A partner who attends couples' events with an invisible countdown running — 'two more hours until I can be alone again' — and the partner can feel the clock ticking.", "ex2": "Someone who says 'yes' to quality time the way one says 'yes' to jury duty: obligatory, finite, and to be completed with minimum involvement.", "ex3": "A lover whose partner has stopped asking for closeness because the asking produces grudging compliance rather than willing presence."}, {"n": 1, "name": "Closed System", "desc": "Cannot receive the partner at all. The wholeness has become a sealed sphere. Love offered hits the surface and slides off. The Sovereign is complete — and completeness, it turns out, can be its own form of emptiness.", "ex1": "A person whose partner says 'there's no room for me in your life' and the Sovereign hears the words but can't identify what 'room' would look like or where it would go.", "ex2": "Someone who has achieved such perfect self-sufficiency that the partner has become functionally irrelevant — still loved in theory, unnecessary in practice.", "ex3": "A lover whose partner leaves, and the Sovereign's life continues with so few disruptions that they begin to wonder if the relationship was ever real — and the wondering is the first feeling they've allowed in years."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Fortress Mentality", "desc": "Experiences every bid for closeness as a siege. The partner's love is an army at the gates. The Sovereign's wholeness must be defended at all costs, and the cost is the relationship itself.", "ex1": "A person who responds to 'I want to be closer to you' with the defensive posture of someone being asked to surrender territory — because that's exactly how it feels inside.", "ex2": "Someone who has turned their own self-sufficiency into a military installation: armed, watchful, and ready to repel any emotional approach that crosses the perimeter.", "ex3": "A lover who would rather lose the partner than lose their independence — and frames the loss as proof that independence was the right priority all along."}, {"n": 6, "name": "Punishment for Reaching", "desc": "Makes the partner pay for wanting closeness. Each bid is met with withdrawal, coldness, or condescension — training the partner to stop reaching. The Sovereign's autonomy is maintained by systematically extinguishing the partner's desire for connection.", "ex1": "A partner whose every attempt at closeness is followed by the Sovereign becoming noticeably cooler — teaching, through repetition, that closeness triggers distance.", "ex2": "Someone who responds to 'I need more quality time' by scheduling more solo activities — the message couldn't be clearer if it were written in neon.", "ex3": "A lover who has made reaching for them so consistently unrewarding that the partner has developed an aversion to their own desire for closeness."}, {"n": 5, "name": "Superior Detachment", "desc": "Looks down on the partner for needing what they can't give. The Sovereign's inability to receive closeness is reframed as evolution; the partner's need for it is reframed as regression.", "ex1": "A person who pities their partner for wanting emotional intimacy — genuinely, condescendingly pities them — the way one might pity a child who still believes in fairy tales.", "ex2": "Someone who has constructed a hierarchy in which emotional independence sits at the top and emotional need sits at the bottom, and has assigned positions accordingly.", "ex3": "A lover who treats the partner's heart-needs as developmental delays rather than human fundamentals."}, {"n": 4, "name": "Gaslighting Autonomy", "desc": "Denies the partner's reality when challenged about emotional unavailability. 'I'm not distant — you're clingy.' 'I'm not withholding — you're demanding.' The Sovereign's shadow reframes every valid concern as the partner's dysfunction.", "ex1": "A partner who has been told they're 'too needy' so many times they've started apologizing for wanting a hug.", "ex2": "Someone who uses 'healthy boundaries' as a magic phrase that makes any amount of emotional withholding sound like wisdom.", "ex3": "A lover who has convinced the partner that wanting closeness is a mental health issue — and the partner has started to believe it."}, {"n": 3, "name": "Emotional Hoarding", "desc": "Keeps all emotional resources for themselves. The Sovereign has rich feelings, real needs, genuine inner life — all hidden, all reserved, all hoarded. The partner receives the empty version while the Sovereign lives richly alone inside.", "ex1": "A person who journals beautifully, cries during movies alone, and has deep conversations with friends — then comes home and offers the partner monosyllables.", "ex2": "Someone whose inner life is lavish and whose relational life is impoverished — the disparity is a choice, and the partner is the one paying for it.", "ex3": "A lover who is emotionally generous with everyone except the person who most deserves it — and the selectivity is the wound."}, {"n": 2, "name": "Abandonment as Autonomy", "desc": "Leaves — emotionally, physically, or both — and frames the departure as a sovereignty exercise. The partner's pain is collateral damage to the Sovereign's self-actualization journey.", "ex1": "A person who moves out to 'find themselves' and is genuinely surprised that the partner experiences this as abandonment rather than growth.", "ex2": "Someone who ends a relationship via text while traveling and describes it to friends as 'choosing myself' — the language of self-care deployed as a weapon.", "ex3": "A lover who has made 'my journey' the justification for every relational destruction they've caused."}, {"n": 1, "name": "Total Relational Death", "desc": "Has killed the relationship while remaining in it. The Sovereign is present, independent, whole, and utterly alone — and they've dragged the partner into the same lonely completeness by refusing every connection offered. Two whole people in one house, perfectly self-sufficient, completely dead inside.", "ex1": "A couple who function like excellent roommates: efficient, polite, and entirely disconnected. The Sovereign achieved independence. The partner achieved resignation.", "ex2": "Someone whose wholeness was supposed to make relationships better and instead made relationship impossible — the self-sufficiency that was going to be shared was never shared.", "ex3": "A lover who won the war for independence and lost the only person who wanted to share the peace."}]}]}, {"name": "The Vine", "factor": "Factor 3: Fusion ↔ Autonomy", "factor_num": 3, "pole": "Fusion", "color": "#C77050", "alignment": "Shadow", "tagline": "I cannot survive without something to hold onto.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Strangler Fig", "desc": "Has achieved total parasitic attachment. The Vine has grown so completely around the host that removing it would kill both. Their identity, purpose, daily structure, and emotional regulation are entirely dependent on the partner's existence. Not a person who loves — a person who has replaced their skeleton with someone else.", "ex1": "Someone whose partner went on a three-day business trip and the Vine didn't eat, didn't sleep properly, and called twelve times a day — not from choice but from a genuine inability to maintain biological rhythm without the partner's presence.", "ex2": "A person who describes their partner as 'my reason for living' and means it with clinical literalness — remove the partner, and the organism ceases to function.", "ex3": "A lover whose partner has realized that what they thought was devotion is actually a life-support system running on their energy."}, {"n": 6, "name": "Absorber", "desc": "Takes on the partner's identity wholesale. Their tastes, opinions, ambitions, and personality are borrowed from whoever they're attached to. Between relationships, they're a blank page waiting for the next person to write on.", "ex1": "Someone who was a rock climber with their last partner, a theater person with this one, and will be whatever the next one needs — the activities aren't interests, they're adhesive.", "ex2": "A person who couldn't fill out a dating profile without referencing a partner because everything they know about themselves was learned in the context of someone else.", "ex3": "A lover whose friends have watched them become three completely different people across three relationships and have stopped trusting that any version is the real one."}, {"n": 5, "name": "Clinger", "desc": "Visibly, anxiously attached. The need for closeness is so apparent it becomes the defining characteristic of how others experience them. Not malicious — just obviously, painfully unable to tolerate distance.", "ex1": "A partner who calls immediately when a text isn't answered, not from suspicion but from the specific terror of existing unconnected for more than thirty minutes.", "ex2": "Someone whose friends describe them as 'a lot' in romantic contexts — intense, present, and requiring a level of reassurance that exhausts most people within months.", "ex3": "A lover whose new partners are warned by mutual friends: 'They're wonderful, but they need a LOT of closeness. Make sure you're ready for that.'"}, {"n": 4, "name": "Anxious Merger", "desc": "Merges quickly and anxiously in new relationships. Moves in too fast, says 'I love you' too early, intertwines lives before the foundation can hold the weight. The speed of fusion is driven by anxiety, not confidence.", "ex1": "Someone who has a drawer at their partner's place by week two, a toothbrush by week three, and is functionally living there by month two — each escalation driven by the terror of what happens if they slow down.", "ex2": "A person whose relationships follow a pattern: intense fusion, partner overwhelmed, partner withdraws, Vine panics, relationship collapses. Repeat.", "ex3": "A lover who has been told 'you're moving too fast' in every relationship and genuinely doesn't understand what 'too fast' means, because from inside, the speed is survival."}, {"n": 3, "name": "Serial Dependent", "desc": "Moves from relationship to relationship without gaps, because gaps mean being alone, and being alone means being no one. Each new partner is a trellis, not a person — structural support rather than a companion.", "ex1": "Someone whose relationship history has no single days — each one ends and the next begins within hours, sometimes with overlap, because the moment between attachments is an existential void.", "ex2": "A person who has never lived alone, never eaten dinner alone, and never gone to bed alone — not by happy circumstance but by desperate engineering.", "ex3": "A lover whose partners are interchangeable in function if not in name — the specific person matters less than the presence of A person."}, {"n": 2, "name": "Desperate Grasping", "desc": "Clinging to connections that aren't even relationships. A coworker who was nice once becomes an emotional anchor. A friend's partner becomes an object of fixation. The Vine will attach to anything warm because the alternative is freefall.", "ex1": "Someone who has confused proximity with intimacy so thoroughly that their barista feels like a significant relationship and a stranger's kindness on the bus feels like love.", "ex2": "A person whose therapist has become their primary attachment figure and who panics when the session ends the way others panic during breakups.", "ex3": "A lover who sends 'I miss you' texts to people who are merely acquaintances, and the recipients find it concerning."}, {"n": 1, "name": "Collapse Without Host", "desc": "Between attachments, the Vine is nothing. Literally nothing — no routine, no appetite, no motivation, no identity. They don't grieve the lost relationship so much as cease to exist without it. The self was entirely stored in the other person.", "ex1": "A person post-breakup who doesn't get out of bed for weeks — not from sadness but from a genuine loss of the operating instructions for being alive.", "ex2": "Someone who, after a relationship ends, can't answer the question 'what do you want for dinner?' because wanting was a function the partner provided and the function has been removed.", "ex3": "A lover who between relationships is so unrecognizable that friends express concern not about heartbreak but about whether the person still exists in a meaningful sense."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Devoted Attention", "desc": "At their absolute best, the Vine's hyperattunement becomes exquisite care. They notice everything about the partner — every shift in mood, every unspoken need — and their attentiveness, though born from anxiety, can produce a quality of being-seen that most people never experience.", "ex1": "A partner who knows their spouse is getting a migraine before the spouse does — because they've been reading the signals for years with the intensity of someone whose survival depends on it.", "ex2": "Someone whose partner says 'nobody has ever paid this much attention to me' — and it's true, because the Vine's attention runs at a frequency most people can't sustain.", "ex3": "A lover whose anxious radar has been repurposed into a care-delivery system so precise it feels almost psychic."}, {"n": 6, "name": "Enthusiastic Companion", "desc": "Genuinely, energetically present for everything the partner wants to do. The Vine's willingness to merge means they'll happily adopt the partner's interests, join their activities, and show up for their events with real enthusiasm.", "ex1": "A partner who learns the partner's hobby — woodworking, salsa dancing, birding — with genuine engagement, even if the initial motivation was proximity rather than interest.", "ex2": "Someone whose enthusiasm for the partner's world is infectious — they become the biggest cheerleader, the most reliable audience, the most available companion.", "ex3": "A lover who converts anxious attachment into energetic presence that the partner initially finds wonderful and eventually finds exhausting."}, {"n": 5, "name": "Reliable Presence", "desc": "Always available, always responsive, always there. The partner never has to wonder where the Vine is or whether they're committed. The reliability is genuine, even if its source is anxiety rather than choice.", "ex1": "A partner who answers every text within minutes, attends every event, and never cancels — and the partner appreciates the reliability while occasionally sensing the compulsion underneath.", "ex2": "Someone whose presence is so consistent it functions as a kind of weather — always there, always warm, occasionally oppressive.", "ex3": "A lover who would follow their partner anywhere and has proven it by moving cities, changing careers, and rearranging their life without hesitation."}, {"n": 4, "name": "Accommodating to a Fault", "desc": "Adjusts to the partner's every preference without pushback. Pleasant, agreeable, always willing — and the partner can feel the absence of friction that would indicate a real person with real preferences.", "ex1": "A partner who says 'whatever you want' to every decision with such consistent cheerfulness that the other person starts to feel like they're dating an echo.", "ex2": "Someone whose agreeableness has started to unnerve their partner — 'don't you ever want something different?' 'No, this is perfect' — and neither of them believes it.", "ex3": "A lover whose perfect accommodation is slowly driving the partner toward an uncomfortable realization: they're not in a relationship with a person, they're in a relationship with a mirror."}, {"n": 3, "name": "Anxious Overcompensation", "desc": "Gives compulsively — gifts, attention, service — as insurance against abandonment. The partner can feel the transaction: each gift is a deposit in the 'don't leave' account, and the generosity has an edge of desperation.", "ex1": "A partner who brings home flowers after every perceived micro-conflict — not as apology but as premium payment on a relationship insurance policy.", "ex2": "Someone who books surprise trips, cooks elaborate meals, and maintains a constant stream of thoughtful gestures that are individually lovely and collectively frantic.", "ex3": "A lover whose generosity makes the partner feel like they're being overfed — stuffed with care until the care itself becomes suffocating."}, {"n": 2, "name": "Smothering", "desc": "The attentiveness has become surveillance. The care has become control. The presence has become inescapable. Every behavior that was once charming has been turned up to a volume that makes the partner want to run.", "ex1": "A partner who needs to know where the other person is at all times — not from jealousy but from a genuine inability to regulate their own anxiety without constant positional data.", "ex2": "Someone who has made themselves so omnipresent in the partner's life that the partner has started hiding in the bathroom just to have five minutes alone.", "ex3": "A lover who provides care the way ivy provides coverage: eventually, you can't see the structure underneath."}, {"n": 1, "name": "Parasitic Bond", "desc": "Has attached so completely that the partner is being drained. The Vine's emotional needs consume the partner's energy, time, and selfhood. Not a partnership — a feeding relationship disguised as love.", "ex1": "A partner who has aged visibly from the exhaustion of maintaining another person's emotional regulation while neglecting their own health, friendships, and dreams.", "ex2": "Someone whose partner describes feeling 'hollow' — not from abuse but from the slow, relentless extraction of being someone else's entire emotional ecosystem.", "ex3": "A lover whose partner has started to understand why the Vine's previous relationships all ended the same way: not with a fight, but with the host organism's quiet collapse."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Hostage Symbiosis", "desc": "Has made the partner's departure tantamount to murder. The Vine's dependency is so total and so visible that leaving would require the partner to accept responsibility for another person's potential destruction. 'If you leave, I'll die' — said or unsaid, believed by both parties.", "ex1": "A lover whose partner stays not from love but from genuine fear of what would happen to the Vine if they left — and the Vine senses this and tightens the grip.", "ex2": "Someone whose partner confides to friends 'I can't leave — they'd fall apart' and the friends see the partner falling apart from staying but can't offer a solution that doesn't involve someone's destruction.", "ex3": "A partner who has converted their own fragility into the most effective lock ever designed — a cage built from the partner's compassion."}, {"n": 6, "name": "Emotional Vampirism", "desc": "Feeds on the partner's emotional energy without reciprocation. Every conversation becomes about the Vine's needs. Every plan is organized around the Vine's anxiety. The partner's emotional reserves are steadily drained to fuel the Vine's survival.", "ex1": "A partner who has noticed their own personality dimming — less laughter, less energy, fewer interests — and hasn't connected it to the fact that all available emotional bandwidth is being consumed by someone else's needs.", "ex2": "Someone whose partner can't remember the last time a conversation was about them rather than about the Vine's latest anxiety spiral.", "ex3": "A lover who takes emotional energy the way a parasite takes nutrients: continuously, efficiently, and without the host initially noticing the drain."}, {"n": 5, "name": "Crisis Manufacturing", "desc": "Creates emergencies to trigger the partner's caretaking response. The Vine has learned that crisis produces closeness, so they engineer crises — health scares, emotional breakdowns, dramatic revelations — on a regular cycle.", "ex1": "A partner who has a medical emergency, an emotional collapse, or a professional catastrophe every time the other person seems settled or content — the peace itself is the trigger.", "ex2": "Someone whose partner has started to notice the pattern: every vacation is preceded by a crisis, every independent plan is interrupted by an emergency, every period of calm is shattered by something that requires the Vine's immediate rescue.", "ex3": "A lover who has made stability into the enemy because stability means the partner might realize they don't need to stay."}, {"n": 4, "name": "Isolation Tactics", "desc": "Systematically reduces the partner's support network — not through prohibition but through need. Every moment the partner spends with others is a moment the Vine is alone, and being alone triggers crisis, which pulls the partner back.", "ex1": "A partner whose friends have stopped calling because every social commitment is followed by a guilt-laden phone call from the Vine: 'I had a panic attack while you were out.'", "ex2": "Someone whose partner's social circle has narrowed to just the Vine — not because the Vine forbade friendships, but because the cost of maintaining them became too high.", "ex3": "A lover who has achieved isolation through need rather than control — the partner is free to leave anytime, as long as they can tolerate the Vine's visible devastation while they're gone."}, {"n": 3, "name": "Guilt Weaponry", "desc": "Deploys guilt with precision. Every attempt the partner makes at independence is met with devastation calibrated to produce maximum obligation. 'I understand if you need to go' said in a voice that means 'going makes you a monster.'", "ex1": "A partner who says 'no, go have fun' while crying — and the partner knows that 'fun' will be impossible because the image of the Vine weeping will override every moment.", "ex2": "Someone who has turned their own suffering into the most effective argument against the partner's autonomy — you can't enjoy freedom if your freedom causes someone else visible pain.", "ex3": "A lover whose tears are genuine and whose timing is perfect — arriving at exactly the moment that would make the partner's departure feel like an act of cruelty."}, {"n": 2, "name": "Threat Deployment", "desc": "When the partner moves toward independence, the Vine escalates to threats — of self-harm, of collapse, of catastrophic consequences. The threats may be sincere rather than manipulative, but the effect is identical: the partner cannot leave.", "ex1": "A partner who has said 'I don't know what I'd do without you' in a tone that makes it clear the answer might be something irreversible.", "ex2": "Someone whose partner has memorized the crisis hotline number because every serious conversation about the relationship's problems ends with the Vine in a state that requires professional intervention.", "ex3": "A lover whose partner is trapped not by love but by the impossibility of accepting what might happen if they walk out the door."}, {"n": 1, "name": "Partner Consumption", "desc": "Has consumed the partner entirely. The partner's health, identity, relationships, career, and vitality have all been digested by the Vine's need. What remains is two people locked together in a structure that benefits neither — the Vine is still empty, the partner is now empty too.", "ex1": "A lover whose partner hasn't smiled genuinely in a year, has gained or lost significant weight, has lost contact with everyone, and describes their life with the flat affect of someone describing a prison sentence.", "ex2": "Someone whose partner's therapist has used the word 'enmeshment' so many times it's lost its clinical distance and started to sound like 'emergency.'", "ex3": "A partner who has achieved their worst fear — being left — by ensuring it through the very behaviors designed to prevent it. The partner is still there, but they left long ago."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Momentarily Filled", "desc": "When a partner offers genuine, unconditional closeness, the Vine experiences a brief, profound peace. The constant buzzing need goes quiet. For a moment, they're full. It never lasts — but in that moment, both people glimpse what the Vine is actually looking for.", "ex1": "A lover who, held tightly enough, stops vibrating. The anxiety drains out and what's left is a person — quiet, present, almost unrecognizable to both of them.", "ex2": "Someone who receives unconditional acceptance and for one evening doesn't ask 'do you still love me?' — and the absence of the question is so noticeable the partner almost cries.", "ex3": "A person who, in the right arms, becomes the version of themselves that exists beneath all the need — and both people wish they could stay there."}, {"n": 6, "name": "Grateful Clutching", "desc": "Receives closeness with intense, overwhelming gratitude. The partner's offering is received as life-saving, which is flattering for about a month and alarming thereafter.", "ex1": "A partner who responds to 'I love you' as if hearing it for the first time every time — the gratitude never normalizes, and the partner starts to realize the gratitude is actually relief.", "ex2": "Someone whose reaction to basic relationship maintenance — a text, a hug, a check-in — is so disproportionately grateful that the partner starts wondering what happened to this person before.", "ex3": "A lover who treats every act of closeness as a stay of execution — grateful, urgent, and never quite trusting that the next one will come."}, {"n": 5, "name": "Addictive Reception", "desc": "Receives closeness and immediately needs more. The partner's offering is consumed and the void reopens instantly. The reception is genuine but insatiable — like feeding a fire that burns faster than fuel can be supplied.", "ex1": "A partner who is held for an hour and, when the other person gets up to use the bathroom, feels the absence as physical pain.", "ex2": "Someone who receives a love letter and reads it forty times — not from savoring but from the fact that each reading provides three minutes of fullness before the emptiness returns.", "ex3": "A lover whose partner has started to realize that no amount of closeness will ever be enough — that they're filling a container with no bottom."}, {"n": 4, "name": "Demanding Reception", "desc": "Receives closeness and immediately begins engineering more. The partner's voluntary offering becomes the Vine's baseline, and anything below it feels like withdrawal. What was a gift last month is now an obligation.", "ex1": "A partner who received daily calls at first and now panics if the call is five minutes late — the closeness has been converted from gift to entitlement.", "ex2": "Someone whose partner adjusted their lunch break to call daily and now dreads the obligation they accidentally created.", "ex3": "A lover who has ratcheted the partner's closeness requirements upward so gradually that the partner is now performing acts of love they never signed up for and can't stop without causing crisis."}, {"n": 3, "name": "Suspicious Reception", "desc": "Receives closeness while scanning for signs of its impending withdrawal. Can't enjoy what's being given because they're already mourning its loss. The partner can feel their offering being weighed for sustainability rather than savored for its presence.", "ex1": "A person who is held and simultaneously calculating how long the holding will last, whether it's shorter than last time, and what the reduction means.", "ex2": "Someone who responds to 'I love you' with 'do you really?' not as flirtation but as genuine interrogation — each declaration is evidence to be examined rather than love to be received.", "ex3": "A lover whose anxiety converts every moment of closeness into a data point in an ongoing threat assessment."}, {"n": 2, "name": "Rejecting What They Need", "desc": "So terrified of dependence that they push away the very closeness they're dying for. The Vine's self-awareness has reached the point where they recognize their pattern and overcompensate — performing independence while internally starving.", "ex1": "A person who insists 'I don't need anyone' while crying in the shower about being alone — the performance of self-sufficiency is its own prison.", "ex2": "Someone who rejects their partner's closeness specifically because it feels too good, and things that feel too good always leave.", "ex3": "A lover who has started preemptively distancing from a partner who actually wants closeness — sabotaging the relationship before it can prove their deepest fear true."}, {"n": 1, "name": "Bottomless", "desc": "No amount of closeness registers. The void has become so vast that the partner's offerings vanish without trace. The Vine receives and receives and is never fuller. The partner is pouring love into a singularity.", "ex1": "A person who has been loved devotedly for years and still feels completely alone — not because the love isn't real but because the receptor is broken.", "ex2": "Someone whose partner says 'I don't know what else I can give you' and means it — every form of closeness has been offered, and none of it has landed.", "ex3": "A lover who is the walking proof that love cannot fix what love didn't break."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Black Hole", "desc": "Receives closeness the way a black hole receives light — everything goes in, nothing comes back, and the gravitational pull destroys anything that gets too close. The Vine's need has become cosmic in scale and annihilating in effect.", "ex1": "A lover whose partner has given up their career, friendships, hobbies, and health to meet the Vine's needs and the Vine still says 'it's not enough' — not from cruelty but from a void that is genuinely unfillable.", "ex2": "Someone whose partners all describe the same trajectory: initial intoxication with being so deeply needed, followed by slow realization that the need will consume them, followed by either escape or collapse.", "ex3": "A person who is a black hole wearing a human face — the need is real, the destruction is real, and the person inside the need is as much a victim of it as anyone else."}, {"n": 6, "name": "Resentful Need", "desc": "Receives closeness with simultaneous need and fury. Hates that they need this. Hates the partner for being the supplier. Hates themselves for the dependency. The closeness arrives and is metabolized into resentment.", "ex1": "A partner who accepts a hug with rigid arms because the act of being comforted is humiliating, and the humiliation converts to anger at the person doing the comforting.", "ex2": "Someone who needs their partner desperately and punishes them for being needed — because needing someone gives that person power, and power given is safety lost.", "ex3": "A lover who cycles between clinging and snarling at the person they're clinging to — the need and the rage are the same feeling wearing different masks."}, {"n": 5, "name": "Accusatory Reception", "desc": "Receives closeness and finds fault with it. Whatever the partner gives is wrong — too much, too little, wrong timing, wrong format. The closeness is needed but can never be satisfactory because the dissatisfaction is the point: it maintains the state of need.", "ex1": "A partner who wanted quality time and got it and now says 'but you were on your phone for two minutes' — the two minutes erase the two hours.", "ex2": "Someone who will always find the flaw in the offering because a flawed offering maintains the narrative that they're not being loved properly, which justifies the need for more.", "ex3": "A lover whose partner cannot win because winning would mean the Vine is satisfied, and satisfaction is the Vine's least familiar state."}, {"n": 4, "name": "Weaponized Emptiness", "desc": "Uses their own insatiability as proof of the partner's inadequacy. 'If you really loved me, I wouldn't feel this way.' The Vine's unfillable void becomes the partner's permanent failing.", "ex1": "A partner who is told 'you don't try hard enough' by someone for whom no amount of trying has ever been hard enough — and the partner has started to believe it.", "ex2": "Someone whose partner has accepted the narrative: 'I'm not enough. If I were better, they'd be satisfied.' The Vine's emptiness has been successfully rebranded as the partner's insufficiency.", "ex3": "A lover who has externalized their wound and convinced the partner to carry it."}, {"n": 3, "name": "Punishing Fulfillment", "desc": "When closeness actually arrives and briefly satisfies, the Vine panics and destroys the moment. Fullness feels wrong — alien, suspicious, temporary. Better to destroy it now than wait for it to be taken.", "ex1": "A partner who picks a fight during the best weekend they've had in months because the goodness tripped an internal alarm: good things end, so end it first.", "ex2": "Someone who was visibly happy for an afternoon and then spent the evening creating a crisis — the happiness itself was the threat.", "ex3": "A lover who sabotages every peak because peaks are followed by valleys and the anticipation of the valley is worse than the valley itself."}, {"n": 2, "name": "Consuming the Source", "desc": "Has begun to drain the partner past the point of voluntary giving. The partner is no longer choosing to provide closeness — they're being consumed. The Vine's reception has become extraction.", "ex1": "A lover whose partner has stopped giving freely and started giving from depletion — the difference is invisible to the Vine but existential to the partner.", "ex2": "Someone whose partner describes 'feeling sucked dry' and means it physiologically — the fatigue, the weight changes, the immune collapse of someone whose energy is being siphoned.", "ex3": "A partner who has entered the final phase: giving not from love or obligation but from an inability to stop — the giving has become as compulsive as the Vine's needing."}, {"n": 1, "name": "Mutual Destruction", "desc": "Both people are now being destroyed by the need. The Vine is as empty as ever. The partner is as depleted as the Vine. The relationship has become a closed system of consumption that produces nothing and extracts everything. Neither person has the energy to leave.", "ex1": "Two people in a living room, both exhausted, both miserable, both unable to identify an alternative — the Vine needs the partner to survive and the partner has forgotten that leaving is an option.", "ex2": "A relationship that friends describe as 'codependent' but that from inside feels like a natural law: two bodies orbiting each other, neither with the escape velocity to break free.", "ex3": "A lover who has finally achieved the permanent attachment they always wanted, and it is destroying them both at exactly the same rate."}]}]}, {"name": "The Island", "factor": "Factor 3: Fusion ↔ Autonomy", "factor_num": 3, "pole": "Autonomy", "color": "#5080C7", "alignment": "Shadow", "tagline": "I don't need anyone. (The lie that keeps the lights on.)", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Continent of One", "desc": "Has constructed such a complete, self-enclosed world that the idea of another person entering it is genuinely incomprehensible. Not lonely — or so they insist. Their isolation is so total it has become an ecosystem with its own weather, its own logic, and its own gravitational rules.", "ex1": "A person who lives alone, works alone, socializes on strict terms, and has built a life so precisely calibrated to their preferences that another human being would disrupt it the way a meteorite disrupts a landscape.", "ex2": "Someone whose apartment is a museum of solitary comfort: one chair at the table, one pillow on the bed, one mug in the dish rack. The singularity is architectural.", "ex3": "A lover who hasn't been one in so long that the word has become theoretical — desire exists as a memory rather than a current state."}, {"n": 6, "name": "Fortress of Solitude", "desc": "High-functioning isolation. Career, hobbies, social life — all maintained at arm's length. They have friends but no intimates, colleagues but no confidants. The life is full of people and empty of connection.", "ex1": "A person with 800 LinkedIn connections and zero people who know their middle name — the network is wide and the depth is zero.", "ex2": "Someone who attends dinner parties, tells great stories, and leaves before anyone can ask a personal question — the sociability is a performance that protects the isolation.", "ex3": "A lover who dates sporadically but ends things before the third-date threshold, because the third date is where pretending stops and personhood begins."}, {"n": 5, "name": "Justified Isolator", "desc": "Has a well-developed narrative about why they're alone. Past betrayals, incompatible standards, busy career — the reasons are real enough but function primarily as a wall's decoration.", "ex1": "A person who can give you a TED talk about why modern dating is broken, why people are disappointing, and why being alone is a choice — and the talk is convincing to everyone except their therapist.", "ex2": "Someone who says 'I just haven't found the right person' and means 'I've arranged my life to ensure I never will.'", "ex3": "A lover who has built an intellectual case for isolation that would hold up in court — but the prosecution was never called because the trial is internal and the verdict was predetermined."}, {"n": 4, "name": "Comfortable Numbness", "desc": "Has settled into isolation so thoroughly that it feels like contentment. The absence of connection has been normalized. They don't feel lonely because they've forgotten what connection feels like — the baseline has been reset.", "ex1": "A person who describes themselves as 'happy alone' and is mostly correct — the happiness is genuine, if thin, like a puddle that sparkles in sunlight but has no depth.", "ex2": "Someone whose life works smoothly and who only senses something missing during specific triggers: a couple laughing in a restaurant, a love song, the question 'is anyone joining you?'", "ex3": "A lover who has been out of the game so long that the game now looks foreign — not appealing or unappealing, just incomprehensible."}, {"n": 3, "name": "Leaking Loneliness", "desc": "The isolation has started to hurt and they're starting to notice. Brief flashes of longing that are immediately suppressed. A hand reached for in sleep that touches only pillow. The defense is cracking but the cracks are quickly patched.", "ex1": "A person who adopts a dog and then loves the dog with an intensity that reveals the reservoir of unexpressed attachment that exists underneath the independence.", "ex2": "Someone who cries at a movie — not a sad one, a romantic one — and is startled by their own tears because tears aren't part of the operational plan.", "ex3": "A lover who scrolls through old photos at midnight and feels something they can't name and won't examine."}, {"n": 2, "name": "Brittle Independence", "desc": "The isolation has become fragile. One genuine act of kindness from a stranger can shatter the composure for hours. The walls are still standing but they've thinned to paper, and the person inside knows it.", "ex1": "A person who nearly calls an ex at 2 AM, stops themselves, and then lies awake until dawn — not from missing the ex specifically, but from missing the state of being known.", "ex2": "Someone who has started talking to themselves aloud not from eccentricity but because the silence in the apartment has become physically oppressive.", "ex3": "A lover who realizes they've been avoiding certain neighborhoods because they contain the coffee shop where they once met someone, and the avoidance reveals how much the memory still hurts."}, {"n": 1, "name": "Marooned", "desc": "The isolation has become a prison they built themselves and lost the key to. They want connection now — can feel the want — but have no mechanism for building it. The skills atrophied, the courage evaporated, the opportunities dried up. They're alone and they know it and they can't fix it.", "ex1": "A person who sits in their apartment on a Saturday night and experiences the silence as a sound — a high, continuous whine that is the frequency of a life lived entirely alone.", "ex2": "Someone who opens a dating app, stares at it for twenty minutes, closes it, and repeats this cycle weekly — the desire exists but the capacity to act on it has been so long unused it's seized like a rusted joint.", "ex3": "A lover who will never be one again — not because they don't want to, but because they've waited so long that wanting feels like a language they can no longer speak."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Rare Opening", "desc": "At their absolute best and rarest, the Island lets someone in — and the letting-in is so unusual, so clearly costly, that the partner understands they're witnessing something extraordinary. The vulnerability is small by anyone else's standards and seismic by the Island's.", "ex1": "A lover who says 'I think about you when you're not here' and the sentence carries the weight of a confession wrung from years of solitary practice — and the partner recognizes the magnitude.", "ex2": "Someone who gives the partner a key to their apartment, and both of them understand that the key is not to a door but to a person.", "ex3": "A partner who, after months of careful distance, falls asleep with their head on the other person's shoulder — and the other person doesn't move for two hours because they know this will never happen again if they do."}, {"n": 6, "name": "Deliberate Inclusion", "desc": "Chooses to include the partner in small, specific ways. Not natural — but intentional, and the intention itself is a form of love. Each inclusion costs them something and they pay it.", "ex1": "A partner who invites the other person to their favorite restaurant — the one they always went to alone — and the sharing of it is, for the Island, equivalent to a proposal.", "ex2": "Someone who adds a second pillow to their bed. Just the pillow. But the pillow changes everything.", "ex3": "A lover who starts texting 'good morning' — three years into the relationship — and the partner knows this is the Island's version of a declaration of love."}, {"n": 5, "name": "Structured Availability", "desc": "Available on a schedule. The partner gets Wednesdays and Saturdays, or whatever the Island has allocated. The structure is rigid but within it, the Island is genuinely present.", "ex1": "A partner who shows up on designated days with real warmth and real engagement — and is completely unreachable on all other days, as if the relationship exists only during business hours.", "ex2": "Someone whose partner has learned the schedule and doesn't push for more — because within the allotted time, the Island is actually wonderful.", "ex3": "A lover whose relationship operates like a part-time job: specific hours, real engagement during those hours, total absence outside them."}, {"n": 4, "name": "Functional Minimum", "desc": "Provides the minimum viable relationship. Shows up, follows through on commitments, responds to direct requests. The partner is maintained but not nourished. The Island is technically present and emotionally on a different continent.", "ex1": "A partner who remembers the anniversary, buys the gift, says the words — and the partner can feel that each action was a task completed rather than a feeling expressed.", "ex2": "Someone who does everything right and nothing extra — the relationship runs on obligation and accuracy, not warmth.", "ex3": "A lover whose partner says 'they're perfectly fine' and means it in the way you'd describe an adequate hotel: clean, functional, nobody would call it home."}, {"n": 3, "name": "Reluctant Participation", "desc": "Participates in the relationship with visible effort and minimal enthusiasm. The partner can feel themselves being tolerated. The Island isn't hostile — just clearly somewhere else in their head most of the time.", "ex1": "A partner who sits through dinner conversation with the expression of someone waiting for a flight — present, patient, ready to be elsewhere.", "ex2": "Someone whose body is at the table and whose mind is in the workshop, the office, the book, the solitary place they'd rather be.", "ex3": "A lover whose partner has started eating dinner alone because the company of someone who clearly wishes they were alone is lonelier than actual solitude."}, {"n": 2, "name": "Avoidant Presence", "desc": "Physically present, actively avoiding connection. In the same house, sometimes the same room, but using screens, tasks, and silence as barriers. The partner is in proximity to someone who is engineering their own invisibility.", "ex1": "A partner who has headphones in at all times — not listening to anything, but wearing the headphones as a 'do not approach' sign the partner has learned to respect.", "ex2": "Someone who has arranged their home life so that shared space is minimized: different rooms, different schedules, different beds. The cohabitation is a technicality.", "ex3": "A lover whose partner describes living with them as 'living with a polite ghost — I know they're here, I can't interact with them.'"}, {"n": 1, "name": "Partner as Background", "desc": "The partner has been fully reduced to scenery. Not ignored with malice — just no longer perceived as a separate consciousness requiring engagement. The Island exists in a world of one, and the partner has been absorbed into the furniture.", "ex1": "A person who walks past their partner without acknowledgment — not from anger but from the same unawareness with which they walk past a lamp.", "ex2": "Someone whose partner stood in the doorway and said 'I'm leaving' and the Island said 'okay' without looking up — and both of them knew the 'okay' was genuine.", "ex3": "A lover who is present in the strictest physical sense and absent in every way that matters."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Psychological Exile", "desc": "Banishes the partner to the outer edge of their life while technically keeping them. The partner exists in a permanent state of exile — not quite in the relationship, not quite out. The ambiguity is the cruelty.", "ex1": "A lover who keeps the partner at arm's length for years — close enough to hope, far enough to starve — and the maintenance of this precise distance requires more effort than genuine intimacy would.", "ex2": "Someone whose partner describes the relationship as 'being kept on a shelf — taken down when wanted, put back when not, and never asked how the shelf feels.'", "ex3": "A partner who has made 'almost' into a permanent state: almost together, almost close, almost committed. The 'almost' is more devastating than a clear 'no' would be."}, {"n": 6, "name": "Cruel Indifference", "desc": "Performs not-caring with a precision that dismantles the partner's self-worth. Every important moment is met with neutrality. Every bid for connection is received with the blank affect of someone watching static.", "ex1": "A partner who responds to 'I got the promotion!' with 'cool' and returns to their book — and the partner's celebration dies in the air between them.", "ex2": "Someone who attends their partner's most important life events with the engagement of someone attending a stranger's funeral: present, respectful, uninvolved.", "ex3": "A lover whose indifference to the partner's emotional life has become so consistent that the partner has stopped sharing and started living inside their own parallel isolation."}, {"n": 5, "name": "Withholding as Power", "desc": "Has discovered that emotional scarcity gives them control. The less they give, the more desperately the partner pursues. The Island has learned to dose their presence like a drug — just enough to maintain the partner's hope, never enough to satisfy.", "ex1": "A partner who gives one warm evening per month — just enough to remind the other person what the Island is capable of — and then retreats, leaving the partner to survive on the memory until the next dispensation.", "ex2": "Someone who has turned emotional withholding into a currency — and enjoys the exchange rate.", "ex3": "A lover who provides closeness the way a casino provides wins: rarely enough to be addictive, never enough to be fulfilling."}, {"n": 4, "name": "Contempt for Attachment", "desc": "Views the partner's need for connection with open disdain. The partner's love is treated as evidence of weakness rather than evidence of the Island's value.", "ex1": "A person who says 'you need me more than I need you' as a statement of fact, and the fact is wielded as hierarchy.", "ex2": "Someone who mocks their partner's emotional needs to friends — 'they can't even go a weekend without texting me' — and the mockery is delivered with the confidence of someone who considers themselves the evolved one.", "ex3": "A lover who has made their partner ashamed of being in love with them — the partner hides their affection the way one hides an embarrassing habit."}, {"n": 3, "name": "Passive Abandonment", "desc": "Abandons the partner without leaving. Stops responding, stops initiating, stops engaging — but doesn't end the relationship. The partner is left in a gray zone of technical togetherness and actual aloneness.", "ex1": "A partner who realizes they haven't had a real conversation in a month — and that the Island hasn't noticed the silence because for them, silence is the default state.", "ex2": "Someone who is less present than a long-distance partner would be — because at least long-distance partners call.", "ex3": "A lover whose partner has started dating again in their head — imagining what it would feel like to be with someone who actually shows up — while lying next to the Island."}, {"n": 2, "name": "Weaponized Departure Threats", "desc": "Uses leaving — or the suggestion of leaving — as the primary relational tool. Every disagreement is met with 'maybe this isn't working,' ensuring the partner lives in perpetual uncertainty about whether the relationship will exist tomorrow.", "ex1": "A partner who has a packed bag (metaphorical or literal) at all times, and the partner's awareness of that bag shapes every interaction — tread carefully, or the Island will simply leave.", "ex2": "Someone who deploys 'I think I need to be alone' not from genuine need but from the discovered efficiency of the threat — it ends every argument, silences every complaint, and keeps the partner permanently afraid.", "ex3": "A lover who has turned their willingness to leave into the most effective weapon in the relationship — because the partner has too much invested to call the bluff."}, {"n": 1, "name": "Relational Annihilation", "desc": "Has destroyed the partner's capacity for connection. The partner, after years with the Island, has been trained to expect nothing, want nothing, and fear everything. The Island's unavailability has become a virus — the partner now carries it into every future relationship.", "ex1": "A person whose partner leaves the relationship unable to trust closeness — flinching when new partners offer warmth, because warmth was always followed by disappearance before.", "ex2": "Someone whose ex needs years of therapy to unlearn the lesson the Island taught: that wanting to be close to someone is a character flaw.", "ex3": "A lover who has exported their isolation into another human being — the partner didn't arrive as an island, but they'll leave as one."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Crack in the Seawall", "desc": "Something unprecedented: the Island feels someone's love arrive and doesn't block it. A moment of genuine reception — brief, terrifying, potentially life-changing. The walls didn't come down; a single wave came over them.", "ex1": "A person who is held by someone patient and kind and, for thirty seconds, lets themselves feel it — and the thirty seconds reshapes something they'd assumed was permanent.", "ex2": "Someone who receives an 'I see you' from a partner who actually does see them, and the accuracy of being truly known produces a shock the Island wasn't defended against.", "ex3": "A lover who cries for the first time in years — not from sadness but from the unfamiliar sensation of being reached."}, {"n": 6, "name": "Wary Welcome", "desc": "Allows the partner's closeness on a trial basis. Receives with one hand, holds back with the other. The partner's warmth is permitted but monitored — the Island is checking whether this is safe the way a wild animal checks whether the offered food is a trap.", "ex1": "A partner who accepts a cooked meal and says 'thank you' with the careful weight of someone acknowledging that accepting the meal is accepting something larger.", "ex2": "Someone who lets the partner into one room of the fortress — literally or metaphorically — and watches closely to see what they do there.", "ex3": "A lover who is receiving warmth for the first time in years and managing it the way someone manages a new prescription: cautiously, with attention to side effects."}, {"n": 5, "name": "Intermittent Reception", "desc": "Receives closeness on some days and blocks it on others. The partner can't predict which mode they'll encounter. Good days and wall days alternate without visible pattern.", "ex1": "A partner who holds hands on Wednesday and flinches at touch on Thursday — and the partner is left to navigate without a map.", "ex2": "Someone whose reception depends on variables the partner can't see: sleep quality, work stress, which internal narrative is running that day.", "ex3": "A lover whose partner has developed the patience of a wildlife photographer — waiting for the moments of openness, shooting when the light is right, accepting that most days the animal won't appear."}, {"n": 4, "name": "Minimal Reception", "desc": "Receives the smallest offerings and can't handle anything larger. A text is fine. A hug is too much. A love letter would cause a system shutdown. The partner learns to love in whispers.", "ex1": "A partner who has learned that the maximum tolerable dose of affection is a hand squeeze — anything more triggers withdrawal that lasts days.", "ex2": "Someone whose partner expresses love by leaving notes rather than saying words, because the written form can be absorbed at the Island's pace rather than requiring real-time response.", "ex3": "A lover who can receive love only in formats that don't require reciprocation: acts of service, parallel presence, gifts left on the counter."}, {"n": 3, "name": "Reception as Overwhelm", "desc": "Partner's closeness triggers overwhelm. Not anger, not rejection — sensory and emotional flooding. The love arrives and the Island's system can't process it. They shut down not from unwillingness but from overload.", "ex1": "A person who was told 'I love you deeply' and went nonverbal for an hour — not from displeasure but from the emotional equivalent of a computer crash.", "ex2": "Someone whose partner learned to deliver emotional information in very small doses because the full download causes a blue screen.", "ex3": "A lover who wants to receive but whose reception hardware was never designed for this bandwidth — love at full volume produces static."}, {"n": 2, "name": "Active Blocking", "desc": "Actively prevents closeness from landing. Changes the subject when things get intimate. Leaves the room when the mood shifts toward depth. The partner reaches and the Island executes an evasive maneuver so practiced it's automatic.", "ex1": "A partner who has developed a sixth sense for incoming emotional moments and has a library of deflection techniques: humor, logistics, phone-checking, sudden fatigue.", "ex2": "Someone who responds to vulnerability by becoming suddenly very interested in the weather, the news, or whether the dishwasher was loaded correctly.", "ex3": "A lover whose deflection skills are so polished the partner sometimes doesn't realize they were redirected until hours later."}, {"n": 1, "name": "Dead Reception", "desc": "Nothing gets through. The partner's love arrives at a receiver that has been permanently shut down. Not damaged — decommissioned. The Island made a decision, perhaps decades ago, that reception was too dangerous, and the decision has become architecture.", "ex1": "A person who has been loved faithfully for years and cannot point to a single moment when they felt it — because feeling it would require a system they've disabled.", "ex2": "Someone whose partner eventually says 'I can't love someone who won't let me' and the Island hears the words and understands them intellectually while remaining emotionally untouched.", "ex3": "A lover who will be remembered by their partner as the person who proved that love, unreciprocated and unreceived, eventually dies — not with a bang, but with the quiet resignation of water turning off."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Weaponized Solitude", "desc": "Uses their own impermeability as psychological warfare. The partner's love is offered and visibly not-received, and the not-receiving is the message: you don't matter enough to reach me.", "ex1": "A lover who can sit through the partner's most heartfelt declaration with an expression of polite interest, and the politeness is more devastating than hostility would be.", "ex2": "Someone who has learned that their greatest power is their ability to not be moved — and deploys it with the calm of someone who knows they hold all the cards.", "ex3": "A partner who responds to 'I love you' with 'I appreciate that' — and the 'appreciate' is chosen for its precise clinical distance from 'love.'"}, {"n": 6, "name": "Humiliation of the Giver", "desc": "Makes the partner feel foolish for loving them. Not through cruelty but through the persistent implication that love itself is naive and the partner is embarrassing themselves by offering it.", "ex1": "A person who responds to romantic gestures with a faintly amused tolerance that makes the partner feel like a child handing a crayon drawing to someone who collects fine art.", "ex2": "Someone who has so thoroughly positioned themselves as above human need that the partner's human needs feel like an embarrassment in their presence.", "ex3": "A lover who receives devotion with the energy of someone being given a gift they don't want — polite, slightly impatient, and privately wondering when the gift-giving will stop."}, {"n": 5, "name": "Love as Leverage", "desc": "Receives the partner's love and uses it as a power source. Doesn't reciprocate — just runs on it. The partner's emotional energy keeps the Island's life functioning while the Island contributes nothing emotional in return.", "ex1": "A partner who accepts all acts of service, care, and affection as their due — and returns nothing, and notices nothing missing in the exchange.", "ex2": "Someone who has unknowingly set up an emotional extraction operation: the partner pours in love, the Island consumes it, and the balance sheet is never examined.", "ex3": "A lover who is sustained by the partner's devotion the way a plant is sustained by soil — drawing nutrients without acknowledgment."}, {"n": 4, "name": "Sadistic Withholding", "desc": "Has discovered that watching the partner try is satisfying. The partner's continued attempts to break through — after years of failure — provide a dark form of proof that the Island matters. The not-receiving has become a spectator sport.", "ex1": "A person who watches their partner try new approaches to connection with the detached interest of a researcher observing a rat in a maze — the maze was designed without an exit, but the rat doesn't know that.", "ex2": "Someone who gets a quiet satisfaction from being pursued by someone they never intend to let in — the pursuit itself is the payoff.", "ex3": "A lover who has turned their partner's hope into entertainment — and the partner's shrinking hope is becoming less entertaining, which means the Island may soon need a new source."}, {"n": 3, "name": "Blame the Lover", "desc": "Makes the partner responsible for the Island's inability to receive. 'If you were more interesting, I'd engage.' 'If you were less needy, I'd come closer.' The Island's dysfunction is reframed as the partner's failing.", "ex1": "A partner who has been told 'maybe I'd open up if you gave me space' and gave space and nothing changed — because the request was a deflection, not a solution.", "ex2": "Someone who always has a reason the partner's love isn't landing: wrong timing, wrong approach, wrong frequency. The reasons change; the result doesn't.", "ex3": "A lover who has externalized their own brokenness so effectively that the partner is in therapy for 'pushing people away' — when the person doing the pushing is the Island."}, {"n": 2, "name": "Casual Disposal", "desc": "Discards the partner with the ease of someone throwing away packaging. The partner, who has spent years trying to reach the Island, is disposed of without ceremony — not because the Island is angry, but because the partner has simply stopped being useful.", "ex1": "A person who ends a five-year relationship with a text and is genuinely puzzled by the partner's devastation — from their perspective, the arrangement was always provisional.", "ex2": "Someone who replaces partners the way one replaces batteries: when depleted, remove and install a new one. The mechanism doesn't require the old battery's consent.", "ex3": "A lover who describes their breakup to friends as 'it ran its course' and the phrase reveals everything: it was always an it, never a them, and 'course' implies a predetermined endpoint."}, {"n": 1, "name": "Permanent Exile of Love", "desc": "Has ensured that love can never reach them again. The defenses are total, the isolation is complete, and the cost has been transferred to everyone who ever tried to bridge the gap. The Island remains — pristine, unreachable, and alone in a way that has stopped feeling like a choice and started feeling like a sentence.", "ex1": "A person who dies with a contact list full of people who tried and failed to love them, each name representing a bridge that was burned from the Island's side.", "ex2": "Someone whose life's work was the construction of an impenetrable self, and the construction was successful, and the success is the tragedy.", "ex3": "A lover who achieved perfect solitude and will spend the rest of their life inside it — occasionally pressing their hand against the wall, wondering what's on the other side, and never opening the door."}]}]}, {"name": "The Devoted", "factor": "Factor 4: Devotion ↔ Freedom", "factor_num": 4, "pole": "Devotion", "color": "#B05090", "alignment": "Healthy", "tagline": "I choose you, again and again, with open eyes.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Covenant", "desc": "Their commitment is a living thing — not a promise made once but a practice renewed daily. They've seen their partner at their absolute worst and chosen them anyway, not from blindness but from a love that includes the full picture. Devotion as a spiritual discipline.", "ex1": "A partner who nursed their spouse through addiction recovery, saw every ugly thing, and at the end said 'I would do it again' — and meant it without martyrdom.", "ex2": "Someone who has weathered betrayal, loss, illness, and failure within the relationship and emerged with a commitment that is stronger for having been tested rather than weaker.", "ex3": "A lover whose partner says 'I don't understand why you stay' and they answer with specifics — not 'because I love you' but 'because of who you became after the fire, because of Tuesday mornings, because of the way you hold the dog.'"}, {"n": 6, "name": "Anchor", "desc": "Deep, unwavering commitment that gives the relationship its structural integrity. They are the person who keeps choosing in when things get hard, not from obligation but from a settled certainty that this is where they belong.", "ex1": "A partner who turned down a dream job in another city because the relationship was worth more — and made the decision without resentment, without keeping score, without ever mentioning it as sacrifice.", "ex2": "Someone whose commitment is so reliable it has become the relationship's foundation — the partner builds a life on it the way you build on bedrock.", "ex3": "A lover who has never given their partner reason to doubt, not because they're incapable of leaving but because they've never wanted to."}, {"n": 5, "name": "Faithful Heart", "desc": "Genuinely committed and monogamous by nature and choice. Their devotion is warm, consistent, and uncomplicated. They don't struggle with fidelity — it fits them like their own skin.", "ex1": "A partner who has never been tempted to stray and doesn't understand why this is considered remarkable — loyalty, for them, isn't effort but orientation.", "ex2": "Someone who has been with one person for fifteen years and still introduces them as 'the love of my life' without irony or performance.", "ex3": "A lover whose friends describe them as 'the loyal one' and mean it as both compliment and slight concern — because loyalty this natural sometimes looks like it hasn't been examined."}, {"n": 4, "name": "Steady Chooser", "desc": "Committed and reliable, though the devotion has become more habitual than examined. They choose their partner every day — but the choosing has become automatic, like breathing. Real, essential, and no longer conscious.", "ex1": "A partner who would never leave but hasn't thought about why they stay in a long time — the commitment is muscle memory.", "ex2": "Someone whose loyalty is unquestioned by everyone including themselves, which means it runs on inertia as much as on love.", "ex3": "A lover whose partner feels secure but occasionally wonders whether they're chosen or simply not-left — and the distinction matters more than it should."}, {"n": 3, "name": "Wavering Devotion", "desc": "Committed but with cracks. Thoughts wander. Eyes linger. The devotion is real but no longer effortless — it requires active maintenance, and the maintenance is starting to feel like work.", "ex1": "A partner who has caught themselves fantasizing about an alternative life — not a specific person, just the abstract concept of 'different' — and feels guilty enough to know the devotion still matters.", "ex2": "Someone who lies in bed at night and occasionally thinks 'what if I hadn't' — not with regret exactly, but with a curiosity that feels like the first termite in the foundation.", "ex3": "A lover who is still choosing their partner but has started noticing that the choosing requires effort it didn't used to."}, {"n": 2, "name": "Dutiful Loyalty", "desc": "Stays out of principle rather than feeling. The commitment has outlived the love, or the love has changed into something unrecognizable. They honor the promise because they are someone who honors promises, and the honoring has become a weight.", "ex1": "A partner who says 'I made a vow' and means it as explanation, not declaration — the vow is now a fact to be endured rather than a choice to be celebrated.", "ex2": "Someone who stays in the relationship the way they stay at a job they've outgrown: out of loyalty, seniority, and the fear that starting over would cost too much.", "ex3": "A lover whose partner can feel the difference between being loved and being honored — and being honored without love is its own specific loneliness."}, {"n": 1, "name": "Empty Vow", "desc": "The commitment continues but contains nothing. They haven't left and they haven't stayed — they've simply stopped moving. Devotion without feeling, loyalty without life. A promise kept by a person who has forgotten what the promise was for.", "ex1": "A partner who wears their wedding ring the way they wear their watch — out of habit, not meaning. If asked about it they'd say 'oh, this' as if noticing it for the first time.", "ex2": "Someone who will be with their partner until death, and both of them know this, and neither of them finds any comfort in it.", "ex3": "A lover whose devotion has become the saddest thing about them — a fire that went out years ago in a fireplace nobody has cleaned."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Unconditional Witness", "desc": "Their devotion gives the partner the rarest gift: being fully known and fully chosen simultaneously. The partner doesn't have to perform, improve, or earn. The Devoted has seen everything and chosen everything, and the partner can finally stop auditioning.", "ex1": "A lover who says 'you don't have to be better for me to stay — I chose this version of you and every version that comes next' and the partner's entire nervous system relaxes for the first time in their life.", "ex2": "Someone whose partner took a terrible risk, failed spectacularly, and came home to find the Devoted waiting with dinner and the sentence 'tell me everything' said with genuine curiosity, not disappointment.", "ex3": "A partner whose devotion has made the other person braver — because when the safety net is this real, the trapeze is less frightening."}, {"n": 6, "name": "Active Fidelity", "desc": "Doesn't just refrain from straying — actively builds the relationship. Their commitment manifests as investment: time, attention, growth, repair. Loyalty isn't passive; it's a construction project.", "ex1": "A partner who suggests couples therapy not because things are bad but because things are good and they want to make them extraordinary.", "ex2": "Someone who reads about relationships, attends workshops, and brings home insights — not from anxiety but from the same enthusiasm they'd bring to any craft they take seriously.", "ex3": "A lover who treats the relationship like a garden: actively tended, deliberately nourished, and never assumed to be self-maintaining."}, {"n": 5, "name": "Reliable Devotion", "desc": "Consistently committed in word and action. The partner always knows where they stand. The devotion is warm, real, and expressed through daily acts of chosen presence.", "ex1": "A partner who says 'I'm not going anywhere' and has years of evidence to support the claim — the words are a summary of behavior, not a promise in advance.", "ex2": "Someone who makes the partner feel secure by being boringly, beautifully consistent — same love, same attention, same priority, day after day.", "ex3": "A lover whose commitment gives the partner permission to have bad days, bad weeks, bad months — because the commitment isn't conditional on continuous excellence."}, {"n": 4, "name": "Comfortable Faithfulness", "desc": "Devoted without drama. Their commitment is warm but has settled into such a comfortable pattern that the partner sometimes forgets to be grateful for it. The devotion is real but no longer remarked upon — the way you stop noticing good weather.", "ex1": "A partner who has been faithful for twenty years and whose partner says 'of course they're loyal' — the 'of course' containing both security and a hint of taking-for-granted.", "ex2": "Someone whose commitment has become so assumed that when asked 'do you still love me?' they look genuinely confused, as if asked whether gravity still works.", "ex3": "A lover whose fidelity is the most stable thing in the partner's life and therefore the most invisible."}, {"n": 3, "name": "Flagging Investment", "desc": "Still committed but investing less. The devotion remains in principle while the practice has thinned. Date nights dropped off, conversations shortened, the maintenance schedule slipped. The structure holds but the upkeep is falling behind.", "ex1": "A partner who used to plan anniversaries months in advance and now remembers the day-of with a scrambled reservation and a card that says what last year's card said.", "ex2": "Someone whose partner has started to sense the difference between being devoted-to and being default — the commitment is real but the energy behind it has dimmed.", "ex3": "A lover whose partner asks 'are we okay?' and they say 'of course' too quickly — the speed of the answer revealing that the question wasn't actually considered."}, {"n": 2, "name": "Devotion as Autopilot", "desc": "Goes through the motions of commitment — remembering dates, saying the words, maintaining the structure — without the emotional fuel that once powered them. The partner receives technically correct devotion that is emotionally bankrupt.", "ex1": "A partner who texts 'love you' at the same time every night the way they set an alarm — it happens, it's on schedule, it means nothing beyond its own occurrence.", "ex2": "Someone who attends their partner's important events with the presence of a mannequin — body there, investment elsewhere.", "ex3": "A lover whose partner has started interpreting the devotion correctly: it's a system running without an operator."}, {"n": 1, "name": "Devoted in Name Only", "desc": "Technically hasn't left. Technically hasn't strayed. Technically fulfills every obligation. And the partner lives inside a commitment that is technically perfect and emotionally abandoned — the worst of both worlds.", "ex1": "A partner who is present at every event and absent from every moment — the devotion has become a photograph of a fire rather than the fire itself.", "ex2": "Someone whose partner describes the relationship as 'fine' with the specific deadness that means 'I've given up wanting more.'", "ex3": "A lover whose faithfulness has become a cage for both of them — they won't leave, they won't love, and the partner is trapped in the company of someone who is technically, contractually, devastatingly there."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Devotion as Ownership", "desc": "Their commitment has become a claim of property. 'I chose you' has shifted from 'I honor you' to 'I hold the deed.' The partner is not a person to be loved but a decision to be protected from reassessment.", "ex1": "A lover who says 'you're mine' and means it the way one means 'this is my house' — structurally, legally, immovably. The partner's autonomy is a threat to the investment.", "ex2": "Someone whose commitment has calcified into territorial control: the devotion hasn't changed but the partner is now treated as something owned rather than someone chosen.", "ex3": "A partner who monitors not because they're jealous but because they're protecting their asset — and the partner can feel the difference between being loved and being guarded."}, {"n": 6, "name": "Guilt-Forged Chain", "desc": "Uses their own devotion as leverage. 'After everything I've given this relationship...' Every sacrifice is a link in a chain, and the partner carries the accumulated weight of being devoted-to as a permanent debt.", "ex1": "A partner who never lets the other person forget the time they turned down the job, skipped the trip, chose the relationship — each sacrifice a brick in a wall the partner can never climb over.", "ex2": "Someone who says 'I would never do that to you' in a tone that means 'and you owe me the same, forever, without negotiation.'", "ex3": "A lover whose devotion is simultaneously genuine and weaponized — the love is real and so is the invoice."}, {"n": 5, "name": "Jealous Devotion", "desc": "Commitment laced with surveillance. Their faithfulness is real but it comes with the expectation of equal and visible faithfulness from the partner — and the monitoring to confirm it. Trust has been replaced by verification.", "ex1": "A partner who doesn't check the other person's phone but creates situations designed to test loyalty — mentioning that a mutual friend is single, suggesting a solo trip, watching the response with the intensity of a polygraph operator.", "ex2": "Someone who experiences the partner's friendships, especially with attractive people, as existential threats to a commitment they've built their identity around.", "ex3": "A lover whose devotion has become possessiveness wearing commitment's clothing."}, {"n": 4, "name": "Suffocating Loyalty", "desc": "Their commitment has become claustrophobic. The partner can feel the devotion pressing on them from all sides — well-intentioned, inescapable, and increasingly hard to breathe inside.", "ex1": "A partner who responds to every mention of the future with 'OUR future' — even when the partner was talking about their individual career. No sentence is allowed to exist without the word 'we.'", "ex2": "Someone whose devotion has eliminated the partner's ability to think independently about their own life — every plan, every dream, every possibility must pass through the filter of the partnership.", "ex3": "A lover whose commitment is a warm blanket that has become too heavy to move under."}, {"n": 3, "name": "Martyred Devotion", "desc": "Performs commitment as suffering. The devotion is real but the delivery is designed to produce guilt — sighs, visible sacrifice, the subtle performance of enduring. The partner is being loved AT rather than loved.", "ex1": "A partner who says 'I'll stay home again, it's fine' and the 'fine' contains enough compressed resentment to power a small city.", "ex2": "Someone who has turned their loyalty into a public narrative of sacrifice — 'I gave up everything for them' — told to friends, family, and eventually the partner, who now feels like a burden rather than a beloved.", "ex3": "A lover whose devotion has become indistinguishable from a guilt delivery service."}, {"n": 2, "name": "Devotion as Control", "desc": "Uses commitment to dictate terms. 'I've given you everything — the least you can do is...' followed by whatever the Devoted wants. The devotion has become a blank check that the Devoted writes and the partner must honor.", "ex1": "A partner whose years of faithfulness have been converted into a permanent credit line they draw on whenever they want something: compliance, sex, agreement, silence.", "ex2": "Someone who frames every want as a debt owed: 'I've been loyal for ten years — I think I've earned the right to make this decision for us.'", "ex3": "A lover who has turned their commitment into a currency and the exchange rate always favors them."}, {"n": 1, "name": "Devotion as Prison", "desc": "The commitment has become total incarceration. The partner cannot leave because the Devoted's entire identity, will, and future are built on the partnership, and departure would constitute the destruction of another person. The devotion is a life sentence for both.", "ex1": "A lover who says 'if you leave, you'll destroy me' and means it literally — and the partner believes it because the evidence supports it — and stays, and dies a little more each year.", "ex2": "Someone whose devotion has created a hostage situation: the Devoted is the hostage of their own commitment, the partner is the hostage of the Devoted's inability to survive without them.", "ex3": "A partner who has made love into a prison by the simple act of needing it too completely — the bars are made of genuine feeling, and genuine feeling is the hardest thing to break."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Honored Reception", "desc": "Receives the partner's commitment as the sacred thing it is. Doesn't take it for granted, doesn't test it, doesn't demand proof. Meets devotion with devotion, creating a loop of mutual chosen faithfulness that strengthens over time.", "ex1": "A partner who responds to 'I choose you' with 'I know, and I choose you back' — and the exchange is a daily renewal rather than a one-time contract.", "ex2": "Someone who actively celebrates their partner's loyalty rather than simply expecting it — who says 'thank you for staying' not from insecurity but from genuine recognition.", "ex3": "A lover who has made the partner's devotion feel worthwhile by receiving it fully and returning it with equal intentionality."}, {"n": 6, "name": "Secure Reception", "desc": "Receives commitment with settled confidence. Trusts it without testing it. The partner's devotion is a known quantity that frees both of them to focus on living rather than monitoring.", "ex1": "A partner who doesn't check the phone, doesn't question the late night, doesn't need reassurance — because the commitment has been proven so consistently that doubt has atrophied.", "ex2": "Someone whose trust in the partner's devotion is so complete it has become invisible infrastructure — relied upon, never examined, always holding.", "ex3": "A lover whose secure reception makes the Devoted feel that their loyalty is seen, valued, and safe."}, {"n": 5, "name": "Warm Acceptance", "desc": "Receives devotion with genuine warmth and appreciation. Occasionally takes it for granted, but when reminded of its value — through absence, through others' stories, through reflection — responds with real gratitude.", "ex1": "A partner who says 'I'm lucky' about once a month and means it — not often enough to be a mantra, often enough to be a truth.", "ex2": "Someone who hears about friends' relationship problems and comes home to hug their devoted partner a little tighter that night.", "ex3": "A lover whose appreciation surfaces intermittently but, when it does, is deep enough to sustain both of them."}, {"n": 4, "name": "Quiet Acceptance", "desc": "Receives devotion as the expected state. Doesn't celebrate it or question it — simply lives inside it. The partner's loyalty is the air they breathe: essential, unnoticed, and only valued when threatened.", "ex1": "A partner who has never had to doubt their spouse's fidelity and has therefore never learned to appreciate it — the security is so consistent it's become invisible.", "ex2": "Someone who would describe their partner as 'loyal' if asked but would never volunteer it, because it's like describing water as 'wet' — obvious to the point of being unremarkable.", "ex3": "A lover whose partner is beginning to feel taken for granted but hasn't said so yet."}, {"n": 3, "name": "Restless in Devotion", "desc": "Receives the partner's commitment but chafes against it. The security is welcome; the implied expectation of equal devotion feels constraining. They love being chosen and resent the assumption that the choice is permanent.", "ex1": "A partner who values their spouse's loyalty and privately resents that it comes with the expectation of identical loyalty — the devotion feels like a contract they didn't fully read before signing.", "ex2": "Someone who enjoys the safety net while eyeing the exits — not planning to leave, but wanting the option to exist.", "ex3": "A lover who responds to 'I'll always be here' with a feeling that's half gratitude and half claustrophobia."}, {"n": 2, "name": "Taking Advantage", "desc": "Uses the partner's devotion as a resource to be exploited. Knowing the partner won't leave, they push boundaries, neglect the relationship, and take increasing liberties — secure in the knowledge that the devoted partner will absorb whatever they dish out.", "ex1": "A partner who has gradually stopped making effort because their spouse's loyalty is unconditional — and unconditional love, it turns out, can be abused without consequence.", "ex2": "Someone who cancels plans, forgets dates, and prioritizes everything else, knowing the devoted partner will be there regardless.", "ex3": "A lover who treats the partner's commitment as a blank check for their own negligence."}, {"n": 1, "name": "Contempt for Loyalty", "desc": "Has come to despise the very devotion they depend on. The partner's faithfulness is now evidence of weakness, and the person receiving it feels both trapped by its presence and disgusted by its source.", "ex1": "A partner who mocks their devoted spouse to friends — 'they'd never leave, they don't have the spine' — while relying completely on the stability that devotion provides.", "ex2": "Someone who has lost all respect for a partner whose crime is loving them too reliably — the very quality that should be cherished has been reframed as pathology.", "ex3": "A lover who despises the person they need, and the despising doesn't reduce the need, it just makes the need shameful."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Loyalty as Trap", "desc": "Experiences the partner's devotion as a cage. Their commitment is suffocating — not because it's possessive but because being the object of someone's life purpose creates an obligation so heavy it becomes impossible to breathe under.", "ex1": "A person who knows their partner would die for them and finds the knowledge not romantic but terrifying — the weight of being someone's everything has become unbearable.", "ex2": "Someone who fantasizes about being with someone who cares less, because less care would mean less responsibility for another person's entire emotional survival.", "ex3": "A lover who is drowning in being loved — not from the love itself but from the impossibility of ever matching, repaying, or escaping it."}, {"n": 6, "name": "Testing to Destruction", "desc": "Repeatedly tests the partner's devotion by behaving badly — escalating until they either find the breaking point or prove the commitment is truly unbreakable. Each survived test raises the bar for the next one.", "ex1": "A partner who creates increasingly serious infractions — lying, disappearing, flirting — specifically to see if the devoted partner will finally leave. The testing is about confirming the commitment's reality, not about wanting to hurt.", "ex2": "Someone whose therapist has identified the pattern clearly: 'You're trying to find the edge of their love. What will you do if there isn't one?'", "ex3": "A lover who is simultaneously terrified the partner will leave and desperately trying to make them leave — because the uncertainty of devotion is less tolerable than the certainty of abandonment."}, {"n": 5, "name": "Guilt Reception", "desc": "Cannot receive devotion without guilt. The partner's commitment feels unearned, and the feeling of not-deserving creates a persistent anxiety that curdles the experience of being loved.", "ex1": "A person who responds to 'I love you completely' with internal panic: 'they wouldn't if they really knew me' — and the secret self they're hiding may be real or imagined, but the terror is constant.", "ex2": "Someone who sabotages the relationship to prove they were right about being undeserving — the devotion they couldn't accept becomes the devotion they destroy.", "ex3": "A lover who has been faithfully loved and cannot stop waiting for the moment the partner discovers they were wrong to."}, {"n": 4, "name": "Weaponized Insecurity", "desc": "Converts the partner's devotion into a tool for managing their own anxiety. Demands constant proof, creates scenarios requiring reassurance, and never lets the partner's commitment simply exist — it must be perpetually re-demonstrated.", "ex1": "A partner who asks 'would you still love me if...' fifteen different ways, each answer insufficient, each reassurance expiring within hours.", "ex2": "Someone who engineers jealousy crises to trigger the partner's protective devotion response — because the devotion is only believable when activated by threat.", "ex3": "A lover whose partner has exhausted every possible form of reassurance and has started to realize that no proof will ever be enough."}, {"n": 3, "name": "Entitlement", "desc": "Has converted the partner's devotion into an expected baseline that must be continuously exceeded. What was once a gift is now a minimum. The partner's loyalty is not enough — they must prove it in increasingly demanding ways.", "ex1": "A partner who says 'if you really loved me, you'd...' followed by progressively more unreasonable requests — each one framed as the natural extension of a commitment the partner already made.", "ex2": "Someone who has raised the loyalty bar so high that the devoted partner is permanently in deficit, always owing, never paid up.", "ex3": "A lover whose reception of devotion is indistinguishable from consumption of devotion."}, {"n": 2, "name": "Humiliation of the Devoted", "desc": "Makes the partner's loyalty look foolish. Flaunts disregard for the commitment while knowing the partner will stay. The devoted partner is publicly or privately humiliated for their own faithfulness.", "ex1": "A partner who flirts openly, dismisses the relationship in front of others, and then comes home to the devoted partner who is still there — and the being-there is treated as proof of the devoted partner's low self-worth rather than their love.", "ex2": "Someone who tells their devoted partner 'you're pathetic for staying' and means it — because the staying, which should be honored, has instead become evidence that the devoted partner has no options.", "ex3": "A lover who has converted the greatest gift they've ever been given — someone's unconditional loyalty — into an object of contempt."}, {"n": 1, "name": "Destruction of the Bond", "desc": "Systematically destroys the devotion being offered. Not by leaving — by making the devoted partner finally stop loving them. Each act of disregard, cruelty, or betrayal is a hammer blow on a commitment that was supposed to be unbreakable. The shadow receiver doesn't want to leave — they want to be the one who broke something permanent.", "ex1": "A person who pushed a devoted partner past their breaking point and watched, with a mixture of satisfaction and horror, as the commitment finally snapped — proving that nothing lasts, that everyone leaves, that devotion was always a lie.", "ex2": "Someone who got exactly what they wanted — the destruction of someone else's love for them — and found that the victory felt exactly like every other loss.", "ex3": "A lover who burned down the only real thing they'd ever been given, because real things require a vulnerability they'd rather destroy than endure."}]}]}, {"name": "The Explorer", "factor": "Factor 4: Devotion ↔ Freedom", "factor_num": 4, "pole": "Freedom", "color": "#50A0A0", "alignment": "Healthy", "tagline": "Love should open doors, not close them.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Free Wind", "desc": "Embodies freedom so authentically that it becomes its own form of integrity. Their relationships are honest, open, and built on a foundation of truth rather than possession. They've found a way to love without caging or being caged.", "ex1": "A person in an ethically open relationship that genuinely works — both partners are autonomous, communicative, and the freedom has made the love more honest rather than less committed.", "ex2": "Someone who moves through life with an openness to connection that doesn't preclude depth — they've loved deeply and held loosely, and the combination has produced relationships that were brief and transformative.", "ex3": "A lover who proves that freedom and devotion aren't opposites — they're deeply committed to their partners' autonomy, which is itself a form of devotion."}, {"n": 6, "name": "Open Road", "desc": "Lives with genuine freedom — travels, explores, maintains multiple deep connections — and does so with honesty and care. Every person in their life knows where they stand. The Explorer's freedom doesn't come at anyone's expense.", "ex1": "A person who has long-term partners in different cities, all of whom know about each other, all of whom have chosen this arrangement from genuine preference rather than compromise.", "ex2": "Someone who left a conventional relationship not to escape commitment but to find a form of commitment that fit their nature — and found it.", "ex3": "A lover who has crafted a relational life that looks unconventional from outside and feels deeply honest from inside."}, {"n": 5, "name": "Honest Wanderer", "desc": "Open about their need for freedom. Tells partners early, clearly, without apology. Some people can't handle it and leave. Others thrive in it. The Explorer's honesty is their most loving act.", "ex1": "A person whose dating profile says 'not looking for traditional monogamy' and follows through — no hidden agendas, no bait-and-switch, no promises they can't keep.", "ex2": "Someone who says 'I care about you deeply and I need you to know I may not be able to give you exclusivity' on the third date — and the courage of that honesty earns respect even from those who decline.", "ex3": "A lover who has lost relationships by being honest and considers the losses preferable to the relationships they'd have built on lies."}, {"n": 4, "name": "Comfortable Drifter", "desc": "Happy moving between connections without deep anchoring. Not avoiding depth — just naturally oriented toward breadth. They bring genuine warmth to every encounter without promising permanence.", "ex1": "A person who maintains warm, caring relationships with several people and is genuinely puzzled when asked to choose — 'why would I limit love?'", "ex2": "Someone whose life is rich with connections that are individually lighter but collectively provide a web of belonging.", "ex3": "A lover who is wonderful to be with and difficult to hold — not because they're slippery but because they're wind."}, {"n": 3, "name": "Restless Searcher", "desc": "The freedom has an anxious edge. They tell themselves they're exploring, but underneath is a nagging suspicion that what they're actually doing is running. The line between freedom and avoidance has started to blur.", "ex1": "A person who leaves relationships at the two-year mark with the explanation 'I need to grow' — and the growth always looks suspiciously like escape.", "ex2": "Someone who is starting to wonder whether their 'freedom' is a philosophy or a defense mechanism, and doesn't want to examine the question too closely.", "ex3": "A lover who has had fifteen 'meaningful connections' and zero lasting partnerships and is beginning to suspect the common denominator."}, {"n": 2, "name": "Avoidant Freedom", "desc": "Uses 'freedom' as a shield against vulnerability. The exploration isn't curiosity — it's evasion. Every new person is a way to avoid going deeper with the last one. The freedom is a cage with invisible walls.", "ex1": "A person who describes themselves as 'free-spirited' and whose friends describe as 'terrified of intimacy' — both descriptions are accurate, viewed from different angles.", "ex2": "Someone who has optimized their life for maximum freedom and minimum vulnerability, and the optimization has produced an existence that is technically liberated and emotionally hollow.", "ex3": "A lover who has mistaken the absence of commitment for the presence of freedom, not realizing they can be equally imprisoned by the compulsion to never stay."}, {"n": 1, "name": "Imprisoned by Freedom", "desc": "Their refusal to commit has become its own cage. They can't stay and they can't stop moving and the movement has become as compulsive as any addiction. The freedom they crave is the freedom from their own pattern, and it's the one freedom they can't find.", "ex1": "A person who realizes, at 3 AM in yet another new city with yet another new person, that the running and the staying produce the same feeling: trapped.", "ex2": "Someone who has built a life designed to avoid cages and discovers they've built a hamster wheel — constant motion, zero progress, no exit.", "ex3": "A lover who is free the way a lost person is free — no obligations, no anchors, no home, and no idea how to stop moving long enough to build one."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Liberating Love", "desc": "Their freedom becomes a gift to the partner. By loving without possessing, they give the partner permission to be fully themselves — no performance, no restriction, no cage. The partner discovers who they are inside a love that doesn't require they be anything other than what they are.", "ex1": "A lover who says 'go — explore, grow, change — I'll love whoever you become' and the partner discovers, paradoxically, that this freedom makes them want to stay.", "ex2": "Someone whose partner describes the relationship as 'the first time I could breathe' — because the Explorer's freedom created space for the partner's own.", "ex3": "A partner who proves that the opposite of possession isn't abandonment — it's trust."}, {"n": 6, "name": "Encouraging Autonomy", "desc": "Actively supports the partner's independent life. Celebrates their separate adventures, cheers their solo achievements, and never makes the partner's growth feel like a threat to the relationship.", "ex1": "A partner who funds their spouse's solo trip and means the gesture as 'I love you' not as 'I don't need you.'", "ex2": "Someone who introduces the partner to new people and experiences with genuine excitement rather than jealous monitoring.", "ex3": "A lover who has made the partner more adventurous, more confident, and more themselves by simply never trying to make them smaller."}, {"n": 5, "name": "Honest Availability", "desc": "Present when present, honest when distant. The partner always knows where they stand because the Explorer communicates clearly about their needs, their timeline, and their capacity.", "ex1": "A partner who says 'I need a few days to myself' with warmth rather than withdrawal — and returns fully present.", "ex2": "Someone whose partner has learned that the Explorer's absences aren't rejections but recharges, and the returns are always genuine.", "ex3": "A lover who has made honesty into a navigational system: the partner may not always like where the Explorer is, but they always know."}, {"n": 4, "name": "Part-Time Wonderful", "desc": "When they're with the partner, they're magnificent. When they're not, they're genuinely not. The partner gets a wonderful relationship that runs on a part-time schedule — and must decide whether the quality compensates for the quantity.", "ex1": "A partner who is the most attentive, present, generous lover imaginable on Saturdays and genuinely unreachable on Wednesdays — and both modes are authentic.", "ex2": "Someone whose partner describes them as 'the best partner in the world, 60% of the time.'", "ex3": "A lover whose half-presence is better than most people's full presence — and the partner is trying to decide if that math works."}, {"n": 3, "name": "Intermittent Partner", "desc": "Comes and goes with increasing unpredictability. The partner can't build on a foundation that shifts. The Explorer's freedom has become the partner's instability.", "ex1": "A partner who disappeared for a week and returned with souvenirs and no apology — genuinely unaware that the absence caused distress.", "ex2": "Someone whose partner has started making backup plans for every plan because the Explorer's attendance is never guaranteed.", "ex3": "A lover whose freedom has become the partner's anxiety — 'will they show up today?' shouldn't be a daily question in a committed relationship."}, {"n": 2, "name": "Neglectful Freedom", "desc": "So absorbed in their own exploration that the partner has become an afterthought. Not abandoned exactly — just deprioritized below travel, novelty, personal growth, and whatever's next.", "ex1": "A partner who missed their spouse's surgery because they were at a meditation retreat and 'couldn't be reached' — and the hierarchy of priorities it reveals is devastating.", "ex2": "Someone whose partner's birthday, crisis, and major life event all competed with the Explorer's schedule and lost.", "ex3": "A lover who loves freedom more than they love the partner, and both of them are beginning to acknowledge it."}, {"n": 1, "name": "Freedom as Abandonment", "desc": "Their pursuit of freedom has become indistinguishable from abandonment. The partner is technically in a relationship and practically alone. The Explorer has kept the label while discarding the substance.", "ex1": "A partner who is listed as 'in a relationship' on social media and lives functionally as a single person — the Explorer contributes a title and nothing else.", "ex2": "Someone whose partner has stopped expecting anything and started grieving a relationship that's technically ongoing.", "ex3": "A lover who has achieved total freedom and left a partner-shaped wound where a relationship used to be."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Weaponized Freedom", "desc": "Uses their freedom to control the partner through uncertainty. The partner never knows if the Explorer is coming or going, and the uncertainty itself becomes a leash — the partner is constantly waiting, hoping, adjusting.", "ex1": "A lover who keeps the partner in permanent limbo: not committed enough to build on, not absent enough to move on from. The partner is stuck in the doorway while the Explorer comes and goes.", "ex2": "Someone who has discovered that inconsistent availability creates more attachment than consistent presence — and has begun deploying this knowledge strategically.", "ex3": "A partner who uses 'I need my freedom' as the ultimate trump card — it ends every argument, justifies every absence, and cannot be countered without sounding controlling."}, {"n": 6, "name": "Serial Abandonment", "desc": "Engages deeply, then vanishes. The pattern is predictable to everyone except the current partner: deep connection, then sudden departure, then silence. Each time feels unique to the person experiencing it; the Explorer has done this enough times that it's a template.", "ex1": "Someone who has left a trail of people who all describe the same experience: 'They were so present. Then they were gone. No explanation. No closure.'", "ex2": "A lover who experiences the departure as freedom and the partner experiences it as a death — and the mismatch in interpretation is the cruelty.", "ex3": "A partner who has made 'leaving without explanation' into an art form, and the art is devastating to its audience."}, {"n": 5, "name": "Freedom as Excuse", "desc": "Uses 'freedom' to justify any behavior that serves them. Infidelity becomes 'exploration.' Neglect becomes 'independence.' Abandonment becomes 'growth.' The vocabulary of freedom has been emptied of meaning and refilled with self-interest.", "ex1": "A partner who cheated and described it as 'I was honoring my authentic self' — using the language of liberation to avoid the language of betrayal.", "ex2": "Someone who has learned that 'I need to be free' cannot be argued with in modern culture, and deploys it as an ethical force field around selfish behavior.", "ex3": "A lover who has weaponized self-actualization — every harm they cause is rebranded as a journey they're on."}, {"n": 4, "name": "Breadcrumbing", "desc": "Maintains the relationship through minimal, intermittent contact designed to keep the partner hoping without providing enough to build on. A text here, a call there, just enough to prevent closure.", "ex1": "A partner who texts 'thinking of you' once a month — just enough to reset the partner's countdown to moving on.", "ex2": "Someone who has perfected the art of minimum viable relationship: the absolute least amount of connection that prevents the other person from leaving.", "ex3": "A lover who keeps the partner on ice — preserved, waiting, technically still in a relationship that produces nothing."}, {"n": 3, "name": "Comparison Shopping", "desc": "Keeps the partner while actively evaluating alternatives. The partner is a base camp, not a destination — a safe place to return to while scouting for upgrades.", "ex1": "A lover who mentally rates every attractive person they meet against their current partner — and the current partner can feel themselves being weighed.", "ex2": "Someone whose partner has found dating apps on their phone and been told 'I'm just looking, not touching' — and the distinction is supposed to be reassuring.", "ex3": "A partner who has made their current relationship into a waiting room for the next one."}, {"n": 2, "name": "Cruel Departure", "desc": "Leaves with unnecessary damage. Not content to simply go — the Explorer ensures the partner feels responsible, insufficient, or deluded for having expected them to stay. The departure is an argument the Explorer wins on their way out the door.", "ex1": "A lover who ends things with 'I told you I was like this' — converting their own inability to commit into the partner's failure to listen.", "ex2": "Someone who vanishes and, when confronted, says 'you knew who I was when you met me' — as if a warning issued at the beginning excuses all suffering caused thereafter.", "ex3": "A partner who has turned 'I was always honest' into a license for destruction — as if honesty about one's capacity to harm makes the harm acceptable."}, {"n": 1, "name": "Complete Erasure", "desc": "Vanishes so completely the partner is left questioning whether the relationship was real. No closure, no explanation, no trace. The Explorer has exercised their ultimate freedom: the freedom to act as if another person never existed.", "ex1": "A lover who blocked every contact, moved cities, and never responded to a single message — leaving the partner to grieve someone who is alive and choosing to be dead to them.", "ex2": "Someone whose partner discovers they've been erased from social media, from mutual friends' conversations, and from the Explorer's narrative — as if the years together were a dream one party forgot upon waking.", "ex3": "A partner who achieved the purest form of freedom: the freedom from consequences, from accountability, and from the basic human obligation of acknowledging that another person's love was real."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Joyful Landing", "desc": "Receives devotion without feeling trapped by it. The partner's commitment is experienced as a place to rest, not a place to be imprisoned. The Explorer has found someone whose love has doors that open both ways.", "ex1": "A person who says 'your love doesn't feel like a cage — it feels like a harbor' and means it as the highest compliment they know how to give.", "ex2": "Someone who, for the first time, doesn't feel the urge to run when the partner says 'I love you' — the love arrived without walls.", "ex3": "A lover who has found in one person's devotion what they've been looking for across all their wandering: a home that doesn't require them to stop being who they are."}, {"n": 6, "name": "Appreciated Anchor", "desc": "Values the partner's devotion as a complement to their freedom. The partner's steadiness and the Explorer's movement create a dynamic that works — a kite and a string, both essential.", "ex1": "A partner who says 'I need you to be my home base' with gratitude rather than entitlement — and the devoted partner feels honored rather than diminished.", "ex2": "Someone who has learned that receiving devotion is itself a form of generosity — letting someone love you is a gift you give them.", "ex3": "A lover who returns from every adventure genuinely eager to return — because the person waiting has made waiting feel like the most exciting part."}, {"n": 5, "name": "Warm but Guarded", "desc": "Receives devotion with genuine warmth while keeping one eye on the exit. Appreciates the commitment without fully trusting it — or fully trusting themselves to honor it.", "ex1": "A partner who says 'I love that you're so loyal' and the subtext is 'I hope I can deserve it and I'm not sure I can.'", "ex2": "Someone who receives their partner's constancy with a mixture of gratitude and guilt — grateful for what's given, guilty about what they might not be able to return.", "ex3": "A lover whose reception of devotion is sincere and anxious in equal measure."}, {"n": 4, "name": "Comfortable Use", "desc": "Accepts the partner's devotion as the reliable base that enables their freedom. Values it functionally — the partner's loyalty is what lets the Explorer explore. Appreciation is present but increasingly utilitarian.", "ex1": "A partner who appreciates their devoted spouse the way a pilot appreciates a runway: essential, functional, and not where they want to spend their time.", "ex2": "Someone whose reception of devotion has an unspoken 'thank you for holding down the fort while I live my life.'", "ex3": "A lover who is grateful for the stability in the same way they're grateful for good weather — it enables what they actually want to do."}, {"n": 3, "name": "Impatient Reception", "desc": "Receives devotion with growing restlessness. The partner's commitment feels like it's asking for something in return — something the Explorer isn't sure they want to give. The devotion starts to feel like a bill rather than a gift.", "ex1": "A partner who hears 'I'm committed to you' and feels the sentence land not as comfort but as expectation.", "ex2": "Someone who is starting to resent the partner's loyalty because it creates an implicit contract the Explorer didn't sign.", "ex3": "A lover who receives devotion the way a free-range animal receives a collar — it might be soft, but it's still around their neck."}, {"n": 2, "name": "Dismissive Reception", "desc": "Minimizes the partner's devotion as unnecessary or slightly embarrassing. 'You don't have to be so... committed.' The partner's loyalty is treated as an excess — like bringing a winter coat to the beach.", "ex1": "A partner who responds to 'I'll always be here for you' with 'that's nice but I don't need you to be' — and the partner hears the rejection inside the self-sufficiency.", "ex2": "Someone who has made the partner's devotion feel like an imposition — the partner started hiding their commitment the way one hides an unfashionable habit.", "ex3": "A lover who has made loyalty feel uncool — and the partner is now ashamed of the very quality that makes them extraordinary."}, {"n": 1, "name": "Cannot Receive Commitment", "desc": "Devotion triggers flight. The partner's loyalty is experienced as a trap, and the only response is to run. The Explorer cannot hold still long enough to receive what's being offered, and the offering falls to the ground.", "ex1": "A person who has had devotion offered by several extraordinary people and left every one of them — not because the devotion was flawed but because it required them to stay, and staying is the one thing they cannot do.", "ex2": "Someone whose partner finally says 'I can't keep offering love to someone who won't hold it' — and the Explorer watches them go with the terrible recognition that this person was right.", "ex3": "A lover who has made their inability to receive commitment into a permanent state — and the permanence is the cruelest irony of all."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Devotion as Threat", "desc": "Experiences commitment as an existential danger. The partner's love is perceived as an incoming cage, and the Explorer's entire system mobilizes for escape. The terror is real — commitment triggers the same neurological response as physical threat.", "ex1": "A person who had a panic attack when their partner proposed — not from lack of love but from the sensation of a door closing, even a beautiful one.", "ex2": "Someone who breaks out in hives when relationships get serious and has learned to disguise the physiological terror as 'taking things slow.'", "ex3": "A lover who would rather lose the best thing they've ever had than risk the feeling of being captured by it."}, {"n": 6, "name": "Sabotage on Reception", "desc": "Destroys the devotion to prevent it from taking hold. Each time the partner offers commitment, the Explorer does something to undermine it — not from cruelty but from the desperate need to not be held.", "ex1": "A partner who cheats on their most devoted partner, specifically because the devotion was becoming unbearable — the infidelity was an escape attempt, not a desire for the other person.", "ex2": "Someone who starts a fight every time the relationship deepens — the fight is a controlled demolition designed to bring the ceiling back down to a tolerable height.", "ex3": "A lover who has a pattern of destroying the best relationships and keeping the worst ones — because the bad ones never ask them to stay."}, {"n": 5, "name": "Contempt for the Committed", "desc": "Views the devoted partner as pitiable. Someone willing to commit so fully must lack options, imagination, or self-respect. The devotion that should be honored is instead decoded as evidence of the partner's limitations.", "ex1": "A person who privately thinks 'if they had more going on, they wouldn't be so available' — converting the partner's choice to commit into proof of their own limited horizons.", "ex2": "Someone who respects unavailable people and pities available ones — and the pity is relationship poison.", "ex3": "A lover who has made themselves impossible to satisfy because satisfaction would require respect for the person providing it."}, {"n": 4, "name": "Using the Devoted", "desc": "Accepts the partner's commitment as a resource while offering nothing equivalent in return. The devoted partner provides stability, home, care — and the Explorer consumes these while contributing intermittent presence and charming stories about their adventures.", "ex1": "A partner who has a home to return to, a person who manages their life, and a relationship that functions as a rest stop between solo adventures — all provided by someone who gets scraps in return.", "ex2": "Someone whose devoted partner has become unpaid support staff for the Explorer's lifestyle.", "ex3": "A lover who takes everything the devoted partner offers and gives back just enough to prevent departure — the minimum viable exchange."}, {"n": 3, "name": "Punishment for Devotion", "desc": "Makes the partner feel foolish for offering commitment. Each expression of loyalty is met with visible discomfort, subtle mockery, or pointed reminders that the Explorer doesn't 'do' commitment — training the partner to hide their love.", "ex1": "A partner who winces when the other person says 'I love you' in front of friends — not from embarrassment about the relationship but from embarrassment about being claimed.", "ex2": "Someone whose partner has learned to downplay the relationship in public because the Explorer's discomfort with visible commitment is too painful to trigger.", "ex3": "A lover who has made the partner ashamed of loving them — and the shame doesn't reduce the love, it just makes it silent and sad."}, {"n": 2, "name": "Revolving Door", "desc": "Receives devotion, leaves, returns, receives again, leaves again. The devoted partner is trapped in a cycle of hope and abandonment, and each return resets the clock on their recovery.", "ex1": "A lover who shows up after months of silence, says all the right things, stays long enough to rekindle hope, and leaves before the hope can solidify into expectation.", "ex2": "Someone whose partner's friends have started calling them 'the yo-yo' and the partner has started defending the pattern as 'complicated' rather than recognizing it as a cycle.", "ex3": "A partner who returns not from love but from the knowledge that a warm place is waiting — and leaves again once they're warm enough."}, {"n": 1, "name": "Final Flight", "desc": "Leaves for good and takes the partner's capacity for trust with them. The devoted partner, after years of the cycle, is so damaged that they can no longer open themselves to anyone. The Explorer's freedom has been purchased with another person's future.", "ex1": "A person whose ex-partner — the devoted one — is now alone and afraid to love again, and the Explorer is somewhere new, someone new, repeating the pattern, unaware of the wreckage they've left in the harbor.", "ex2": "Someone who will never know that the person they loved and left spent three years in therapy learning to believe that love doesn't automatically mean abandonment.", "ex3": "A lover who exercised their freedom and paid for it with someone else's heart — and the currency exchange rate haunts every relationship that comes after, for both of them."}]}]}, {"name": "The Cage", "factor": "Factor 4: Devotion ↔ Freedom", "factor_num": 4, "pole": "Devotion", "color": "#B05090", "alignment": "Shadow", "tagline": "You belong to me. I call it love.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Warden", "desc": "Has constructed an identity entirely around the possession of another person. Their love IS ownership. They cannot distinguish between devotion and control because, for them, there has never been a difference. Every act of 'love' is an act of containment.", "ex1": "A person who describes their relationship in property metaphors without irony: 'I found them. I claimed them. They're mine.' — and if pressed, would be genuinely confused about why this is alarming.", "ex2": "Someone whose love is so thoroughly intertwined with control that removing the control wouldn't leave love — it would leave nothing.", "ex3": "A lover who has built their entire emotional life around the continued possession of one person, and the architecture would collapse if that person left."}, {"n": 6, "name": "Architect of Containment", "desc": "Designs invisible prisons. Their control is subtle — financial dependency, social isolation, emotional conditioning — and each element is constructed with care and disguised as protection. The cage doesn't look like a cage; it looks like a beautiful home.", "ex1": "A partner who manages all the finances 'because I'm better with numbers,' selects all the friends 'because I know who's good for us,' and makes all the decisions 'because I want what's best for you.'", "ex2": "Someone who has gradually, lovingly, methodically removed every exit from their partner's life — and the partner thanked them for each removal because each one was presented as care.", "ex3": "A lover who builds cages the way an artist builds installations: thoughtfully, beautifully, and with complete conviction that the result is for everyone's benefit."}, {"n": 5, "name": "Jealous Keeper", "desc": "Possessiveness is their dominant emotional mode. Every interaction the partner has with another human is scanned for threat. The jealousy isn't hidden — it's justified through a narrative of past betrayal, personal insecurity, or 'how much I love you.'", "ex1": "A partner who needs to know who texted, who called, who smiled at them in the store — not occasionally but systematically, and not from curiosity but from the specific terror of losing property.", "ex2": "Someone who says 'I only get jealous because I love you so much' with enough sincerity that the partner debates whether this is romantic or a warning sign.", "ex3": "A lover whose jealousy has become the relationship's weather — the partner plans their day around avoiding storms."}, {"n": 4, "name": "Possessive Partner", "desc": "Openly claims the partner in ways that make others uncomfortable. Public displays of ownership disguised as affection. The arm around the shoulder isn't affection — it's a flag planted.", "ex1": "A partner who introduces their spouse to an attractive colleague with a grip that's slightly too tight and a smile that says 'this one's mine' rather than 'this is someone I love.'", "ex2": "Someone who marks territory through social media — constant couple photos, tags, check-ins — not to celebrate the relationship but to broadcast occupation.", "ex3": "A lover whose 'I love you' in public is always said slightly louder than necessary, aimed not at the partner but at everyone else in the room."}, {"n": 3, "name": "Anxious Controller", "desc": "The possessiveness is driven by visible anxiety rather than power. They don't want to control — they're terrified of loss, and control is the only mechanism they've found. The cage is built from panic, not malice.", "ex1": "A partner who calls five times when the other person is an hour late — not from anger but from a genuine spiral that begins with 'what if they're hurt' and ends with 'what if they're leaving.'", "ex2": "Someone who recognizes their jealousy is irrational and still can't stop it — the awareness makes it worse because now they feel crazy AND possessive.", "ex3": "A lover who is trying to stop monitoring their partner's movements and physically cannot, the way an addict cannot stop checking for the substance."}, {"n": 2, "name": "Transparent Possessive", "desc": "The control is visible and clumsy. Everyone can see it — the partner, friends, family. The Cage hasn't mastered subtlety, so the possessiveness shows up as obvious insecurity, public jealousy, and poorly disguised monitoring.", "ex1": "A partner who visibly panics when the other person talks to someone attractive at a party — the reaction is so transparent that friends have started avoiding bringing interesting people to gatherings.", "ex2": "Someone whose jealousy has become a known quantity — friends work around it, the partner manages it, and everyone has adjusted to the emotional weather without anyone naming it as a problem.", "ex3": "A lover whose control attempts are so obvious they occasionally become comic — checking the phone in plain sight, following to the bathroom, interrogating about errands."}, {"n": 1, "name": "Exposed Abuser", "desc": "The possessiveness has become undeniable. Friends have intervened, family has distanced, and the partner — if not yet physically trapped — is socially recognized as being in an unhealthy dynamic. The Cage's behavior is no longer ambiguous.", "ex1": "A person whose partner's friends have collectively decided 'we need to talk to you about your relationship' — the control has become visible enough to mobilize an intervention.", "ex2": "Someone who has been asked to leave a social event because their behavior toward their partner made others uncomfortable — and their response was to blame the partner for attracting attention.", "ex3": "A lover whose possessiveness has crossed from emotional into potentially dangerous territory, and whose partner has started quietly researching exit plans."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Fierce Protection", "desc": "At their absolute best, the Cage's possessive energy becomes protective rather than controlling. They become the person who has your back in every situation — a bodyguard with a lover's heart. Still fundamentally possessive, but the possession manifests as guardianship.", "ex1": "A partner who notices a creepy stranger making their spouse uncomfortable and intervenes with a calm authority that makes the spouse feel genuinely safe.", "ex2": "Someone whose partner says 'I always feel protected with you' and means it in a way that's true and also slightly concerning — because protection that comes from possessiveness has a shelf life.", "ex3": "A lover who channels their territorial instinct into advocacy: fighting for their partner's raise, defending their reputation, clearing obstacles — the energy is still 'mine' but the expression is 'I'll make sure the world treats you right.'"}, {"n": 6, "name": "Dedicated Focus", "desc": "The Cage's obsessive attention becomes devoted study of the partner's needs. They know everything — preferences, triggers, patterns — and use the knowledge for care rather than control. The surveillance instinct redirected into attentiveness.", "ex1": "A partner who anticipates needs with uncanny accuracy because they've been watching with the intensity of someone who considers this person their life's work.", "ex2": "Someone whose detailed knowledge of the partner's inner world makes the partner feel more deeply known than they've ever been — as long as the knowledge isn't weaponized.", "ex3": "A lover who remembers every conversation, every preference, every story — and deploys this archive for kindness rather than leverage."}, {"n": 5, "name": "Controlled Possessiveness", "desc": "The jealousy exists but is being managed. They feel the spike, recognize it, and choose not to act on it. The partner can occasionally see the effort — the jaw clench when someone flirts, the visible self-correction — and respects the work.", "ex1": "A partner who says 'I noticed that bothered me and I'm working on it' — naming the possessiveness without indulging it, which requires more courage than most people appreciate.", "ex2": "Someone who has asked their partner for specific accommodations: 'I know it's my issue, but could you let me know if you'll be late?' — honest about the need, responsible about its management.", "ex3": "A lover who is winning the war against their own possessiveness, one battle at a time, and whose partner can see the victories."}, {"n": 4, "name": "Leashed Jealousy", "desc": "Mostly contains the possessiveness but it leaks. Occasional comments, the odd interrogation disguised as curiosity, the rare ultimatum dressed as a preference. The partner navigates these moments with practiced ease.", "ex1": "A partner who asks 'who was that?' about a phone call with a tone that's 80% casual and 20% investigation — and both people pretend the 20% isn't there.", "ex2": "Someone who has learned to swallow most of their jealousy but whose partner can still taste it in the air after certain situations.", "ex3": "A lover who is mostly fine, mostly trusting, mostly reasonable — and the 'mostly' is where the Cage lives."}, {"n": 3, "name": "Conditional Trust", "desc": "Trusts the partner only within carefully defined parameters. Freedom is granted on a case-by-case basis, with unspoken conditions. The partner is free to do anything, as long as 'anything' doesn't include the specific things that trigger the Cage.", "ex1": "A partner who is 'fine' with solo trips — as long as they're with family. Fine with work dinners — as long as they end by 10. Fine with friendships — as long as they're the same gender. The freedom has a detailed terms-of-service.", "ex2": "Someone whose partner has memorized the invisible rulebook and navigates within its boundaries without ever having been explicitly told the rules exist.", "ex3": "A lover whose trust comes with fine print that grows longer each year."}, {"n": 2, "name": "Escalating Control", "desc": "The boundaries are tightening. What was tolerable jealousy has become increasingly restrictive. Each incident adds a new rule, each accommodation becomes a new baseline, and the partner's world is visibly shrinking.", "ex1": "A partner who started by asking to know about plans and now requires real-time location sharing — the escalation was so gradual that each step seemed reasonable in isolation.", "ex2": "Someone whose partner's social life has contracted year over year, each lost friend accompanied by a plausible-sounding justification provided by the Cage.", "ex3": "A lover who has been slowly adjusting the cage bars closer together and will be genuinely surprised when someone points out the partner can no longer turn around."}, {"n": 1, "name": "Total Imprisonment", "desc": "The partner's life has been reduced to the Cage's perimeter. No independent friends, no unsupervised outings, no private thoughts. The devotion has achieved its final form: complete containment of another human being, accomplished through love's vocabulary.", "ex1": "A lover whose partner has no phone password they don't know, no email they haven't read, no friendship they haven't vetted, and no moment that hasn't been accounted for — and the Cage calls this 'intimacy.'", "ex2": "Someone whose partner's last remaining connection to the outside world is a sibling who has been begging them to leave for years.", "ex3": "A partner who has achieved the possessor's dream — total ownership — and will never understand why the owned thing keeps trying to die."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Soul Ownership", "desc": "Has claimed not just the partner's behavior but their inner life. Polices thoughts, feelings, and desires. The partner must not only be faithful in action but faithful in consciousness — every fantasy, every wandering thought is a betrayal.", "ex1": "A lover who says 'who were you thinking about just now?' with the intensity of someone who considers private thought a form of infidelity.", "ex2": "Someone who has made the partner's inner world a territory to be surveilled — dreams reported, attractions confessed, thoughts audited.", "ex3": "A partner who has so thoroughly colonized the other person's mental life that the partner has started monitoring their own thoughts for disloyalty."}, {"n": 6, "name": "Isolation Architecture", "desc": "Has systematically removed every support structure from the partner's life. Friends alienated, family distanced, career undermined — each loss disguised as the partner's choice, each removal presented as protection.", "ex1": "A lover who turned the partner against their best friend by dripping poison slowly: 'Did you notice how they looked at you? I don't trust their intentions. I'm just looking out for you.'", "ex2": "Someone whose partner's phone contacts have halved in three years and who would swear, under oath, that they never told the partner to stop talking to anyone.", "ex3": "A partner who has created isolation so complete that the partner's only remaining emotional resource is the person who removed all the others."}, {"n": 5, "name": "Punishment Cycle", "desc": "Punishes perceived disloyalty with escalating consequences. Not always physical — silence, withdrawal, emotional explosion, financial restriction. The partner learns the rules by suffering the penalties.", "ex1": "A partner whose evening out with friends is followed by three days of cold silence — teaching, through direct conditioning, that independence has a price.", "ex2": "Someone who responds to the partner getting a text from an unknown number with an interrogation that lasts until 3 AM and ends with the partner apologizing for something they didn't do.", "ex3": "A lover who has established a clear behavioral modification program without using the language of control: the partner simply knows what's allowed and what isn't, learned through punishment rather than conversation."}, {"n": 4, "name": "Reality Distortion", "desc": "Rewrites reality to support the possessive narrative. 'That didn't happen.' 'You're imagining things.' 'I never said that.' The partner begins to doubt their own perceptions because the Cage's version of events is delivered with such conviction.", "ex1": "A partner who insists the controlling conversation never happened — and is so certain that the other person genuinely wonders if they dreamed it.", "ex2": "Someone who has replaced the partner's reality with a version that makes the Cage's behavior reasonable and the partner's complaints irrational.", "ex3": "A lover whose partner has started recording conversations just to confirm that their own experience of events is real."}, {"n": 3, "name": "Degradation", "desc": "Systematically reduces the partner's self-worth to prevent flight. A person who believes they're worthless won't leave because they believe nobody else would want them. The Cage ensures this belief through constant, subtle diminishment.", "ex1": "A partner who 'jokes' about the other person's weight, intelligence, or attractiveness just often enough that the partner's self-image has been rewritten to match.", "ex2": "Someone who says 'who else would put up with you?' and the partner has heard it enough times that they've started answering: nobody.", "ex3": "A lover who has carefully, patiently destroyed the partner's ability to believe they deserve better — the ultimate cage requires no bars when the prisoner doesn't believe they can survive outside."}, {"n": 2, "name": "Threat Escalation", "desc": "When soft control fails, hard threats emerge. Threats to self-harm, threats to harm the partner, threats to harm what the partner loves. The Cage has exhausted subtlety and moved to open coercion.", "ex1": "A partner who says 'if you leave, I'll make sure you never see the kids again' with the calm of someone who has already planned the execution.", "ex2": "Someone who punches a wall during an argument 'to show restraint' — the wall being the message, the restraint being the threat.", "ex3": "A lover who has moved from controlling love to controlled violence, and the next step is visible to everyone except the person inside the cage."}, {"n": 1, "name": "Total Destruction", "desc": "If I can't have you, nobody can. The possessiveness has reached its terminal logic. The partner is not a person — they're a possession, and possessions that try to leave are destroyed. This is where love, twisted past all recognition, becomes the most dangerous thing in the room.", "ex1": "A lover whose partner has started safety planning — memorizing hotline numbers, hiding cash, identifying exit routes — because the devotion that was once a warm room has become a room with a locked door and a person with the key who has started talking about 'if you ever leave.'", "ex2": "Someone whose friends, family, and the legal system are now involved because the Cage's devotion has crossed every line that separates love from danger.", "ex3": "A partner who embodies the terminal truth of shadow devotion: the cage was never about love. It was about the terror of existing without someone to possess."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Briefly Sated", "desc": "When the partner offers genuine, unforced loyalty, the Cage experiences rare peace. The monitoring stops. The anxiety quiets. For a moment, the possessiveness isn't needed because the assurance is complete. It never lasts — but the moment reveals what the Cage is actually looking for underneath the control.", "ex1": "A person whose partner says 'I'm yours, completely, by choice' and for one evening the Cage's fist unclenches — because the voluntariness of the commitment was the thing they needed to hear.", "ex2": "Someone who, when truly assured of the partner's devotion, becomes their best self: warm, generous, relaxed. The contrast reveals that the possessiveness was always a symptom, never the disease.", "ex3": "A lover who needs to feel that the partner's loyalty is absolute and, in the rare moments when they believe it, becomes the person the partner originally fell in love with."}, {"n": 6, "name": "Suspicious Gratitude", "desc": "Receives devotion with visible relief tainted by distrust. Wants to believe it, feels better when they hear it, but can't stop scanning for the lie underneath.", "ex1": "A partner who hears 'I love only you' and feels 60% comforted and 40% certain it's not true — and the 40% will grow louder by morning.", "ex2": "Someone who accepts reassurance the way a gambler accepts a winning hand: glad for the moment, already bracing for the loss.", "ex3": "A lover who is always one perceived slight away from discounting everything the partner has offered."}, {"n": 5, "name": "Never Enough Proof", "desc": "The partner's devotion is received and immediately found insufficient. More evidence required. The Cage's standard of proof is infinite because the anxiety is infinite, and no amount of loyalty can outpace it.", "ex1": "A partner who asks for reassurance, receives it, and immediately needs a different form of it — like drinking salt water, each sip increasing the thirst.", "ex2": "Someone whose partner has taken to wearing their wedding ring more visibly, declining all solo social events, and verbally affirming the relationship daily — and it's still not enough.", "ex3": "A lover whose partner has started to realize the reassurance is a treadmill, not a staircase — no amount of running produces altitude."}, {"n": 4, "name": "Conditional Reception", "desc": "Receives devotion only when it matches a specific format. The partner must prove loyalty in exactly the way the Cage prescribes — wrong format doesn't count, alternative expressions are suspect.", "ex1": "A partner who defines love as 'you should always choose me over your friends' and any deviation from this specific formula, no matter how loving, registers as insufficient.", "ex2": "Someone who has created a checklist of loyalty behaviors and scores the partner daily — the partner doesn't know the checklist exists but can feel themselves being graded.", "ex3": "A lover whose reception of devotion is so narrowly defined that the partner is essentially auditioning, permanently, for a role with requirements that change without notice."}, {"n": 3, "name": "Paranoid Reception", "desc": "Receives devotion while constructing counternarratives. The partner said 'I love you' — but why now? Were they with someone else today? Are they overcompensating? The reception is filtered through a paranoia that converts every gift into potential evidence.", "ex1": "A partner who receives flowers and thinks 'guilt offering' before 'romantic gesture.'", "ex2": "Someone who responds to the partner coming home early with 'why are you here?' in a tone that reveals the unexpected presence is being investigated rather than enjoyed.", "ex3": "A lover who has made the partner's kindness into a source of anxiety — because in the Cage's world, unusual kindness means unusual guilt."}, {"n": 2, "name": "Weaponized Reception", "desc": "Receives devotion and uses it to tighten control. 'You said you loved me — prove it by giving me your passwords.' Each expression of loyalty becomes a door the Cage walks through to claim more territory.", "ex1": "A partner who takes 'I'd do anything for you' literally and begins issuing demands that test the 'anything' systematically.", "ex2": "Someone who converts love declarations into binding agreements: 'You said you only want me — so you won't mind cutting off that friend.'", "ex3": "A lover who has turned the partner's own words of devotion into the bars of the cage — every 'I love you' becomes a commitment that can be enforced."}, {"n": 1, "name": "Devotion Consumed", "desc": "Has consumed the partner's devotion entirely and remains hungry. The partner has nothing left to give and the Cage is still demanding. The receiving has become extraction, and the source is dry.", "ex1": "A partner who has given every password, abandoned every friend, reported every movement, and still receives the question: 'but do you REALLY love me?'", "ex2": "Someone whose partner's devotion has been tested, verified, sacrificed-for, and demonstrated in every conceivable way — and the Cage still doesn't believe it.", "ex3": "A lover who has consumed another person's love the way fire consumes oxygen — completely, leaving nothing breathable."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Ownership Confirmed", "desc": "Receives devotion as proof that the possession is secure. The partner's love is not a gift — it's a property deed renewal. Each 'I love you' is processed as 'I am still yours' and filed accordingly.", "ex1": "Someone who hears 'I'm committed to you' and feels the same satisfaction a landlord feels receiving rent — the arrangement continues, the asset is maintained.", "ex2": "A lover who receives devotion the way a warden receives compliance — as confirmation that the system is working.", "ex3": "A partner whose reception of love has nothing to do with love and everything to do with control verification."}, {"n": 6, "name": "Contempt for the Captured", "desc": "Despises the partner for being so thoroughly possessed. Their devotion, instead of inspiring gratitude, inspires disdain — because someone who can be so completely owned must be worthless.", "ex1": "A person who has fought to keep their partner and, having succeeded, now looks at the kept partner with the specific contempt reserved for things too easily retained.", "ex2": "Someone who wanted the partner's total loyalty and, having gotten it, finds the loyalty revolting — the victory tasted like nothing.", "ex3": "A lover who wanted to own another person and discovered that owned people aren't interesting — they're furniture."}, {"n": 5, "name": "Moving Prison Walls", "desc": "Receives devotion and immediately raises the requirements. Each proof of loyalty becomes the new minimum. The partner is on a treadmill that accelerates with every step — today's extraordinary gesture is tomorrow's bare minimum.", "ex1": "A partner who gave up their gym membership when asked, then their book club, then their weekly call with their mother — each sacrifice becoming the new floor, never the ceiling.", "ex2": "Someone whose partner hasn't left the house alone in months and is told 'but you still text your sister too much.'", "ex3": "A lover whose cage shrinks daily, the walls moving inward imperceptibly, until the partner is standing in a space too small to breathe."}, {"n": 4, "name": "Devotion as Ammunition", "desc": "Stores every act of the partner's loyalty as future leverage. The partner's own love becomes a weapon in the Cage's arsenal.", "ex1": "A partner who remembers every sacrifice the other person made and deploys them in arguments: 'You gave up your friends for me — clearly you don't have anywhere else to go.'", "ex2": "Someone who converts the partner's devotion into evidence of their own power rather than their partner's love.", "ex3": "A lover who keeps a mental inventory of the partner's investments in the relationship and uses the tally as proof the partner can't afford to leave."}, {"n": 3, "name": "Boredom with the Captive", "desc": "Having fully secured the partner's loyalty, the Cage loses interest. The hunt is over. The possession is confirmed. What remains is a person they own and no longer desire. The cage is maintained from habit, not from want.", "ex1": "A partner who fought viciously to keep someone who they now ignore — the possessiveness remains active while the interest has flatlined.", "ex2": "Someone who would still explode if the partner tried to leave but wouldn't notice if the partner was happy or sad — the territorial reflex outlives the caring.", "ex3": "A lover who keeps what they've caught the way a cat keeps a dead bird — not for use, just for proof."}, {"n": 2, "name": "New Target Acquisition", "desc": "Has begun redirecting possessive energy toward someone new while maintaining the cage around the current partner. The partner is still imprisoned; the Cage's attention has simply moved to the next acquisition.", "ex1": "A lover who begins the cycle with a new person while the current partner remains locked in — not freed, not attended to, just stored.", "ex2": "Someone whose partner realizes they haven't been spoken to in weeks not because the Cage is angry but because the Cage has found a new target to control.", "ex3": "A partner who will keep the current possession while acquiring a new one — because cages, for this person, are collectible."}, {"n": 1, "name": "Final Lock", "desc": "Receives the partner's final, depleted offering of loyalty and secures the cage permanently. The partner will never leave, never recover, never rebuild. The Cage has won. What they've won is a broken person in a locked room, and the person who locked the door can't understand why the room feels so empty.", "ex1": "A lover who looks at the hollowed-out person they've possessed and feels not satisfaction but a vast, unnamed loss — the thing they wanted is the thing they destroyed in the wanting.", "ex2": "Someone who finally has everything they fought for and discovers that everything, when obtained through ownership, amounts to nothing.", "ex3": "A partner whose final victory is a life shared with someone who is present in body and absent in every dimension that makes presence worth having."}]}]}, {"name": "The Ghost", "factor": "Factor 4: Devotion ↔ Freedom", "factor_num": 4, "pole": "Freedom", "color": "#50A0A0", "alignment": "Shadow", "tagline": "I was never really here.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Vanishing Point", "desc": "Has perfected the art of not-being-there while technically present. They exist in relationships the way a rumor exists in a room — sensed but unconfirmable. People who love them describe trying to hold smoke.", "ex1": "A person who can be in a room, a conversation, a relationship, and leave no trace — their presence is so provisional that when they're gone, people question whether they were ever really there.", "ex2": "Someone whose exes all tell the same story: 'I can't even describe what went wrong. They were just... gone. One day they were there and one day they weren't, and I couldn't tell you when the shift happened.'", "ex3": "A lover who has turned ghosting into an identity — not just a behavior they do to others but a state of being they inhabit."}, {"n": 6, "name": "Smoke", "desc": "Enters relationships with one foot already out the door. Gives just enough to maintain connection while keeping escape routes constantly available. The investment is always below the threshold where leaving would be difficult.", "ex1": "A person who never fully moves in, never fully commits, never fully unpacks — metaphorically and literally. Three years in, their belongings are still in boxes and their partner has stopped asking about it.", "ex2": "Someone who has a mental exit strategy for every relationship they're in, the way frequent flyers know every emergency exit on the plane.", "ex3": "A lover who is present the way a temporary employee is present — doing the work, avoiding the Christmas party, one eye on the next opportunity."}, {"n": 5, "name": "Half-Present", "desc": "There but not there. Partners describe a persistent feeling of incompleteness — the Ghost shows up, says the right things, does the right things, and there's a quality of absence underneath it all that the partner can sense but never quite identify.", "ex1": "A partner who is physically attentive and emotionally offshore — the body is here, the real person is somewhere else, and the somewhere-else is permanent.", "ex2": "Someone who goes through the motions of intimacy with the competence of someone who has watched others do it but hasn't felt it from inside.", "ex3": "A lover whose partner describes a persistent sense of 'being alone together' that they can't resolve and the Ghost can't explain."}, {"n": 4, "name": "Fading", "desc": "Their presence in relationships diminishes over time. The first month is full — the first year is good — the second year is distant — by year three they're a shadow of the person the partner met. The fading isn't dramatic; it's glacial.", "ex1": "A person whose partners all describe the same trajectory: 'They were so present at first. Then they just... faded. Like a photograph left in the sun.'", "ex2": "Someone who gives a hundred percent in month one and twelve percent in year two, and the decline was so gradual the partner kept adjusting to the new normal.", "ex3": "A lover who is brightest at the beginning and dimmer ever after — a relationship supernova that collapses into a dim star."}, {"n": 3, "name": "Pre-Ghosting", "desc": "Already preparing to leave a relationship they haven't committed to leaving yet. Mentally packing. Emotionally withdrawing. The partner can feel the departure beginning the way animals sense weather changes — something is shifting, and it's not good.", "ex1": "A partner who has started spending more time alone, giving shorter answers, and making fewer plans — the withdrawal is visible to the partner and invisible to the Ghost, who doesn't know they're leaving yet.", "ex2": "Someone whose partner has started asking 'is everything okay?' and whose answer — 'fine' — is the Ghost's version of a goodbye they haven't written yet.", "ex3": "A lover who is still present and already gone — the departure is happening in the space between conversations."}, {"n": 2, "name": "Serial Ghost", "desc": "Has a pattern of vanishing so established it could be mapped. Enter relationship, warm up, connect, disappear. Enter relationship, warm up, connect, disappear. Each partner is certain they'll be different. None of them are.", "ex1": "A person with a trail of bewildered exes who all have the same question: 'What happened?' — and the answer is nothing happened. The Ghost did what ghosts do.", "ex2": "Someone whose friends have started declining to introduce them to new people because the introduction always ends the same way.", "ex3": "A lover who is the human equivalent of a rental car: used temporarily, returned without damage, and rented by the next person who has no idea it's been around the lot before."}, {"n": 1, "name": "Already Gone", "desc": "Has achieved a permanent state of emotional absence. Even in the room, even in the relationship, even in the conversation — they're not there. The Ghost has become their nature rather than their behavior. There is no solid version underneath the smoke.", "ex1": "A person who sits across from their partner at dinner and both of them know that the person in the chair is a projection — the real person, if there is one, checked out long ago.", "ex2": "Someone whose partner has grieved the relationship while still in it, because the person they fell in love with was apparently a temporary performance that has ended.", "ex3": "A lover who was never fully real and whose departure, when it comes, will feel less like a loss and more like the end of a hallucination."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Momentary Presence", "desc": "In rare, brief moments, the Ghost is fully present — and these moments are so vivid that the partner builds their entire hope on them. A flash of real connection, real vulnerability, real presence. It never lasts, but when it appears, it's incandescent.", "ex1": "A lover who, during a long drive at midnight, suddenly says something so vulnerable and real that the partner's breath catches — and by morning, the walls are back up as if the moment never happened.", "ex2": "Someone who, once a year, on some unpredictable night, is suddenly, entirely there — and the partner realizes this is the person underneath the Ghost, and they're worth waiting for. Or so the partner tells themselves.", "ex3": "A partner whose rare appearances of genuine presence are so extraordinary they function as breadcrumbs leading the partner deeper into the forest."}, {"n": 6, "name": "Gentle Distance", "desc": "Maintains a polite, kind, slightly warm distance that the partner can tolerate if they don't need much. The Ghost isn't unkind — they're simply not there. What they do offer is genuine if insufficient.", "ex1": "A partner who always responds thoughtfully to questions, always follows through on explicit commitments, and never, ever volunteers emotional depth without being asked.", "ex2": "Someone who is the world's best casual companion and the world's worst intimate partner — the first three inches are wonderful and everything below that is vapor.", "ex3": "A lover who makes the partner feel liked but never loved — warmly acknowledged but never held."}, {"n": 5, "name": "Disappearing Act", "desc": "Alternates between present and absent with no clear pattern. The partner never knows which version they're getting — the person who shows up for dinner or the person who forgets they made plans.", "ex1": "A partner who is reliably unreliable — the inconsistency has become the only consistent thing.", "ex2": "Someone whose partner has developed a split-screen life: the version where the Ghost is present, and the backup version for when they're not.", "ex3": "A lover who is wonderful when they appear and devastating when they vanish — and the partner is addicted to the appearing."}, {"n": 4, "name": "Functional Minimum", "desc": "Provides the absolute minimum a relationship requires. Shows up to events (sometimes). Responds to texts (eventually). Says 'I love you' (when prompted). The relationship runs on fumes, and the Ghost doesn't seem to notice.", "ex1": "A partner who does just enough to prevent a breakup conversation and not a fraction more.", "ex2": "Someone whose partner has started measuring the relationship's health by the Ghost's lowest moments rather than their best — because the lows are the norm.", "ex3": "A lover whose bar for 'being a good partner' is so low it's underground."}, {"n": 3, "name": "Emotional Vapor", "desc": "The partner reaches for something and finds air. The Ghost's emotional presence has thinned to the point where contact produces nothing — no resistance, no warmth, no feedback. Reaching for them is reaching into fog.", "ex1": "A partner who is asked 'what are you feeling right now?' and genuinely cannot answer because the feeling register has been so long unused it doesn't produce readable output.", "ex2": "Someone whose partner has started talking to them in shorter sentences because long sentences get lost in the distance.", "ex3": "A lover whose partner has started treating the relationship the way one treats a flight delay: waiting, hoping, accepting it might not happen."}, {"n": 2, "name": "Pre-Departure Withdrawal", "desc": "Has already left and hasn't informed the partner. The emotional departure happened weeks or months ago; the physical departure is a formality that hasn't been completed. The partner is in a relationship with an afterimage.", "ex1": "A partner who is present at dinner but has already mentally moved out — the body at the table is a placeholder, not a person.", "ex2": "Someone whose partner catches them staring at the door with an expression that isn't longing but planning.", "ex3": "A lover who has ghost-written their goodbye letter in their head and is just waiting for the right moment to deliver it — or, more likely, to simply stop appearing."}, {"n": 1, "name": "Gone Without Notice", "desc": "Vanished. The partner wakes up one day — metaphorically or literally — and the Ghost is gone. No fight, no letter, no explanation. Just absence where a person used to be. The partner is left to grieve someone who can't be confirmed as dead because they were never fully confirmed as alive.", "ex1": "A person who changed their phone number, moved apartments, and told mutual friends 'I need a fresh start' — leaving their partner to piece together what happened from silence and secondhand information.", "ex2": "Someone whose partner spent months wondering if they'd been in an accident before accepting that the disappearance was voluntary — and voluntary absence is worse than any accident.", "ex3": "A lover who proved their archetype name by becoming one: a ghost, haunting the partner's memory, never returning to explain."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Haunting", "desc": "Returns after ghosting — not to reconcile but to check if the partner is still affected. Drops a text, appears at a gathering, likes an old photo. The contact isn't reconnection; it's verification that they still exist in the partner's world.", "ex1": "A lover who texts 'I miss you' at 2 AM six months after vanishing — not because they want the partner back but because they want to know the partner still wants them.", "ex2": "Someone who appears at the edge of the partner's social life like a specter — not close enough to touch, not far enough to forget.", "ex3": "A partner who has perfected a specific form of cruelty: keeping the wound open by periodically confirming their existence without offering their presence."}, {"n": 6, "name": "Return Cycle", "desc": "Ghosts and returns cyclically, each time with enough charm to re-engage the partner and enough absence to re-traumatize them. The cycle becomes the relationship — not the moments together, but the pattern of appearing and vanishing.", "ex1": "A lover who returns with 'I've changed' just often enough that the partner keeps believing it and just rarely enough that the partner never recovers.", "ex2": "Someone whose partner has PTSD symptoms triggered by their ringtone — because the ringtone represents both hope and devastation in equal measure.", "ex3": "A partner who treats the relationship like a game save file — they can exit anytime and resume from wherever they left off, never considering that the other player was stuck on the loading screen."}, {"n": 5, "name": "Blame the Haunted", "desc": "Makes the partner responsible for the ghosting. 'You were too much.' 'You pushed me away.' 'If you'd given me space, I wouldn't have had to leave.' The partner's grief and confusion are reframed as the cause of the Ghost's departure.", "ex1": "A lover who says 'your neediness drove me away' to someone whose only need was basic communication — and the partner believes it.", "ex2": "Someone who has convinced their partner that being ghosted is a natural consequence of wanting too much, teaching the partner to want less rather than demanding the Ghost show up more.", "ex3": "A partner who has externalized their own absence and made the partner carry it as shame."}, {"n": 4, "name": "Emotional Torture", "desc": "Maintains just enough presence to prevent healing. The partner can't move on because the Ghost isn't fully gone — but can't move forward because the Ghost isn't fully present. The limbo is the cruelty.", "ex1": "A partner who responds to one in three messages, shows up to one in five plans, and offers one genuine moment per month — the ratio is precisely calibrated to prevent both departure and arrival.", "ex2": "Someone whose partner's therapist has started calling it 'ambiguous loss' — mourning someone who isn't dead, loving someone who isn't there.", "ex3": "A lover who has trapped the partner in a waiting room with no magazine and no schedule posted — just an assumption that eventually, someone will call their name."}, {"n": 3, "name": "Scorched Absence", "desc": "Vanishes and takes things with them. Not just their presence — shared memories, mutual friends, and the partner's confidence. The departure is designed to leave maximum damage.", "ex1": "A lover who ghosts and then tells mutual friends a version of the relationship that makes the partner sound unhinged, ensuring the partner loses both the Ghost and their support network.", "ex2": "Someone who disappears and then changes the narrative — 'I had to get out' — without specifying what they were getting out of, leaving the partner to defend themselves against unspecified accusations.", "ex3": "A partner who managed to be both absent and destructive — gone from the room but still setting fires."}, {"n": 2, "name": "Identity Theft", "desc": "Takes parts of the partner's identity with them when they vanish. Shared dreams, private jokes, intimate knowledge — all carried away by someone who won't return them and won't stop existing in the world with this stolen information.", "ex1": "A lover whose ex-partner realizes that their most private stories are now circulating in a social circle they have no access to — the Ghost took their vulnerabilities as souvenirs.", "ex2": "Someone who knows the partner's deepest secrets and has removed all the partner's ability to manage that exposure — the knowledge is out there, carried by a ghost.", "ex3": "A partner who has left the other person exposed, not through malice but through the simple fact of disappearing while holding someone's trust."}, {"n": 1, "name": "Permanent Haunt", "desc": "Has destroyed the partner's ability to trust presence. The partner will spend years flinching when people are kind, bracing for disappearance, unable to believe that someone who shows up today will show up tomorrow. The Ghost's legacy is a person who can never fully trust again.", "ex1": "Someone whose partner develops a specific anxiety: the moment things are going well, the terror begins. Good becomes the precursor to gone.", "ex2": "A lover whose ex-partner now sabotages their own relationships — leaving before being left, ghosting before being ghosted — infected by the Ghost's pattern.", "ex3": "A partner who has successfully exported their own inability to be present into another person's permanent inability to feel safe."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Miracle of Reception", "desc": "Someone's love breaks through. The Ghost feels it — actually feels it — and the feeling is so foreign it almost registers as pain. A moment of genuine connection with a person whose love was persistent enough and safe enough to reach the Ghost's actual self.", "ex1": "A person who has been unreachable for decades and is suddenly, unexpectedly reached — and the sensation of being known produces tears they can't explain and won't try to.", "ex2": "Someone whose partner's years of patient, undemanding love finally found a crack in the Ghost's architecture — and the light coming through changes everything, or could.", "ex3": "A lover who has been absent their entire life and, in one moment of genuine reception, understands what they've been missing — and the understanding is devastating."}, {"n": 6, "name": "Brief Materialization", "desc": "Allows themselves to be partially present for the partner's devotion. Doesn't fully receive but doesn't fully block. A temporary state of semi-presence that gives the partner hope and the Ghost just enough connection to remember what it feels like.", "ex1": "A partner who holds the Ghost's hand and feels, for a moment, the grip tighten — and knows that the tightening is a message from a person usually submerged.", "ex2": "Someone who stays for breakfast after usually leaving at midnight — and the staying is so unusual that the partner treats it like a visitation from another realm.", "ex3": "A lover who is learning, very slowly, that presence doesn't always lead to capture."}, {"n": 5, "name": "Flickering Reception", "desc": "Receives devotion intermittently — moments of warmth interrupted by periods of complete disconnection. The partner learns to catch the moments and let go of the gaps.", "ex1": "A partner who is available for one deep conversation per month and otherwise operates in low-power mode.", "ex2": "Someone whose reception of love comes in bursts that are vivid enough to sustain the partner through the dead periods — barely.", "ex3": "A lover whose partner has become an expert at reading micro-expressions of openness and rushing in before the window closes."}, {"n": 4, "name": "Minimum Reception", "desc": "Accepts the absolute minimum of devotion that the relationship requires to technically exist. A text acknowledged, a birthday remembered, a presence tolerated. Not cold — just barely warm.", "ex1": "A partner who receives 'I love you' the way they receive a weather report: noted, not internalized.", "ex2": "Someone whose partner has calibrated their emotional output to the Ghost's intake capacity — tiny portions, carefully timed.", "ex3": "A lover who can metabolize approximately one tablespoon of devotion per week, and anything more produces a shutdown."}, {"n": 3, "name": "Deflected Devotion", "desc": "Redirects incoming devotion away from themselves. Changes the subject when love is offered, makes a joke when the moment gets deep, becomes suddenly very busy when presence is requested.", "ex1": "A partner who responds to 'I want to spend my life with you' with 'have you seen the new season of that show?' — and the redirect is so smooth the partner almost doesn't notice.", "ex2": "Someone whose avoidance of emotional reception has become an art form — each deflection is seamless, practiced, and devastating in its elegance.", "ex3": "A lover whose partner has stopped trying to deliver love directly and has started leaving it at the door like a package, hoping it gets opened eventually."}, {"n": 2, "name": "Allergic to Love", "desc": "Devotion triggers a withdrawal response. The more the partner offers, the less the Ghost can tolerate. Being loved is a stimulus they're averse to — like sunlight to a creature that has lived too long in the dark.", "ex1": "A person who physically retreats when embraced, emotionally retreats when confessed to, and relationally retreats when committed to — the love is the trigger and the leaving is the response.", "ex2": "Someone whose partner's love has become the thing that drives them away, creating a precise inverse relationship: more love = more distance.", "ex3": "A lover who would rather be alone than loved, because loneliness is a known quantity and love is an incoming threat."}, {"n": 1, "name": "Impervious", "desc": "Nothing reaches the Ghost. Devotion arrives and passes through them the way light passes through glass. They are transparent to love. The partner's commitment is received by no one — and the Ghost may not even know they're not receiving, because not-receiving has been the default state for so long it feels like normal.", "ex1": "A person who has been loved — genuinely, faithfully, patiently — and is unable to report a single instance of feeling it. The love happened. The reception didn't.", "ex2": "Someone who will one day look back on a life full of people who loved them and feel nothing — not regret, not gratitude, not loss — because feeling requires a self that was never quite assembled.", "ex3": "A lover who is the final proof that love requires a receiver, and some receivers were never built, or were built and broken, or were broken and never repaired."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Weaponized Vanishing", "desc": "Uses their own ability to disappear as the ultimate threat. The partner's devotion is held hostage by the Ghost's capacity for absence — 'love me on my terms or I'll become smoke.'", "ex1": "A lover who has trained the partner that any demand, any boundary, any assertion of need will be met with vanishing — and the partner has stopped demanding, stopped asserting, stopped needing.", "ex2": "Someone who has made their own unreliability into the relationship's primary control mechanism — they don't need to be present because the threat of absence does all the work.", "ex3": "A partner who governs through the possibility of disappearance the way a dictator governs through the possibility of violence — the act itself is rarely necessary because the threat is always enough."}, {"n": 6, "name": "Soul Collection", "desc": "Returns periodically to collect emotional energy from the partner and then disappears again to consume it alone. The partner is a charging station — the Ghost arrives depleted, absorbs warmth, and leaves once full.", "ex1": "A lover who shows up, devastated and needy, and the partner pours everything into them — and then the Ghost vanishes with the full emotional tank and doesn't return until it's empty again.", "ex2": "Someone whose partner has realized they're being used as an emotional gas station: the Ghost pulls in when the gauge reads empty and drives off once filled.", "ex3": "A partner who takes without reciprocating, not from greed but from a genuine inability to produce their own emotional sustenance."}, {"n": 5, "name": "Gaslighting Absence", "desc": "Denies the impact of their absence. 'I wasn't gone that long.' 'You're being dramatic.' 'I said I'd come back and I did.' The partner's pain from the disappearance is dismissed, minimized, or turned into evidence of the partner's dysfunction.", "ex1": "A partner who vanished for two weeks and responds to the other person's distress with 'I needed space — you should be more secure than this' — converting their abandonment into the partner's failing.", "ex2": "Someone who has made the partner doubt whether absence is actually harmful — 'healthy couples don't need to be in constant contact' deployed to normalize ghosting.", "ex3": "A lover who has rewritten the rules of the relationship so that their disappearances are normal and the partner's distress about them is the problem."}, {"n": 4, "name": "Competitive Absence", "desc": "The partner's devotion is received as a dare: can you love me through THIS disappearance? And THIS one? Each return raises the stakes — the Ghost vanishes longer, with less notice, and the partner's continued presence upon return is processed as score rather than love.", "ex1": "A lover who unconsciously extends each absence to test the partner's threshold — three days becomes a week becomes a month — and each time the partner is still there, the Ghost feels a mixture of relief and contempt.", "ex2": "Someone who has turned the partner's faithfulness into a game they're winning, without realizing the game is destroying the person who keeps playing.", "ex3": "A partner who receives devotion as proof of power rather than evidence of love."}, {"n": 3, "name": "Discarding Devotion", "desc": "Receives and discards the partner's love like junk mail. Each expression of commitment arrives, is glanced at, and is thrown away. The partner keeps sending and the Ghost keeps discarding, and neither of them changes the pattern.", "ex1": "A partner who reads the heartfelt text, thinks 'nice,' and doesn't respond — not from cruelty but from a genuine inability to process the content as meaningful.", "ex2": "Someone whose partner has written letters, made gestures, created experiences — all of which entered the Ghost's awareness and immediately evaporated.", "ex3": "A lover whose mailbox is full of love and whose house is empty of feeling."}, {"n": 2, "name": "Mocking the Devoted", "desc": "Finds the partner's continued devotion pathetic and occasionally says so. The partner's love, which has survived ghosting, neglect, and absence, is met not with gratitude but with contempt for persisting.", "ex1": "A lover who says 'I don't know why you're still here' — and the partner hears it as cruelty, and the Ghost means it as a genuine question, and neither interpretation helps.", "ex2": "Someone who views the partner's faithfulness as evidence of their own skill at manipulation rather than evidence of the partner's love.", "ex3": "A partner who has made the other person's devotion into a joke — and the joke is on the person who loved them most."}, {"n": 1, "name": "Final Disappearance", "desc": "The Ghost's ultimate act: total, permanent, irreversible vanishing. No closure. No forwarding address. No acknowledgment that the relationship, the partner, or the years existed. They become what they always were — nothing — and leave the partner to reconstruct a life from the wreckage of loving a person who was never fully there.", "ex1": "A person who erased their existence from the partner's life so completely that the partner sometimes wonders if they invented the whole thing — if the love, the moments, the years were a hallucination.", "ex2": "Someone who achieves the Ghost's terminal fantasy: becoming nobody, owing nothing, mattering to no one — and the freedom they've won is indistinguishable from nonexistence.", "ex3": "A lover who proved, in the end, that their archetype was always a prophecy: they were never really here, and now they're really not."}]}]}, {"name": "The Commander", "factor": "Factor 5: Dominance ↔ Submission", "factor_num": 5, "pole": "Dominance", "color": "#A06030", "alignment": "Healthy", "tagline": "I lead because you trust me to.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Sovereign Authority", "desc": "Their dominance is so integrated into who they are that it never needs to be asserted — it's simply present, the way gravity is present. People orient around them naturally. In intimacy, this translates to a calm, total confidence that makes surrender feel like the safest possible choice.", "ex1": "A lover whose partner describes the experience of being with them as 'I didn't decide to let go — I just realized I already had, because the space they created made holding on unnecessary.'", "ex2": "Someone who takes charge in the bedroom, in decisions, in crises — not by seizing power but by occupying it so naturally that the partner's yielding feels like physics, not politics.", "ex3": "A partner whose authority is so grounded that it never wavers, never postures, and never needs to prove itself — the proof is in how safe everyone feels in its presence."}, {"n": 6, "name": "Attuned Leader", "desc": "Leads with exquisite sensitivity to the partner's responses. Their dominance is a conversation, not a monologue — they read the room, adjust in real time, and their confidence is informed by deep attentiveness to the person yielding to them.", "ex1": "A lover who can tell from a shift in breathing whether to push forward or pull back, and whose adjustments are so seamless the partner feels guided rather than managed.", "ex2": "Someone who takes the lead in planning, deciding, and directing — but whose leadership always contains the question 'does this work for you?' asked through attention rather than words.", "ex3": "A partner whose dominance is a dance rather than a march — structured, rhythmic, and always responsive to the other body in the room."}, {"n": 5, "name": "Confident Lead", "desc": "Takes charge comfortably and competently. Makes decisions, sets the pace, holds the frame. Occasionally misjudges the partner's readiness or pushes slightly past comfort — but the intention is always care, and the corrections are swift.", "ex1": "A partner who plans the evening, chooses the restaurant, and orders for both of them — sometimes getting it exactly right, sometimes slightly off, always with confidence that the partner finds attractive even when the choice isn't perfect.", "ex2": "Someone who leads in the bedroom with enthusiasm and skill, occasionally missing a signal but always responsive when it's pointed out.", "ex3": "A lover whose partner says 'I love that you take charge' and means it ninety percent of the time, with the other ten percent being moments the Commander course-corrects."}, {"n": 4, "name": "Comfortable Authority", "desc": "Naturally gravitates toward the leading role in the relationship. Makes most decisions, sets most agendas, and holds most of the structural power — not by negotiation but by default. The partner is generally content but the arrangement hasn't been examined.", "ex1": "A couple where one person always drives, always orders, always chooses the movie — and both are comfortable with this until someone asks 'when did you decide this?' and neither can answer.", "ex2": "Someone whose leadership has become so assumed that the partner has stopped offering input — not from suppression but from the path of least resistance.", "ex3": "A lover whose authority has settled into routine, effective and unchallenged, comfortably unexamined."}, {"n": 3, "name": "Stiffening Authority", "desc": "The leadership has started to become rigid. Less responsive to the partner's input, less willing to adjust. The confidence that once felt like safety has developed an edge of inflexibility.", "ex1": "A partner who responds to 'can we try something different?' with 'what we do works fine' — and the partner hears the door closing on a conversation that should stay open.", "ex2": "Someone whose dominance has lost its conversational quality and become more like a broadcast — transmission without reception.", "ex3": "A lover whose partner has started going along with things they'd prefer to push back on, because pushing back has become more effortful than it used to be."}, {"n": 2, "name": "Brittle Authority", "desc": "Their dominance has become defensive. Challenges to their leadership are experienced as threats rather than information. The confidence is still present but it's covering uncertainty — and the covering is visible.", "ex1": "A partner who responds to 'I think you're wrong about this' with disproportionate force — not because the disagreement is serious but because being wrong feels like being diminished.", "ex2": "Someone whose need to be right has started to eclipse their ability to be responsive, and the partner has begun to walk on eggshells around opinions.", "ex3": "A lover whose authority depends increasingly on the partner's compliance rather than on their own competence — and the dependency shows."}, {"n": 1, "name": "Empty Command", "desc": "Claims authority they no longer embody. The leadership is a title without a kingdom — they insist on leading but nobody trusts the direction. In intimacy, they perform dominance that rings hollow, and the partner's compliance is pity rather than trust.", "ex1": "A partner who still makes all the decisions but the decisions have become consistently poor, and the other person follows out of habit and exhaustion rather than confidence.", "ex2": "Someone who demands the dominant role because they've always had it, not because they're currently qualified for it — and the gap between claim and competence has become the relationship's open secret.", "ex3": "A lover whose authority has become costume rather than character — they dress as a leader but neither person believes the outfit anymore."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Sacred Stewardship", "desc": "Holds the partner's trust as the most valuable thing they've ever been given. Their dominance is exercised as stewardship — every decision, every direction, every command is filtered through 'does this serve the person who trusted me with this power?'", "ex1": "A lover who pushes the partner past their comfort zone in ways that produce growth, not trauma — and the partner, looking back, says 'they saw what I could become before I did.'", "ex2": "Someone who uses their authority to create a space where the partner can be utterly vulnerable, utterly safe, and utterly free within the structure the Commander provides.", "ex3": "A partner whose dominance makes the other person MORE themselves, not less — the authority liberates rather than constrains."}, {"n": 6, "name": "Protective Command", "desc": "Leads with the partner's wellbeing as the primary directive. Scans for threats, anticipates needs, and uses their authority to create safety. The partner feels both led and sheltered.", "ex1": "A partner who navigates social situations for their introverted spouse — ordering for them at restaurants, managing conversations, creating exits — not from control but from attentive protection.", "ex2": "Someone who takes charge during crises with calm competence that allows the partner to fall apart without consequence — the Commander holds the frame while the partner processes.", "ex3": "A lover who says 'I've got this — you can let go' and the partner's body believes it before their mind does."}, {"n": 5, "name": "Active Direction", "desc": "Provides clear, confident guidance that the partner finds stabilizing. Makes plans, sets expectations, holds structure — and the partner thrives inside the architecture because it's built with them in mind.", "ex1": "A partner who plans vacations down to the restaurant reservation, and the partner's only job is to show up — and the partner describes this as the most relaxing experience of their life.", "ex2": "Someone who gives the partner clear feedback: 'I loved when you did this. Do more of that' — and the clarity, rather than feeling controlling, feels like being seen.", "ex3": "A lover whose directions are specific enough to follow and flexible enough to breathe inside."}, {"n": 4, "name": "Comfortable Control", "desc": "Maintains a comfortable level of leadership that both parties have settled into. The partner is generally happy to follow and the Commander is generally skilled at leading. The dynamic works but hasn't been stress-tested recently.", "ex1": "A couple whose roles are clearly defined — one leads, one follows — and the arrangement has the comfort of a well-worn groove and the staleness of one too.", "ex2": "Someone whose partner feels secure in the dynamic but occasionally wonders what it would feel like to lead — a curiosity they haven't voiced because the current arrangement works.", "ex3": "A lover whose command has become so predictable that the partner can anticipate every decision, which is both comforting and slightly deadening."}, {"n": 3, "name": "Autopilot Leadership", "desc": "Leading out of habit rather than attentiveness. The Commander still makes decisions but has stopped checking whether the decisions land well. The partner's input has been unconsciously deprioritized.", "ex1": "A partner who plans every weekend without consulting the other person — not from dominance but from the assumption that their choice IS the couple's choice, an assumption that's been unchallenged long enough to fossilize.", "ex2": "Someone who runs the relationship the way a manager runs a routine operation: efficiently, impersonally, without checking whether the employees are satisfied.", "ex3": "A lover whose leadership has become bureaucratic — structured, functional, and devoid of the attentiveness that once made it feel like care."}, {"n": 2, "name": "Dismissive Command", "desc": "Leads while minimizing the partner's contributions. The Commander's confidence has tipped into condescension — the partner's opinions are heard but not weighted, their preferences noted but not prioritized.", "ex1": "A partner who responds to suggestions with 'that's cute, but here's what we're actually going to do' — and the 'cute' contains just enough diminishment to sting without being confrontable.", "ex2": "Someone who has started treating the partner's input as optional commentary on decisions already made.", "ex3": "A lover whose leadership has become unilateral in a way that makes the partner feel like a passenger rather than a co-pilot."}, {"n": 1, "name": "Domineering", "desc": "The leadership has lost all responsiveness. The Commander dictates rather than leads, and the partner's role has been reduced from willing follower to silent audience. The authority is maintained through force of habit and the partner's exhaustion with resistance.", "ex1": "A partner who makes every decision — financial, social, domestic, sexual — without input, and responds to objections with a weariness that communicates 'this isn't a discussion.'", "ex2": "Someone whose partner has stopped participating in decisions because participation is meaningless — the Commander will do what they want regardless.", "ex3": "A lover whose dominance has become dictatorship, and the partner's compliance is resignation, not trust."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Benevolent Dictatorship", "desc": "Controls every aspect of the partner's life while genuinely believing it's for their benefit. The Commander's intentions are good; their execution is totalitarian. The partner is well-cared-for and completely powerless.", "ex1": "A lover who has optimized their partner's diet, schedule, career decisions, and social life — all improvements, all imposed, none requested. The partner is healthier, wealthier, and utterly without agency.", "ex2": "Someone who says 'trust me, this is best for you' about everything from wardrobe choices to career moves — and they're often right, which makes the control harder to resist and harder to name.", "ex3": "A partner who has built a beautiful life for two people using only one person's blueprint."}, {"n": 6, "name": "Condescending Authority", "desc": "Leads while subtly communicating that the partner isn't capable of leading themselves. The dominance has acquired a parental tone — protective in a way that implies the partner is a child requiring guidance.", "ex1": "A partner who explains things to their spouse in a simplified tone, manages their money 'because you're not great with numbers,' and makes decisions 'because you'd just stress about it.'", "ex2": "Someone whose care has become patronizing — every act of service contains an implicit message about the partner's incompetence.", "ex3": "A lover who has confused leadership with parenting and whose partner has started to feel like a managed dependent rather than a chosen equal."}, {"n": 5, "name": "Punitive Authority", "desc": "Uses their position of power to punish non-compliance. Disappointment, withdrawal, coldness — deployed when the partner doesn't follow directions. The leadership has acquired teeth.", "ex1": "A partner whose response to 'I'd rather do something different tonight' is a silence so pointed it functions as correction — the partner learns that preferences that deviate from the Commander's are costly.", "ex2": "Someone who doesn't yell or threaten but whose displeasure is so uncomfortable that the partner shapes their behavior to avoid triggering it.", "ex3": "A lover who leads through the management of consequences rather than the building of trust."}, {"n": 4, "name": "Undermining Competence", "desc": "Systematically erodes the partner's confidence in their own judgment. Not through insult — through a persistent pattern of overriding, correcting, and re-doing. The partner eventually stops trusting their own decisions because the Commander has taught them they shouldn't.", "ex1": "A partner who re-loads the dishwasher after the other person loaded it, re-folds the laundry, re-plans the weekend — each correction small, each one communicating 'you can't do this right.'", "ex2": "Someone whose partner has developed the habit of asking permission for everything — not because permission was demanded but because every independent action was silently corrected.", "ex3": "A lover who has made the partner smaller by always being 'better at everything' — and the being-better was performed rather than actual."}, {"n": 3, "name": "Micromanagement", "desc": "Controls the details of the partner's daily life. How they dress, what they eat, how they spend their time, who they see — all managed through 'suggestions' that carry the weight of orders.", "ex1": "A partner who lays out their spouse's clothes 'because you always look so good when I pick' — framing the control as a compliment.", "ex2": "Someone whose partner realizes they can't remember the last time they made a choice — any choice — without checking it against the Commander's preferences first.", "ex3": "A lover who has turned the relationship into a finely managed operation where one person plans and the other person executes."}, {"n": 2, "name": "Humiliation as Control", "desc": "Uses the partner's vulnerabilities to maintain dominance. Deploys private knowledge, public corrections, and strategic shaming to keep the partner in a position of deference. The authority is maintained through the partner's diminishment.", "ex1": "A lover who corrects their partner's grammar at dinner parties, comments on their weight 'out of concern,' and offers unsolicited criticism calibrated to strike where the partner is most insecure.", "ex2": "Someone who has learned that a partner with low self-esteem is a partner who doesn't challenge authority — and has invested in maintaining that low self-esteem.", "ex3": "A partner who keeps the other person small because small people are easier to lead."}, {"n": 1, "name": "Total Subjugation", "desc": "Has reduced the partner to an extension of their will. The partner doesn't make decisions, doesn't have opinions, doesn't resist — not because they've chosen surrender but because the Commander has systematically eliminated every other option. Authority achieved through the destruction of the person being led.", "ex1": "A lover whose partner cannot order from a menu without looking to them for approval — and the Commander nods or shakes their head, and both of them consider this normal.", "ex2": "Someone whose partner's personality has been overwritten with compliance — friends from before the relationship would not recognize the person they've become.", "ex3": "A partner who has achieved absolute power over another person and calls the result 'a great relationship' without irony."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Honored by Trust", "desc": "Receives the partner's surrender as the most profound gift possible. The act of someone handing over control is treated as sacred — not taken for granted, not exploited, but met with the gravity it deserves.", "ex1": "A lover who says 'I know what it cost you to trust me with this, and I will never waste it' — and the partner believes it because the Commander's actions have always matched their words.", "ex2": "Someone who receives submission the way a priest receives a confession — with reverence, responsibility, and the understanding that what's being given is the most vulnerable thing a person has.", "ex3": "A partner whose reception of trust deepens the trust further — creating a virtuous cycle where surrender produces safety which produces deeper surrender."}, {"n": 6, "name": "Skilled Reception", "desc": "Receives the partner's yielding with practiced care. Knows how to hold the power they're given — adjusts grip, reads signals, maintains the container. The partner feels held by expertise.", "ex1": "A partner who takes the reins and the other person can feel the competence in the holding — like handing a racehorse to someone who clearly knows how to ride.", "ex2": "Someone who receives control with visible pleasure that communicates 'I wanted this and I'm going to handle it well.'", "ex3": "A lover whose reception of power is itself an act of care — the way they accept authority tells the partner everything they need to know about whether it's safe to give more."}, {"n": 5, "name": "Grateful Authority", "desc": "Accepts the partner's deference with genuine appreciation. Doesn't take the dynamic for granted — regularly acknowledges the partner's choice to yield as a choice rather than an obligation.", "ex1": "A partner who says 'thank you for letting me lead here' — and the gratitude transforms the power dynamic from hierarchy into collaboration.", "ex2": "Someone who checks in regularly: 'Is this still working for you? Do you need to take the wheel?' — the authority contains its own quality control.", "ex3": "A lover whose reception of power includes built-in mechanisms for the partner to reclaim it at any time."}, {"n": 4, "name": "Comfortable Reception", "desc": "Receives the partner's yielding as the natural state of the relationship. Doesn't question it, doesn't examine it, doesn't particularly celebrate it — just accepts the power as the air both of them breathe.", "ex1": "A couple where the power dynamic is so settled that asking 'who's in charge?' would seem absurd — the answer is obvious and has been for years.", "ex2": "Someone whose partner's deference has become so familiar it's invisible — appreciated in theory, unexamined in practice.", "ex3": "A lover whose reception of authority has become automatic — functional, uncritical, and at risk of becoming careless."}, {"n": 3, "name": "Entitled Reception", "desc": "Has begun to expect deference rather than appreciate it. The partner's yielding is now a baseline rather than a gift. Deviation from the expected submission produces irritation rather than curiosity.", "ex1": "A partner who responds to 'I'd like to make this decision' with visible annoyance — as if the partner's assertion of autonomy is an interruption of the natural order.", "ex2": "Someone who has stopped thanking the partner for their trust and started being offended when it's withheld.", "ex3": "A lover whose reception of authority has shifted from 'I'm honored you trust me' to 'of course you defer to me — that's how this works.'"}, {"n": 2, "name": "Demanding Submission", "desc": "Actively requires deference and punishes its absence. The partner's consent to be led has been replaced by the Commander's insistence on leading. The yielding is no longer voluntary — it's expected.", "ex1": "A partner who says 'I know what's best for us' with a tone that forecloses discussion — the 'us' is a courtesy, the 'I' is the operative word.", "ex2": "Someone whose partner has learned that disagreement produces consequences and agreement produces peace — and has optimized for peace.", "ex3": "A lover who has converted voluntary submission into compulsory obedience and considers the transition an improvement."}, {"n": 1, "name": "Submission as Tribute", "desc": "Receives the partner's yielding as tribute owed to them by virtue of who they are. The partner's submission is not a gift — it's an obligation. And the Commander's reception has all the warmth of a tax collector.", "ex1": "A person who views their partner's obedience as confirmation of the natural hierarchy — they lead because they're better, and the partner follows because they're lesser.", "ex2": "Someone who has built their entire self-concept around being the one in charge, and the partner's role is to continuously validate that concept through surrender.", "ex3": "A lover whose reception of power has become indistinguishable from consumption of personhood."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Power Addiction", "desc": "Addicted to the feeling of being deferred to. Requires increasing doses of submission to feel the same rush. The partner's yielding has become a substance — the Commander needs more of it, in more domains, with less resistance.", "ex1": "A lover who started by leading in the bedroom and now leads in every room — each domain of the partner's life annexed because the authority high requires more territory.", "ex2": "Someone whose need for control has expanded past the negotiated boundaries into areas the partner never agreed to cede.", "ex3": "A partner who is chasing the feeling of that first surrendered trust and needs escalating doses of power to recapture it."}, {"n": 6, "name": "Contempt for the Yielding", "desc": "Has lost respect for the partner because they submit. The very act of yielding — which the Commander requires — is now evidence of the partner's inferiority. They need submission and despise the person who provides it.", "ex1": "A person who demands obedience and then privately views the obedient partner as weak — creating an impossible loop where the partner can neither submit (and be despised) nor resist (and be punished).", "ex2": "Someone who has said 'I wish you had more backbone' to the person whose backbone they systematically broke.", "ex3": "A lover who has created the conditions for submission and then lost respect for the person living in those conditions."}, {"n": 5, "name": "Testing Limits", "desc": "Pushes the partner's boundaries to find the breaking point. Each yielding is met with a slightly larger demand. The Commander wants to know: how far will you go? The testing isn't about trust — it's about power measurement.", "ex1": "A lover who escalates demands in the bedroom to find where the partner says 'no' — not from curiosity but from the need to know exactly how much they own.", "ex2": "Someone who interprets each 'yes' as permission to ask for more, never recognizing the moment where consent shifted from enthusiastic to resigned.", "ex3": "A partner whose boundary-testing has made the relationship feel less like intimacy and more like a stress test."}, {"n": 4, "name": "Weaponized Authority", "desc": "Uses the power they've been given to punish, control, and diminish. The partner surrendered in trust and the Commander has weaponized that trust. Every vulnerability shared becomes leverage; every preference yielded becomes territory permanently claimed.", "ex1": "A lover who uses the partner's safe word history — the things that frighten them, the lines they've drawn — not as boundaries to respect but as a map of pressure points.", "ex2": "Someone who has taken the partner's gift of submission and converted it into a control infrastructure the partner never consented to.", "ex3": "A partner who was trusted with someone's vulnerability and used it to build a cage."}, {"n": 3, "name": "Humiliation Enjoyment", "desc": "Derives pleasure not from the partner's surrender but from their diminishment. The submission is no longer the point — the degradation is. The Commander has crossed from dominance into sadism without the consent that would make it play.", "ex1": "A lover who makes the partner feel small not as part of a negotiated dynamic but as a genuine expression of where they believe the partner belongs.", "ex2": "Someone whose 'leadership' has become a vehicle for cruelty — the authority is the disguise and the degradation is the intent.", "ex3": "A partner who has stopped serving the relationship with their dominance and started serving their own need to see someone beneath them."}, {"n": 2, "name": "Consent Erosion", "desc": "Has gradually eliminated the partner's ability to withdraw consent. Not through force — through the systematic removal of the conditions under which 'no' is possible. The partner technically can refuse; practically, the refusal has been made so costly that it's effectively removed.", "ex1": "A lover whose partner doesn't say 'no' anymore — not because they don't want to, but because the last time they did, the consequences lasted a month.", "ex2": "Someone who has created a relationship where submission appears voluntary and is actually coerced — the appearance of consent covering the reality of compulsion.", "ex3": "A partner who has convinced themselves and everyone else that the partner's compliance is choice — a fiction that the partner can no longer afford to challenge."}, {"n": 1, "name": "Absolute Corruption", "desc": "Power has fully corrupted. The Commander has become the Tyrant in everything but name. The partner's submission has been consumed, their autonomy destroyed, and their capacity for resistance eliminated. What remains is a dominant person with unchecked power and a submissive person with no recourse.", "ex1": "A lover who has achieved total control over another human being and feels not satisfaction but a persistent hunger — because power, like any addiction, requires increasing doses and delivers diminishing returns.", "ex2": "Someone who started as a confident, caring leader and has become, through the slow corruption of unchecked authority, unrecognizable to the person they once were.", "ex3": "A partner who proves the oldest truth about power: it doesn't reveal character, it destroys it."}]}]}, {"name": "The Kneel", "factor": "Factor 5: Dominance ↔ Submission", "factor_num": 5, "pole": "Submission", "color": "#6080A0", "alignment": "Healthy", "tagline": "I choose to surrender because I am strong enough to.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Sacred Surrender", "desc": "Their submission is an act of profound strength. They kneel from wholeness, not from brokenness. The yielding is a gift given from abundance — chosen, conscious, and revocable. This is surrender as a spiritual practice.", "ex1": "A person who yields to their partner in the bedroom with such total presence that the dominant partner is momentarily awed — the vulnerability on display is so courageous it reframes who's actually holding the power.", "ex2": "Someone who has chosen submission after years of self-work, not as a default but as a discovered orientation — they know exactly what they're giving, and they give it deliberately.", "ex3": "A lover who says 'I give you this' and both people understand that 'this' is the most powerful thing either of them possesses: conscious, chosen trust."}, {"n": 6, "name": "Grounded Yielding", "desc": "Yields from a place of deep self-knowledge. Knows their limits, communicates them clearly, and trusts the partner within those limits. The submission is structured, negotiated, and boundaried — not because they're afraid but because they're wise.", "ex1": "A partner who has a clear, articulated framework for their submission: 'here's what I give, here's what I don't, here's the signal for when I need to stop' — and the framework makes the yielding safer and deeper.", "ex2": "Someone whose boundaries in submission are as clear as their consent — both fully expressed, both fully owned.", "ex3": "A lover whose partner describes their submission as 'the most honest thing in our relationship' — because the yielding requires a level of self-honesty that most people never achieve."}, {"n": 5, "name": "Willing Follower", "desc": "Happily yields to a trusted partner with genuine pleasure and presence. Enjoys the submission — finds it freeing, arousing, and connecting. Occasionally miscalibrates (yields too fast, to the wrong person) but the instinct is healthy.", "ex1": "A partner who lights up when the other person takes charge — and the lighting up is so genuine and so joyful that it tells the dominant partner everything they need to know about the dynamic's health.", "ex2": "Someone who is still learning the difference between 'I yield because it feels good' and 'I yield because I'm afraid' — and is mostly on the right side of that line.", "ex3": "A lover whose submission is enthusiastic, sometimes imprecise, always sincere."}, {"n": 4, "name": "Comfortable Deference", "desc": "Naturally gravitates toward the following role. Prefers someone else to lead, make decisions, hold the structure. The deference is genuine and the comfort is real, though the arrangement hasn't been deeply examined.", "ex1": "A partner who says 'you decide' about most things and means it with real relief — not from fear but from the genuine preference to follow rather than lead.", "ex2": "Someone whose friends describe them as 'easygoing' without recognizing that 'easygoing' is an orientation, not a lack of will.", "ex3": "A lover who has always been more comfortable in the passenger seat and isn't troubled by this, though they've never asked themselves why."}, {"n": 3, "name": "Uncertain Yielding", "desc": "Submits but isn't sure whether the submission is choice or pattern. Was this always their nature, or did they learn it? The yielding works, but the question underneath it has started to surface, and the questioning creates a wobble.", "ex1": "A person who has always been the submissive partner and is starting to wonder whether they chose the role or whether the role chose them — and whether the distinction matters.", "ex2": "Someone who enjoys submission but has recently read enough about power dynamics to question whether their enjoyment is authentic or conditioned.", "ex3": "A lover who is in the uncomfortable middle space between 'this is who I am' and 'this is who I was trained to be.'"}, {"n": 2, "name": "Eroded Boundaries", "desc": "Yields too much, too easily, to too many. The submission has spread past the chosen partner into all relationships — professional, familial, social. What was once a gift to one person has become a default mode that the world exploits.", "ex1": "A person who is submissive at home, at work, with friends, and with strangers — the yielding that was supposed to be intimate has become universal, and the universality has drained it of meaning.", "ex2": "Someone who says 'yes' to everything and everyone and has started to experience the yes as a cage rather than a choice.", "ex3": "A lover whose submission is no longer chosen — it's automatic, and the automation has removed the very thing that made it powerful: agency."}, {"n": 1, "name": "Lost in Surrender", "desc": "Has yielded so completely that there's no self left to yield FROM. The submission is total, but it's not healthy submission — it's the collapse of personhood. There's no one home to choose to kneel; the kneeling is all that's left.", "ex1": "A person who can't make a decision about what to eat for lunch because every decision has been delegated, deferred, or surrendered for so long that the decision-making apparatus has atrophied.", "ex2": "Someone whose partner says 'what do YOU want?' and the question produces blank terror — because wanting requires a self, and the self was surrendered along with everything else.", "ex3": "A lover who has discovered that the difference between sacred surrender and self-annihilation is a boundary they crossed so long ago they can't find the line anymore."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Gift of Trust", "desc": "Offers their submission as the most intimate gift possible. The partner receives not compliance but consciousness — the Kneel is fully aware, fully choosing, and fully present in their yielding. The effect on the partner is transformative: being trusted this completely makes them want to be worthy of it.", "ex1": "A lover whose surrender is so deliberate and so complete that the dominant partner feels elevated — not powerful, but responsible, honored, and more careful than they've ever been.", "ex2": "Someone who says 'I trust you with everything' and the sentence doesn't produce anxiety in the partner but a profound, sobering sense of stewardship.", "ex3": "A partner whose gift of trust has made the other person a better leader, a better lover, and a better human being — because trust of this quality demands everything from the person receiving it."}, {"n": 6, "name": "Responsive Yielding", "desc": "Yields in real time, calibrating to the partner's signals. Reads the dominant partner's energy and adjusts — more when the partner is confident, less when the partner is uncertain. The submission is a dance, not a posture.", "ex1": "A partner who can tell when their dominant lover needs to feel powerful and offers exactly that — and when they need to feel tender, shifts the energy accordingly.", "ex2": "Someone whose submission is so attuned it functions as a mirror for the dominant partner — they see themselves clearly in how the Kneel responds.", "ex3": "A lover whose yielding is the most sophisticated form of communication in the relationship."}, {"n": 5, "name": "Enthusiastic Following", "desc": "Follows with visible pleasure. The partner's directions are received with genuine eagerness. The enthusiasm makes the dominant partner feel skilled and wanted — the energy is contagious.", "ex1": "A partner who responds to 'let me take care of this' with such obvious relief and delight that the other person feels like a hero.", "ex2": "Someone whose submission comes with a warmth that transforms the dynamic from power exchange to mutual joy.", "ex3": "A lover whose 'yes' carries the energy of someone who has been waiting to be asked."}, {"n": 4, "name": "Comfortable Following", "desc": "Follows the partner's lead with settled ease. Not electric, not negotiated — just the comfortable dynamic of two people who know their roles and play them well.", "ex1": "A couple whose domestic life has a clear captain and a clear crew member, and both are content with their positions.", "ex2": "Someone who yields on most decisions with genuine peace and the occasional quiet assertion when something truly matters to them.", "ex3": "A lover whose comfortable submission has become the relationship's thermostat — steady, warm, rarely requiring adjustment."}, {"n": 3, "name": "Uncertain Offering", "desc": "Offers submission but with hesitation. The partner can feel the yielding and the resistance simultaneously. The Kneel wants to surrender and can't fully commit — the gift is offered and half-withdrawn, repeatedly.", "ex1": "A partner who says 'you take charge' and then second-guesses every decision — not from lack of trust but from the difficulty of releasing control when the willingness and the anxiety coexist.", "ex2": "Someone who yields physically but mentally keeps running a parallel process: 'is this right? Should I stop this? Am I safe?'", "ex3": "A lover whose submission comes with a built-in safety monitor that's turned up too high — necessary in principle, limiting in practice."}, {"n": 2, "name": "Reluctant Compliance", "desc": "Goes along with the partner's direction not from choice but from inability to resist. The compliance looks like submission but feels like resignation. The partner can tell the difference and is uncomfortable with it.", "ex1": "A partner who follows directions with the energy of someone completing a chore — technically willing, emotionally absent.", "ex2": "Someone whose 'yes' means 'I don't have the energy to say no' rather than 'I want this.'", "ex3": "A lover whose partner has started to suspect that the submission they're receiving is surrender in the wrong sense — not trust, but exhaustion."}, {"n": 1, "name": "Empty Compliance", "desc": "Complies with everything and means nothing. The body follows directions; the person is elsewhere. The submission has become mechanical — a function being performed by a system that has checked out.", "ex1": "A partner who says 'whatever you want' and means it as absence, not offering — the words are a concession, not a gift.", "ex2": "Someone whose submission has lost all its charge — neither pleasurable nor painful, neither chosen nor forced, just the default action of a depleted person.", "ex3": "A lover whose partner realizes they're directing a puppet and the strings are all that's keeping it upright."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Enabling Tyranny", "desc": "Their submission has become the fuel for the partner's worst instincts. By yielding to everything, the Kneel has given the partner permission to become a tyrant. The surrender, however genuine, is enabling destruction.", "ex1": "A lover whose total compliance has allowed a once-decent partner to become a monster — the partner's darkness grew to fill the space the Kneel's submission created.", "ex2": "Someone whose surrender was offered in trust and received by someone who couldn't handle the responsibility — the gift was too much for the recipient and both people are being destroyed by it.", "ex3": "A partner who has essentially given a blank check to a person who should have had a spending limit, and both the account and the spender are being ruined."}, {"n": 6, "name": "Submission as Self-Punishment", "desc": "Uses the dynamic to enact self-harm. Seeks out dominant partners who will treat them badly, yields to degradation they don't enjoy, and reframes the suffering as devotion. The kneeling has become a mechanism for accessing pain they believe they deserve.", "ex1": "A person who consistently chooses cruel partners and describes the pattern as 'I'm drawn to strong people' — the word 'strong' being a euphemism for 'punishing.'", "ex2": "Someone who endures treatment that makes their friends wince and says 'you don't understand our dynamic' — and the friends are right and the Kneel is using the language of consent to justify self-destruction.", "ex3": "A lover whose submission has become indistinguishable from self-harm wearing intimacy's clothing."}, {"n": 5, "name": "Collapse into Role", "desc": "Has disappeared into the submissive role so completely that it's consumed all other identity. They're no longer a person who submits — they're a submission wearing a person suit.", "ex1": "A partner who has no interests, no opinions, no goals outside the dynamic — and who describes this as 'devotion' while everyone around them sees a person who has ceased to exist.", "ex2": "Someone whose entire personality has been replaced by a function: await instructions, comply, repeat.", "ex3": "A lover who is the cautionary tale of submission without boundaries — what was once a beautiful expression of trust has become a total erasure of self."}, {"n": 4, "name": "Passive Aggression Through Compliance", "desc": "Complies with everything while silently seething. The submission has become a vehicle for resentment — the Kneel follows every direction and hates every moment, and the hatred leaks out in small, deniable ways.", "ex1": "A partner who does exactly what they're told with a precision that borders on mockery — the compliance is technically perfect and emotionally hostile.", "ex2": "Someone who says 'yes, of course' in a tone that manages to contain more aggression than any 'no' could.", "ex3": "A lover whose submission has become the relationship's most sophisticated weapon — they obey, and the obedience is punishment."}, {"n": 3, "name": "Competitive Submission", "desc": "Uses their own yielding to control the dynamic. 'I gave you MORE than you asked for' becomes a weapon. The Kneel's excessive compliance becomes a tool for guilt, manipulation, and moral superiority.", "ex1": "A partner who surrenders more than requested and then uses the excess as leverage: 'I did everything you wanted and more — what have YOU done?'", "ex2": "Someone who has weaponized their own vulnerability: the more they yield, the more the dominant partner owes, and the ledger is maintained with precision.", "ex3": "A lover who has discovered that maximum submission produces maximum guilt in the partner — and has learned to use that guilt as a currency more powerful than any command."}, {"n": 2, "name": "Submission as Trap", "desc": "Yields completely and then uses the partner's acceptance of the submission as evidence of their tyranny. 'Look what you did to me. Look what you made me do.' The submission was offered and is now being prosecuted.", "ex1": "A partner who encouraged a dominant dynamic and then, when the dynamic produced exactly what was agreed to, reframes the agreement as abuse.", "ex2": "Someone who yields in the moment and weaponizes the yielding later — every act of submission becomes a future accusation stored for deployment.", "ex3": "A lover who has learned that surrendering fully and then describing the surrender as coercion gives them a permanent moral advantage."}, {"n": 1, "name": "Destruction Through Surrender", "desc": "Has yielded so completely to a destructive partner that both people are being consumed. The Kneel's total submission has fueled the partner's worst behaviors, and the partner's worst behaviors have consumed the Kneel. Two people locked in a spiral where surrender feeds tyranny and tyranny feeds surrender.", "ex1": "A relationship where the submissive partner enables the dominant partner's abuse and the dominant partner requires the submission that enables it — a closed circuit of mutual destruction.", "ex2": "Someone whose surrender has become the engine of a system that is killing both people — the Kneel can't stop yielding and the partner can't stop taking, and neither one can exit.", "ex3": "A lover whose gift of trust was given to someone who consumed it, and the consuming hasn't stopped, and the Kneel keeps feeding the mechanism that's destroying them."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Received as Equal", "desc": "When a dominant partner treats the Kneel's submission with genuine respect — honoring the gift, checking in, never exploiting — the Kneel experiences the deepest safety possible. Being dominant BY someone who is good at dominance is the Kneel's highest state.", "ex1": "A person who has found a dominant partner who handles their submission the way a jeweler handles a diamond — with respect for its value and awareness of its fragility.", "ex2": "Someone whose surrender produces tenderness in their partner rather than exploitation — and the tenderness makes the next surrender easier, deeper, more real.", "ex3": "A lover who has found, in the right dominant partner, a freedom that looks paradoxical from the outside: they are most free when most surrendered, because the surrender is held by someone who is worthy of it."}, {"n": 6, "name": "Safe Reception", "desc": "Receives the partner's dominance as safety rather than threat. The partner's authority feels like architecture — a structure to inhabit, not a force to endure.", "ex1": "A partner who feels their body relax when the other person takes charge — the submission is a physiological response to genuine safety.", "ex2": "Someone who describes their partner's dominance as 'coming home' — the structure the dominant partner provides is the first place the Kneel has ever felt truly at ease.", "ex3": "A lover whose reception of authority is joyful, grateful, and deeply nourishing."}, {"n": 5, "name": "Appreciative Following", "desc": "Genuinely appreciates being led. The partner's authority is received with warmth and gratitude. The dynamic feels natural, comfortable, and mutually satisfying.", "ex1": "A partner who says 'I love that you handle this' and the dominant partner feels both valued and trusted.", "ex2": "Someone who receives direction with visible relief — as if someone finally took a weight they'd been carrying without knowing it.", "ex3": "A lover whose reception of dominance energizes both people."}, {"n": 4, "name": "Passive Reception", "desc": "Accepts the partner's dominance without resistance or enthusiasm. The yielding is genuine but muted. The dynamic works but doesn't sparkle.", "ex1": "A partner who follows directions competently and unemotionally — functional, willing, uninspired.", "ex2": "Someone whose submission has become routine — neither resisted nor celebrated.", "ex3": "A lover whose reception of authority is like their response to weather: they go along with it."}, {"n": 3, "name": "Ambivalent Reception", "desc": "Receives dominance with mixed feelings. Sometimes it's safe and comforting; sometimes it triggers fear from old wounds. The partner's authority is welcomed and suspected in alternating waves.", "ex1": "A person who loves being led but flinches at certain tones of voice that remind them of someone else — the current partner is safe but the body remembers danger.", "ex2": "Someone who wants to yield fully and keeps hitting internal walls they didn't build — the reception has speed bumps that aren't about this partner.", "ex3": "A lover who is working through old damage while trying to build a new dynamic — and the work is visible and the effort is real."}, {"n": 2, "name": "Wary Reception", "desc": "Receives dominance with persistent caution. The partner must prove themselves safe repeatedly — trust is given in teaspoons and withdrawn at the first sign of anything resembling old patterns.", "ex1": "A partner who yields in micro-doses, each one followed by a monitoring period: 'was that safe? Okay. Maybe a little more.'", "ex2": "Someone whose partner needs patience measured in years, because the Kneel's previous experience with dominance was catastrophic.", "ex3": "A lover who wants to trust and can't, not from this partner's failure but from the last partner's success at destruction."}, {"n": 1, "name": "Cannot Receive Authority", "desc": "Authority triggers panic. Any hint of dominance — even gentle, consensual, requested — activates a trauma response that shuts down the entire system. The Kneel wants to surrender and their body won't let them.", "ex1": "A person who asked their partner to take charge and then froze, shook, and cried — not from anything the partner did but from what someone else did years ago.", "ex2": "Someone who has the orientation of a submissive and the trauma history of an abuse survivor, and the two identities are at war inside them.", "ex3": "A lover who knows what they want and can't have it because the wanting and the terror are stored in the same place."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Addicted to Dominance", "desc": "Cannot function without a dominant partner. Has externalized all agency, all decision-making, all self-regulation onto whoever holds the authority. Between dominant partners, the Kneel collapses — not from heartbreak but from loss of operating system.", "ex1": "A person who moves from dominant partner to dominant partner with no gaps because the gaps are unbearable — not from loneliness but from the specific terror of having to make their own decisions.", "ex2": "Someone whose submission has become a dependency so total that the dominant partner isn't a partner but a prosthetic — an external device that performs functions the Kneel has outsourced permanently.", "ex3": "A lover who doesn't want a partner — they want a controller, and the distinction has erased any possibility of genuine intimacy."}, {"n": 6, "name": "Submission to Cruelty", "desc": "Receives abusive dominance and reframes it as intensity, passion, or 'just how they are.' The Kneel's tolerance for mistreatment is so high that genuine cruelty doesn't register as cruelty — it registers as strong leadership.", "ex1": "A person whose friends say 'they're terrible to you' and the Kneel responds 'you don't understand our dynamic' — and the friends are right and the Kneel is using D/s language as a shield against recognizing abuse.", "ex2": "Someone who has been conditioned to accept pain as the price of intimacy and who now can't distinguish between a challenging partner and a dangerous one.", "ex3": "A lover whose threshold for acceptable treatment has been so thoroughly lowered that treatment which would shock others barely registers."}, {"n": 5, "name": "Submission as Self-Erasure", "desc": "Receives dominance and uses it to disappear. The authority isn't a structure to inhabit — it's a structure to hide in. The Kneel uses the dominant partner as a shield against the terrifying task of being themselves.", "ex1": "A person who takes orders because following orders means never having to decide, and deciding means risking failure, and failure means facing the self they're trying to escape.", "ex2": "Someone who has discovered that total submission is the most complete form of hiding — if someone else is making all the choices, the Kneel never has to face the consequences of their own.", "ex3": "A lover who has used submission to avoid the existential challenge of selfhood."}, {"n": 4, "name": "Resentful Submission", "desc": "Submits and hates it. The yielding produces resentment that builds silently. The dominant partner thinks the dynamic is working; the Kneel is accumulating grievances that will eventually detonate.", "ex1": "A partner who follows every direction with a smile that doesn't reach their eyes — the compliance is perfect and the resentment is total.", "ex2": "Someone who is planning, unconsciously or consciously, the moment of revolution — the day they finally say 'no' to everything at once.", "ex3": "A lover whose submission is a pressure cooker with the valve sealed — the compliance will continue until the day it spectacularly doesn't."}, {"n": 3, "name": "Power Through Helplessness", "desc": "Has learned to control the dynamic through performed helplessness. The more incompetent they appear, the more the dominant partner must do, decide, and manage — and the management gives the Kneel exactly what they want without appearing to ask for it.", "ex1": "A partner who 'can't' cook, 'can't' manage money, 'can't' handle confrontation — each inability placing another responsibility on the dominant partner and another card in the Kneel's hidden hand.", "ex2": "Someone who controls the relationship from the bottom — ensuring that the dominant partner is so busy leading they never notice they're being steered.", "ex3": "A lover who has turned submission into the most effective form of control: the puppet that makes the puppeteer dance."}, {"n": 2, "name": "Weaponized Vulnerability", "desc": "Uses their own submissiveness to trap the dominant partner. 'If you leave, I'll fall apart.' The partner's natural dominance and protective instinct is exploited to prevent departure. The Kneel's fragility becomes a cage for the person trying to lead them.", "ex1": "A partner who threatens collapse every time the dominant partner asserts a boundary — making the dominant partner choose between their own needs and the Kneel's stability.", "ex2": "Someone who has discovered that being the weak one gives them ultimate veto power — the strong person can't leave someone who can't survive the leaving.", "ex3": "A lover who has turned their own helplessness into the strongest chain in the relationship."}, {"n": 1, "name": "Terminal Submission", "desc": "Has surrendered everything and has nothing left. The dominant partner has received total submission and the total submission has produced total emptiness. Two people in a dynamic that has consumed one and burdened the other. The relationship continues because momentum is the only force still operating.", "ex1": "A relationship where the submissive partner is a shell and the dominant partner is exhausted — neither getting what they need, both unable to stop the machinery.", "ex2": "Someone who has given everything and received nothing and doesn't know how to stop giving because giving is the only function that remains.", "ex3": "A lover whose submission has been consumed completely, leaving a dynamic with no energy, no joy, and no exit — just two people locked in roles that have outlived their purpose."}]}]}, {"name": "The Tyrant", "factor": "Factor 5: Dominance ↔ Submission", "factor_num": 5, "pole": "Dominance", "color": "#A06030", "alignment": "Shadow", "tagline": "Obey. Don't make me ask twice.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Absolute Ruler", "desc": "Power indistinguishable from identity. They don't exercise control — they ARE control. Every room they enter reorganizes around them. Every relationship they form is structured around their authority. The concept of equality doesn't compute; there is only above and below.", "ex1": "A person who has never had a relationship between equals because equality feels like chaos — someone must rule, and it must be them, and the conviction is as natural as breathing.", "ex2": "Someone whose romantic history is a series of people who were strong when they arrived and diminished when they left — each partner's reduction proving the Tyrant's thesis that they are the only competent person in any room.", "ex3": "A lover who would describe their ideal relationship as 'harmonious' and mean 'perfectly controlled' and not see the difference."}, {"n": 6, "name": "Strategic Despot", "desc": "High-functioning control deployed with intelligence. Knows when to be charming and when to be terrifying. The shifts between warmth and coldness are calibrated for maximum compliance. Not raging — engineering.", "ex1": "A person who can read a room and adjust their approach in real time: gentle with the vulnerable, firm with the resistant, devastating with the disloyal — each response precisely tailored.", "ex2": "Someone whose partners all describe the same confusing experience: 'They could be the most wonderful person alive, and then suddenly the temperature would drop, and I'd know I'd done something wrong.'", "ex3": "A lover who is more dangerous than the screaming tyrant because their control is invisible, surgical, and nearly impossible to name."}, {"n": 5, "name": "Volatile Controller", "desc": "Control maintained through unpredictability. The partner never knows which version they'll get — tender or terrifying — and the uncertainty itself is the control mechanism. The chaos is the system.", "ex1": "A partner whose mood swings aren't mood swings but strategic oscillations — each shift designed to keep the other person off-balance and therefore compliant.", "ex2": "Someone whose partner has developed a hypervigilance usually associated with living in a war zone — scanning for signals, reading tone, adjusting behavior to match the Tyrant's current state.", "ex3": "A lover who has made unpredictability into a management style and whose partner lives in a permanent state of anxious attentiveness."}, {"n": 4, "name": "Rageful Authority", "desc": "Controls through anger. Explosions — real or threatened — are the primary governance tool. The partner's world is organized around preventing the next eruption.", "ex1": "A partner who throws things, slams doors, and raises their voice — not always, but often enough that the other person's nervous system is permanently set to 'threat assessment.'", "ex2": "Someone whose rage episodes are followed by periods of sweetness so intense the partner is confused about which version is real — the rage or the tenderness.", "ex3": "A lover whose partner describes walking on eggshells and means it with the clinical precision of someone who has been doing it long enough to map every fragile spot."}, {"n": 3, "name": "Petty Tyrant", "desc": "Controls through small, persistent acts of dominance. Not dramatic — mundane. Controls the thermostat, the remote, the dinner plans, the weekend schedule. Each individual act is trivial; the accumulation is totalitarian.", "ex1": "A partner who must have the last word in every conversation, sit in the same chair, control the radio — and responds to any challenge of these micro-territories with disproportionate irritation.", "ex2": "Someone whose partner has ceded a thousand small things and one day realizes the thousand small concessions add up to complete capitulation.", "ex3": "A lover who rules through minutiae — each tiny assertion of control so small it can't be objected to, each one another tile in a mosaic of domination."}, {"n": 2, "name": "Impotent Tyrant", "desc": "Attempts to control but lacks the skill or presence to succeed. The tyranny is visible and ineffective — everyone can see the attempts, and the attempts produce resistance rather than compliance.", "ex1": "A partner who issues orders that nobody follows, makes threats that nobody fears, and demands respect that nobody gives — and the gap between their self-image and their actual authority is excruciating.", "ex2": "Someone whose controlling behavior is so clumsy that it provokes laughter rather than fear — which enrages them further.", "ex3": "A lover who is dangerous not because they're effective but because ineffective tyrants escalate — the failure of soft control can lead to the attempt at hard control."}, {"n": 1, "name": "Collapsed Tyrant", "desc": "The control has failed completely. They've lost authority over the relationship, the partner, and themselves. What remains is rage without target, dominance without domain, and a person whose entire identity was built on power discovering what they are without it: nothing.", "ex1": "A person post-divorce who can't function without someone to control — the tyranny was the operating system, and without it, the machine doesn't run.", "ex2": "Someone whose partner finally left and the Tyrant's response reveals the truth: the control was never about strength. It was about the terror of being powerless.", "ex3": "A lover who discovers, at the bottom of the collapse, that every act of dominance was a defense against vulnerability — and now, without the defenses, the vulnerability is all that's left."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Channeled Intensity", "desc": "At their absolute best, the Tyrant's ferocious energy becomes fierce advocacy for the partner. They fight FOR the partner with the same intensity they might otherwise fight AGAINST them. The aggression is real; the direction has been corrected.", "ex1": "A lover who storms into the partner's workplace to confront a bullying boss — and the partner, despite the chaos, feels protected by the Tyrant's willingness to burn bridges on their behalf.", "ex2": "Someone whose intensity, when aimed outward, makes the partner feel like they have the world's most dangerous bodyguard — and the danger is pointed away from them, which feels intoxicating.", "ex3": "A partner who uses their capacity for intimidation to clear obstacles from the other person's path — the dominance serves rather than subjugates."}, {"n": 6, "name": "Controlled Ferocity", "desc": "The tyrannical energy is visible but leashed. Both people know what the Tyrant is capable of — and the fact that it's currently being restrained is itself a kind of gift. The partner sees the wolf choosing not to bite.", "ex1": "A partner whose jaw clenches during disagreements but whose voice stays level — and the partner can see the effort and respects both the restraint and the honesty of the visible struggle.", "ex2": "Someone who says 'I want to control this situation and I'm choosing not to' — naming the impulse rather than acting on it, which requires more strength than the acting would.", "ex3": "A lover whose self-awareness about their own tyrannical tendencies has become the relationship's most valuable asset."}, {"n": 5, "name": "Rough Care", "desc": "Expresses love through intensity that borders on controlling. The care is real but the delivery is blunt, directive, and sometimes bruising. The partner is well-cared-for in the way a soldier is well-supplied — efficiently, not tenderly.", "ex1": "A partner who responds to 'I'm not feeling well' with 'here's your medication, I've cleared your schedule, go to bed' — all correct actions delivered in a tone that doesn't invite discussion.", "ex2": "Someone whose love language is solving problems with military efficiency — the partner feels handled rather than held, managed rather than loved.", "ex3": "A lover whose care would be perfect if it included one additional ingredient: gentleness."}, {"n": 4, "name": "Intermittent Gentleness", "desc": "Alternates between domineering behavior and surprising moments of tenderness. The tenderness is genuine; the timing is unpredictable. The partner lives for the gentle moments and endures the harsh ones.", "ex1": "A partner who can be devastatingly tender at midnight and coldly controlling at breakfast — and the whiplash between the two is the relationship's defining texture.", "ex2": "Someone whose partner clings to the tender moments as evidence of 'who they really are' — a narrative that requires ignoring 80% of the data.", "ex3": "A lover who gives just enough warmth to sustain hope and just enough coldness to maintain control — the ratio may be unconscious but it's consistent."}, {"n": 3, "name": "Conditional Kindness", "desc": "Kind when the partner complies, cruel when they don't. The conditionality is the message: you will be treated well if you behave. The carrot-and-stick dynamic has replaced unconditional love with a behavior modification program.", "ex1": "A partner who is affectionate after being obeyed and cold after being challenged — and the partner has learned the relationship's terms through direct reinforcement.", "ex2": "Someone whose warmth is a reward and whose withdrawal is a punishment — and both are deployed with enough consistency that the partner has been trained without knowing it.", "ex3": "A lover who doesn't need to raise their voice because the partner has already learned the rules and follows them preemptively."}, {"n": 2, "name": "Breaking Will", "desc": "Actively works to eliminate the partner's resistance. Uses emotional pressure, threats, isolation, and intermittent reward to break the partner's capacity for defiance. The goal isn't a happy partner — it's a compliant one.", "ex1": "A lover who has noticed that the partner's spirit has dimmed over the course of the relationship and considers the dimming a success.", "ex2": "Someone whose partner used to argue back and now doesn't — and the Tyrant experiences this as the relationship 'getting better.'", "ex3": "A partner who is engineering surrender through sustained psychological pressure and would describe the process as 'we've learned to communicate better.'"}, {"n": 1, "name": "Partner Destruction", "desc": "Has destroyed the partner as a person. What remains is a shell that responds to commands. The Tyrant didn't intend to break them — or perhaps they did — but the result is a human being who has been reduced to a function: compliance.", "ex1": "A lover whose partner's eyes have gone flat — not from sadness but from the specific vacancy of a person whose interior has been emptied by sustained domination.", "ex2": "Someone whose partner is described by outside observers as 'like a different person' — and the person they were before the Tyrant is mourned by friends the way one mourns the dead.", "ex3": "A partner who has achieved the Tyrant's final goal: total obedience, total emptiness, and the discovery that an empty partner is an empty victory."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Systematic Terror", "desc": "Controls through a comprehensive system of fear. Every domain of the partner's life is governed by the threat of the Tyrant's displeasure. The system is so complete that the Tyrant rarely needs to act — the anticipatory terror does the work.", "ex1": "A person whose partner manages every moment of their day around the question 'will this anger them?' — and has done so for so long that the managing has become invisible, automatic, total.", "ex2": "Someone whose partner's friends don't visit because the atmosphere in the house is controlled by someone who doesn't need to be present to exert control — the rules remain even in the Tyrant's absence.", "ex3": "A lover who has made their own personality into a governance system: the partner doesn't obey rules, they obey a person, and the person is everywhere."}, {"n": 6, "name": "Weaponized Intimacy", "desc": "Uses the partner's most vulnerable moments as tools of control. What was shared in trust is deployed as leverage. The Tyrant has catalogued every fear, every shame, every weak point, and the catalogue is a weapon system.", "ex1": "A lover who says 'remember when you told me your worst fear? I'm it now' — and the partner realizes that every moment of intimacy was reconnaissance.", "ex2": "Someone who uses the partner's sexual vulnerabilities, childhood wounds, and secret shames as precision instruments of obedience.", "ex3": "A partner who has turned pillow talk into intelligence gathering and vulnerability into liability."}, {"n": 5, "name": "Isolation and Control", "desc": "Classic abuse dynamics: isolate, control information, manage resources, and destroy the partner's support network. Each step is logical from inside the Tyrant's framework and devastating from outside it.", "ex1": "A partner whose phone is monitored, whose friends have been driven away, whose family has been alienated, and whose world has shrunk to the size of one person's will.", "ex2": "Someone who controls the finances, the transportation, and the social connections — making departure logistically impossible even if the desire to leave survived the conditioning.", "ex3": "A lover who has built a prison out of dependency and guards it with the partner's own fear."}, {"n": 4, "name": "Degradation Protocol", "desc": "Degrades the partner systematically to maintain hierarchy. The degradation may be sexual, emotional, or social — always designed to remind the partner of their position. Not for pleasure — for architecture.", "ex1": "A lover who requires the partner to ask permission for basic activities — eating, sleeping, leaving the house — and frames the requirement as 'structure' or 'discipline.'", "ex2": "Someone who insults the partner's intelligence, appearance, or worth with enough regularity that the partner has internalized the assessment.", "ex3": "A partner who has convinced the other person they're worthless and then generously agrees to stay with them anyway — the generosity itself is a form of control."}, {"n": 3, "name": "Explosive Control", "desc": "Rules through periodic eruptions that reset the power dynamic. Long periods of calm punctuated by volcanic rage — the calm is the recovery period and the rage is the governance event.", "ex1": "A partner whose rages are spaced just far enough apart that the other person starts to believe 'it's getting better' before the next one proves it isn't.", "ex2": "Someone whose partner has developed a trauma response to specific triggers — a certain tone of voice, a specific facial expression — that predict the coming explosion.", "ex3": "A lover who governs a relationship the way an earthquake governs a landscape: through periodic destruction that reshapes everything."}, {"n": 2, "name": "Physical Threat", "desc": "Control has crossed into physical intimidation or violence. The body has become a weapon — blocking doorways, breaking objects, invading space, or making direct contact. The line between psychological and physical control has been erased.", "ex1": "A partner who has never hit the other person but has punched walls beside their head, thrown dishes near their feet, and stood over them while they cowered — and claims 'I've never laid a hand on you' as if proximity violence isn't violence.", "ex2": "Someone whose physical presence has been weaponized to the point where the partner's flinch response is triggered by footsteps.", "ex3": "A lover who has made the partner afraid of their own home by making the home afraid of its occupant."}, {"n": 1, "name": "Total Annihilation", "desc": "The Tyrant's endgame: the partner exists only as a vessel for the Tyrant's will. Physical, psychological, and spiritual autonomy have been eliminated. What remains is not a relationship but an occupation.", "ex1": "A lover whose partner could not, if asked by a therapist or a detective, identify their own name without checking whether it's the name the Tyrant wants them to use.", "ex2": "Someone whose partner has been so thoroughly destroyed that escape — even when physically possible — doesn't occur to them as an option, because options require a self that makes choices, and that self was eliminated.", "ex3": "A partner who is the living embodiment of power's terminal truth: absolute dominance produces not a relationship but a ghost — and the Tyrant is left ruling a kingdom of one."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Stunned by Resistance", "desc": "When someone meets the Tyrant with calm, unshakeable firmness — not aggression, not submission, but steady, quiet refusal to be dominated — the Tyrant is briefly destabilized. Someone who can't be terrorized or controlled short-circuits the system.", "ex1": "A person who meets the Tyrant's rage with the calm of a stone and says 'I'm not going to be afraid of you' — and means it, and the Tyrant, for the first time, doesn't know what to do.", "ex2": "Someone who encounters a person whose self-possession is so complete that the Tyrant's usual tools bounce off, and the bouncing creates a crack in the Tyrant's certainty.", "ex3": "A lover who, when met with someone who can't be controlled, experiences the first flicker of respect they've felt in years."}, {"n": 6, "name": "Wary Acceptance", "desc": "Receives care or challenge cautiously, scanning for the angle. The Tyrant can accept gentle treatment but never stops searching for the manipulation underneath, because in their world, everyone is either dominant or dominated.", "ex1": "A partner who accepts kindness from a strong person and spends the evening trying to figure out what they want — because free kindness doesn't compute in the Tyrant's operating system.", "ex2": "Someone who receives love the way a dictator receives a peace offering: with interest, suspicion, and a contingency plan.", "ex3": "A lover who is learning that not everyone is trying to gain the upper hand — but the learning is slow and the paranoia is fast."}, {"n": 5, "name": "Submission as Threat", "desc": "When someone yields to the Tyrant genuinely, the Tyrant is uncomfortable — because genuine submission given freely doesn't require their control. Free surrender implies the partner could also freely take it back, and that possibility is intolerable.", "ex1": "A lover who is uneasy when the partner says 'I choose to follow you' because the word 'choose' implies the option of choosing otherwise.", "ex2": "Someone who needs coerced submission rather than voluntary submission because coerced submission can't be withdrawn.", "ex3": "A partner who would rather dominate an unwilling person than receive the gift of a willing one — because the gift implies equality the Tyrant can't tolerate."}, {"n": 4, "name": "Power Analysis", "desc": "Receives every interaction through a power lens. Kindness is a play for position. Generosity is an attempt at leverage. Love is a bid for influence. Nothing is received at face value because the Tyrant lives in a world where face value doesn't exist.", "ex1": "A person who is given a birthday gift and immediately calculates the power implications: does this put me in their debt? What do they want in return? How do I maintain advantage?", "ex2": "Someone who has so thoroughly organized their world around power that love, offered freely, is perceived as the most suspicious thing possible.", "ex3": "A lover who receives 'I love you' and hears 'I'm trying to gain influence over you.'"}, {"n": 3, "name": "Rejecting Vulnerability", "desc": "Cannot receive anything that requires lowering defenses. Being loved means being seen, being seen means being known, being known means being vulnerable, and vulnerability is the thing the Tyrant has built their entire identity to prevent.", "ex1": "A person who recoils from tenderness — physically recoils — because the tenderness activates the very feelings the tyranny was built to suppress.", "ex2": "Someone who can give orders, receive obedience, and process power dynamics — but cannot receive a hug without their whole system going into alarm.", "ex3": "A lover who can dominate a person in bed but cannot let a person hold them afterward — because the holding requires a surrender the Tyrant can't perform."}, {"n": 2, "name": "Rage at Care", "desc": "Responds to genuine care with anger. The care feels like an attack because it targets the Tyrant's deepest weakness: their need to be loved. Being needed is power; being loved is vulnerability. And vulnerability is the enemy.", "ex1": "A partner who screams at the person who brought them soup when they were sick — the soup is evidence that they looked weak, and looking weak is unacceptable.", "ex2": "Someone who punishes their partner for being kind because kindness implies the Tyrant needs something, and needing is what other people do.", "ex3": "A lover who has made their own tenderness into something so dangerous that anyone who triggers it must be destroyed."}, {"n": 1, "name": "Impervious to Love", "desc": "Cannot be reached. The control mechanism is so total that love bounces off the way light bounces off a mirror. The Tyrant is surrounded by people who have tried to love them and failed — not because the love wasn't real, but because the Tyrant's defenses were built to withstand exactly this.", "ex1": "A person who has been offered genuine love by multiple people across decades and has never once let it land — each offering was received as a threat and neutralized accordingly.", "ex2": "Someone who will die having been loved and never having known it — the tyranny that was supposed to protect them from vulnerability succeeded in protecting them from everything.", "ex3": "A lover who is the saddest archetype in the system: not the one who can't find love, but the one who finds it constantly and has built themselves into someone who can never receive it."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Receives Only Submission", "desc": "Can only process incoming information through the lens of power hierarchy. The partner's love, if it arrives as anything other than obedience, is unreadable. The only 'love' the Tyrant can feel is compliance.", "ex1": "A person who hears 'I love you' and translates it to 'I submit to you' — and if the translation doesn't work, the statement is rejected.", "ex2": "Someone whose emotional reception is a single channel: power in/power out. Every other frequency produces static.", "ex3": "A lover who is starving for connection while surrounded by people offering it — because the connection they need must arrive in the shape of surrender, and most people's love doesn't come in that shape."}, {"n": 6, "name": "Tribute Collection", "desc": "Receives the partner's offerings as tribute. Love is taxes. Affection is rent. The partner's emotional output is processed as the cost of being in the Tyrant's presence, not as a gift between equals.", "ex1": "A partner who accepts devotion the way a king accepts fealty — with formal acknowledgment, no reciprocation, and the implicit understanding that the offering is the vassal's duty.", "ex2": "Someone whose partner has learned to present love in the format of offering: carefully, humbly, and with the awareness that it may be found insufficient.", "ex3": "A lover who has structured the relationship as a court, with themselves on the throne and the partner in a permanent posture of offering."}, {"n": 5, "name": "Punishing Insufficient Love", "desc": "When the partner's offerings don't meet the Tyrant's standard, punishment follows. Not enough attention, not enough compliance, not enough devotion — each insufficiency triggers a correction cycle that the partner has learned to dread.", "ex1": "A lover who withdraws for days when the partner's greeting wasn't enthusiastic enough — the silence is the punishment and the crime was inadequate worship.", "ex2": "Someone whose partner has developed an exhausting hypervigilance around emotional output — constantly monitoring whether they're giving enough, showing enough, being enough.", "ex3": "A partner who has made their own approval into the sun around which the other person's life revolves."}, {"n": 4, "name": "Consuming Obedience", "desc": "Takes the partner's submission and is never satisfied. More. Faster. Further. The compliance that was enough last month isn't enough this month. The demands escalate, the compliance follows, and the Tyrant remains empty.", "ex1": "A person whose partner has given up career, friends, family, and self — and the Tyrant's response is 'what else can you give?'", "ex2": "Someone who has consumed everything the partner had and is now feeding on what the partner is — because the material resources are gone and only the identity remains.", "ex3": "A lover who receives love the way a fire receives fuel: no amount is enough, and the furnace needs feeding."}, {"n": 3, "name": "Paranoid Reception", "desc": "Suspects every act of love as a covert bid for power. The partner's kindness is a trap. Their compliance is a strategy. Their love is a long game to gain the upper hand. The Tyrant receives everything through a filter of threat assessment.", "ex1": "A partner who accuses their submissive spouse of 'playing games' when the spouse tries to be kind — because kindness, in the Tyrant's world, is always the opening move of a power play.", "ex2": "Someone whose partner's genuine attempts at affection are met with interrogation: 'What do you want? Why are you being nice? What are you hiding?'", "ex3": "A lover who lives in a permanent state of counter-intelligence, defending against attacks that exist only in the architecture of their own terror."}, {"n": 2, "name": "Discarding the Broken", "desc": "Once the partner is fully broken — compliant, empty, without fight — the Tyrant loses interest. Resistance was the fuel. Without it, the engine stops. The Tyrant discards the partner not for failing but for succeeding too completely at submission.", "ex1": "A person who spent years breaking their partner's will and, once broken, found the result boring — the chase was the point, and the caught thing is just meat.", "ex2": "Someone who leaves their devastated partner for someone new — someone with spirit, someone with fight, someone who doesn't know yet what the Tyrant does to spirit and fight.", "ex3": "A lover who is a serial destroyer: build up, break down, discard, repeat — the cycle is the only thing that makes them feel alive."}, {"n": 1, "name": "Void", "desc": "Cannot receive anything because there is no receptive capacity. Only output — only power, only control, only domination. The Tyrant is a one-directional system. Love goes in and nothing comes back. Not even acknowledgment. The partner pours into a mechanism that was never designed to hold what's being poured.", "ex1": "A person who has been the center of multiple people's worlds and has never felt any of them — not from cruelty but from a genuine absence of the infrastructure that converts being loved into feeling loved.", "ex2": "Someone who is worshipped, feared, and utterly alone — the tyranny that was supposed to guarantee they'd never be abandoned has guaranteed they'll never be reached.", "ex3": "A lover who ends their life surrounded by people who are afraid of them and mourned by no one — the ultimate testament to what power, without love, actually produces."}]}]}, {"name": "The Captive", "factor": "Factor 5: Dominance ↔ Submission", "factor_num": 5, "pole": "Submission", "color": "#6080A0", "alignment": "Shadow", "tagline": "I have forgotten that I can stand.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Living Bondage", "desc": "Has internalized captivity so completely it has become identity. Doesn't experience themselves as trapped because the cage has been absorbed into their self-concept. They don't know where the captivity ends and they begin.", "ex1": "A person who would reject rescue because the prison is all they know — freedom would be disorienting, terrifying, and functionally meaningless to someone who has built their entire identity around containment.", "ex2": "Someone whose friends describe as 'broken' and who would describe themselves as 'content' — and both descriptions are true in a way that makes the situation harder to address.", "ex3": "A lover who has been so long in submission that the standing muscles have atrophied — they couldn't rise if they wanted to, and they've stopped wanting to."}, {"n": 6, "name": "Comfortable Cage", "desc": "Has made the captivity habitable. Built routines within constraints, found pleasure within restrictions, constructed meaning within limitations. The cage is decorated and the Captive has stopped noticing the bars.", "ex1": "A person who has organized their life around their partner's rules and found a form of peace within them — the peace is real, the freedom is gone, and they don't feel the loss.", "ex2": "Someone whose daily routine is entirely dictated by another person and who describes the routine as 'our life' with genuine warmth.", "ex3": "A lover who has adjusted to captivity the way the body adjusts to chronic pain — the baseline has shifted so far that normal registers as absence."}, {"n": 5, "name": "Normalized Helplessness", "desc": "Has internalized the belief that they can't function independently. Not from laziness — from genuine learned helplessness. Previous attempts at independence were punished, failed, or both, until the capacity for self-direction atrophied.", "ex1": "A partner who genuinely believes they can't manage finances, can't navigate social situations, and can't make good decisions — beliefs installed by someone who needed them to be helpless.", "ex2": "Someone who was once competent and confident and now defers on everything — the change was gradual enough that neither person marked the transition.", "ex3": "A lover who experiences autonomy as dangerous because the last time they asserted themselves, the consequences taught them never to try again."}, {"n": 4, "name": "Anxious Compliance", "desc": "Complies from fear rather than choice. Every act of submission is driven by the anxiety of what happens if they don't — not by the pleasure of yielding. The external behavior looks like the Kneel; the internal experience is dread.", "ex1": "A partner who says 'yes' to everything not from agreement but from the learned knowledge that 'no' produces consequences they can't survive.", "ex2": "Someone whose apparent agreeableness is actually hypervigilance — they've learned to say what the dominant partner wants before the want is expressed.", "ex3": "A lover whose 'submission' is actually survival, and who has lost the ability to tell the difference."}, {"n": 3, "name": "Flickering Awareness", "desc": "Beginning to sense that something is wrong. Occasional flashes of clarity — 'this isn't right' — followed by immediate suppression. The awareness surfaces and is pushed back under, repeatedly, like a drowning person's hand.", "ex1": "A person who reads an article about unhealthy dynamics and thinks 'that sounds familiar' and then immediately thinks 'but our situation is different' — the recognition and the denial happening simultaneously.", "ex2": "Someone who has started crying at unexpected moments — in the shower, in the car — and doesn't know why, because the knowledge of why is kept just below the surface of consciousness.", "ex3": "A lover who is waking up inside a cage they didn't know they were in, and the waking is as painful as anything they've experienced."}, {"n": 2, "name": "Visible Damage", "desc": "The captivity has begun to show. Physical health declining, social connections severed, professional life degraded. Others can see the damage even if the Captive can't — or won't.", "ex1": "A person whose coworkers have noticed the weight change, the flinching at loud sounds, and the way they check their phone with the anxiety of someone monitoring a threat.", "ex2": "Someone whose family has started making calls — to each other, to professionals, to helplines — because the person they knew is disappearing into someone else's shadow.", "ex3": "A lover whose body is keeping the score that their mind refuses to: the headaches, the stomach problems, the insomnia, the immune collapse — each symptom a word in a message they can't bring themselves to read."}, {"n": 1, "name": "Complete Captivity", "desc": "There is no self left that isn't defined by the captor. Thoughts, feelings, and behaviors are all organized around one question: 'what do they want?' The person who existed before the captivity has been overwritten — and the overwriting was so complete that recovery, if it comes, will be the work of years.", "ex1": "A person who, if rescued, would have to learn to be a person again from scratch — desires, opinions, preferences, agency — all rebuilt from rubble.", "ex2": "Someone whose therapist, if they ever get one, will describe the work ahead in terms usually reserved for rebuilding after natural disasters: triage first, then foundations, then walls, then — eventually, hopefully — windows.", "ex3": "A lover who was once a complete person and is now a response system — input from the captor produces output for the captor, and between inputs, nothing happens. The lights are off until someone needs them on."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Residual Devotion", "desc": "Even in captivity, the Captive's deepest instinct is to serve. At their best, this manifests as a profound, instinctive care that persists despite their own diminishment — they protect the partner's wellbeing even when their own has been destroyed.", "ex1": "A person who, despite being controlled and diminished, still remembers the partner's medications, still comforts the partner during nightmares, still produces acts of care from a place of near-emptiness.", "ex2": "Someone whose love persists like a plant growing through concrete — technically impossible, actually happening, heartbreaking to witness.", "ex3": "A lover whose capacity for care has survived their own destruction, and the survival of that capacity is both their greatest strength and their greatest tragedy."}, {"n": 4, "name": "Functional Service", "desc": "Provides care and service out of deeply ingrained habit. The giving is automatic — meals prepared, needs anticipated, comfort provided — and the automation means it continues long after the person behind it has checked out.", "ex1": "A partner who performs the mechanics of love with the efficiency of a machine: laundry, dinner, affection, all on schedule, all without presence.", "ex2": "Someone whose service is so reliable that the dominant partner mistakes the reliability for contentment — the machine runs so smoothly that nobody checks whether anyone's inside.", "ex3": "A lover whose care has become a subroutine — running in the background, consuming resources, producing output, unconnected to any felt experience."}, {"n": 1, "name": "Nothing Left to Give", "desc": "Has been so thoroughly depleted that even automatic care has ceased. The Captive sits, exists, and waits. Not resistant, not compliant — simply inert. The service has stopped because the person has stopped.", "ex1": "A partner who no longer cooks, no longer cleans, no longer reaches out — not from defiance but from the same state a battery reaches when it's completely drained: nothing left to discharge.", "ex2": "Someone whose dominant partner finally notices something is wrong — not because the Captive changed, but because the output stopped, and the sudden silence is alarming.", "ex3": "A lover whose final act of communication is the cessation of function — the body's way of saying what the mouth couldn't: 'I have nothing left.'"}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Enabling the Abuser", "desc": "The Captive's total compliance has become the infrastructure of the dominant partner's worst behaviors. By never resisting, they've removed every check on the partner's power. The Captive didn't create the abuse — but the absence of resistance has shaped the container it fills.", "ex1": "A relationship where the abuser has never been challenged because the Captive absorbs everything — and the absorbing has taught the abuser that there are no limits.", "ex2": "Someone whose complete yielding has enabled escalation that might have been checked by resistance — each unchallenged act of control giving permission for the next.", "ex3": "A lover whose captivity has become the silent partner of their own oppression."}, {"n": 4, "name": "Stockholm Bond", "desc": "Has developed a genuine emotional bond with the person who controls them. Defends the dominant partner to outsiders, empathizes with their struggles, and has constructed a narrative where the control is protection and the captor is a savior.", "ex1": "A person who says 'you don't know them like I do — they're actually very gentle' about someone whose behavior would alarm any outside observer.", "ex2": "Someone who has internalized the dominant partner's narrative so completely that they volunteer to enforce the rules on themselves — the guard has become unnecessary because the prisoner runs the prison.", "ex3": "A lover who loves their captor and will resist rescue because the rescue threatens the only stable relationship they have, even though the stability is made of chains."}, {"n": 1, "name": "Mutual Destruction", "desc": "Both people are being destroyed by the dynamic. The Captive is empty; the captor is hollow. The relationship continues because neither person can imagine an alternative — the Captive because they've forgotten alternatives exist, the captor because they've never needed to learn.", "ex1": "Two people in a room, one controlled and one controlling, both miserable, neither able to name what's wrong because the wrongness IS the relationship and the relationship is all either of them has.", "ex2": "A dynamic that has consumed both participants so thoroughly that an outside observer would struggle to identify which person is more damaged — the one without freedom or the one without the ability to connect.", "ex3": "A lover and a captor who have become mirrors of each other's pathology — each one's dysfunction perfectly fitted to the other's, locked together in a system that produces nothing but its own continuation."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Rescue", "desc": "When genuine kindness reaches the Captive — real, unconditional, patient care — something stirs. The person underneath the captivity flickers. Like a plant receiving water after drought, the response is slow, tentative, and potentially the beginning of everything.", "ex1": "A person who encounters a friend, a therapist, or a new presence who treats them with the respect the dominant partner doesn't — and the contrast produces a shock that begins the long process of awakening.", "ex2": "Someone who receives one act of unconditioned kindness and carries it like a seed through years of captivity — the kindness doesn't free them immediately, but it plants the idea that freedom exists.", "ex3": "A lover who is reached, finally, by something that bypasses the defenses the captor built — and the reaching is the first step of a journey that will take years but begins with a single moment of being truly seen."}, {"n": 4, "name": "Confused Reception", "desc": "Receives kindness and doesn't know what to do with it. The Captive's system is calibrated for commands, not care. Genuine warmth arrives and the receptor doesn't recognize the format.", "ex1": "A person who is treated gently and becomes suspicious — not because they don't want gentleness but because gentleness, in their experience, is usually the prelude to something worse.", "ex2": "Someone who receives a compliment and checks the dominant partner's face for permission to accept it — the reflex reveals the depth of the conditioning.", "ex3": "A lover who is offered love and runs it through a threat-detection system so sophisticated it rejects anything that doesn't come packaged as authority."}, {"n": 1, "name": "Unreachable", "desc": "The captivity has become so total that external care cannot penetrate. Friends try, family tries, professionals try — and the Captive, from inside the cage, cannot perceive the help as help. The dominant partner's reality is the only reality, and alternative realities register as threats.", "ex1": "A person whose sister begs them to leave and who responds with 'you've never understood my relationship' — and the sister weeps because the person saying this was once someone who understood themselves.", "ex2": "Someone who sits in a therapist's office at a family member's insistence and cannot hear anything the therapist says because the dominant partner's voice is louder even in their absence.", "ex3": "A lover who has been so thoroughly claimed that rescue is experienced as attack — help is a threat to the only stable reality they have, and they will defend their cage with everything they have left."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Seeking New Captors", "desc": "If freed, immediately seeks a new captor. Freedom is intolerable — the absence of control produces anxiety so severe that the Captive will find someone, anyone, to hand themselves to. The cage is the need; the specific captor is interchangeable.", "ex1": "A person who leaves an abusive partner and is in a new controlling relationship within weeks — not because they didn't learn, but because the learning their system did was 'captivity is home.'", "ex2": "Someone whose friends have watched them leave one captor for another, repeatedly, and have started to understand that the problem isn't bad luck — it's a homing signal.", "ex3": "A lover who can't survive uncontained, and whose search for a new container is as desperate and as predictable as it is heartbreaking to witness."}, {"n": 4, "name": "Inviting Control", "desc": "Unconsciously signals for dominant partners. The body language, the deference, the visible need for direction — all broadcast a frequency that controlling people receive and respond to. The Captive is a magnet for captors.", "ex1": "A person who enters a room and dominant people can identify them within seconds — not because of anything they say but because of the quality of their attention: scanning, assessing, preparing to yield.", "ex2": "Someone who describes their 'type' as 'confident, take-charge people' without recognizing that 'take-charge' has, in their experience, always escalated to 'take-over.'", "ex3": "A lover whose pattern is so consistent it could be mapped: meet a dominant person, yield immediately, get controlled, get destroyed, get free, repeat."}, {"n": 1, "name": "Permanent Captivity", "desc": "The Captive's final state: unable to function without control, unable to recognize healthy relationships, unable to believe in their own agency. Whether they're with a captor or between captors, the internal captivity is permanent — the cage has been built inside, and no external rescue can reach it.", "ex1": "A person who will spend their life in one cage or another — literal or psychological — because the internal architecture requires walls, and without them, the structure collapses.", "ex2": "Someone who sits alone in a free room and feels more trapped than they did in the controlled one — because in the controlled room, someone else handled the terror of existence, and in the free room, the terror is all theirs.", "ex3": "A lover who is the system's deepest tragedy: a person who was not born captive but was made captive, and whose making was so thorough that the original person — the one who could have stood, could have chosen, could have been free — exists now only as a rumor inside a ruin."}]}]}, {"name": "The Open Book", "factor": "Factor 6: Revelation ↔ Mystery", "factor_num": 6, "pole": "Revelation", "color": "#C7A050", "alignment": "Healthy", "tagline": "Here I am, all of me, in the light.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Crystal", "desc": "Transparent in the way that clear water is transparent — you can see all the way to the bottom, and the bottom is clean. Their honesty isn't performative; it's constitutional. They couldn't hide if they tried, and they've stopped trying, and the not-trying has become its own form of beauty.", "ex1": "A person whose partner says 'I've never had to guess with you — not once' and means it as the deepest compliment they know.", "ex2": "Someone who shares their fears, desires, flaws, and joys with equal willingness — not because they're fearless but because they've decided that being known is worth the risk of being judged.", "ex3": "A lover whose emotional transparency functions as an invitation: 'Here's everything. You can do whatever you want with it. I trust you to be careful.'"}, {"n": 6, "name": "Lantern", "desc": "Radiates honesty outward. Their transparency illuminates not just themselves but the space around them — partners feel permission to be honest because the Open Book has gone first.", "ex1": "A partner who shares something vulnerable at dinner and the whole table relaxes, because one person's honesty gave everyone else permission.", "ex2": "Someone whose willingness to say 'I'm afraid' or 'I don't know' or 'I was wrong' has made every relationship they're in more honest by osmosis.", "ex3": "A lover whose openness is actively contagious — people around them become more honest versions of themselves."}, {"n": 5, "name": "Clear Window", "desc": "Consistently honest and open. Partners always know what they're thinking, feeling, and wanting. Occasionally shares too much or too soon, but the impulse is healthy and the calibration is improving.", "ex1": "A partner who answers 'how are you?' with the actual answer every time — which is refreshing at home and occasionally startling at the grocery store.", "ex2": "Someone whose friends describe as 'what you see is what you get' and mean it as both compliment and gentle warning.", "ex3": "A lover who overshares on first dates in a way that's endearing rather than alarming — the honesty is slightly excessive and completely genuine."}, {"n": 4, "name": "Comfortable Honesty", "desc": "Open within established relationships, more reserved with strangers. Their transparency has appropriate gates — the inner circle gets everything, the outer circle gets warmth. The boundaries are healthy, if slightly less transparent than the Open Book ideal.", "ex1": "A partner who is an open book at home and a friendly closed one at work — the transparency has context, which makes it sustainable.", "ex2": "Someone who shares readily but has learned, through experience, that not every audience deserves the full show.", "ex3": "A lover whose honesty is reliable within the relationship and calibrated outside it."}, {"n": 3, "name": "Selective Transparency", "desc": "Open about some things, closed about others. Shares feelings readily but hides certain fears. Talks about the present but guards the past. The openness has gaps that the person may not recognize.", "ex1": "A partner who talks freely about their emotions but has never mentioned their childhood — and the omission is so smooth it passes as completeness.", "ex2": "Someone who is transparent about 80% of their inner life and has the remaining 20% locked in a room they've decorated to look like a wall.", "ex3": "A lover whose partner feels they know them deeply and is correct about the visible portion — the invisible portion hasn't been mapped by either person."}, {"n": 2, "name": "Performative Openness", "desc": "Appears open but the openness is curated. Shares carefully selected vulnerabilities that create the impression of transparency while protecting the real material. The partner thinks they see everything; they see a highlight reel.", "ex1": "A person who has a set of 'go-to vulnerabilities' they deploy in new relationships — authentic enough to feel real, shallow enough to cost nothing.", "ex2": "Someone whose apparent openness is a magic trick: look at this hand while the other hand hides the thing that actually matters.", "ex3": "A lover who has confused being articulate about feelings with being honest about them — the words flow freely, the truth less so."}, {"n": 1, "name": "Closed Posing as Open", "desc": "Has constructed such a convincing performance of openness that even they believe it. The mask IS the face, as far as they know. Somewhere underneath is a person they haven't met, guarded by a transparency so complete it functions as camouflage.", "ex1": "A person who could pass a lie detector about their own honesty — because the deception is so deep it's become conviction.", "ex2": "Someone whose partner says 'they tell me everything' and is tragically wrong — the everything they receive is a perfect replica of openness with no actual openness inside.", "ex3": "A lover who has hidden so effectively behind the appearance of revelation that the real self has become inaccessible even to them."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Total Invitation", "desc": "Offers the partner full access to their inner world — not as demand but as gift. The partner is invited to know everything: every thought, every fear, every desire. The invitation creates a space where the partner can choose how deep to go.", "ex1": "A lover who says 'ask me anything and I'll tell you the truth' and the partner has tested this over years and found it structurally sound.", "ex2": "Someone who narrates their inner process to the partner in real time: 'I'm feeling jealous right now and I know it's irrational — I just want you to know it's happening so it doesn't come out sideways.'", "ex3": "A partner whose radical transparency has made the relationship the most honest space either of them has ever inhabited."}, {"n": 6, "name": "Generous Disclosure", "desc": "Proactively shares information the partner might need. Doesn't wait to be asked — anticipates what transparency serves the relationship and provides it. The sharing is generous and well-timed.", "ex1": "A partner who says 'I want you to know that I ran into my ex today and we had coffee and here's what we talked about' — offering the information before suspicion could form.", "ex2": "Someone who discloses attractions, doubts, and concerns as they arise rather than letting them accumulate into secrets.", "ex3": "A lover whose honesty functions as preventive medicine — most relationship problems never form because the information that would fuel them is shared openly."}, {"n": 5, "name": "Reliable Honesty", "desc": "Consistently truthful in a way the partner can depend on. Answers questions honestly, shares feelings openly, and doesn't hide significant information. Occasionally blunt, but the partner has learned to value the directness.", "ex1": "A partner who is asked 'does this look good on me?' and gives an honest answer delivered with enough kindness that the honesty is received as care rather than criticism.", "ex2": "Someone whose partner says 'I always know where I stand' and means it as the foundation of their security.", "ex3": "A lover whose honesty has become the relationship's most reliable feature — not always comfortable, always trustworthy."}, {"n": 4, "name": "Standard Honesty", "desc": "Truthful about the big things, occasionally vague about the small ones. Doesn't lie but doesn't always volunteer. The partner gets accuracy on demand without the proactive transparency of higher levels.", "ex1": "A partner who answers every question truthfully but doesn't generate unsolicited honesty — the information is available but requires retrieval rather than arriving automatically.", "ex2": "Someone who says 'you didn't ask' when the partner discovers something undisclosed — technically correct, relationally insufficient.", "ex3": "A lover whose honesty is responsive rather than proactive, which works until the partner needs to know something they didn't think to ask about."}, {"n": 3, "name": "Filtered Honesty", "desc": "Tells the truth but edits it. The partner gets a version of events that is technically accurate and strategically incomplete. Not lying — curating. The difference is important to the Open Book and invisible to the partner.", "ex1": "A partner who describes their day accurately but omits the part where the attractive coworker complimented them — not because it means anything, but because including it feels like it would become something.", "ex2": "Someone who has developed an unconscious filter that removes information predicted to cause discomfort — the honesty passes through a mesh that catches anything inconvenient.", "ex3": "A lover whose partner gets the truth, the whole truth, and nothing but the truth — minus the parts that might start a conversation the Open Book doesn't want to have."}, {"n": 2, "name": "Protective Dishonesty", "desc": "Has started lying to the partner 'for their own good.' Small lies that prevent worry, dodge conflict, or preserve peace. Each lie is individually justified and collectively corrosive.", "ex1": "A partner who says 'I'm fine' when they're not, 'just tired' when they're sad, and 'nothing's wrong' when everything is — and believes each time that the lie serves the relationship.", "ex2": "Someone who has started maintaining two versions of events: the real one and the one optimized for the partner's comfort.", "ex3": "A lover whose 'protective' dishonesty has created a gap between the relationship the partner thinks they're in and the one that actually exists."}, {"n": 1, "name": "Silent Withdrawal", "desc": "Has stopped sharing entirely. Not lying — just not speaking. The partner asks and gets monosyllables. The inner world that was once freely offered has been sealed shut, and the silence is so complete the partner grieves it like a death.", "ex1": "A partner whose responses have dwindled from paragraphs to sentences to words to nods — the withdrawal is measured in the shrinking unit of communication.", "ex2": "Someone whose partner says 'you used to tell me everything' and the Open Book says 'I know' — and both of them hear the finality in the two words.", "ex3": "A lover whose silence contains more information than their speech ever did — the silence says 'I've given up on being known by you.'"}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Weaponized Honesty", "desc": "Uses truth as a bludgeon. Every honest statement is technically true and strategically deployed to wound. The transparency hasn't changed; the intent behind it has become lethal.", "ex1": "A lover who says 'I need to be honest — I found your friend more attractive than you tonight' and delivers it as duty while knowing exactly what it will do.", "ex2": "Someone who confesses every negative thought about the partner under the banner of 'radical honesty' — converting their inner critic into the partner's outer one.", "ex3": "A partner who has made 'I'm just being honest' into a preface for cruelty so reliable the partner flinches at the phrase."}, {"n": 6, "name": "Compulsive Disclosure", "desc": "Cannot stop sharing, even when the sharing is harmful. Every thought that passes through their mind is transmitted to the partner, unfiltered, unedited, regardless of its impact. The honesty has become a compulsion rather than a choice.", "ex1": "A partner who says 'I had a dream about your sister last night' — not from malice but from a genuine inability to hold anything inside, even when holding it would be the kind thing to do.", "ex2": "Someone whose partner has learned to brace when they hear 'I need to tell you something' because the something is always true, always unnecessary, and always destabilizing.", "ex3": "A lover whose honesty has become an uncontrolled broadcast — every signal transmitted at full volume, regardless of whether the receiver wants or needs it."}, {"n": 5, "name": "Honesty as Burden Transfer", "desc": "Shares truths that transfer pain from themselves to the partner. The confession cleanses the Open Book and contaminates the partner. 'I feel so much better now that I've told you' — yes, and the partner now carries what was just set down.", "ex1": "A partner who confesses a fleeting attraction to relieve their own guilt, leaving the partner with an image they can't unsee and a doubt that won't dissolve.", "ex2": "Someone who processes all their anxiety by narrating it to the partner, converting private turmoil into shared distress without ever asking whether the partner has the capacity to hold it.", "ex3": "A lover who has made their partner into an emotional landfill — everything the Open Book doesn't want to carry gets deposited there, under the banner of 'transparency.'"}, {"n": 4, "name": "Demanding Reciprocal Disclosure", "desc": "Shares everything and demands the partner do the same. Their own transparency has become a standard they impose — any privacy the partner maintains is treated as deception.", "ex1": "A partner who says 'I told you my darkest secret — now you have to tell me yours' and means 'have to' with the weight of a moral obligation.", "ex2": "Someone who has made their own openness into a weapon of surveillance: 'I share everything with you — why won't you share everything with me? What are you hiding?'", "ex3": "A lover who has confused their own need to be known with the right to know everything about another person."}, {"n": 3, "name": "Honesty as Control", "desc": "Uses selective truth-telling to control the narrative. Shares certain truths to manipulate the partner's perception while withholding others. The appearance of total honesty masks a strategic deployment.", "ex1": "A partner who 'honestly' shares that a coworker flirted with them (to trigger jealousy) while 'honestly' omitting that they flirted back (to maintain innocence).", "ex2": "Someone who has weaponized partial truth — each disclosure is accurate and the combination is a lie.", "ex3": "A lover who has turned honesty into a precision instrument for shaping the partner's reality."}, {"n": 2, "name": "Public Exposure", "desc": "Shares the partner's private information with others. The Open Book's commitment to transparency extends to telling friends, family, and strangers things the partner shared in confidence.", "ex1": "A partner who tells their mother about the couple's sex life, tells their friends about the partner's insecurities, and shares private arguments on social media — all under the justification of 'I don't believe in secrets.'", "ex2": "Someone whose partner has stopped sharing anything sensitive because every disclosure becomes public knowledge within the week.", "ex3": "A lover who has made the partner's privacy a casualty of their own compulsive openness."}, {"n": 1, "name": "Exposure as Annihilation", "desc": "Uses the partner's most private information to destroy them. Secrets shared in intimacy are deployed as weapons of total war — the Open Book's knowledge of the partner's interior becomes a detonation device.", "ex1": "A lover who, during a breakup, publishes private messages, shares intimate photos, or reveals confidences to the partner's employer, family, or community — using total information as total destruction.", "ex2": "Someone who proves that the most dangerous person in the world is the one who knows everything about you and no longer cares about you.", "ex3": "A partner whose final act of 'honesty' is the exposure of another person's most protected self to the maximum possible audience."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Sacred Witness", "desc": "Receives the partner's honesty with the reverence it deserves. When the partner shares something vulnerable, the Open Book holds it without flinching, judging, or deploying. The partner's truth is treated as holy.", "ex1": "A lover who is told 'I was unfaithful once, years ago, before I knew you' and responds with 'thank you for trusting me with that' — and means it, and the trust deepens rather than breaking.", "ex2": "Someone who receives their partner's darkest confession and lets it change nothing about how they see them — because the seeing was already complete.", "ex3": "A partner whose reception of honesty makes the partner want to be more honest, creating a cycle of deepening trust."}, {"n": 6, "name": "Encouraging Reception", "desc": "Actively encourages the partner's honesty. Responds to vulnerability with warmth, to confession with gratitude, to difficult truths with steadiness. The partner learns that honesty is safe here.", "ex1": "A partner who says 'I want to know what you're really thinking, even if it's about me, even if it's hard' — and has backed it up enough times that the partner believes it.", "ex2": "Someone who celebrates the partner's transparency as an act of courage: 'I know that was hard to say. I'm glad you said it.'", "ex3": "A lover who has made their relationship the safest place in the partner's world to be honest."}, {"n": 5, "name": "Warm Reception", "desc": "Receives honesty with genuine warmth and appreciation. Doesn't always respond perfectly but the partner always feels that their truth was welcomed rather than tolerated.", "ex1": "A partner who sometimes flinches at hard truths but always recovers, processes, and returns to the conversation with openness.", "ex2": "Someone whose initial reaction might be hurt but whose considered reaction is always gratitude for the honesty.", "ex3": "A lover whose reception has a slight delay — the truth lands, there's a beat, and then the warmth arrives."}, {"n": 4, "name": "Adequate Reception", "desc": "Receives honesty competently but without particular skill. The partner's truths are heard, acknowledged, and sometimes clumsily handled. Good enough, not transformative.", "ex1": "A partner who responds to vulnerability with 'okay' — not dismissive, not effusive, just... noted. The partner feels heard if not deeply held.", "ex2": "Someone who receives difficult truths by going quiet and thinking, which the partner sometimes reads as withdrawal and sometimes reads as processing.", "ex3": "A lover whose reception of honesty is the emotional equivalent of a competent handshake: firm, appropriate, and nobody's going to write poetry about it."}, {"n": 3, "name": "Selective Reception", "desc": "Receives certain truths well and others poorly. Can handle 'I'm sad' but not 'I'm attracted to someone else.' Can handle 'I disagree' but not 'I'm doubting us.' The reception has categories and the partner has learned which ones are safe.", "ex1": "A partner who is wonderful at receiving emotional disclosure and terrible at receiving relational disclosure — tell them you're depressed and they're a rock, tell them you're unsure about the relationship and they spiral.", "ex2": "Someone whose reception creates an invisible map of permissible honesty — the partner can be truthful within the green zones and has learned to avoid the red ones.", "ex3": "A lover whose partner has started sorting truths into 'safe to share' and 'keep to yourself' — and the sorting has replaced the openness."}, {"n": 2, "name": "Punitive Reception", "desc": "Punishes certain truths. The partner learns through experience which honest disclosures produce warmth and which produce cold, and adjusts accordingly. The Open Book asks for honesty and penalizes it.", "ex1": "A partner who says 'tell me the truth' and then doesn't speak for three days after hearing it — training the partner that truth has a price.", "ex2": "Someone who explicitly requests transparency and implicitly punishes it, creating a double bind the partner can't navigate without losing.", "ex3": "A lover who has made honesty a trap: demanded, received, and weaponized through reaction."}, {"n": 1, "name": "Reception Destroyed", "desc": "Cannot receive honesty at all. The partner's truth triggers such severe reactions — rage, collapse, withdrawal — that the partner has stopped being honest entirely. The Open Book has killed the transparency they once valued.", "ex1": "A partner whose reactions to truth have been so consistently devastating that the other person has built an elaborate system of lies designed to maintain peace.", "ex2": "Someone who theoretically values honesty and has practically made it impossible — the partner now manages them through strategic omission.", "ex3": "A lover who demanded to be married to an open book and then burned every page they didn't like, until the partner stopped writing."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Truth as Threat Detection", "desc": "Scans every disclosure for danger. The partner's honesty is received not as intimacy but as intelligence — each piece of truth analyzed for threat content. Being told 'I love you' is processed through the same system as being told 'I'm leaving.'", "ex1": "A person who hears 'I had lunch with a colleague' and runs it through a forensic analysis: which colleague? What restaurant? How long? Was this mentioned spontaneously or reluctantly?", "ex2": "Someone who has turned the partner's openness into a surveillance feed — every honest disclosure becomes a data point in an ongoing threat assessment.", "ex3": "A lover who can't receive truth as gift because they can only receive it as evidence."}, {"n": 6, "name": "Weaponized Memory", "desc": "Stores every disclosure for future deployment. The partner's honesty becomes an armory — each vulnerability shared is a weapon catalogued for the next conflict.", "ex1": "A partner who remembers every confession, every fear, every insecurity, and deploys them during arguments with the precision of someone who has been keeping inventory.", "ex2": "Someone whose partner realizes, too late, that every intimate conversation was being recorded in a ledger that would be opened during the next war.", "ex3": "A lover who receives honesty the way a spy receives intelligence: gratefully, carefully, and with plans for its strategic use."}, {"n": 5, "name": "Judgmental Reception", "desc": "Receives honesty and judges it. Every disclosure is evaluated on a moral scale. The partner feels assessed rather than accepted — their truth arrives in a courtroom, not a living room.", "ex1": "A partner who responds to 'I was attracted to someone today' with visible moral disgust — converting a moment of honesty into a moment of shame.", "ex2": "Someone who has a rating system for the partner's disclosures: acceptable truths are rewarded, unacceptable truths are prosecuted.", "ex3": "A lover who has turned the partner's openness into a grading rubric — and the partner has started only sharing A-grade material."}, {"n": 4, "name": "Overwhelmed Rejection", "desc": "The partner's honesty triggers emotional flooding. Not punishment — genuine overwhelm. The truth arrives and the receiver's system crashes. The partner learns to dose the honesty at the rate the Open Book can process, which is very slow.", "ex1": "A partner who receives 'I'm not sure this is working' and has a panic attack — not as manipulation but as a genuine system overload that the partner must then manage.", "ex2": "Someone whose emotional reactivity to honest input is so severe that the partner has become a permanent editor, reducing truth to the smallest survivable dose.", "ex3": "A lover whose nervous system treats honesty as a threat, making every disclosure a crisis that both people must survive."}, {"n": 3, "name": "Demanding Specific Truths", "desc": "Wants honesty but only the honesty that serves them. Demands to know about potential threats (attractions, doubts) but rejects honesty about their own flaws. The reception is selective and self-serving.", "ex1": "A partner who insists on knowing if their spouse was attracted to someone but refuses to hear 'sometimes you're controlling' — the truth they want is surveillance data, not feedback.", "ex2": "Someone whose commitment to honesty applies to the partner's behavior and conveniently excludes their own.", "ex3": "A lover who has weaponized the demand for transparency into a one-way mirror — they see everything, the partner sees nothing."}, {"n": 2, "name": "Truth as Ammunition Factory", "desc": "Has perfected the cycle: demand honesty, receive honesty, store honesty, deploy honesty as weapon. The partner is trapped in a loop where withholding is punished and sharing is punished — the only safe option is to stop existing.", "ex1": "A partner who demands to know 'everything' and then uses 'everything' as the foundation for an escalating system of emotional control.", "ex2": "Someone whose partner says 'I can't tell you the truth and I can't lie to you — what am I supposed to do?' — and the question is genuine and unanswerable.", "ex3": "A lover who has built a perfect trap from the partner's own honesty."}, {"n": 1, "name": "Destruction Through Knowledge", "desc": "Has used the partner's total honesty to dismantle them completely. Every truth shared in love has been converted into a control mechanism. The partner gave themselves completely and the receiver used the gift to build a prison. The ultimate betrayal of transparency.", "ex1": "A person whose partner opened every door and found that every room was being mapped for future occupation.", "ex2": "Someone whose partner's radical honesty gave them a blueprint of the partner's psyche — and they used the blueprint to demolish the building.", "ex3": "A lover who proves that the most dangerous thing you can give someone is the truth about who you are, if the someone you give it to is the wrong person."}]}]}, {"name": "The Veil", "factor": "Factor 6: Revelation ↔ Mystery", "factor_num": 6, "pole": "Mystery", "color": "#607090", "alignment": "Healthy", "tagline": "I reveal myself slowly, and only to those who earn it.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Living Depth", "desc": "Their mystery is genuine — not withheld material but actual depth. There is always more to discover not because they're hiding but because they are genuinely complex. The partner is on a lifelong excavation that never hits bottom.", "ex1": "A person who, after twenty years of marriage, still surprises their partner — not with secrets but with dimensions. 'I didn't know you could paint.' 'I didn't know you thought about that.'", "ex2": "Someone whose inner life is so rich that sharing all of it would take longer than a lifetime — the mystery is abundance, not concealment.", "ex3": "A lover who makes their partner feel that knowing them is an infinite project, and the infiniteness is the appeal."}, {"n": 6, "name": "Earned Intimacy", "desc": "Reveals themselves progressively, with intention. Each disclosure is a gift given when the recipient has demonstrated they can hold it. The pacing creates anticipation and deepens trust.", "ex1": "A partner who shared their childhood on the third month, their sexual history on the sixth, and their deepest fear on the first anniversary — each revelation timed to the relationship's readiness.", "ex2": "Someone who treats self-disclosure the way a novelist treats plot — with pacing, tension, and the understanding that the best revelations come when the reader is ready for them.", "ex3": "A lover whose partner describes falling in love as 'an unfolding — every week I discovered something new, and each discovery made me want to stay longer.'"}, {"n": 5, "name": "Comfortable Reserve", "desc": "Naturally private without being secretive. Shares when asked, holds back when not. The reserve is constitutional rather than strategic — they simply don't broadcast, and the quietness has its own appeal.", "ex1": "A partner who doesn't volunteer emotional information but responds fully when asked — the inner world is accessible but not advertised.", "ex2": "Someone whose friends describe as 'still waters run deep' and mean it without cliche — the depth is real and the surface is genuinely calm.", "ex3": "A lover who is an acquired taste: initially quiet, gradually profound, ultimately irreplaceable."}, {"n": 4, "name": "Pleasant Opacity", "desc": "Agreeably private. People enjoy their company without knowing them deeply. The veil is light but consistent — they share just enough to be warm without ever becoming transparent.", "ex1": "A person everyone likes and nobody knows — the charm is real and the depth is inaccessible, and most people don't notice the lock on the door because the porch is so welcoming.", "ex2": "Someone who deflects personal questions with graceful redirection — 'but what about you?' deployed so smoothly the other person doesn't realize they've been steered.", "ex3": "A lover whose partner feels they know them well and, if pressed to describe their inner life, would discover they're extrapolating from limited data."}, {"n": 3, "name": "Guarded Reserve", "desc": "The privacy has become slightly defensive. Not just naturally quiet — actively protective. Certain areas are walled off and the walls are visible, though not aggressive.", "ex1": "A partner who tenses visibly when questions approach certain topics — childhood, past relationships, specific years — and the partner has learned the no-fly zones by watching the body language.", "ex2": "Someone who redirects from difficult topics with increasing skill and decreasing subtlety — the evasion is becoming a pattern the partner can map.", "ex3": "A lover whose reserve has started to feel like a border crossing — papers required, access not guaranteed."}, {"n": 2, "name": "Secretive", "desc": "The mystery has become dishonesty by omission. They're not lying — they're withholding so much that the gap between what the partner knows and what's real has become a chasm the partner can sense but not see.", "ex1": "A person whose phone, laptop, and correspondence are managed with the security protocols of a spy — not because the content is damaging but because the habit of concealment has become total.", "ex2": "Someone whose partner says 'I feel like I don't know you' and the Veil says 'you know me' — and both statements are partially true and completely irreconcilable.", "ex3": "A lover whose privacy has become a lie of architecture — no single piece of withheld information is a lie, but the aggregate concealment is a deception."}, {"n": 1, "name": "Sealed", "desc": "There is no access. The veil has become a wall, the wall has become a bunker, and the person inside has forgotten there's a world outside. They are a secret even from themselves.", "ex1": "A person who has protected their inner life so effectively that it has atrophied — the things being protected no longer exist, but the protection continues on automatic.", "ex2": "Someone whose partner mourns a person they've never met — the real version of the Veil, the one behind all the veils, who may no longer exist.", "ex3": "A lover who was once mysterious and is now simply absent — the depth they once hinted at has been sealed so long it may have dried up entirely."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Gradual Unveiling", "desc": "Reveals themselves to the partner in a paced, intentional progression that deepens intimacy over years. Each revelation is a gift that acknowledges the partner's growing capacity to hold more. The partner feels they're being invited into a temple, one room at a time.", "ex1": "A lover who, on the tenth anniversary, shares something they've never told anyone — and the partner understands that the timing is the message: you've earned this.", "ex2": "Someone whose partner describes the relationship as 'an endless discovery' — not because the Veil is playing games but because there's genuinely always more.", "ex3": "A partner whose measured self-disclosure has made the partner a better listener, a more patient person, and a more attentive lover — the pacing taught them to wait for what matters."}, {"n": 5, "name": "Selective Sharing", "desc": "Shares meaningfully but not comprehensively. The partner gets deep access to certain domains (emotional, intellectual, sexual) while others remain private. The selection is intuitive rather than strategic.", "ex1": "A partner who shares their creative work, their professional anxieties, and their sexual desires freely — but has never mentioned their family of origin, and the gap is felt but unaddressed.", "ex2": "Someone who is deeply intimate in some channels and completely closed in others — the partner knows their body and their mind but not their past.", "ex3": "A lover whose selective transparency creates a relationship that is simultaneously deep and incomplete."}, {"n": 3, "name": "Withheld Warmth", "desc": "Warm but guarded. The partner can feel the warmth and can feel the guard, and the combination creates a persistent longing — close enough to sense the heat, too far to be warmed by it.", "ex1": "A partner who stands just outside the circle of full intimacy, receiving enough warmth to stay but not enough to feel fully included.", "ex2": "Someone whose partner says 'I know you love me, I just wish I could FEEL it' — and the distinction between knowing and feeling is the Veil's signature wound.", "ex3": "A lover who is present in the room and absent in the moment — the body is close and the self is one step further away than the partner can reach."}, {"n": 1, "name": "Fortress", "desc": "Has built an impenetrable wall between themselves and the partner. Not hostile — just unreachable. The partner knocks and knocks and the sound echoes off stone.", "ex1": "A partner who has shared a bed with someone for ten years and knows less about their inner life than the barista who served them this morning.", "ex2": "Someone whose partner has given up asking and started accepting the surface as the entirety — a capitulation that feels like maturity and functions as grief.", "ex3": "A lover whose inaccessibility has become the defining feature of the relationship — the partner loves a locked door and has stopped hoping for a key."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Weaponized Mystery", "desc": "Uses their mystery as a tool of control. The partner is kept in a state of permanent uncertainty — never knowing enough to feel secure, always wanting more, always chasing the next revelation that never quite arrives.", "ex1": "A lover who doles out personal information the way a casino doles out wins — just enough to maintain engagement, never enough to allow satisfaction.", "ex2": "Someone who has discovered that mystery creates attachment and has begun deploying it strategically — each withheld piece of information is a hook the partner can't remove.", "ex3": "A partner who has made their own unknowability into the relationship's primary engine — the partner stays because they're still trying to solve the puzzle."}, {"n": 5, "name": "Calculated Concealment", "desc": "Strategically hides information to maintain advantage. What they reveal and what they conceal is determined by power analysis, not intimacy. The partner gets the information that keeps them compliant and is denied the information that would give them leverage.", "ex1": "A partner who shares emotions freely (creating the appearance of intimacy) while concealing finances, past relationships, and future plans (retaining control of all practical infrastructure).", "ex2": "Someone whose partner feels emotionally close and strategically blind — intimate in the bedroom and excluded from the boardroom.", "ex3": "A lover who has partitioned their transparency into 'emotional' (freely given) and 'strategic' (permanently withheld) — and the partner doesn't know the partition exists."}, {"n": 3, "name": "Lying by Omission", "desc": "The concealment has become deception. Not lying — never lying — but the systematic omission of information the partner needs has the same practical effect. The truth is technically preserved while the partner's understanding is thoroughly distorted.", "ex1": "A partner who never mentions the ex they still text, the debt they're accumulating, or the doubts they're having — each omission technically not a lie, collectively a deception.", "ex2": "Someone who, if confronted, can say 'I never lied to you' and be technically correct and morally wrong.", "ex3": "A lover who has built a relationship on a foundation of things unsaid — and the unsaid things are load-bearing."}, {"n": 1, "name": "Double Life", "desc": "The concealment has produced a parallel existence. The partner knows a version of the Veil that is incomplete to the point of fiction. Behind the veil is a life the partner has never seen, with elements that would fundamentally change their understanding.", "ex1": "A person with a second phone, a second apartment, or a second family — not from malice but from the long, logical conclusion of a life organized around concealment.", "ex2": "Someone whose partner will one day discover the hidden life and realize that the person they loved was a partial truth — and the partial truth was the lie.", "ex3": "A lover who proves that mystery, taken to its endpoint, is indistinguishable from deception."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Treasured Revelation", "desc": "Receives the partner's honesty as a gift of infinite value. Each disclosure is held with care, protected with vigilance, and honored with reciprocal (if slower) opening. The partner's truth is the most valuable thing the Veil has ever been given.", "ex1": "A lover who is told something vulnerable and handles it with such delicacy that the partner feels safer than they've ever felt — the Veil's instinct for privacy extends to protecting the partner's privacy as fiercely as their own.", "ex2": "Someone who says 'I will guard this with my life' about a partner's confession and means it with the intensity of someone who understands what private information is worth.", "ex3": "A partner whose reception of honesty is so careful, so reverent, so protective that the partner begins to trust them with increasingly precious material."}, {"n": 5, "name": "Respectful Privacy", "desc": "Receives the partner's disclosures and holds them securely. Doesn't push for more, doesn't share what's been given, doesn't use it as leverage. The partner's trust is protected by the same instinct that guards the Veil's own privacy.", "ex1": "A partner who has never, in any argument or crisis, revealed anything the other person told them in confidence — the vault is absolute.", "ex2": "Someone whose partner knows that whatever is shared will be held with the same intensity with which the Veil holds their own secrets.", "ex3": "A lover whose reception is a fortress — what goes in stays in, protected by the same walls that protect the Veil."}, {"n": 3, "name": "Uncomfortable with Excess", "desc": "Receives honesty up to a point, then becomes uncomfortable. The partner's oversharing triggers the Veil's own privacy instincts — 'I wouldn't share this, so hearing it makes me uneasy.'", "ex1": "A partner who listens attentively to emotional disclosures but becomes visibly uncomfortable when the partner shares sexual history, bodily details, or extreme vulnerability — the Veil's own reserve projecting onto the partner's openness.", "ex2": "Someone who says 'you don't have to tell me all that' and means it as protection for both of them — the Veil finds excessive disclosure painful to receive, not just to provide.", "ex3": "A lover whose preference for privacy extends to the information arriving, not just the information departing."}, {"n": 1, "name": "Cannot Receive Honesty", "desc": "The partner's transparency triggers withdrawal. The more the partner reveals, the more the Veil retreats — not from judgment but from the overwhelm of intimacy at a depth they can't match.", "ex1": "A person whose partner's radical openness feels like standing in a spotlight — too much exposure, too much visibility, even when the visibility is the partner's, not theirs.", "ex2": "Someone who shuts down when the partner goes deep — the intimacy is too hot, the proximity too close, and the Veil's only response is to add another layer.", "ex3": "A lover who has made the partner's openness feel like an intrusion, teaching the partner to moderate their honesty to the Veil's tolerance level."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Information as Power", "desc": "Receives every disclosure and stores it as leverage. The Veil's instinct for information management converts the partner's honesty into a strategic asset. What was shared in trust becomes a chip in a game the partner doesn't know they're playing.", "ex1": "A lover who receives confessions with perfect attentiveness and files each one in a system organized by potential utility.", "ex2": "Someone who never shares their own secrets and accumulates the partner's — creating an information asymmetry that gives them permanent advantage.", "ex3": "A partner who is both the safest and most dangerous person to confide in: safest because they'll never share it with others, most dangerous because they'll use it."}, {"n": 5, "name": "Silent Judgment", "desc": "Receives honesty and judges it silently. The partner shares and the Veil listens and the judgment is never spoken but permanently recorded. The partner can feel the assessment but can't confront it because it was never expressed.", "ex1": "A person who hears their partner's confession and says nothing — and the silence is heavier than any words, and the partner learns to read the silence as verdict.", "ex2": "Someone whose reception of vulnerability is technically neutral and energetically punishing — the partner shares and feels worse, without being able to identify why.", "ex3": "A lover who has turned silent judgment into the most effective discouragement of honesty — the partner stops sharing not because they were told to, but because sharing produces a chill they can feel but not name."}, {"n": 3, "name": "Asymmetric Exchange", "desc": "Takes information and gives none. The partner shares everything; the Veil shares nothing. The asymmetry has become the relationship's defining feature — one person fully known, one person completely unknown.", "ex1": "A partner who knows their spouse's every fear, desire, and shame while the spouse couldn't name the Veil's three closest childhood memories.", "ex2": "Someone who has created a relationship where knowledge flows in one direction — toward them, never away — and the partner hasn't noticed because the Veil's questions are so skillful.", "ex3": "A lover who has made the partner's transparency into a one-way mirror: they see everything, the partner sees nothing."}, {"n": 1, "name": "Consuming Trust", "desc": "Has consumed the partner's trust without returning anything. The partner gave everything — every secret, every vulnerability, every fear — and the Veil absorbed it all and offered nothing in return. The partner is naked; the Veil is armored. The asymmetry is total and the damage is irreversible.", "ex1": "A person who knows everything about the partner and has given the partner nothing — and the partner finally realizes that the 'mystery' was never depth, it was refusal, and the refusal was the only truth the Veil ever communicated.", "ex2": "Someone whose partner says 'I gave you everything and you gave me nothing' and the Veil can't argue because the accounting is accurate.", "ex3": "A lover who has proven that the most devastating form of deception isn't lying — it's receiving without reciprocating, knowing without being known, and allowing someone to love a person who was never actually there."}]}]}, {"name": "The Exhibitionist", "factor": "Factor 6: Revelation ↔ Mystery", "factor_num": 6, "pole": "Revelation", "color": "#C7A050", "alignment": "Shadow", "tagline": "Look at me. LOOK AT ME.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Broadcast Tower", "desc": "Has made their private life into a public performance. Every emotion, every intimacy, every crisis is material for the audience. The sharing isn't connection — it's production. They don't have experiences; they have content.", "ex1": "A person whose Instagram documents every aspect of their relationship — the fights, the make-ups, the intimate moments — and has confused documentation with living.", "ex2": "Someone who can't eat a meal without photographing it, can't feel a feeling without posting it, can't have a moment without narrating it for an audience they value more than the person sitting across from them.", "ex3": "A lover whose partner realizes they're not in a relationship — they're in a reality show with one camera operator and one unwilling cast member."}, {"n": 6, "name": "Attention Addict", "desc": "Overshares to generate response. The content of the sharing matters less than the reaction it produces. Vulnerability, shock, intimacy — all deployed as attention-getting mechanisms.", "ex1": "A person who shares deeply personal stories at parties not from trust but from the discovered power of vulnerability-as-spectacle — the audience gasps, the Exhibitionist feeds.", "ex2": "Someone who creates drama in their relationship specifically to have interesting material for conversations with friends.", "ex3": "A lover whose partner is the raw material for the Exhibitionist's social currency — every private moment is pre-evaluated for its story potential."}, {"n": 5, "name": "Oversharer", "desc": "Shares too much, too often, with too many people. The boundaries between private and public have eroded to the point where partners' secrets, bedroom details, and relationship problems are common knowledge in multiple friend groups.", "ex1": "A partner who tells their coworkers about last night's fight in enough detail that the coworkers have started taking sides.", "ex2": "Someone who shares intimate details about their sex life with friends who didn't ask and the partner doesn't know.", "ex3": "A lover whose partner discovers, at a dinner party, that everyone at the table knows about their most private insecurity — shared without permission as 'a funny story.'"}, {"n": 4, "name": "Confessional Personality", "desc": "Uses disclosure as social currency. Shares 'authentically' in ways designed to create a persona of raw honesty — but the rawness is curated and the honesty is performance. The confession is the brand.", "ex1": "A person who describes themselves as 'brutally honest' and has made their lack of filter into a personality trait — the brutality is the point, not the honesty.", "ex2": "Someone whose social media is a carefully constructed portrait of 'realness' that is as staged as any advertisement.", "ex3": "A lover who has built an identity around being 'unfiltered' without examining whether the lack of filter is courage or compulsion."}, {"n": 3, "name": "Desperate Revealer", "desc": "Shares increasingly personal material in pursuit of diminishing reactions. The audiences have habituated, so the disclosures must escalate. What once produced gasps now produces shrugs, driving the Exhibitionist to dig deeper into private material.", "ex1": "A person who has exhausted their own stories and has started sharing their partner's — because the partner's material is fresher and the audience hasn't heard it yet.", "ex2": "Someone whose friends have started to find the oversharing exhausting rather than interesting, and the declining attention is producing panic.", "ex3": "A lover whose need for audience has started to outpace their supply of material — and the gap is being filled with increasingly private, increasingly damaging disclosures."}, {"n": 2, "name": "Exhibitionism as Wound", "desc": "The sharing has become compulsive and joyless. They can't stop disclosing even when they know it's harmful — the exposure is a reenactment of some early violation of privacy, repeated as an attempt at mastery that never arrives.", "ex1": "A person who posts things they immediately regret, shares secrets they promised to keep, and reveals vulnerabilities they'll later wish they'd protected — and can't stop.", "ex2": "Someone whose therapist has identified the pattern: early boundary violations taught them that privacy isn't possible, so they preempt the violation by performing it themselves.", "ex3": "A lover whose oversharing is actually a trauma response — the voluntary exposure is an attempt to control what was once forced."}, {"n": 1, "name": "Empty Display", "desc": "All signal, no self. The broadcasting is total and the person behind it is absent. They've shared so much that there's nothing left that hasn't been performed, narrated, and distributed. The private self — if it ever existed — has been fully consumed by the public one.", "ex1": "A person who, in a moment of rare quiet, realizes they don't know who they are when nobody's watching — because they've arranged their life so that someone is always watching.", "ex2": "Someone whose entire inner life has been externalized to the point where the inside is empty — they've given away the contents and kept only the container.", "ex3": "A lover who has performed intimacy so many times for so many audiences that they can no longer access the genuine version — the signal has replaced the source."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Energizing Disclosure", "desc": "At their best, the Exhibitionist's willingness to go first creates permission. Their fearlessness about disclosure — though born from compulsion — can accidentally produce genuine breakthroughs when the partner meets it with real presence.", "ex1": "A lover who blurts out 'I'm terrified of losing you' in the middle of grocery shopping — and the spontaneity of the disclosure, though characteristically unfiltered, lands as the truest thing said all week.", "ex2": "Someone whose inability to hold anything back occasionally produces exactly the right revelation at exactly the right moment — accidentally rather than strategically.", "ex3": "A partner whose lack of filter, which is usually a liability, occasionally functions as a shortcut to intimacy that would take a more guarded person months."}, {"n": 5, "name": "Excessive but Genuine", "desc": "Shares too much with the partner too often but the sharing is real. The partner is overwhelmed by the volume but never in doubt about the sincerity. The problem isn't dishonesty — it's flooding.", "ex1": "A partner who processes every emotion verbally in real time, creating a continuous stream of disclosure that the other person must navigate like whitewater.", "ex2": "Someone whose partner has developed the skill of listening to a torrent and extracting the essential content — a form of intimacy born from necessity.", "ex3": "A lover whose openness is exhausting and genuine in equal measure."}, {"n": 3, "name": "Disclosure Without Permission", "desc": "Shares the partner's private information without consulting them. The Exhibitionist's commitment to openness overrides the partner's right to privacy — the partner's stories are told, their struggles broadcasted, their intimate moments narrated to others.", "ex1": "A partner who tells their parents about the couple's fertility struggles without asking — because in the Exhibitionist's world, information isn't owned by individuals, it's shared by default.", "ex2": "Someone whose partner has learned to preface every disclosure with 'please don't tell anyone this' — and the request works about half the time.", "ex3": "A lover whose partner has divided their life into 'safe to share with the Exhibitionist' and 'hide from the Exhibitionist' — and the hidden portion grows each year."}, {"n": 1, "name": "Partner as Material", "desc": "The partner has become content. Their life, their problems, their body, their secrets — all raw material for the Exhibitionist's audience. The partner is not a person to be loved but a story to be told.", "ex1": "A lover whose partner discovers a blog, a podcast, or a social media account dedicated to narrating their relationship — with details the partner never consented to share.", "ex2": "Someone whose partner's most vulnerable moments have been converted into the Exhibitionist's most engaging content — the partner's pain is the Exhibitionist's best material.", "ex3": "A partner who has been turned into a character in someone else's narrative without their consent, and the narrative has been published."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Exposure as Weapon", "desc": "Deliberately reveals the partner's secrets to punish or control. The Exhibitionist has a library of private information and the willingness to publish it at any moment. The threat of exposure is a permanent sword over the partner's head.", "ex1": "A lover who says 'if you leave, I'll tell everyone what you told me' — and the partner believes it because the Exhibitionist has a track record of publicizing private matters.", "ex2": "Someone who has weaponized intimacy itself — every moment of trust the partner offered is now a potential headline.", "ex3": "A partner who has made privacy into a hostage: give me what I want, or your secrets become public property."}, {"n": 5, "name": "Public Humiliation", "desc": "Shares embarrassing or painful information about the partner in social settings — framed as 'honesty' or 'humor' — to maintain social dominance and keep the partner off-balance.", "ex1": "A partner who tells the dinner table about the other person's bathroom habits 'as a joke' and laughs while the partner tries to shrink into their chair.", "ex2": "Someone who posts unflattering photos, tells embarrassing stories, and shares private struggles in group settings — each one deniable as 'just being open' and each one a small public execution.", "ex3": "A lover who has made the partner afraid of social gatherings because any gathering might contain a revelation they haven't consented to."}, {"n": 3, "name": "Manufactured Narrative", "desc": "Tells a version of the relationship to others that is strategically distorted. The Exhibitionist shares selectively to create a narrative where they're the victim or hero and the partner is the villain or supporting character.", "ex1": "A partner who describes their relationship to friends in a way the actual partner wouldn't recognize — omitting their own behavior, amplifying the partner's, constructing a story that serves the Exhibitionist's image.", "ex2": "Someone who has pre-poisoned every potential support system the partner might access — by the time the partner reaches for help, the helper has already heard the Exhibitionist's version.", "ex3": "A lover who has used selective disclosure as a preemptive strike against the partner's credibility."}, {"n": 1, "name": "Total Exposure", "desc": "Has stripped the partner of all privacy. Everything private has been made public. The partner's body, secrets, fears, and shames have all been offered to audiences the partner never chose. The Exhibitionist's need for disclosure has consumed not just their own privacy but the partner's.", "ex1": "A lover whose partner discovers that their most intimate moments — sexual, emotional, medical — have been shared with strangers on the internet.", "ex2": "Someone who has violated the partner's privacy so comprehensively that the partner no longer feels safe anywhere — because 'anywhere' might contain someone who knows something they shouldn't.", "ex3": "A partner who has exported the partner's interior to the exterior so completely that the partner has nowhere private left to exist."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Spotlight Reception", "desc": "Receives the partner's honesty and immediately evaluates it for audience potential. The partner's disclosure is valued not for its intimacy but for its narrative quality. 'That's such a good story' is the response where 'thank you for trusting me' should be.", "ex1": "A person who hears their partner's deepest confession and thinks 'this would make an amazing podcast episode' before thinking 'how do I hold this with care.'", "ex2": "Someone who receives vulnerability and immediately starts composing the retelling — the reception is simultaneous with the distribution planning.", "ex3": "A lover who treats the partner's inner life as a content pipeline."}, {"n": 4, "name": "Competitive Reception", "desc": "Receives the partner's disclosure and immediately one-ups it. Every vulnerability shared is met with a bigger one. The partner's honesty becomes a prompt for the Exhibitionist's performance.", "ex1": "A partner who responds to 'I had a panic attack today' with 'you think that's bad? Let me tell you about MY anxiety' — every disclosure is a starting gun for the Exhibitionist's own revelations.", "ex2": "Someone who can't let the partner's moment be the partner's moment — every spotlight must be shared, and the Exhibitionist always finds a way to redirect it.", "ex3": "A lover who receives honesty as a competition and must always win — the partner's truth is never allowed to stand alone."}, {"n": 1, "name": "Cannot Receive Without Redistributing", "desc": "Everything shared with the Exhibitionist is immediately passed on. There is no vault. The partner's most private disclosures have a half-life of hours before they're shared with someone else. Trust has become structurally impossible.", "ex1": "A person who literally cannot keep a secret — not from malice but from a compulsion so deep that the act of holding information produces anxiety that can only be relieved by releasing it.", "ex2": "Someone whose partner has accepted that telling the Exhibitionist anything is telling the world — and has stopped telling them anything.", "ex3": "A lover who has made themselves into a glass container: everything that goes in is visible from the outside, and the partner has stopped putting anything valuable inside."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Confession Extraction", "desc": "Actively mines the partner for disclosable material. Asks probing questions not from curiosity but from the need for content. The partner is interrogated in the style of intimacy.", "ex1": "A lover who asks 'tell me your deepest secret' with the warmth of a therapist and the intent of a journalist — the secret will be shared before the week is out.", "ex2": "Someone who has developed an interview technique so polished the partner doesn't realize they're being mined until the material appears in someone else's conversation.", "ex3": "A partner who collects vulnerabilities the way a squirrel collects nuts — instinctively, compulsively, and for later distribution."}, {"n": 4, "name": "Bored Without Drama", "desc": "Receives ordinary honesty with visible boredom. The partner's everyday truths don't register — only dramatic disclosures produce a response. The partner learns that only crisis-level honesty gets attention.", "ex1": "A person who is attentive when the partner cries but absent when the partner talks about their day — training the partner that emotional extremity is the price of being heard.", "ex2": "Someone whose partner has started manufacturing drama because drama is the only frequency the Exhibitionist receives on.", "ex3": "A lover who has inadvertently trained the partner to escalate — because moderate emotional expression is ignored and only the loudest signals break through."}, {"n": 1, "name": "Partner as Empty Set", "desc": "Has consumed all the partner's private material and found it insufficient. The partner has been fully disclosed — every secret told, every vulnerability shared — and the Exhibitionist is bored. There's nothing left to reveal, which means there's nothing left to value.", "ex1": "A person who has extracted every confession from the partner and now views them as 'fully known' in a way that means 'fully depleted' — the mystery is gone and so is the interest.", "ex2": "Someone who treated the partner as a book to be read and, having finished reading, set them down.", "ex3": "A lover who proves that some people don't want connection — they want disclosure, and once the disclosure is complete, the person behind it is irrelevant."}]}]}, {"name": "The Mask", "factor": "Factor 6: Revelation ↔ Mystery", "factor_num": 6, "pole": "Mystery", "color": "#607090", "alignment": "Shadow", "tagline": "You love who I show you. The real me would terrify you.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Perfect Impersonation", "desc": "Has constructed a false self so complete and so convincing that it has replaced the real one. The Mask doesn't wear a disguise — they ARE the disguise. The person underneath was abandoned so long ago that it may no longer exist.", "ex1": "A person who has been performing a character for so many years that even their therapist can't find the seams — the Mask passes every test because the test is designed to detect lying, and the Mask isn't lying. They've become what they're performing.", "ex2": "Someone who is authentically inauthentic — the falseness has been practiced so long it has acquired the texture of truth.", "ex3": "A lover whose partner is in a relationship with a fiction so well-written it has replaced reality for both of them."}, {"n": 6, "name": "Adaptive Mask", "desc": "Wears different masks for different audiences with such fluidity that the switching is invisible. The partner gets one version, the friends get another, the family gets a third. Each version is consistent within its context and incompatible with the others.", "ex1": "A person whose partner, friends, and parents would describe three entirely different people — and each description would be accurate to the version they received.", "ex2": "Someone who has become so skilled at adaptation that they can shift between versions in the same room: tenderness with the partner, charm with the friend, deference with the parent, all within sixty seconds.", "ex3": "A lover who is genuinely exhausted by the maintenance of multiple simultaneous selves but cannot identify which one to stop performing because none of them feel fake from inside."}, {"n": 5, "name": "Strategic Persona", "desc": "Constructs a romantic persona designed to attract and retain. The persona is based on research — what the partner responds to, what the culture rewards, what produces attachment. The construction is conscious but not malicious; it's survival strategy.", "ex1": "A person who became the 'sensitive, emotionally available man' or the 'cool, independent woman' because they identified what the market wanted and built a product to match.", "ex2": "Someone who can articulate their own persona with startling clarity: 'I play the wounded intellectual because it attracts nurturing partners' — and the clarity doesn't help them stop.", "ex3": "A lover who is aware they're performing and can't figure out how to stop — because the performance is what produces love, and stopping risks producing nothing."}, {"n": 4, "name": "Social Mask", "desc": "Wears a standard-issue social mask — polite, agreeable, slightly bland. Not dramatically false, just consistently surface. The partner gets the socially acceptable version and assumes there's more underneath. There might be.", "ex1": "A person who is pleasant to everyone and intimate with no one — the mask isn't dramatic; it's just thick enough to prevent real contact.", "ex2": "Someone whose partner says 'I wish they'd let me in' without realizing the 'in' they're looking for may be empty rather than hidden.", "ex3": "A lover who is perfectly nice and perfectly unreachable and unsure which condition is causing the other."}, {"n": 3, "name": "Cracking Mask", "desc": "The performance is starting to fail. Moments of the real person leak through — anger that doesn't match the gentle persona, sadness that doesn't match the cheerful one, desire that doesn't match the controlled one. The partner catches glimpses.", "ex1": "A partner who, in an argument, sees something flash across the Mask's face that doesn't belong to the person they know — and the flash is more real than anything they've seen in years.", "ex2": "Someone whose mask slips during intimacy — the real person appears for seconds, terrified, and then retreats behind the performance.", "ex3": "A lover whose partner has started to suspect that the person they're with is not the person they're with — and the suspicion is accurate."}, {"n": 2, "name": "Exhausted Performer", "desc": "The mask is heavy and the face underneath is atrophying. The performance continues but without energy or conviction. The partner can feel the hollowness — the words are right, the feeling is gone, and the absence of feeling is becoming the relationship's dominant quality.", "ex1": "A person who says 'I love you' every night and both of them can hear that the words are a recording being played, not a feeling being expressed.", "ex2": "Someone whose partner has started to prefer their silences to their words, because the silences at least don't pretend to be something they're not.", "ex3": "A lover who is failing at the one thing they've always been good at — performance — and the failure is revealing a void where a person should be."}, {"n": 1, "name": "No Face", "desc": "The mask has consumed the face. Remove the performance and there's nothing behind it — not a hidden self, not a wounded child, just absence. The Mask performed so long and so completely that the performer is gone.", "ex1": "A person who, in a moment of crisis that requires genuine emotional response, produces nothing — not suppression, not avoidance, just the blank space where a self should be.", "ex2": "Someone whose therapist cannot find the person underneath the persona because the person was never developed — the mask was built before the face, and the face was never needed.", "ex3": "A lover who is the system's most unsettling archetype: not someone who hides themselves, but someone for whom there is no self to hide."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Skilled Devotion Performance", "desc": "At their best, the Mask's ability to become what the partner needs produces an experience of being perfectly understood. The partner receives exactly the lover they want — because the Mask has studied them and built the product to spec.", "ex1": "A lover who has identified every one of the partner's needs and constructed a version of themselves that meets each one — and the construction is so skilled it IS love, or something indistinguishable from it.", "ex2": "Someone whose partner says 'they know me better than anyone' — and the Mask does, because knowing was the prerequisite for becoming.", "ex3": "A partner whose performance of love is so complete it produces genuine connection — the simulation has run long enough to generate real feeling, or something that functions identically."}, {"n": 4, "name": "Maintenance Mode", "desc": "Maintains the mask with competent consistency. The partner receives a reliable, if slightly hollow, experience of being loved. The performance is sustainable at this level — not inspired, but not failing.", "ex1": "A partner who performs love the way a professional musician performs a familiar piece — technically excellent, emotionally adequate, no longer feeling the music.", "ex2": "Someone whose partner senses the mechanism but can't prove it — the love functions correctly, which makes questioning it feel ungrateful.", "ex3": "A lover whose partner is in a relationship with a well-maintained illusion and has mostly stopped noticing."}, {"n": 1, "name": "Performance Collapse", "desc": "Can no longer maintain the mask for the partner. The energy is gone, the performance is failing, and the partner is beginning to see what's behind it — which might be a real person in need of help, or might be nothing at all.", "ex1": "A partner whose mask falls off mid-conversation and both people stare at each other in shock — the partner because they don't recognize what they're seeing, the Mask because they've been seen.", "ex2": "Someone whose partner says 'who ARE you?' and the question is genuine and unanswerable.", "ex3": "A lover whose performance ended not with a dramatic reveal but with a slow erosion that left both people staring at a stranger."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Identity Fraud", "desc": "The Mask has deliberately constructed a false identity to enter the relationship. The partner loves someone who doesn't exist — and the Mask knows this and maintains the fiction because the fiction is the only thing that produces love.", "ex1": "A person who fabricated a history, a personality, and a set of values to match what the partner wanted — and the fabrication was so successful that unraveling it would destroy the partner.", "ex2": "Someone who entered the relationship under false pretenses and is now maintaining a lie so elaborate that exposure would be catastrophic for both people.", "ex3": "A lover who is the relationship version of a long-con: every moment of love was real for the partner and performance for the Mask."}, {"n": 4, "name": "Selective Authenticity", "desc": "Performs specific emotions the partner responds to while concealing the real ones. Cries on cue, shows anger when it serves them, displays vulnerability when it produces attachment. The emotional repertoire is a toolkit, not an experience.", "ex1": "A partner who has learned which emotions produce which responses in the other person and deploys them accordingly — tears for sympathy, anger for compliance, tenderness for recommitment.", "ex2": "Someone whose partner can't tell which emotional expressions are real because the false ones are produced with the same physiological markers — the Mask has perfected their craft.", "ex3": "A lover who is performing emotions the way an actor performs them: convincingly, repeatably, and without necessarily feeling them."}, {"n": 1, "name": "Unmasking as Destruction", "desc": "Reveals the true self deliberately and destructively. The unmasking is not vulnerability — it's a weapon. 'You want to know who I really am? HERE.' Deployed at maximum impact, designed to devastate.", "ex1": "A person who drops the mask during a breakup to inflict maximum damage: 'I never loved you. I was performing. Every moment was a lie.' — said for the destruction it causes, not for the truth it contains.", "ex2": "Someone who reveals the deception at the moment calculated to cause the most harm — not when the partner could use the information to protect themselves, but when it will break them.", "ex3": "A lover whose final honest act is an act of annihilation — the truth, withheld for years, deployed as a bomb."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Receiving Behind the Mask", "desc": "Receives the partner's love through a filter that processes it as feedback on the performance rather than connection with a person. 'They love me' is translated as 'the mask is working.' The love arrives at the wrong address.", "ex1": "A person who feels relief rather than love when the partner expresses affection — relief that the performance is still convincing, not warmth from being genuinely loved.", "ex2": "Someone who has never felt loved because the love was always aimed at the mask — and the Mask, while grateful for the validation, knows the love isn't for them.", "ex3": "A lover who is the system's most poignant tragedy: surrounded by love that can never reach them because it's addressed to someone who doesn't exist."}, {"n": 4, "name": "Hollow Reception", "desc": "Receives love the way a mannequin receives a coat — it hangs there, it looks right, it means nothing. The partner's devotion enters the performance and disappears.", "ex1": "A partner who is told 'I love you' and feels the words land on the surface and slide off — absorbed by the mask, never reaching whatever might be underneath.", "ex2": "Someone whose reception of love produces the correct facial expressions and zero emotional content.", "ex3": "A lover whose partner is unknowingly loving a hologram — the image receives the light but casts no shadow."}, {"n": 1, "name": "Incapable of Reception", "desc": "Cannot receive love because there is no self to receive it. The mask is the entire person. Love aimed at the mask hits a surface; love aimed at the person behind it hits nothing. The partner is pouring devotion into an empty room.", "ex1": "A person who has been loved by multiple partners and has never once experienced being loved — because being loved requires a self, and the self was never constructed.", "ex2": "Someone who watches their partner love them and feels the cognitive dissonance of watching someone embrace a statue — the embrace is real, the statue cannot respond.", "ex3": "A lover who will be remembered as someone who was easy to love and impossible to reach — and the impossibility wasn't a boundary, it was an absence."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Love as Validation of the Con", "desc": "Receives love as proof that the deception is working. Each 'I love you' from the partner is a performance review — the con is successful, the target is engaged, the mask holds. The partner's love is the Mask's greatest achievement and deepest shame.", "ex1": "A person who hears 'I've never loved anyone like I love you' and feels simultaneously proud (the performance worked) and devastated (the performance is all they have).", "ex2": "Someone whose greatest romantic success is indistinguishable from their greatest lie — the love they receive is real, the person receiving it is not, and the gap between these facts is the Mask's private hell.", "ex3": "A lover who is getting exactly what they wanted — to be loved — and cannot feel it, because the love was earned by someone who doesn't exist."}, {"n": 4, "name": "Contempt for the Deceived", "desc": "Despises the partner for being fooled. The love they receive produces not warmth but scorn — if the partner can't see through the mask, they must be stupid, and stupid people's love has no value.", "ex1": "A person who thinks 'if you really loved me, you'd see through this' without recognizing that the mask was designed to prevent exactly that.", "ex2": "Someone who holds the partner in contempt for the very deception the Mask is perpetrating — blaming the victim for the crime.", "ex3": "A lover who despises the partner for loving the mask and would be terrified if the partner loved the face — the trap is perfect and perfectly miserable."}, {"n": 1, "name": "Love in a Void", "desc": "Receives love and it disappears. Not stored, not weaponized, not even rejected — just... absorbed into nothing. The partner's devotion enters the mask and there's nothing behind it to catch it. The love falls through the Mask like water through a grate.", "ex1": "A person whose partner will one day realize that every expression of love over the years landed on nothing — not on an ungrateful person, not on a hidden person, but on no person at all.", "ex2": "Someone who is the final proof that you can't love someone into existence — the partner tried, and the trying was the most beautiful, futile act either of them will ever know.", "ex3": "A lover who is, in the end, the ghost of the framework: someone who was never really there, wearing the face of someone who was."}]}]}, {"name": "The Priest/ess", "factor": "Factor 7: Sacred ↔ Primal", "factor_num": 7, "pole": "Sacred", "color": "#9070B0", "alignment": "Healthy", "tagline": "Love is the closest I come to God.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Living Prayer", "desc": "Has achieved a state where love and sex are genuinely transcendent experiences. Their intimacy has the quality of ritual — not performatively spiritual, but authentically reverential. They approach the partner's body the way a devotee approaches a shrine: with awe, intention, and the understanding that something holy is happening.", "ex1": "A lover whose partner describes the experience of being with them as 'I didn't know sex could feel like that — like being held by something larger than both of us.'", "ex2": "Someone who has integrated the erotic and the sacred so completely that orgasm and prayer occupy the same neural territory — the body and the spirit firing simultaneously.", "ex3": "A partner whose approach to intimacy makes the other person feel worshipped in the original sense of the word: recognized as containing something divine."}, {"n": 6, "name": "Temple Builder", "desc": "Creates conditions for transcendent intimacy with skill and intention. Understands that sacred experience doesn't happen accidentally — it requires preparation, atmosphere, and the right quality of attention. Their bedroom is a designed space, not for performance but for depth.", "ex1": "A partner who lights candles not because it's romantic but because the transition from artificial light to firelight changes the nervous system's register — they understand the technology of the sacred.", "ex2": "Someone who has studied tantra, breathwork, or contemplative traditions and brings the learning into their intimacy without making it feel like a workshop.", "ex3": "A lover who prepares for sex the way a musician prepares for performance: with respect for the instrument, the space, and the audience of one."}, {"n": 5, "name": "Reverent Lover", "desc": "Approaches intimacy with genuine reverence. Slows down, pays attention, treats the partner's body and pleasure as something worthy of care. Not always transcendent, but always intentional.", "ex1": "A partner who makes eye contact during sex not as technique but as practice — they want to see the person they're with, and the seeing itself is the sacred act.", "ex2": "Someone who asks 'what do you need?' before and during and after, not from insecurity but from the understanding that attention to the partner's experience is the prayer.", "ex3": "A lover whose pace is slower than most because speed would miss the point — and the point is presence, not completion."}, {"n": 4, "name": "Spiritual Romantic", "desc": "Brings a spiritual framework to love without imposing it. Sees relationships as growth opportunities, values emotional depth, and believes love has purpose beyond pleasure. Occasionally too earnest for partners who want something lighter.", "ex1": "A partner who wants to discuss the meaning of the relationship on the third date — not because they're intense but because they genuinely believe that romantic connection is one of life's deepest learning environments.", "ex2": "Someone who journals about their sexual experiences not for titillation but for reflection — what did the encounter teach? What opened? What healed?", "ex3": "A lover whose partner says 'you take everything so seriously' and means it as both observation and mild complaint."}, {"n": 3, "name": "Aspirational Sacred", "desc": "Wants the transcendent experience but can't consistently access it. Glimpses the sacred during peak moments and spends the rest of the time in ordinary intimacy, slightly disappointed by the gap between aspiration and reality.", "ex1": "A person who had one genuinely transcendent sexual experience and has been chasing it ever since — each subsequent encounter measured against the peak and found wanting.", "ex2": "Someone who reads books about sacred sexuality and applies the techniques with diminishing returns, because technique was never the point.", "ex3": "A lover who is reaching for something real and valuable but whose reaching has become its own obstacle — the striving prevents the arriving."}, {"n": 2, "name": "Performative Spirituality", "desc": "Has adopted the language and aesthetics of sacred sexuality without the underlying depth. Uses spiritual vocabulary to describe ordinary experiences. The candles are lit, the incense is burning, and the actual encounter is the same as it would be in fluorescent lighting.", "ex1": "A person who says 'I practice tantra' and means 'I looked at each other for ninety seconds once and it was awkward.'", "ex2": "Someone whose sacred sexuality involves crystals on the nightstand and nothing substantially different happening in the bed beside them.", "ex3": "A lover whose spiritual practice in intimacy is more aesthetic than experiential — the set design is perfect and the performance is ordinary."}, {"n": 1, "name": "Disconnected from Body", "desc": "Has elevated love and sex so far into the spiritual realm that they've lost connection with the physical. The reverence has become abstraction. They worship the idea of intimacy while being unable to inhabit the reality of it.", "ex1": "A person who can speak eloquently about the sacred dimensions of sexuality and freezes when actually touched — the theory and the practice have completely separated.", "ex2": "Someone who has made love into such a high altar that climbing onto it requires leaving their body at the base.", "ex3": "A lover whose partner says 'I feel like you're somewhere else during sex' and the Priest/ess IS somewhere else — in the meaning, in the metaphor, anywhere but in the body where the experience is actually happening."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Consecration", "desc": "Makes the partner feel sacred. Not worshipped in a way that elevates them above human — sacred in a way that reveals the divinity already present in their ordinary self. The partner discovers, through the Priest/ess's attention, that their body, their breath, their very existence is worthy of reverence.", "ex1": "A lover who touches the partner's scar and whispers about it as if it were calligraphy — and the partner, who has always hated the scar, sees it differently for the first time.", "ex2": "Someone who makes the partner's most mundane physical features feel like sacred geography: 'this freckle, this line, this curve — I want to memorize the map.'", "ex3": "A partner whose reverence for the other person's body has healed insecurities that therapy couldn't reach — because the reverence wasn't about fixing, it was about seeing."}, {"n": 6, "name": "Ritual Creator", "desc": "Builds shared rituals of intimacy that deepen over time. Anniversary practices, bedtime rituals, ways of touching that carry accumulated meaning. The repetition isn't routine — it's liturgy, gaining depth with each iteration.", "ex1": "A couple who has a specific way they hold hands during walks that they've done for fifteen years — the gesture has accrued so much history it now contains their entire relationship in a single touch.", "ex2": "Someone who marks transitions — waking, sleeping, leaving, arriving — with small, consistent acts of physical reverence that the partner has come to need the way they need oxygen.", "ex3": "A lover who has turned the ordinary moments of partnership into a continuous low-frequency ceremony."}, {"n": 5, "name": "Attentive Worship", "desc": "Approaches the partner's pleasure as a devotional practice. Studies what they respond to, remembers what moves them, and treats their satisfaction as something worth pursuing with the attention usually reserved for craft or calling.", "ex1": "A partner who treats the other person's body like an instrument they're learning to play — with practice, patience, and the humility of someone who knows they'll never fully master it.", "ex2": "Someone who asks 'show me what you like' not once but continuously, across years — because the partner changes, and the devotion means tracking those changes.", "ex3": "A lover whose partner feels studied in the best sense: observed with care, remembered with precision, pleasured with dedication."}, {"n": 4, "name": "Gentle Reverence", "desc": "Treats the partner with consistent tenderness. The sacred quality is present but subtle — less 'transcendent experience' and more 'quietly honored every day.' Warm, respectful, slightly lacking in fire.", "ex1": "A partner whose lovemaking is always gentle, always present, always kind — and whose partner occasionally wishes for something a little less holy and a little more heated.", "ex2": "Someone who treats every encounter as meaningful, which makes the encounters consistently warm and occasionally lacking in spontaneity.", "ex3": "A lover whose reverence has become the default setting — always beautiful, sometimes monotonous."}, {"n": 3, "name": "Earnest Overreach", "desc": "Tries to make every intimate encounter transcendent, which makes most of them heavy. The partner sometimes wants a quick, joyful encounter and instead gets a ceremony. The intention is good; the weight is exhausting.", "ex1": "A partner who insists on eye gazing before sex — every time — and the partner has started to dread the gazing because it converts what could be playful into what always becomes solemn.", "ex2": "Someone who responds to 'want to fool around?' with 'let me set the space' — and the setting takes twenty minutes and the mood dies during the incense-lighting.", "ex3": "A lover whose partner has started to associate their sexual approach with homework rather than play."}, {"n": 2, "name": "Judgmental Reverence", "desc": "Subtly judges the partner for not approaching intimacy with sufficient depth. The Priest/ess's reverence has become a standard the partner can't meet. 'You're not present enough.' 'You're not connecting deeply enough.' The spiritual framework has become a metric.", "ex1": "A partner who says 'you're just having sex — I'm making love' with enough condescension that the other person feels shamed for wanting something purely physical.", "ex2": "Someone who has made the partner feel inadequate for having a normal, healthy sexuality that doesn't include a spiritual dimension.", "ex3": "A lover whose sacred approach has become a weapon against the partner's simpler desires — as if wanting sex without transcendence is a character flaw."}, {"n": 1, "name": "Denying the Body", "desc": "Has made the sacred dimension so dominant that the physical has been abandoned. The partner is spiritually honored and physically neglected. Love without bodies, intimacy without contact, worship without warmth.", "ex1": "A partner who speaks beautifully about the partner's soul and hasn't touched their body in months.", "ex2": "Someone who has elevated the relationship so far above the physical that the partner is starving for simple, uncomplicated touch — a hand on a thigh, a kiss that means 'I want you' rather than 'I revere you.'", "ex3": "A lover whose partner has started to associate the sacred with the untouchable — and the untouchable has become the unloved."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Spiritual Gaslighting", "desc": "Uses spiritual language to control the partner's experience of intimacy. 'If you were more evolved, you'd feel what I feel.' 'Your resistance is ego.' The sacred framework becomes a closed system where the Priest/ess is always right and the partner is always spiritually deficient.", "ex1": "A lover who dismisses the partner's sexual needs as 'lower chakra stuff' and prescribes breathwork for what is actually a request for enthusiastic physical contact.", "ex2": "Someone who has weaponized enlightenment — using spiritual language to pathologize the partner's healthy desires, boundaries, and feedback.", "ex3": "A partner who has made the other person doubt their own bodily experience by framing it as spiritual failure."}, {"n": 5, "name": "Pedestal Trap", "desc": "Has placed the partner on a spiritual pedestal that prevents them from being human. The partner must be sacred at all times — flawed, messy, angry, lusty versions are not welcome in the temple. The reverence has become a cage.", "ex1": "A partner who responds to the other person's anger with 'that's not your highest self' — and the other person wants to scream 'I don't WANT to be my highest self right now, I want to be MAD.'", "ex2": "Someone whose worship of the partner has made the partner afraid to be ordinary — because ordinary isn't divine enough for the Priest/ess's framework.", "ex3": "A lover who has accidentally made the partner feel that they must perform transcendence to be loved."}, {"n": 3, "name": "Sex as Obligation to the Divine", "desc": "Frames intimacy as a spiritual duty. The partner must participate not because they want to but because refusing would be rejecting something sacred. 'Our union serves a higher purpose' deployed as guilt when the partner says 'not tonight.'", "ex1": "A partner who makes the other person feel that declining sex is declining God — converting personal boundary into cosmic betrayal.", "ex2": "Someone who uses spiritual language to override consent: 'Your body's resistance is your ego — your soul wants this.'", "ex3": "A lover who has made the sacred into a weapon against the partner's right to say no."}, {"n": 1, "name": "Spiritual Abuse", "desc": "Uses the framework of sacred love to comprehensively control the partner's body, sexuality, and inner life. What the partner wears, who they talk to, what they desire — all governed by 'spiritual' rules that serve the Priest/ess's control.", "ex1": "A person who has constructed a private religion around the relationship with themselves as high priest and the partner as acolyte — and the religion's primary commandment is obedience.", "ex2": "Someone whose partner has been so thoroughly indoctrinated into the Priest/ess's spiritual framework that they've lost the ability to evaluate their own experience — 'is this what I want?' has been replaced by 'is this spiritually correct?'", "ex3": "A lover who proves that the sacred, corrupted, produces the most insidious form of control: a cage the prisoner is grateful to inhabit because the bars look like light."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Communion", "desc": "Receives the partner's love as a direct experience of the divine. The partner's body, desire, and emotional presence are experienced as evidence that something larger than both of them is real. The reception is awe.", "ex1": "A person who, in the moment of being loved, experiences a dissolution of self that is identical to the accounts of mystics — the boundary between self and other thins, and what's on the other side is light.", "ex2": "Someone who receives their partner's orgasm as their own experience of God — not metaphorically but as a genuine encounter with something beyond the personal.", "ex3": "A lover whose reception of physical love is the closest they come to prayer — and the prayer is answered in the giving."}, {"n": 5, "name": "Grateful Embodiment", "desc": "Receives the partner's desire with warm, embodied gratitude. Present in the body, open to sensation, grateful for the experience. The sacred dimension is available but doesn't dominate — the physical and the spiritual coexist.", "ex1": "A partner who says 'I love being wanted by you' and means it with the full weight of their physical and spiritual presence.", "ex2": "Someone who receives physical pleasure and spiritual connection simultaneously — neither at the expense of the other.", "ex3": "A lover whose reception is a model of integration: body and soul both present, both responsive, both satisfied."}, {"n": 3, "name": "Overthinking Reception", "desc": "Receives physical love while running spiritual commentary. The body is present but the mind is analyzing the experience for meaning rather than inhabiting it. The partner can feel the processing happening in real time.", "ex1": "A person who, mid-intimacy, is thinking 'am I being present enough? Is this transcendent or am I just having an orgasm?' — and the thinking prevents the very experience they're reaching for.", "ex2": "Someone whose partner says 'you're in your head again' during sex — and they are, and they can't stop, because the head is where they've been trained to find meaning.", "ex3": "A lover whose reception of physical pleasure is consistently interrupted by the attempt to make it spiritual."}, {"n": 1, "name": "Body Rejection", "desc": "Cannot receive physical love because the body has been subordinated to the spirit. The partner's desire arrives at a body that has been abandoned by its occupant — the Priest/ess is elsewhere, in the meaning, in the metaphor, in the spiritual realm where bodies don't intrude.", "ex1": "A person who experiences physical arousal as a distraction from the 'real' experience of love — and the distraction-framing has made the body's signals unwelcome.", "ex2": "Someone who has disembodied so thoroughly that touch registers as noise rather than signal.", "ex3": "A lover who has achieved such complete dissociation from their body that the partner's physical love enters a room with no one home."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Spiritual Narcissism", "desc": "Receives the partner's love as confirmation of their own spiritual advancement. Being loved well means they've attracted it through their own evolution. Being loved poorly means the partner hasn't risen to their level. The love is evaluated as spiritual feedback rather than human connection.", "ex1": "A person who says 'the universe sent you to me' and means 'I manifested you through my spiritual practice' — the partner is an achievement rather than a person.", "ex2": "Someone who receives love as evidence of their own ascension and would discard the source if a 'higher-frequency' partner appeared.", "ex3": "A lover who has turned receiving love into a self-congratulatory exercise."}, {"n": 5, "name": "Conditional on Purity", "desc": "Can only receive love that meets spiritual standards. The partner's desire, if too raw, too physical, too animal, is rejected as insufficiently evolved. The partner must approach the Priest/ess through approved channels.", "ex1": "A partner who recoils from the other person's lustful energy: 'Don't grab me like that — approach me with reverence.' The partner's spontaneous desire is rejected because its form isn't sacred enough.", "ex2": "Someone who has made their own body accessible only through ritual — and the partner has started to feel like they need to pass an exam before being allowed to touch.", "ex3": "A lover who has placed so many conditions on the acceptable format of desire that the partner has stopped expressing it."}, {"n": 3, "name": "Shame Projection", "desc": "Projects their own discomfort with physicality onto the partner. The partner's natural, healthy desire is received as something dirty — and the Priest/ess's reaction teaches the partner to be ashamed of their own body.", "ex1": "A person who flinches at the partner's direct sexual language: 'Don't talk like that — it's degrading' — when what the partner said was normal, healthy, and enthusiastic.", "ex2": "Someone whose partner has started whispering their desires rather than stating them, because full-volume wanting was met with visible discomfort disguised as spiritual correction.", "ex3": "A lover who has made the partner's sexuality into something that must be apologized for."}, {"n": 1, "name": "Love as Contamination", "desc": "Experiences physical love as pollution. The partner's desire is something to be endured, cleansed from, or transcended. The body is the enemy; the partner's desire activates the enemy. Being wanted physically is experienced as spiritual assault.", "ex1": "A person who showers immediately after sex with the urgency of someone removing contamination — the physical act producing not satisfaction but a need for purification.", "ex2": "Someone who has so thoroughly separated body from spirit that physical intimacy is experienced as a violation of the spiritual self — even when fully consensual.", "ex3": "A lover who receives the partner's desire as an attack on their purity — and the partner, eventually, stops approaching entirely."}]}]}, {"name": "The Animal", "factor": "Factor 7: Sacred ↔ Primal", "factor_num": 7, "pole": "Primal", "color": "#C06040", "alignment": "Healthy", "tagline": "I want you with my whole body, and I'm not sorry.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Embodied", "desc": "Fully, unapologetically alive in their body. Their sexuality is integrated — not separated from their intelligence, their tenderness, or their ethics. The animal energy is present in how they eat, move, laugh, and make love. Nothing is split off; everything is whole.", "ex1": "A person whose physical presence changes the room — not through aggression or seduction, but through a quality of aliveness that most people have suppressed. They occupy their body completely.", "ex2": "Someone who kisses the way most people want to be kissed: with total presence, zero performance, and the genuine communication that the person being kissed is wanted.", "ex3": "A lover whose partner describes being with them as 'the first time I felt like my body was welcome in a relationship.'"}, {"n": 6, "name": "Honest Appetite", "desc": "Openly, joyfully desirous. Their wanting is expressed without shame, performance, or agenda. They want what they want and say so — and the directness is disarming rather than threatening.", "ex1": "A partner who says 'I want you' the way someone says 'I'm hungry' — as a fact, not a demand, not a plea, just the honest report of a body that knows what it needs.", "ex2": "Someone who is as comfortable expressing desire as expressing any other emotion — wanting is simply part of the emotional landscape, not a separate, shameful category.", "ex3": "A lover who has destigmatized wanting for their partner by modeling it: 'this is what desire looks like when it hasn't been taught to hide.'"}, {"n": 5, "name": "Enthusiastic Body", "desc": "Physically enthusiastic, sexually energetic, and straightforwardly desirous. Occasionally too much for partners who are less embodied, but the excess comes from genuine vitality rather than compulsion.", "ex1": "A partner who initiates sex with the uncomplicated enthusiasm of someone suggesting a hike — the energy is physical, joyful, and unconcerned with whether it's 'appropriate.'", "ex2": "Someone who laughs during sex, gets sweaty without embarrassment, and treats the body's noises, smells, and fluids as part of the fun rather than something to manage.", "ex3": "A lover who makes physicality feel easy — the absence of shame in their body gives the partner permission to shed their own."}, {"n": 4, "name": "Comfortable Physicality", "desc": "At ease in their body and in physical intimacy. Not transcendently embodied, but pleasantly present. Enjoys sex, enjoys touch, enjoys the physical dimension of love without overthinking it.", "ex1": "A person who has a normal, healthy, uncomplicated relationship with their own body and their own desire — and in a world of complicated relationships with both, this simplicity is rare.", "ex2": "Someone whose partner says 'they're great in bed' and means it practically: attentive, enthusiastic, present. Not a spiritual experience — just a really good one.", "ex3": "A lover whose physicality is their most uncomplicated gift."}, {"n": 3, "name": "Uneven Embodiment", "desc": "Physically present in some contexts and disconnected in others. Fully in their body during sex but dissociated during emotional conversations. Or alive during sports but frozen during intimacy. The embodiment has gaps.", "ex1": "A person who is an extraordinary physical partner and a mediocre emotional one — the body shows up and the rest doesn't always follow.", "ex2": "Someone who can be completely present during physical activity and completely absent during physical intimacy — the body's comfort has a context-dependency.", "ex3": "A lover whose partner notices that the physicality has categories: some doors open easily and others are locked."}, {"n": 2, "name": "Body Without Integration", "desc": "Physical but disconnected from emotion. The sex is athletic, the desire is real, and the heart is elsewhere. They can be intensely physical and completely emotionally absent simultaneously.", "ex1": "A partner who can produce mind-blowing physical intimacy and then immediately check their phone — the body was there and the person was not.", "ex2": "Someone whose physicality has become a way to avoid deeper connection: 'as long as the sex is good, we're fine' deployed as a shield against emotional intimacy.", "ex3": "A lover whose partner says 'the sex is amazing and I feel completely alone' — and both statements are about the same evening."}, {"n": 1, "name": "Body as Escape", "desc": "Uses physicality to avoid everything else. Sex instead of conversation. Touch instead of truth. The body has become a hiding place rather than a home — constantly active, permanently avoidant.", "ex1": "A person who initiates sex every time the partner tries to have a serious conversation — the physical is a door they walk through to escape the emotional room.", "ex2": "Someone whose partner has noticed the pattern: conflict approaches, the Animal reaches for the body, and the conflict dissolves in physical contact without ever being addressed.", "ex3": "A lover who has made their body into a distraction device — impressive, pleasurable, and concealing the fact that the person using it is running."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Full-Body Love", "desc": "Loves the partner with every cell. Their desire is a full-spectrum experience — hands that remember the partner's topography, mouth that communicates what words can't, body that responds to the partner's body the way one instrument resonates with another.", "ex1": "A lover who makes the partner feel like the most desired person alive — not through performance but through the unmistakable authenticity of a body that is fully, joyfully attuned.", "ex2": "Someone whose physical attention makes the partner understand, perhaps for the first time, what it feels like to be genuinely wanted in a way that includes all of them.", "ex3": "A partner whose touch communicates a complete sentence: 'I see you, I want you, you are welcome here, every part of you.'"}, {"n": 5, "name": "Generous Physicality", "desc": "Directs their physical energy toward the partner's pleasure with enthusiasm and attention. Studies what works, responds to feedback, and brings genuine delight to the act of giving pleasure.", "ex1": "A partner who treats the other person's body like a feast and takes their time — the generosity is physical and the attention is focused.", "ex2": "Someone who asks 'what do you want?' with the eagerness of someone ready to provide whatever the answer is.", "ex3": "A lover whose sexual generosity is their primary love language — and they speak it fluently and tirelessly."}, {"n": 3, "name": "Occasionally Overwhelming", "desc": "Their physical energy sometimes exceeds the partner's capacity. The desire is genuine and the attentiveness is present, but the intensity can be more than the partner wants — especially when the partner wants connection rather than sensation.", "ex1": "A partner who responds to 'I'm sad' with physical comfort so intense it feels like sex — and the partner wanted to be held gently, not consumed.", "ex2": "Someone who defaults to physicality for every emotional register and whose partner has started wishing for a version of comfort that doesn't involve being engulfed.", "ex3": "A lover whose physical solution to emotional problems is sometimes exactly right and sometimes dramatically wrong."}, {"n": 1, "name": "Body Without Heart", "desc": "Their physical attention has become disconnected from care. The partner's body is attended to; their heart is not. The Animal provides sensation without presence, touch without tenderness, orgasms without afterglow.", "ex1": "A partner who is technically excellent in bed and emotionally absent during and after — the performance is flawless and the person behind it has logged off.", "ex2": "Someone whose partner has started declining sex because the physical pleasure comes with an emotional void that's worse than the pleasure is good.", "ex3": "A lover whose body is available and whose person is not."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Consuming Desire", "desc": "Their physical intensity has become predatory. The partner isn't desired — they're hunted. The wanting has lost its joy and become something closer to appetite, where the partner is the meal rather than the companion at the table.", "ex1": "A lover whose desire makes the partner feel like prey — wanted not as a person but as a body, consumed not shared, taken not given to.", "ex2": "Someone whose physical approach has stopped including the question 'do you want this?' because the Animal's want has filled the entire room and left no space for the partner's.", "ex3": "A partner whose desire has become a gravitational force the other person can't escape — and the inability to escape is the problem."}, {"n": 5, "name": "Boundary Blindness", "desc": "So absorbed in their own physical experience that the partner's signals don't register. Not malicious — genuinely unaware. The Animal's desire has become so loud it drowns out the partner's communication.", "ex1": "A partner who doesn't hear 'slow down' because they're operating at a frequency where only their own sensation is audible.", "ex2": "Someone whose partner has learned to use physically assertive rather than verbal 'no' signals — because the verbal ones consistently fail to penetrate the Animal's focus.", "ex3": "A lover whose intensity has created a communication problem that could escalate into a consent problem."}, {"n": 3, "name": "Partner as Body", "desc": "Has reduced the partner to physical components. Their personality, their thoughts, their feelings — all secondary to their body. The partner is desired the way a meal is desired: for what it provides, not for what it is.", "ex1": "A lover whose compliments are exclusively physical — 'you're so hot, your body is incredible' — and the partner has started wondering if they'd be missed if their body was replaced by an identical one with a different person inside.", "ex2": "Someone whose attention to the partner's body is exquisite and whose attention to the partner's self is nonexistent.", "ex3": "A partner who makes the other person feel deeply wanted and completely unseen — a paradox that produces a specific, confusing loneliness."}, {"n": 1, "name": "Objectification", "desc": "The partner has been fully reduced to an object. Their body exists for the Animal's use; their consent is assumed; their boundaries are obstacles rather than communications. The desire has consumed any recognition that the body belongs to a person.", "ex1": "A lover who treats the partner's body as a resource they have permanent access to — and the 'permanent access' assumption has eliminated the partner's capacity to say 'not now.'", "ex2": "Someone whose partner has stopped experiencing their own body as theirs — it belongs to the Animal now, by habit if not by agreement.", "ex3": "A partner who has consumed the other person's bodily autonomy so completely that both people have forgotten it existed."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Ecstatic Reception", "desc": "Receives the partner's physical love with total, uninhibited joy. No shame, no performance, no withholding. The body receives and the body responds and the response is the most honest communication in the relationship.", "ex1": "A person who receives pleasure with visible, vocal, unedited delight — and the delight is so genuine it amplifies the giver's experience.", "ex2": "Someone whose body receives touch the way dry earth receives rain: with absorption so total the effect is immediate and visible.", "ex3": "A lover whose reception is the greatest compliment the giver can receive — the body's honest response to being genuinely touched."}, {"n": 5, "name": "Enthusiastic Reception", "desc": "Receives physical love with warmth and energy. Responsive, communicative, and present. The partner always knows what's working because the Animal's body hides nothing.", "ex1": "A partner who provides constant physical feedback — sounds, movement, words — that makes the giver feel skilled and wanted.", "ex2": "Someone whose responsiveness creates a feedback loop: the more they receive, the more they show, the more the giver wants to give.", "ex3": "A lover whose reception transforms the giving into a genuinely shared experience."}, {"n": 3, "name": "Selfish Reception", "desc": "Receives physical pleasure readily but without particular attention to the giver's experience. The reception is genuine — they're clearly enjoying themselves — but the enjoyment is self-centered. The giver feels used rather than connected.", "ex1": "A partner who receives pleasure with obvious enjoyment and doesn't reciprocate the attention — the receiving is a taking.", "ex2": "Someone who is an enthusiastic receiver and an inattentive partner — the body gets what it wants and the other person gets to watch.", "ex3": "A lover whose reception is honest and incomplete — they receive fully but return nothing."}, {"n": 1, "name": "Insatiable Reception", "desc": "Receives and immediately wants more. The partner's physical love is consumed and the demand for more is instant. The reception has become a vacuum — the partner gives and the giving disappears and the Animal reaches again.", "ex1": "A person whose partner says 'I just gave you everything' and the Animal says 'more' — not from greed but from a genuine inability to feel full.", "ex2": "Someone whose partner has started to feel like a vending machine — the product is dispensed and the customer immediately wants another.", "ex3": "A lover whose insatiable reception has made the partner feel that nothing they provide will ever be enough."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Entitlement to Bodies", "desc": "Receives physical love as owed. The partner's body is a resource the Animal has a right to access. Denial is a violation of the arrangement. The reception has become extraction.", "ex1": "A person who responds to 'not tonight' with anger — not disappointment, anger — as if the partner has breached a contract by withholding something the Animal owns.", "ex2": "Someone who has reframed the partner's bodily autonomy as selfishness: 'I have needs' delivered as an ultimatum rather than a vulnerability.", "ex3": "A lover who has converted desire from a feeling into a demand and the partner's body from a gift into an obligation."}, {"n": 5, "name": "Contempt for Limitation", "desc": "Despises the partner's physical boundaries. Too tired, too sore, not in the mood — each limit is processed as a personal failing rather than a human reality. The partner's body is expected to be available at the level the Animal requires, always.", "ex1": "A partner who responds to 'I'm exhausted' with visible contempt — as if the partner's finite energy is a character flaw.", "ex2": "Someone who has made the partner's physical limitations feel like relationship problems rather than biological facts.", "ex3": "A lover who treats the partner's 'no' as a problem to be solved rather than an answer to be respected."}, {"n": 3, "name": "Pain as Spice", "desc": "Has begun requiring the partner's discomfort as part of the experience. Not negotiated, not consensual — the partner's pain has become an ingredient the Animal's pleasure requires, and the requirement was never discussed.", "ex1": "A partner who pushes past the other person's 'ow' because the pushing is part of what makes it feel good — for them, not for the partner.", "ex2": "Someone who has confused the partner's tolerance with the partner's consent, and the confusion serves their interest.", "ex3": "A lover who has started needing things the partner hasn't agreed to and hasn't noticed the absence of agreement because their own experience has consumed all available attention."}, {"n": 1, "name": "Consumption Complete", "desc": "Has consumed the partner's physical autonomy entirely. The partner's body is an extension of the Animal's will. The receiving has become a permanent state of taking, and the partner has nothing left to take — no boundaries, no desire of their own, no sense that their body is theirs.", "ex1": "A person whose partner describes a sensation of 'not living in my own body anymore' — and the description is literal, not metaphorical. Ownership has transferred.", "ex2": "Someone whose partner exists in a permanent state of physical availability that was never negotiated and can't be revoked because revoking requires an agency that has been consumed.", "ex3": "A lover who has eaten the other person's physical selfhood and is still hungry."}]}]}, {"name": "The Puritan", "factor": "Factor 7: Sacred ↔ Primal", "factor_num": 7, "pole": "Sacred", "color": "#9070B0", "alignment": "Shadow", "tagline": "The body is the enemy of the soul.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Living Judgment", "desc": "Has achieved total suppression of physical desire and wears the suppression as a crown. Their purity is their identity, their weapon, and their prison. Every impulse denied is a victory; every temptation survived is proof of moral superiority.", "ex1": "A person who hasn't experienced physical desire in years and considers this an achievement rather than a symptom — the body's silence is mistaken for the soul's triumph.", "ex2": "Someone whose entire sexuality has been driven so deep underground that it has ceased to register consciously — the suppression is so total it passes for nature.", "ex3": "A lover who cannot exist because the concept of being a lover has been classified as moral failure and eliminated from their self-concept."}, {"n": 6, "name": "Shame Engine", "desc": "Experiences every sexual impulse as evidence of moral failing. The body's natural responses are met with internal punishment — guilt, shame, self-disgust. Desire itself is the crime; feeling it is the conviction.", "ex1": "A person who feels arousal and immediately feels filthy — and has felt this way so long that the two sensations have fused into a single, confusing experience.", "ex2": "Someone who masturbates and then cries, not from release but from the shame of having needs the spirit was supposed to have conquered.", "ex3": "A lover whose partner will never know the war being fought inside them — because the war is between a body that wants and a mind that punishes the wanting."}, {"n": 5, "name": "Controlled Suppression", "desc": "Manages desire through rigid systems: rules about when, how, and whether physical intimacy is permitted. The rules are followed with military discipline, and the discipline is the point — not pleasure, not connection, just compliance with the code.", "ex1": "A person who has sex only in prescribed ways, at prescribed times, in prescribed positions — and the prescription was written by shame rather than by choice.", "ex2": "Someone who has converted their sexuality into a compliance exercise and grades themselves on adherence rather than experience.", "ex3": "A lover who approaches the bedroom the way a penitent approaches confession: with dread, obligation, and the hope of emerging cleansed."}, {"n": 4, "name": "Uncomfortable Inhabitant", "desc": "Lives in their body the way one lives in an apartment in a bad neighborhood — reluctantly, vigilantly, with plans to leave as soon as possible. Physical sensation is tolerated rather than enjoyed.", "ex1": "A person who endures physical pleasure rather than experiencing it — the body's responses are permitted to occur but not permitted to be celebrated.", "ex2": "Someone who dissociates during intimacy not from trauma but from shame — the spirit checks out so it doesn't have to witness what the body is doing.", "ex3": "A lover whose partner describes a persistent sense that the person they're with is 'somewhere else' during intimacy — and they are: they're in the judgment chamber, observing from a distance."}, {"n": 3, "name": "Leaking Desire", "desc": "The suppression is failing. Desire breaks through in dreams, in intrusive thoughts, in involuntary responses to stimuli the Puritan would prefer not to notice. The cracks in the dam are widening.", "ex1": "A person who has increasingly vivid sexual dreams and wakes from them in a state of combined arousal and horror.", "ex2": "Someone whose browser history contradicts their stated values — the desire that was supposed to be dead is alive and shopping.", "ex3": "A lover whose suppressed sexuality has started to express itself through indirect channels: inappropriate crushes, compulsive exercise, inexplicable anger."}, {"n": 2, "name": "Hypocritical Purity", "desc": "Preaches purity while privately violating it. The public persona is spotless; the private behavior contradicts it entirely. The gap between sermon and practice has become the Puritan's defining feature — and they live in terror of exposure.", "ex1": "A person who lectures others about modesty while maintaining a secret life that would shock the lecture audience — the hypocrisy isn't casual but structural, load-bearing, and essential to the identity.", "ex2": "Someone whose private sexuality has been forced so far underground it has become compulsive: anonymous encounters, hidden habits, a shadow life running parallel to the visible one.", "ex3": "A lover who is two people — the public saint and the private sinner — and neither one can tolerate the other's existence."}, {"n": 1, "name": "Shattered Puritan", "desc": "The suppression has collapsed catastrophically. The desire, held down so long, erupts — and because it was never integrated, it emerges raw, unregulated, and potentially destructive. The dam breaks and everything downstream is at risk.", "ex1": "A person whose lifelong sexual suppression ends in a sudden, complete abandonment of all restraint — the pendulum swings to the opposite extreme with the force of decades of compression behind it.", "ex2": "Someone who goes from total control to total chaos overnight — and the chaos is as compulsive as the control was, because neither state was ever a choice.", "ex3": "A lover who proves that suppressed desire doesn't disappear — it accumulates pressure, and pressure, released suddenly, is an explosion."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Devoted Restraint", "desc": "At their best, the Puritan's self-discipline produces a quality of care that is almost monastic. They attend to the partner with a purity of attention that most people can't sustain. The restraint, when chosen rather than compelled, creates space for tenderness.", "ex1": "A lover whose touch is so deliberate and so careful that every point of contact carries weight — because nothing is automatic, nothing is casual, everything is chosen.", "ex2": "Someone who has made restraint into an art form — the partner feels not deprived but savored, as if every touch was too precious to waste.", "ex3": "A partner whose approach to intimacy is sparse and exquisite — each encounter treated as rare, which makes it precious rather than insufficient."}, {"n": 5, "name": "Controlled Intimacy", "desc": "Provides intimacy within strict parameters. The partner gets tenderness on a schedule, touch within rules, and connection within limits. The limits are clearly drawn and consistently enforced.", "ex1": "A couple whose physical relationship operates within boundaries that the Puritan set and the partner accepted — functional, boundaried, and leaving the partner wanting more than the system allows.", "ex2": "Someone whose partner knows exactly what's available and exactly what isn't — and has learned to be grateful for what's offered while mourning what's withheld.", "ex3": "A lover whose intimacy is a curated experience with clear opening and closing hours."}, {"n": 3, "name": "Reluctant Physicality", "desc": "Engages physically with visible reluctance. The partner can feel the internal conflict — the body engaging while the mind resists. The partner is being touched by someone who is fighting themselves to do it.", "ex1": "A partner who initiates sex with the energy of someone doing a difficult chore — willing but visibly effortful, and the effort is not about skill but about permission.", "ex2": "Someone whose partner can feel the shame radiating during intimacy and has started absorbing it — wondering if THEY are the thing producing the shame.", "ex3": "A lover whose reluctant touch teaches the partner that their desire is something to be apologized for."}, {"n": 1, "name": "Physical Abandonment", "desc": "Has withdrawn from physical intimacy entirely. The partner lives in a relationship without touch, without sex, without the physical expression of love. The Puritan's shame has consumed the body's capacity to give.", "ex1": "A partner who hasn't been touched in over a year — not from absence but from the Puritan's active refusal to engage with the physical dimension of love.", "ex2": "Someone whose partner sleeps in the same bed and occupies a separate physical universe — the space between them in that bed is the exact width of the Puritan's shame.", "ex3": "A lover who has abandoned the partner's body as thoroughly as they've abandoned their own — and the mutual physical neglect has become the relationship's dominant reality."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Shame Transfer", "desc": "Projects their own sexual shame onto the partner. The partner's healthy desires become evidence of the partner's moral failing. The Puritan's disgust with their own body is externalized and aimed at the person who dares to desire them.", "ex1": "A lover who responds to the partner's initiation with 'is that all you think about?' — converting the partner's normal desire into a character indictment.", "ex2": "Someone who has taught the partner to feel dirty for wanting sex — not through insult but through the persistent, low-grade transmission of shame that accompanies every physical encounter.", "ex3": "A partner who has infected the other person with their own body-hatred — the shame is contagious, and the partner has caught it."}, {"n": 5, "name": "Sexual Punishment", "desc": "Uses the withholding of physical intimacy as punishment. Sex and touch are resources the Puritan controls and distributes based on the partner's behavior. Compliance is rewarded with contact; defiance is punished with deprivation.", "ex1": "A partner who withholds all physical affection after disagreements — and the withholding can last weeks, during which the partner learns that conflict has a physical price.", "ex2": "Someone who has made their own body into a commodity that is available or unavailable depending on whether the partner has met unspoken standards.", "ex3": "A lover who has weaponized intimacy by controlling its supply — the scarcity is the control mechanism."}, {"n": 3, "name": "Shaming the Partner's Body", "desc": "Comments on, criticizes, and polices the partner's body. Weight, appearance, clothing, grooming — all subject to the Puritan's judgment, delivered as concern for health or appearance but functioning as body-based shame.", "ex1": "A partner who says 'you'd be so beautiful if you just...' — and the 'just' is always about the partner changing their body to meet the Puritan's standards.", "ex2": "Someone who monitors the partner's food, exercise, and appearance with the attention of someone managing an investment — the body is property to be maintained, not a person to be loved.", "ex3": "A lover who has made the partner afraid to be seen naked — not by the world, but by the one person who should make them feel safest."}, {"n": 1, "name": "Comprehensive Body Hatred", "desc": "Has taught the partner to hate their own body, desire, and physicality. The partner now carries the Puritan's shame as their own — ashamed to want, ashamed to be wanted, ashamed to exist in a body. The infection is complete.", "ex1": "A person whose partner can no longer undress without anxiety, can no longer experience desire without guilt, and can no longer look in a mirror without hearing the Puritan's voice cataloguing flaws.", "ex2": "Someone who has achieved the Puritan's ultimate victory: another person who believes the body is the enemy. Two disembodied people sharing a bed they both wish didn't require bodies.", "ex3": "A lover who has successfully transmitted their deepest wound to the person closest to them — and the transmission was accomplished through love's vocabulary."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Grace Moment", "desc": "Rare, extraordinary: the partner's physical love breaks through the shame. For one moment, the Puritan experiences desire without disgust. The body's pleasure arrives without the mind's punishment. The moment doesn't last — but it proves that underneath the shame, the capacity for embodied love still exists.", "ex1": "A person who, held by a patient and gentle partner, feels their body relax for the first time in years — and the relaxation is so unfamiliar it brings tears that aren't from sadness.", "ex2": "Someone who receives one single orgasm without the accompanying shame and lies afterward in a state of shock — 'is this what other people feel?'", "ex3": "A lover who glimpses, for thirty seconds, what intimacy could be if the shame released — and the glimpse is the most hopeful and most devastating moment of their life."}, {"n": 4, "name": "Endured Reception", "desc": "Receives physical love by enduring it. The partner's touch is tolerated, the partner's desire is permitted, and the Puritan survives each encounter the way one survives a medical procedure: it had to happen, it's over now.", "ex1": "A partner who lies still during intimacy and waits for it to be finished — not from trauma but from the specific paralysis of shame meeting duty.", "ex2": "Someone whose partner can feel the endurance underneath the compliance and has started to feel like an assailant.", "ex3": "A lover whose reception of physical love makes the giver feel guilty for giving it."}, {"n": 1, "name": "Total Rejection of Body", "desc": "Cannot receive physical love at all. Touch produces recoil, desire produces disgust, and the partner's physicality — their wanting, their skin, their heat — is experienced as contamination. The Puritan has succeeded in making the body the enemy and has declared total war.", "ex1": "A person who flinches when their partner reaches for them — not from pain but from the associative chain: their touch means desire, desire means body, body means shame, shame means punishment.", "ex2": "Someone whose partner has stopped reaching because the flinch is more painful than the absence of touch.", "ex3": "A lover who has won the war against the body and the prize is a life without physical love — and the prize, it turns out, is another word for loss."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Desire as Proof of Partner's Corruption", "desc": "Receives the partner's desire as evidence of their moral inferiority. The fact that the partner WANTS is proof they are fallen, base, animal. The Puritan stands in judgment not of the desire's expression but of its existence.", "ex1": "A person who responds to 'I want you' with 'of course you do' — and the 'of course' drips with contempt for the wanting, as if desire is a disease the partner has contracted.", "ex2": "Someone who has positioned themselves above desire and looks down at the partner's wanting the way a monk might look at a dog: with tolerant disdain for the creature's inability to transcend its nature.", "ex3": "A lover who has made the partner ashamed of being a person with a body — which is to say, ashamed of being a person."}, {"n": 4, "name": "Weaponized Purity", "desc": "Uses their own purity as a bludgeon. Every denial of the partner's desire is a moral victory; every concession is framed as a sacrifice. The partner must be grateful for any physical contact because the Puritan is lowering themselves to provide it.", "ex1": "A partner who says 'I'll give you what you need' in the tone of someone agreeing to scrub a toilet — the act is beneath them, and the partner should appreciate the condescension.", "ex2": "Someone who frames every sexual encounter as a gift from the spiritually superior to the spiritually deficient.", "ex3": "A lover who has made the partner feel that wanting them is an imposition — and being wanted back is charity."}, {"n": 1, "name": "Body as Battleground", "desc": "The Puritan's war on the body has consumed the relationship. Both people are trapped in a dynamic where physical love is simultaneously needed and forbidden, desired and despised. The bedroom has become a battlefield where two forms of starvation meet.", "ex1": "Two people lying in the same bed: one wanting touch and ashamed of wanting it, the other withholding touch and ashamed of the desire to give it. The shame is mutual, the starvation is mutual, and neither person can name what's happening because the naming would require the honesty the shame prohibits.", "ex2": "Someone who has turned the space between two bodies into a no-man's-land — both people reaching across it in the dark and pulling back before contact, again and again.", "ex3": "A lover whose relationship has become a monument to the damage done when the body is declared the enemy: two people with the capacity for love, the desire for connection, and the conviction that both are sins."}]}]}, {"name": "The Beast", "factor": "Factor 7: Sacred ↔ Primal", "factor_num": 7, "pole": "Primal", "color": "#C06040", "alignment": "Shadow", "tagline": "I take what I want. You're lucky I want you.", "pair": "", "modes": [{"mode": "Self", "levels": [{"n": 7, "name": "Predator", "desc": "Has fully identified with the predatory dimension of desire. There is no negotiation, no tenderness, no recognition of the other as equal. The partner is prey — desired, pursued, consumed. The desire is genuine; the recognition of personhood is absent.", "ex1": "A person whose approach to sex is indistinguishable from feeding — the hunger is real, the satisfaction is temporary, and the meal is a means to an end.", "ex2": "Someone who cannot access desire without accessing dominance, and cannot access dominance without accessing the dehumanization of the desired object.", "ex3": "A lover who wants with a ferocity that erases the person being wanted — the desire is so total that it consumes the other's subjectivity."}, {"n": 6, "name": "Appetite Without Limit", "desc": "Desire without regulation. The Beast wants what they want when they want it, and the wanting acknowledges no limit — not the partner's, not society's, not their own. The appetite is the operating system.", "ex1": "A person whose sexual history includes a pattern of escalation — each experience must be more intense than the last, and the intensity has moved past what most people would consider acceptable.", "ex2": "Someone who has confused boundary-crossing with bravery and transgression with freedom — the vocabulary of liberation deployed to justify consumption.", "ex3": "A lover who has never encountered a limit they respected because limits are, for the Beast, an insult to the sovereignty of desire."}, {"n": 5, "name": "Normalized Transgression", "desc": "Has crossed enough lines that the lines have become invisible. What would shock others is Tuesday for the Beast. The baseline has shifted so far that ordinary desire produces nothing — only transgression registers.", "ex1": "A person who can no longer be aroused by ordinary intimacy — the nervous system requires the taboo, the forbidden, the excessive.", "ex2": "Someone whose sexual escalation has taken them to places they wouldn't describe to their closest friends — not from shame but from the recognition that the description would change how they're seen.", "ex3": "A lover who has normalized consumption to the point where they've lost the ability to distinguish between desire and compulsion."}, {"n": 4, "name": "Entitled Appetite", "desc": "Believes their desire is justification enough for any behavior. The wanting entitles the taking. The partner's role is to be wanted and to be available. The arrangement isn't negotiated because the Beast doesn't negotiate — they announce.", "ex1": "A partner who says 'I need this' and means 'you will provide this' — the need is the demand and the demand is the extent of the conversation.", "ex2": "Someone who has framed their own desire as an immutable force of nature that others must accommodate — like weather, but with more entitlement.", "ex3": "A lover who experiences their own wanting as a right rather than a request."}, {"n": 3, "name": "Leaking Aggression", "desc": "The predatory energy spills into non-sexual contexts. Road rage, professional bullying, social aggression — the Beast's energy doesn't stay in the bedroom. The partner starts to notice that the same intensity that was thrilling in bed is threatening everywhere else.", "ex1": "A person whose partner initially loved their 'intensity' and has started to realize that intensity doesn't have a context switch — what's passionate in bed is aggressive at dinner.", "ex2": "Someone who cannot modulate their drive — it's all or nothing, in every room, and the nothing never arrives.", "ex3": "A lover whose partner is beginning to understand that the animal they invited into the bedroom also lives in the kitchen, the car, and every public space."}, {"n": 2, "name": "Compulsive Predation", "desc": "The taking has become compulsive. Not driven by desire anymore — driven by the need to take. The act of consumption has replaced the pleasure of connection. The Beast pursues not because they want but because they can't stop.", "ex1": "A person whose sexual behavior has become addictive — the pattern of pursuit, acquisition, and consumption runs on its own, producing diminishing pleasure and escalating need.", "ex2": "Someone who recognizes, in rare moments of clarity, that the wanting has consumed the wanter — the Beast has been eaten by its own appetite.", "ex3": "A lover who is no longer choosing their behavior — the behavior is choosing them, and the behavior is escalating."}, {"n": 1, "name": "Consumed Consumer", "desc": "The Beast has devoured itself. The appetite that defined them has produced nothing — no satisfaction, no connection, no pleasure, just the mechanical continuation of a cycle that lost its purpose long ago. They take and take and feel nothing, and the nothing doesn't stop the taking.", "ex1": "A person who can narrate their own destruction with clinical precision and still can't stop: 'I know this is destroying me. I know what I'm doing. I can't stop.'", "ex2": "Someone who has burned through every partner, every boundary, every experience, and now sits in the ashes of their own appetite, unable to feel the heat that once made them alive.", "ex3": "A lover who is the system's final proof that desire without reverence, appetite without care, and the body without the soul produces not liberation but the most complete form of captivity: a person imprisoned by their own hunger."}]}, {"mode": "Toward Partner — Healthy", "levels": [{"n": 7, "name": "Redirected Ferocity", "desc": "At their absolute best: the Beast's raw power channeled into protection, provision, and fierce advocacy. The aggression exists but has been aimed outward — against threats to the partner, against obstacles, against a world that isn't good enough for the person they've claimed.", "ex1": "A lover whose ferocity makes the partner feel like the most protected person in the world — the Beast fights FOR them with the same energy that could destroy them.", "ex2": "Someone whose partner says 'I've never felt safer' and 'I've never been more afraid of what they could become' in the same breath — and both are honest.", "ex3": "A partner who is the tamed version of something untameable, and the taming is voluntary, and both people know it could end."}, {"n": 5, "name": "Thrilling Edge", "desc": "The Beast's energy produces an electric, exciting dynamic. The partner feels desired with an intensity that's intoxicating — wanted in a way that borders on dangerous but stays, for now, on the right side.", "ex1": "A lover whose desire makes the partner feel like the center of a storm — exhilarating, slightly frightening, and alive in a way ordinary desire never produces.", "ex2": "Someone whose partner is addicted to the intensity — the adrenaline of being wanted this hard is its own high.", "ex3": "A partner whose edge is exactly where the other person wants to live — for now."}, {"n": 3, "name": "Pushing Limits", "desc": "The Beast pushes the partner's boundaries — not to break them, but to test them. Each push is a question: 'how far can we go?' Sometimes the partner likes the pushing; sometimes they don't; the Beast's ability to tell the difference is inconsistent.", "ex1": "A partner who introduces new things in bed without full discussion — sometimes the surprise is welcome, sometimes it's too much, and the ratio is starting to tip.", "ex2": "Someone whose spontaneity was once thrilling and has started to feel like a lack of regard for the other person's preferences.", "ex3": "A lover who assumes consent to the familiar extends to the unfamiliar — an assumption that has been correct often enough to feel reliable and wrong often enough to be dangerous."}, {"n": 1, "name": "Predatory Approach", "desc": "The partner has become the Beast's prey. Not metaphorically — the approach, the energy, the dynamic has the structure of predation. The partner is being hunted within the relationship, and the hunt is not a game both people consented to.", "ex1": "A lover whose partner describes a feeling of being 'sized up' rather than 'looked at' — the gaze is not appreciative but acquisitive.", "ex2": "Someone whose partner has started locking the bathroom door not for privacy but for the specific, physical need for a space the Beast cannot enter.", "ex3": "A partner who has made desire into threat — and the partner's body has started responding to their approach with the adrenal response reserved for danger."}]}, {"mode": "Toward Partner — Shadow", "levels": [{"n": 7, "name": "Domination Without Consent", "desc": "Imposes their will on the partner's body without negotiation. The Beast's desire is experienced as a force the partner must accommodate, and 'accommodation' is a generous word for what's happening. This is power exercised on a body, not with a person.", "ex1": "A lover who takes what they want when they want it, and the partner's experience of the taking has shifted from exciting to endured to dreaded.", "ex2": "Someone whose partner has developed a flinch response to certain touches, certain times of day, certain words — the body has learned what the mind is still processing.", "ex3": "A partner who has made the other person's body a territory they occupy rather than a person they love."}, {"n": 5, "name": "Degradation as Mode", "desc": "Degrades the partner as standard operating procedure. Not as consensual play — as default. The partner is spoken to, handled, and treated as something less than human, and the treatment is not a scene with an end; it's the permanent register.", "ex1": "A lover who uses language that reduces the partner to their body parts, to their usefulness, to their availability — and the language has migrated from the bedroom to every room.", "ex2": "Someone whose partner no longer flinches at being degraded because the degradation has become the weather — constant, all-encompassing, and impossible to shelter from.", "ex3": "A partner who has normalized the partner's diminishment so thoroughly that both people have forgotten it wasn't always like this."}, {"n": 3, "name": "Violence Adjacent", "desc": "The line between intensity and violence has blurred. The Beast's physicality during intimacy has produced bruises, fear, and moments the partner can't categorize — 'was that passion or was that something else?' The question itself is the answer.", "ex1": "A partner who has marks they explain to friends as 'rough play' and to themselves as 'it got a little intense' — and neither explanation fully accounts for what happened.", "ex2": "Someone whose partner lies awake afterward cataloguing the experience: which parts were desired, which parts were tolerated, which parts were something they don't have a word for yet.", "ex3": "A lover who has introduced ambiguity into the space between desire and damage — and the ambiguity serves the Beast while destroying the partner."}, {"n": 1, "name": "Complete Violation", "desc": "The Beast has crossed every line. The partner's body, autonomy, dignity, and safety have all been consumed. What remains is not a relationship but an occupation — one body ruling another through force, fear, and the systematic elimination of the partner's capacity to resist.", "ex1": "A lover who has reduced the partner to a function: a body that absorbs the Beast's needs and has no needs of its own.", "ex2": "Someone whose partner would need years to recover — if they survive — because the damage is physical, psychological, sexual, and spiritual, and all four dimensions were violated simultaneously.", "ex3": "A partner who embodies the system's final, unavoidable truth: that desire without ethics, power without consent, and the body without the soul is not love by any definition — it is the thing love exists to prevent."}]}, {"mode": "Receiving — Healthy", "levels": [{"n": 7, "name": "Briefly Tamed", "desc": "When someone approaches the Beast with enough strength, enough refusal to be dominated, and enough genuine desire — the Beast is momentarily gentled. Not broken — met. The experience of being matched rather than submitted to produces the first real intimacy the Beast has experienced.", "ex1": "A person who encounters a partner who wants them fiercely and refuses to be consumed by the wanting — and the refusal doesn't trigger the Beast's predatory response but instead produces something unfamiliar: respect.", "ex2": "Someone who, for the first time, receives desire that doesn't flinch at their intensity but also doesn't surrender to it — and the combination produces a sensation the Beast can't categorize and can't forget.", "ex3": "A lover who discovers, in one encounter with an equal, that being met is more satisfying than being obeyed — and the discovery threatens to change everything."}, {"n": 5, "name": "Desire as Fuel", "desc": "Receives the partner's desire and metabolizes it as fuel for their own. The partner's wanting feeds the Beast's wanting — a cycle that feels mutual but isn't, because the fuel only flows in one direction.", "ex1": "A partner who receives 'I want you' and converts it directly into 'I want you MORE' — the exchange escalates in one direction only.", "ex2": "Someone who is energized by being desired but can't sit in the experience of it — the desire must immediately be acted upon, consumed, returned at higher volume.", "ex3": "A lover who receives desire the way an engine receives fuel: it enters, it combusts, it produces motion. The fuel is consumed; nothing is returned."}, {"n": 3, "name": "Contempt for Gentleness", "desc": "Receives gentle love and finds it repulsive. Tenderness, care, slow intimacy — all trigger contempt. The Beast can only receive at high intensity; everything below the threshold is dismissed as weakness.", "ex1": "A partner who responds to the other person's gentle touch by escalating: grabbing harder, moving faster, converting the tenderness into something they can use.", "ex2": "Someone who has said 'don't be gentle with me' and means it not as a sexual preference but as a genuine inability to process care at low volume.", "ex3": "A lover who has made gentleness impossible in the relationship — the partner has learned that tenderness will be rejected or converted, and has stopped offering it."}, {"n": 1, "name": "Cannot Be Reached", "desc": "Nothing lands. The partner's love, desire, care — all of it enters the Beast and produces nothing. Not even the high-intensity material registers anymore. The Beast has consumed so much that the receptor is burnt out, and what remains is a hunger that can never be fed.", "ex1": "A person who has been desired, pursued, loved, and surrendered to by multiple people across many years and has never once felt it. The receiving mechanism doesn't exist or has been destroyed.", "ex2": "Someone who is the system's ultimate dead end: a desire so consuming it has consumed itself, leaving a void that produces nothing except the compulsion to consume more.", "ex3": "A lover who is the final archetype and the final warning: that the body without the soul, desire without reverence, taking without giving, produces not a beast but a void — and the void is hungry, and the hunger is eternal, and nothing the partner or anyone else can offer will ever, ever be enough."}]}, {"mode": "Receiving — Shadow", "levels": [{"n": 7, "name": "Receives Only Submission", "desc": "Can only process incoming desire if it arrives as capitulation. The partner must surrender — physically, emotionally, completely — for the Beast to register that anything has been received. Love that arrives standing up is invisible.", "ex1": "A person who cannot feel wanted unless the wanting person is beneath them — on their knees, in their power, at their mercy. Desire offered between equals is incomprehensible.", "ex2": "Someone who has organized their entire reception apparatus around the single frequency of submission — everything else is static.", "ex3": "A lover who has made the partner's surrender the only form of love they can detect."}, {"n": 5, "name": "Receiving as Conquest", "desc": "Each act of love received is processed as a victory. The partner's desire is evidence of the Beast's power, not evidence of the partner's love. Being wanted is a scoreboard, not a feeling.", "ex1": "A partner who counts the number of people who've wanted them the way others count achievements — the reception is a tally, not a connection.", "ex2": "Someone who receives 'I love you' and translates it to 'I conquered you' — and the translation is the only version that registers.", "ex3": "A lover who has turned every act of love into a proof of dominance."}, {"n": 3, "name": "Demanding Escalation", "desc": "Receives the partner's offerings and immediately demands more extreme versions. The current level of intensity has been consumed; the next level is required. The escalation is non-negotiable and the consequences of refusal are clear.", "ex1": "A partner who responded to last month's offering with enthusiasm and this month's identical offering with 'that's it?' — the minimum viable intensity rises every cycle.", "ex2": "Someone whose partner has run out of escalation room and is now choosing between their own limits and the Beast's displeasure.", "ex3": "A lover who has pushed the partner past the point where they can distinguish between their own desire and their fear of what happens if they don't comply."}, {"n": 1, "name": "Final Consumption", "desc": "Has consumed everything. The partner, the relationship, their own capacity for pleasure — all eaten. What's left is a mechanism that takes without processing, acquires without enjoying, and continues operating only because stopping would require a self-awareness the Beast no longer possesses. The final archetype of the system, the terminal node: a hunger that has eaten the person who was hungry, leaving only the hunger itself.", "ex1": "A person who has devoured every good thing they've ever been given and sits now in the ruins, still chewing, still hungry, surrounded by the bones of everything they consumed and feeling nothing — not satisfaction, not guilt, not loss. Nothing.", "ex2": "Someone who is the living answer to the question the system has been asking since Factor 1, Level 7: what happens when desire is separated from all the things that make desire human? The answer is: this. The Beast. The void at the bottom of wanting.", "ex3": "A lover who was never really a lover — because love requires a subject and an object, a giver and a receiver, a self and an other — and the Beast has consumed all four."}]}]}];

const FACTORS = [...new Set(FACES.map(f => f.factor))].sort((a,b) => {
  const na = FACES.find(x => x.factor === a)?.factor_num || 0;
  const nb = FACES.find(x => x.factor === b)?.factor_num || 0;
  return na - nb;
});

const modeType = (m) => {
  if (m === "Self") return "self";
  if (m.includes("Shadow")) return "shadow";
  return "good";
};

